def _build_users_db() -> Dict[str, str]:
    raw = os.environ.get("USERS", "zyni,abdul manan")
    db: Dict[str, str] = {}
    for u in raw.split(","):
        u = u.strip().lower()
        if u:
            key = "USER_" + u.replace(" ", "_").upper() + "_PASS"
            db[u] = os.environ.get(key, APP_PASSWORD)
