def send_verification_email(to_email: str, code: str, username: str,
                            purpose: str = "verify") -> "tuple[bool, str]":
    """Send a 6-digit OTP email directly to the user.
    purpose: 'verify' (email activation) | '2fa' (sign-in code)
    Attempts in order:
      1. Resend Python SDK  (RESEND_API_KEY env var — works on all cloud hosts)
      2. Gmail SMTP_SSL   port 465
      3. Gmail STARTTLS   port 587
    Returns (success: bool, fail_reason: str): 'ok' | 'missing_config' | 'delivery_failed'
    """
    frm = _email_from()
    pwd = _email_pass()
    if not to_email:
        return False, "missing_config"

    if purpose == "2fa":
        subject = "Your ZyNi SMC sign-in code"
    else:
        subject = "Your ZyNi SMC verification code"

    html_body = _build_verification_email(username, code, purpose)
    text_body = _build_verification_email_text(username, code, purpose)

    print(f"[VERIFY-EMAIL] Attempting to send {purpose} OTP to {to_email}")

    # ── Method 1: Resend HTTP API (works even when SMTP ports are blocked) ──
    if _send_via_resend(to_email, subject, html_body, text_body):
        return True, "ok"

    # ── Method 2 & 3: Gmail SMTP ─────────────────────────────────────────
    if not frm or not pwd:
        print(f"[VERIFY-EMAIL] SMTP skipped — "
              f"ALERT_EMAIL_FROM={'set' if frm else 'MISSING'}, "
              f"ALERT_EMAIL_PASS={'set' if pwd else 'MISSING'}")
        return False, "missing_config"

    def _build_msg():
        msg = MIMEMultipart("alternative")
        msg["Subject"]         = subject
        msg["From"]            = f"ZyNi SMC <{frm}>"
        msg["To"]              = to_email
        msg["Reply-To"]        = frm
        msg["Precedence"]      = "transactional"
        msg["X-Entity-Ref-ID"] = "zyni-otp"
        # Plain-text first — spam filters prefer multipart/alternative with text first
        msg.attach(MIMEText(text_body, "plain", "utf-8"))
        msg.attach(MIMEText(html_body, "html",  "utf-8"))
        return msg

    # Method 2: SMTP_SSL port 465
    try:
        with smtplib.SMTP_SSL("smtp.gmail.com", 465, timeout=15) as srv:
            srv.login(frm, pwd)
            srv.sendmail(frm, to_email, _build_msg().as_string())
        print(f"[VERIFY-EMAIL] Sent via Gmail SSL/465 to {to_email}")
        return True, "ok"
    except Exception as e1:
        print(f"[VERIFY-EMAIL] Gmail SSL/465 failed: {e1}")

    # Method 3: STARTTLS port 587
    try:
        ctx = ssl.create_default_context()
        with smtplib.SMTP("smtp.gmail.com", 587, timeout=15) as srv:
            srv.ehlo()
            srv.starttls(context=ctx)
            srv.ehlo()
            srv.login(frm, pwd)
            srv.sendmail(frm, to_email, _build_msg().as_string())
        print(f"[VERIFY-EMAIL] Sent via Gmail STARTTLS/587 to {to_email}")
        return True, "ok"
    except Exception as e2:
        print(f"[VERIFY-EMAIL] Gmail STARTTLS/587 also failed: {e2}")

    # Credentials were present but all delivery methods failed (SMTP likely blocked)
    print(f"[VERIFY-EMAIL] All methods failed for {to_email} — credentials set but delivery blocked")
    return False, "delivery_failed"


def _auto_migrate():
    """Add new columns / tables to an existing database without Flask-Migrate."""
    with app.app_context():
        try:
            from sqlalchemy import text
            with db.engine.connect() as conn:
                # Create any brand-new tables (email_verifications, etc.)
                db.create_all()
                # Add email_verified column to users if it doesn't exist yet
                conn.execute(text(
                    "ALTER TABLE users ADD COLUMN IF NOT EXISTS "
                    "email_verified BOOLEAN NOT NULL DEFAULT FALSE"
                ))
                # Preserve access for users registered before this migration
                conn.execute(text(
                    "UPDATE users SET email_verified = TRUE "
                    "WHERE email_verified = FALSE AND created_at < NOW() - INTERVAL '1 hour'"
                ))
                conn.commit()
                print("[MIGRATE] email_verified column ensured on users table")
                # Phase 10.8: OB Distance/Approach settings column on user_preferences
                conn.execute(text(
                    "ALTER TABLE user_preferences ADD COLUMN IF NOT EXISTS "
                    "ob_da_settings_json TEXT"
                ))
                conn.commit()
                print("[MIGRATE] ob_da_settings_json column ensured on user_preferences table")
                # Phase 11.9: TP/SL close metadata on paper positions
                for _stmt in [
                    "ALTER TABLE live_monitor_paper_positions ADD COLUMN IF NOT EXISTS close_reason  VARCHAR(30)",
                    "ALTER TABLE live_monitor_paper_positions ADD COLUMN IF NOT EXISTS close_price   VARCHAR(40)",
                    "ALTER TABLE live_monitor_paper_positions ADD COLUMN IF NOT EXISTS closed_at     TIMESTAMP",
                    "ALTER TABLE live_monitor_paper_positions ADD COLUMN IF NOT EXISTS exit_fill_id  INTEGER",
                    # Phase 11.9: close fill metadata on paper fills
                    "ALTER TABLE live_monitor_paper_fills ADD COLUMN IF NOT EXISTS fill_type    VARCHAR(30)",
                    "ALTER TABLE live_monitor_paper_fills ADD COLUMN IF NOT EXISTS position_id  INTEGER",
                    "ALTER TABLE live_monitor_paper_fills ADD COLUMN IF NOT EXISTS fee          NUMERIC(20,8)",
                ]:
                    conn.execute(text(_stmt))
                conn.commit()
                print("[MIGRATE] Phase 11.9 paper position/fill close metadata columns ensured")
                # Phase 11.10: paper trades journal table — db.create_all() above handles
                # the new table on fresh installs; ALTER TABLE below is idempotent insurance
                # for live DBs that already ran without the new model registered.
                for _stmt in [
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS account_id        INTEGER",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS exit_fill_id      INTEGER",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS quantity          VARCHAR(40)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS entry_price       VARCHAR(40)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS exit_price        VARCHAR(40)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS outcome           VARCHAR(20)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS outcome_reason    VARCHAR(40)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS realized_pnl      NUMERIC(20,8)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS realized_pnl_pct  NUMERIC(10,4)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS risk_reward       NUMERIC(10,4)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS duration_seconds  INTEGER",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS max_favorable_excursion NUMERIC(20,8)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS max_adverse_excursion   NUMERIC(20,8)",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS entry_snapshot_json           TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS exit_snapshot_json            TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS execution_intent_json         TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS execution_intelligence_json   TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS mtf_orderflow_history_json    TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS ai_context_json               TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS ai_decision_json              TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS automation_policy_json        TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS paper_order_draft_json        TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS entry_order_json              TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS exit_fill_json                TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS entry_orderflow_snapshot_json TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS exit_orderflow_snapshot_json  TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS ai_post_trade_review_json     TEXT",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS closed_at  TIMESTAMP",
                    "ALTER TABLE live_monitor_paper_trades ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP",
                ]:
                    try:
                        conn.execute(text(_stmt))
                    except Exception:
                        pass
                conn.commit()
                print("[MIGRATE] Phase 11.10 paper trades journal table columns ensured")
                # Phase 11.11: Execution mode on user_preferences
                for _stmt in [
                    "ALTER TABLE user_preferences ADD COLUMN IF NOT EXISTS "
                    "execution_mode VARCHAR(40) NOT NULL DEFAULT 'internal_paper'",
                    "ALTER TABLE user_preferences ADD COLUMN IF NOT EXISTS "
                    "policy_mode VARCHAR(40) NOT NULL DEFAULT 'paper_manual'",
                ]:
                    try:
                        conn.execute(text(_stmt))
                    except Exception:
                        pass
                conn.commit()
                print("[MIGRATE] Phase 11.11 execution_mode/policy_mode columns ensured on user_preferences")
                # Phase 11.12: Paper Auto Gate — table created by db.create_all() above
                print("[MIGRATE] Phase 11.12 live_monitor_paper_auto_gate_events table ensured via create_all")
                # Phase 11.13: Paper Risk Guard — add column to user_preferences
                for _stmt_1113 in [
                    "ALTER TABLE user_preferences ADD COLUMN IF NOT EXISTS "
                    "paper_risk_guard_settings_json TEXT",
                ]:
                    try:
                        conn.execute(text(_stmt_1113))
                    except Exception:
                        pass
                conn.commit()
                print("[MIGRATE] Phase 11.13 paper_risk_guard_settings_json column ensured on user_preferences")
        except Exception as exc:
            print(f"[MIGRATE] Auto-migration warning: {exc}")


