@app.route("/forgot-password", methods=["POST"])
def forgot_password():
    is_ajax = request.headers.get("X-Requested-With") == "XMLHttpRequest"

    data       = request.get_json(silent=True) or {}
    identifier = (data.get("identifier") or request.form.get("identifier", "")).strip().lower()

    # Always return a generic success message to prevent user enumeration
    generic_ok = {"success": True,
                  "message": "If that account exists, a reset link has been sent to the registered email."}

    if not identifier:
        if is_ajax:
            return jsonify({"error": "validation", "message": "Please enter your email or username."}), 400
        return redirect(url_for("login"))

    # Rate-limit: allow at most 1 reset request per email per 5 minutes
    user = _DBUser.query.filter(
        (_DBUser.email == identifier) | (_DBUser.username == identifier)
    ).first()

    if user:
        cutoff = datetime.now(timezone.utc) - timedelta(minutes=5)
        recent = (_PasswordResetToken.query
                  .filter_by(user_id=user.id)
                  .filter(_PasswordResetToken.created_at > cutoff)
                  .first())
        if not recent:
            raw_token  = secrets.token_urlsafe(32)
            token_hash = hashlib.sha256(raw_token.encode()).hexdigest()
            expires    = datetime.now(timezone.utc) + timedelta(minutes=30)
            prt = _PasswordResetToken(user_id=user.id, token_hash=token_hash, expires_at=expires)
            db.session.add(prt)
            db.session.commit()

            reset_url  = url_for("reset_password", token=raw_token, _external=True)
            email_body = _build_password_reset_email(user.username, reset_url)
            _send_via_resend(user.email, "ZyNi SMC — Reset Your Password", email_body)
            print(f"[RESET] Sent password reset to {user.email}")
        else:
            print(f"[RESET] Rate-limited: reset already sent for user_id={user.id}")

    if is_ajax:
        return jsonify(generic_ok)
    return redirect(url_for("login"))


@app.route("/reset-password/<token>", methods=["GET", "POST"])
def reset_password(token):
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    now        = datetime.now(timezone.utc)

    prt = (_PasswordResetToken.query
           .filter_by(token_hash=token_hash, used=False)
           .filter(_PasswordResetToken.expires_at > now)
           .first())

    if not prt:
        return render_template("reset_password.html", invalid=True)

    if request.method == "GET":
        return render_template("reset_password.html", token=token)

    # POST — set new password
    password  = request.form.get("password", "")
    password2 = request.form.get("password2", "")
    is_ajax   = request.headers.get("X-Requested-With") == "XMLHttpRequest"

    def _err(msg):
        if is_ajax:
            return jsonify({"error": "validation", "message": msg}), 400
        return render_template("reset_password.html", token=token, error=msg)

    if not password:
        return _err("Please enter a new password.")
    if len(password) < 6:
        return _err("Password must be at least 6 characters.")
    if password != password2:
        return _err("Passwords do not match.")

    try:
        user = _DBUser.query.get(prt.user_id)
        if not user:
            return render_template("reset_password.html", invalid=True)
        user.set_password(password)
        prt.used = True
        db.session.commit()
        print(f"[RESET] Password updated for user_id={user.id}")
        if is_ajax:
            return jsonify({"success": True, "redirect": url_for("login")})
        return redirect(url_for("login"))
    except Exception as exc:
        db.session.rollback()
        print(f"[RESET] Error updating password: {exc}")
        return _err("Something went wrong. Please try again.")


@app.route("/admin/test-email")
def admin_test_email():
    """Diagnostic endpoint — accessible by admin session OR ?token=zynismctest query param."""
    token = request.args.get("token", "")
    if not session.get("is_admin") and token != "zynismctest2026":
        return "Access denied. Add ?token=zynismctest2026 to the URL.", 403

    frm         = _email_from()
    pwd         = _email_pass()
    to          = _email_to()
    resend_key  = os.environ.get("RESEND_API_KEY", "").strip()
    send_to     = request.args.get("send_to", "")  # ?send_to=you@email.com sends a live test

    result = {
        # ── Provider priority ──────────────────────────────────────────────────
        "provider_priority": ["1. Resend SDK (RESEND_API_KEY)", "2. Gmail SMTP SSL/465", "3. Gmail SMTP STARTTLS/587"],
        "active_provider":   "unknown — run diagnostics below to determine",

        # ── Resend ─────────────────────────────────────────────────────────────
        "resend": {
            "RESEND_API_KEY":  f"set ({len(resend_key)} chars, ends …{resend_key[-4:]})" if resend_key else "*** NOT SET ***",
            "from_address":    "ZyNi SMC <support@smcsetups.com>",
            "sdk_importable":  False,
            "test":            "SKIPPED",
        },

        # ── Gmail SMTP ─────────────────────────────────────────────────────────
        "smtp": {
            "ALERT_EMAIL_FROM": frm if frm else "*** NOT SET ***",
            "ALERT_EMAIL_PASS": f"{'*' * len(pwd)} ({len(pwd)} chars)" if pwd else "*** NOT SET ***",
            "ALERT_EMAIL_TO":   to  if to  else "(not set — only needed for login-alert emails)",
            "test":             "SKIPPED — credentials missing",
        },

        "send_to_tested": send_to or None,
        "note": "",
    }

    # ── Test Resend ────────────────────────────────────────────────────────────
    # NOTE: Resend API keys scoped to "Sending access" only will get 403 on
    # management endpoints (e.g. /domains). The only reliable way to validate
    # such a key is to send an actual email. We check SDK availability here
    # and rely on the live_send result (see below) to confirm the key works.
    if resend_key:
        try:
            import resend as _r  # noqa: F401
            result["resend"]["sdk_importable"] = True
            result["resend"]["test"] = "SDK loaded — key validity confirmed by live_send below"
            result["active_provider"] = "Resend SDK (pending live_send confirmation)"
            result["resend"]["note"] = (
                "Sending-only API keys cannot list domains via the Resend API. "
                "To verify smcsetups.com is authenticated, log in to resend.com → Domains."
            )
        except Exception as exc:
            result["resend"]["test"] = f"SDK import error: {exc}"
            result["active_provider"] = "Resend SDK unavailable — will fall back to Gmail SMTP"
    else:
        result["resend"]["test"] = "SKIPPED — RESEND_API_KEY not set"
        result["active_provider"] = "Gmail SMTP (Resend not configured)"

    # ── Test Gmail SMTP ────────────────────────────────────────────────────────
    if frm and pwd:
        e465 = e587 = None
        try:
            with smtplib.SMTP_SSL("smtp.gmail.com", 465, timeout=12) as srv:
                srv.login(frm, pwd)
            result["smtp"]["test"] = "OK via SSL port 465"
        except Exception as ex:
            e465 = str(ex)
            try:
                ctx = ssl.create_default_context()
                with smtplib.SMTP("smtp.gmail.com", 587, timeout=12) as srv:
                    srv.ehlo(); srv.starttls(context=ctx); srv.ehlo()
                    srv.login(frm, pwd)
                result["smtp"]["test"] = "OK via STARTTLS port 587"
            except Exception as ex2:
                e587 = str(ex2)
                result["smtp"]["test"]      = "FAILED on both ports"
                result["smtp"]["error_465"] = e465
                result["smtp"]["error_587"] = e587
                if not resend_key:
                    result["active_provider"] = "NONE — both Resend and SMTP are broken"
                    result["note"] = "No working email provider. Set RESEND_API_KEY in Koyeb env vars."

    # ── Live send test — always run to confirm active provider ─────────────────
    # Use ?send_to= to choose destination; defaults to the admin alert address.
    live_target = send_to or to or frm
    if live_target:
        ok, reason = send_verification_email(live_target, "123456", "testuser", purpose="2fa")
        result["live_send"] = {
            "to":      live_target,
            "success": ok,
            "reason":  reason,
        }
        # Use the actual send result to confirm (or correct) active_provider
        if ok:
            if resend_key:
                result["active_provider"] = "Resend SDK — confirmed working (live send succeeded)"
                result["note"] = (
                    "Resend is sending OTP emails. "
                    "If emails land in spam, verify smcsetups.com at resend.com/domains "
                    "and add the SPF/DKIM/DMARC DNS records in Cloudflare."
                )
            else:
                result["active_provider"] = "Gmail SMTP — confirmed working (live send succeeded)"
        else:
            result["active_provider"] = "BROKEN — live send failed (reason: " + reason + ")"
            result["note"] = "No email provider is working. Check RESEND_API_KEY in Koyeb env vars."
    else:
        result["live_send"] = {"skipped": True, "reason": "no destination address available"}

    return jsonify(result)



@app.route("/logout")
def logout():
    username = session.get("username", "").lower()
    # Update session duration in login history
    uid = session.get("user_id")
    if uid:
        def _end_session(_uid):
            try:
                with app.app_context():
                    from models import LoginHistory as _LH
                    lh = _LH.query.filter_by(user_id=_uid).order_by(_LH.logged_in_at.desc()).first()
                    if lh and lh.session_duration is None:
                        mins = int((datetime.now(timezone.utc) - lh.logged_in_at.replace(tzinfo=timezone.utc)).total_seconds() / 60)
                        lh.session_duration = mins
                        db.session.commit()
            except Exception:
                pass
        threading.Thread(target=_end_session, args=(uid,), daemon=True).start()
    with _sessions_lock:
        _active_sessions.pop(username, None)
    session.clear()
    return redirect(url_for("index"))



