# ── helpers ──────────────────────────────────────────────────────────────────

def _lm_rest_cached(key: str, ttl: int, fetch_fn):
    """Generic TTL cache for REST calls. Returns cached data or calls fetch_fn."""
    now = time.time()
    with _lm_rest_lock:
        entry = _lm_rest_cache.get(key)
        if entry and (now - entry["ts"]) < ttl:
            return entry["data"]
    try:
        data = fetch_fn()
        if data is not None:
            with _lm_rest_lock:
                _lm_rest_cache[key] = {"ts": now, "data": data}
        return data
    except Exception as e:
        print(f"[LM-REST] {key}: {e}")
        with _lm_rest_lock:
            old = _lm_rest_cache.get(key)
        return old["data"] if old else None


def _lm_fetch_oi_rest(symbol: str):
    r = req.get(f"{BINANCE_FUTURES_API}/fapi/v1/openInterest",
                params={"symbol": symbol}, timeout=5)
    if r.status_code == 200:
        d = r.json()
        return {"oi_contracts": float(d.get("openInterest", 0)), "symbol": symbol,
                "ts": float(d.get("time", time.time() * 1000)) / 1000}
    return None


def _lm_fetch_mark_price_rest(symbol: str):
    """Fetch mark price, index price, and funding rate via REST premiumIndex (Binance Futures).
    Used as fallback when WS cache is not yet populated.
    """
    try:
        r = req.get(f"{BINANCE_FUTURES_API}/fapi/v1/premiumIndex",
                    params={"symbol": symbol}, timeout=5)
        if r.status_code == 200:
            d = r.json()
            mp = d.get("markPrice")
            ip = d.get("indexPrice")
            fr = d.get("lastFundingRate")
            if mp:
                return {
                    "mark_price":   float(mp),
                    "index_price":  float(ip) if ip else None,
                    "funding_rate": float(fr) if fr else None,
                    "fetched_at":   time.time(),
                }
    except Exception as e:
        print(f"[LM-WS] mark_price REST error {symbol}: {e}")
    return None


def _lm_fetch_agg_trades_delta_rest(symbol: str):
    """Compute rolling buy/sell/delta from recent aggTrades via REST (Binance Futures).
    Covers 60s and 5m windows. Used as fallback when WS aggTrade cache is empty.
    """
    try:
        r = req.get(f"{BINANCE_FUTURES_API}/fapi/v1/aggTrades",
                    params={"symbol": symbol, "limit": 1000},
                    timeout=6)
        if r.status_code != 200:
            return None
        trades = r.json()
        if not isinstance(trades, list) or not trades:
            return None
        now = time.time()
        c60 = now - 60
        c5m = now - 300
        buy_60 = sell_60 = buy_5m = sell_5m = 0.0
        for t in trades:
            ts_s = t.get("T", 0) / 1000
            is_buyer_maker = t.get("m", False)  # True = seller aggressor = SELL
            try:
                vol = float(t.get("p", 0)) * float(t.get("q", 0))
            except (TypeError, ValueError):
                continue
            if ts_s >= c5m:
                if is_buyer_maker:
                    sell_5m += vol
                else:
                    buy_5m  += vol
            if ts_s >= c60:
                if is_buyer_maker:
                    sell_60 += vol
                else:
                    buy_60  += vol
        tot60 = buy_60 + sell_60
        tot5m = buy_5m + sell_5m
        return {
            "buy_vol_60s":   buy_60,
            "sell_vol_60s":  sell_60,
            "delta_60s":     buy_60 - sell_60,
            "delta_pct_60s": round((buy_60 - sell_60) / tot60 * 100, 1) if tot60 > 0 else 0.0,
            "buy_vol_5m":    buy_5m,
            "sell_vol_5m":   sell_5m,
            "delta_5m":      buy_5m - sell_5m,
            "delta_pct_5m":  round((buy_5m - sell_5m) / tot5m * 100, 1) if tot5m > 0 else 0.0,
            "data_age_sec":  0.0,
            "status":        "fresh",
            "fetched_at":    now,
        }
    except Exception as e:
        print(f"[LM-DELTA] aggTrades REST error {symbol}: {e}")
    return None


def _lm_fetch_bybit_delta_rest(symbol: str):
    """Compute buy/sell/delta from Bybit recent trades (public REST, linear perpetual)."""
    try:
        sym = _lm_symbol_for_exchange(symbol, "bybit")
        r = req.get(f"{BYBIT_API_V5}/v5/market/recent-trade",
                    params={"category": "linear", "symbol": sym, "limit": 1000},
                    timeout=_TOUT_EXCHANGE)
        if r.status_code != 200:
            return None
        trades = (r.json().get("result") or {}).get("list") or []
        if not trades:
            return None
        now = time.time()
        c60 = now - 60
        c5m = now - 300
        buy_60 = sell_60 = buy_5m = sell_5m = 0.0
        for t in trades:
            try:
                ts_s = int(t.get("time", 0)) / 1000
                side = t.get("side", "")
                vol  = float(t.get("size", 0)) * float(t.get("price", 0))
            except (TypeError, ValueError):
                continue
            if ts_s >= c5m:
                if side == "Buy": buy_5m  += vol
                else:             sell_5m += vol
            if ts_s >= c60:
                if side == "Buy": buy_60  += vol
                else:             sell_60 += vol
        tot60 = buy_60 + sell_60
        tot5m = buy_5m + sell_5m
        if not (tot60 > 0 or tot5m > 0):
            return None
        return {
            "buy_vol_60s":   buy_60,  "sell_vol_60s":  sell_60,
            "delta_60s":     buy_60 - sell_60,
            "delta_pct_60s": round((buy_60 - sell_60) / tot60 * 100, 1) if tot60 > 0 else 0.0,
            "buy_vol_5m":    buy_5m,  "sell_vol_5m":   sell_5m,
            "delta_5m":      buy_5m  - sell_5m,
            "delta_pct_5m":  round((buy_5m - sell_5m) / tot5m * 100, 1) if tot5m > 0 else 0.0,
            "data_age_sec":  0.0, "status": "fresh", "fetched_at": now,
        }
    except Exception as e:
        print(f"[LM-DELTA] bybit REST error {symbol}: {e}")
    return None


def _lm_fetch_okx_delta_rest(symbol: str):
    """Compute buy/sell/delta from OKX recent trades (public REST, SWAP)."""
