def _lm_mx_active_symbols() -> list:
    """Return sorted list of symbols from active Live Monitor items."""
    try:
        with app.app_context():
            from models import LiveMonitorItem as _LMI
            rows = _LMI.query.filter_by(is_active=True).with_entities(_LMI.symbol).all()
            return sorted({r.symbol for r in rows})
    except Exception as e:
        print(f"[MX-WS] active_symbols error: {e}")
        return []


# ── Cache updaters ───────────────────────────────────────────────────────────

def _lm_mx_book_update(exchange: str, symbol: str, bids_raw, asks_raw,
                       is_snapshot: bool = True):
    key = f"{exchange}:{symbol}"
    now = time.time()
    with _lm_mx_books_lock:
        if is_snapshot or key not in _lm_mx_books:
            bids = {float(p): float(q) for p, q in bids_raw if float(q) > 0}
            asks = {float(p): float(q) for p, q in asks_raw if float(q) > 0}
            _lm_mx_books[key] = {"bids": bids, "asks": asks, "ts": now, "ready": True}
        else:
            book = _lm_mx_books[key]
            for p, q in bids_raw:
                fp, fq = float(p), float(q)
                if fq == 0:
                    book["bids"].pop(fp, None)
                else:
                    book["bids"][fp] = fq
            for p, q in asks_raw:
                fp, fq = float(p), float(q)
                if fq == 0:
                    book["asks"].pop(fp, None)
                else:
                    book["asks"][fp] = fq
            book["ts"] = now
            book["ready"] = True


def _lm_mx_delta_update(exchange: str, symbol: str, side: str, qty: float, price: float):
    """side: 'buy' or 'sell'"""
    key    = f"{exchange}:{symbol}"
    now    = time.time()
    usd    = qty * price
    cutoff = now - 310
    with _lm_mx_delta_lock:
        if key not in _lm_mx_delta:
            _lm_mx_delta[key] = {"trades": deque(), "last_update_ts": now}
        e = _lm_mx_delta[key]
        e["trades"].append((now, side, usd))
        while e["trades"] and e["trades"][0][0] < cutoff:
            e["trades"].popleft()
        e["last_update_ts"] = now


def _lm_mx_liq_update(exchange: str, symbol: str, side: str, qty: float, price: float):
    """Record a liquidation event. side: 'long' or 'short'"""
    key = f"{exchange}:{symbol}"
    now = time.time()
    usd = qty * price
    with _lm_mx_liq_lock:
        if key not in _lm_mx_liq:
            _lm_mx_liq[key] = {"events": deque(maxlen=500), "last_update_ts": now,
                                "last_liq_price": None, "last_liq_side": ""}
        e = _lm_mx_liq[key]
        e["events"].append((now, side, usd))
        e["last_liq_price"] = price
        e["last_liq_side"]  = side
        e["last_update_ts"] = now


# ── Cache readers ─────────────────────────────────────────────────────────────

def _lm_mx_get_book(exchange: str, symbol: str):
    """Return (book_dict, status_str) or (None, 'unavailable')."""
    key = f"{exchange}:{symbol}"
    now = time.time()
    with _lm_mx_books_lock:
        entry = dict(_lm_mx_books.get(key) or {})
    if not entry or not entry.get("ready"):
        return None, "unavailable"
    age = now - entry.get("ts", 0)
    status = "fresh" if age <= 5 else "stale"
    return entry, status


def _lm_mx_get_delta(exchange: str, symbol: str):
    """Return (delta_dict, status_str) or (None, 'unavailable')."""
    key = f"{exchange}:{symbol}"
    now = time.time()
    with _lm_mx_delta_lock:
        entry = dict(_lm_mx_delta.get(key) or {})
    if not entry:
        return None, "unavailable"
    trades = list(entry.get("trades") or [])
    w60 = now - 60
    w5m = now - 300
    buy_60  = sum(t[2] for t in trades if t[0] >= w60 and t[1] == "buy")
    sell_60 = sum(t[2] for t in trades if t[0] >= w60 and t[1] == "sell")
    buy_5m  = sum(t[2] for t in trades if t[0] >= w5m  and t[1] == "buy")
    sell_5m = sum(t[2] for t in trades if t[0] >= w5m  and t[1] == "sell")
    tot60   = buy_60 + sell_60
    tot5m   = buy_5m + sell_5m
    age     = now - entry.get("last_update_ts", 0)
    return {
        "buy_vol_60s":   buy_60,  "sell_vol_60s":  sell_60,
        "delta_60s":     buy_60 - sell_60,
        "delta_pct_60s": round((buy_60 - sell_60) / tot60 * 100, 1) if tot60 > 0 else 0.0,
        "buy_vol_5m":    buy_5m,  "sell_vol_5m":   sell_5m,
        "delta_5m":      buy_5m  - sell_5m,
        "delta_pct_5m":  round((buy_5m - sell_5m) / tot5m * 100, 1) if tot5m > 0 else 0.0,
        "data_age_sec":  round(age, 1),
        "status":        "fresh" if age <= 5 else "stale",
    }, ("fresh" if age <= 5 else "stale")


def _lm_mx_get_liq(exchange: str, symbol: str):
    """Return (liq_dict, status_str) or (None, 'unavailable')."""
    key = f"{exchange}:{symbol}"
    now = time.time()
    with _lm_mx_liq_lock:
        entry = dict(_lm_mx_liq.get(key) or {})
    if not entry:
        return None, "unavailable"
    events = list(entry.get("events") or [])
    w5m   = now - 300
    long_u  = sum(e[2] for e in events if e[0] >= w5m and e[1] == "long")
    short_u = sum(e[2] for e in events if e[0] >= w5m and e[1] == "short")
    age     = now - entry.get("last_update_ts", 0)
    return {
        "total_liq_usd_5m": long_u + short_u,
        "long_liq_usd_5m":  long_u,
        "short_liq_usd_5m": short_u,
        "last_liq_price":   entry.get("last_liq_price"),
        "last_liq_side":    entry.get("last_liq_side", ""),
        "data_age_sec":     round(age, 1),
    }, ("fresh" if age <= 8 else "stale")


def _lm_mx_stream_status(exchange: str) -> str:
    """Return 'running', 'stopped', or 'disabled'."""
    if not _LM_MX_WS_ENABLED:
        return "disabled"
    t = _lm_mx_threads.get(exchange)
    return "running" if (t and t.is_alive()) else "stopped"


# ── Bybit public WS thread ───────────────────────────────────────────────────

def _lm_bybit_ws_loop():
    """Bybit public linear WS: orderbook + publicTrade + liquidation."""
    global _lm_mx_running
    print("[MX-BYBIT] Background thread started")
    _lm_mx_ws_state["bybit"]["thread_started_at"] = time.time()
    current_symbols: list = []
    sock = None

    while _lm_mx_running.get("bybit", False):
        new_symbols = _lm_mx_active_symbols()
        if new_symbols != current_symbols or sock is None:
            if sock:
                try: sock.close()
                except Exception: pass
                sock = None
            current_symbols = new_symbols
            if not current_symbols:
                time.sleep(10)
                continue
            try:
                print(f"[MX-BYBIT] Connecting for {current_symbols}")
                _lm_mx_ws_state["bybit"]["last_connect_attempt"] = time.time()
                sock = _raw_ws_connect("stream.bybit.com", "/v5/public/linear")
                sock.settimeout(30)
                args = []
                for sym in current_symbols:
                    bs = _mx_bybit_sym(sym)
                    args += [f"orderbook.1.{bs}", f"publicTrade.{bs}", f"liquidation.{bs}"]
                _ws_send_text(sock, json.dumps({"op": "subscribe", "args": args}))
                _lm_mx_ws_state["bybit"]["last_connected_at"]  = time.time()
                _lm_mx_ws_state["bybit"]["subscribed_symbols"] = list(current_symbols)
                print("[MX-BYBIT] Subscribed")
            except Exception as e:
                print(f"[MX-BYBIT] Connect error: {e}")
                _lm_mx_ws_state["bybit"]["last_error"] = f"{type(e).__name__}: {e}"[:120]
                sock = None
                time.sleep(5)
                continue

        try:
            raw = _ws_recv_frame(sock)
        except socket.timeout:
            try:
                _ws_send_text(sock, json.dumps({"op": "ping"}))
            except Exception:
                sock = None
            continue
        except Exception as e:
            print(f"[MX-BYBIT] Recv error: {e}")
            try: sock.close()
            except Exception: pass
            sock = None
            time.sleep(2)
            continue

        if raw is None:
            try: sock.close()
            except Exception: pass
            sock = None
            time.sleep(2)
            continue
        if not raw:
            continue

        try:
            msg = json.loads(raw.decode("utf-8"))
        except Exception:
            continue

        topic = msg.get("topic", "")
        data  = msg.get("data")
        _lm_mx_ws_state["bybit"]["last_message_at"] = time.time()

        if topic.startswith("orderbook") and data:
            sym_raw = (data.get("s") or "").upper()
            bids    = data.get("b", [])
            asks    = data.get("a", [])
            is_snap = msg.get("type") == "snapshot"
            if sym_raw and (bids or asks):
                try:
                    _lm_mx_book_update("bybit", sym_raw, bids, asks, is_snapshot=is_snap)
                except Exception:
                    pass

        elif topic.startswith("publicTrade") and isinstance(data, list):
            for trade in data:
                sym_raw = (trade.get("s") or "").upper()
                side    = "buy" if trade.get("S") == "Buy" else "sell"
                try:
                    p = float(trade.get("p", 0))
                    q = float(trade.get("v", 0))
                    if sym_raw and p > 0 and q > 0:
                        _lm_mx_delta_update("bybit", sym_raw, side, q, p)
                except Exception:
                    pass

        elif topic.startswith("liquidation") and data:
            sym_raw = (data.get("symbol") or "").upper()
            side    = "long" if data.get("side") == "Sell" else "short"
            try:
                p = float(data.get("price", 0))
                q = float(data.get("size", 0))
                if sym_raw and p > 0 and q > 0:
                    _lm_mx_liq_update("bybit", sym_raw, side, q, p)
            except Exception:
                pass

    print("[MX-BYBIT] Thread stopped")
    if sock:
        try: sock.close()
        except Exception: pass


# ── OKX public WS thread ─────────────────────────────────────────────────────

def _lm_okx_ws_loop():
    """OKX public WS (wss://ws.okx.com:8443): books5 + trades + liquidation-orders."""
    global _lm_mx_running
    print("[MX-OKX] Background thread started")
    _lm_mx_ws_state["okx"]["thread_started_at"] = time.time()
    current_symbols: list = []
    sock = None

    while _lm_mx_running.get("okx", False):
        new_symbols = _lm_mx_active_symbols()
        if new_symbols != current_symbols or sock is None:
            if sock:
                try: sock.close()
                except Exception: pass
                sock = None
            current_symbols = new_symbols
            if not current_symbols:
                time.sleep(10)
                continue
            try:
                print(f"[MX-OKX] Connecting for {current_symbols}")
                _lm_mx_ws_state["okx"]["last_connect_attempt"] = time.time()
                sock = _raw_ws_connect_port("ws.okx.com", "/ws/v5/public", port=8443)
                sock.settimeout(30)
                args = []
                for sym in current_symbols:
                    inst = _mx_okx_instid(sym)
                    args += [
                        {"channel": "books5",           "instId": inst},
                        {"channel": "trades",            "instId": inst},
                        {"channel": "liquidation-orders","instId": inst},
                    ]
                _ws_send_text(sock, json.dumps({"op": "subscribe", "args": args}))
                _lm_mx_ws_state["okx"]["last_connected_at"]  = time.time()
                _lm_mx_ws_state["okx"]["subscribed_symbols"] = list(current_symbols)
                print("[MX-OKX] Subscribed")
            except Exception as e:
                print(f"[MX-OKX] Connect error: {e}")
                _lm_mx_ws_state["okx"]["last_error"] = f"{type(e).__name__}: {e}"[:120]
                sock = None
                time.sleep(5)
                continue

        try:
            raw = _ws_recv_frame(sock)
        except socket.timeout:
            try:
                _ws_send_text(sock, "ping")
            except Exception:
                sock = None
            continue
        except Exception as e:
            print(f"[MX-OKX] Recv error: {e}")
            try: sock.close()
            except Exception: pass
            sock = None
            time.sleep(2)
            continue

        if raw is None:
            try: sock.close()
            except Exception: pass
            sock = None
            time.sleep(2)
            continue
        if not raw:
            continue

        try:
            raw_text = raw.decode("utf-8")
            if raw_text == "pong":
                continue
            msg = json.loads(raw_text)
        except Exception:
            continue

        ch   = (msg.get("arg") or {}).get("channel", "")
        data_list = msg.get("data", [])
        _lm_mx_ws_state["okx"]["last_message_at"] = time.time()
        if not isinstance(data_list, list) or not data_list:
            continue

        if ch == "books5":
            for d in data_list:
                inst = d.get("instId", "")
                sym_raw = inst.replace("-USDT-SWAP", "USDT").replace("-", "")
                bids = d.get("bids", [])
                asks = d.get("asks", [])
                if sym_raw and (bids or asks):
                    try:
                        _lm_mx_book_update("okx", sym_raw.upper(), bids, asks, is_snapshot=True)
                    except Exception:
                        pass

        elif ch == "trades":
            for trade in data_list:
                inst    = trade.get("instId", "")
                sym_raw = inst.replace("-USDT-SWAP", "USDT").replace("-", "")
                side    = "buy" if trade.get("side") == "buy" else "sell"
                try:
                    p = float(trade.get("px", 0))
                    q = float(trade.get("sz", 0))
                    if sym_raw and p > 0 and q > 0:
                        _lm_mx_delta_update("okx", sym_raw.upper(), side, q, p)
                except Exception:
                    pass

        elif ch == "liquidation-orders":
            for item_d in data_list:
                inst    = item_d.get("instId", "")
                sym_raw = inst.replace("-USDT-SWAP", "USDT").replace("-", "")
                for det in (item_d.get("details") or []):
                    side = "short" if det.get("side") == "buy" else "long"
                    try:
                        p = float(det.get("bkPx", 0))
                        q = float(det.get("sz", 0))
                        if sym_raw and p > 0 and q > 0:
                            _lm_mx_liq_update("okx", sym_raw.upper(), side, q, p)
                    except Exception:
                        pass


    print("[MX-OKX] Thread stopped")
    if sock:
        try: sock.close()
        except Exception: pass


# ── MEXC public WS thread ────────────────────────────────────────────────────

def _lm_mexc_ws_loop():
    """MEXC public contract WS: depth + deals. No liquidation (unavailable public)."""
    global _lm_mx_running
    print("[MX-MEXC] Background thread started")
    current_symbols: list = []
    sock = None

    while _lm_mx_running.get("mexc", False):
        new_symbols = _lm_mx_active_symbols()
        if new_symbols != current_symbols or sock is None:
            if sock:
                try: sock.close()
                except Exception: pass
                sock = None
            current_symbols = new_symbols
            if not current_symbols:
                time.sleep(10)
                continue
            try:
                print(f"[MX-MEXC] Connecting for {current_symbols}")
                sock = _raw_ws_connect("contract.mexc.com", "/edge")
                sock.settimeout(30)
                for sym in current_symbols:
                    ms = _mx_mexc_sym(sym)
                    _ws_send_text(sock, json.dumps({"method": "sub.depth.step",
                                                     "param": {"symbol": ms, "step": "step0"}}))
                    _ws_send_text(sock, json.dumps({"method": "sub.deal",
                                                     "param": {"symbol": ms}}))
                print("[MX-MEXC] Subscribed")
            except Exception as e:
                print(f"[MX-MEXC] Connect error: {e}")
                sock = None
                time.sleep(5)
                continue

        try:
            raw = _ws_recv_frame(sock)
        except socket.timeout:
            try:
                _ws_send_text(sock, json.dumps({"method": "ping"}))
            except Exception:
                sock = None
            continue
        except Exception as e:
            print(f"[MX-MEXC] Recv error: {e}")
            try: sock.close()
            except Exception: pass
            sock = None
            time.sleep(2)
            continue

        if raw is None:
            try: sock.close()
            except Exception: pass
            sock = None
            time.sleep(2)
            continue
        if not raw:
            continue

        try:
            msg = json.loads(raw.decode("utf-8"))
        except Exception:
            continue

        channel = msg.get("channel", "")
        data    = msg.get("data") or {}
        sym_raw = (msg.get("symbol") or "").upper().replace("_", "")

        if channel == "push.depth.step0" and sym_raw:
            bids_raw = data.get("bids", [])
            asks_raw = data.get("asks", [])
            if bids_raw or asks_raw:
                try:
                    bids = [[str(b[0]), str(b[1])] for b in bids_raw if len(b) >= 2]
                    asks = [[str(a[0]), str(a[1])] for a in asks_raw if len(a) >= 2]
                    _lm_mx_book_update("mexc", sym_raw + "USDT" if not sym_raw.endswith("USDT") else sym_raw,
                                       bids, asks, is_snapshot=True)
                except Exception:
                    pass

        elif channel == "push.deal" and sym_raw:
            for trade in (data.get("list") or []):
                try:
                    p    = float(trade.get("p", 0))
                    q    = float(trade.get("v", 0))
                    side = "buy" if trade.get("T") == 1 else "sell"
                    if p > 0 and q > 0:
                        key_sym = sym_raw + "USDT" if not sym_raw.endswith("USDT") else sym_raw
                        _lm_mx_delta_update("mexc", key_sym, side, q, p)
                except Exception:
                    pass

    print("[MX-MEXC] Thread stopped")
    if sock:
        try: sock.close()
        except Exception: pass


# ── Start/stop helpers ───────────────────────────────────────────────────────

def _ensure_lm_mx_exchange_stream(exchange: str):
    """Start multi-exchange WS thread for exchange if not already running."""
    if not _LM_MX_WS_ENABLED:
        return
    with _lm_mx_thread_lock:
        existing = _lm_mx_threads.get(exchange)
        if existing and existing.is_alive():
            return
        _lm_mx_running[exchange] = True
        targets = {"bybit": _lm_bybit_ws_loop, "okx": _lm_okx_ws_loop, "mexc": _lm_mexc_ws_loop}
        target = targets.get(exchange)
        if not target:
            return
        t = threading.Thread(target=target, daemon=True, name=f"lm-mx-{exchange}")
        _lm_mx_threads[exchange] = t
        t.start()


def _ensure_lm_mx_ws():
    """Ensure all multi-exchange WS threads are running."""
    if not _LM_MX_WS_ENABLED:
        return
    for ex in ("bybit", "okx", "mexc"):
        _ensure_lm_mx_exchange_stream(ex)


if _LM_MX_WS_ENABLED:
    _ensure_lm_mx_ws()


# ── Phase 10.7: True Aggregated Exchange Data Engine ─────────────────────────

_LM_ANALYSIS_SOURCES        = {"aggregated", "binance", "bybit", "okx", "mexc"}
_LM_SPECIFIC_ANALYSIS_SRCS  = {"binance", "bybit", "okx", "mexc"}
_LM_AGGREGATED_EXCHANGES    = ["binance", "bybit", "okx", "mexc"]
_TOUT_EXCHANGE              = 4    # seconds — conservative REST timeout per exchange


def _lm_normalize_analysis_source(value) -> str:
    """Normalize analysis source string. Fallback: 'binance'."""
    v = (value or "").lower().strip()
    return v if v in _LM_ANALYSIS_SOURCES else "binance"


def _lm_symbol_for_exchange(symbol: str, exchange: str, market: str = "perpetual") -> str:
    """Convert internal BTCUSDT → exchange-specific format."""
    s = (symbol or "").upper().replace("-", "").replace("_", "")
    if exchange == "okx":
        if s.endswith("USDT"):
            return f"{s[:-4]}-USDT-SWAP" if market == "perpetual" else f"{s[:-4]}-USDT"
        return s
    if exchange == "mexc":
        return (s[:-4] + "_USDT") if s.endswith("USDT") else s
    return s   # binance, bybit: BTCUSDT as-is


# ── Task 1: Central analysis source config ────────────────────────────────────

def _lm_analysis_source_config(row=None, snapshot=None, selected_source=None) -> dict:
    """Return canonical analysis source architecture config for one item.

    Never modifies parent setup price levels.
    analysis_source: from explicit param > snapshot > item exchange > 'binance'
    """
    snap = snapshot or {}
    if row is not None and not snap:
        snap = _json_loads_safe(getattr(row, "snapshot_json", None), {})
    parent_exchange = _lm_normalize_exchange(
        getattr(row, "exchange", None) if row else None
    ) or "binance"
    raw_src = (
        selected_source
        or snap.get("analysis_source")
        or (snap.get("data_sources") or {}).get("analysis_source")
        or parent_exchange
    )
    return {
        "analysis_source":       _lm_normalize_analysis_source(raw_src),
        "parent_setup_exchange": parent_exchange,
        "fallback_exchange":     "binance",
        "execution_exchange":    "not_in_scope_phase10_7",
        "price_levels_source":   "parent_setup_exchange",
        "rules": {
            "analysis_data_only":                                     True,
            "do_not_rewrite_parent_zone":                             True,
            "binance_fallback_for_missing_specific_exchange_metrics": True,
        },
    }


# ── Task 3: Canonical metric result schema ────────────────────────────────────

def _lm_metric_result(metric: str, value=None, status: str = "unavailable",
                       source: str = None, sources_used=None, sources_skipped=None,
                       notes: str = None, updated: str = None, raw=None) -> dict:
    """Standard metric result dict used by aggregated and fallback builders."""
    return {
        "metric":          metric,
        "value":           value if value is not None else "—",
        "status":          status,
        "source":          source or "unavailable",
        "sources_used":    list(sources_used  or []),
        "sources_skipped": list(sources_skipped or []),
        "updated":         updated or "—",
        "notes":           notes or "",
        "raw":             raw or {},
    }


# ── Task 4: Per-exchange public metric fetchers ───────────────────────────────

def _lm_fetch_exchange_live_price(exchange: str, symbol: str) -> dict:
    """Return {available, price, status, source, age_sec?} for live price."""
    try:
        if exchange == "binance":
            ws_e, ws_s = _lm_ws_get("binance", symbol)
            if ws_e and ws_e.get("live_price"):
                return {"available": True, "price": float(ws_e["live_price"]),
                        "status": ws_s, "source": "binance_ws",
                        "age_sec": ws_e.get("data_age_sec", 0)}
            return {"available": False, "status": "unavailable", "source": "binance_ws"}
        if exchange == "bybit":
            sym = _lm_symbol_for_exchange(symbol, "bybit")
            r = req.get(f"{BYBIT_API_V5}/v5/market/tickers",
                        params={"category": "linear", "symbol": sym}, timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                items = (r.json().get("result") or {}).get("list") or []
                if items:
                    p = float(items[0].get("lastPrice") or 0)
                    if p > 0:
                        return {"available": True, "price": p,
                                "status": "fresh", "source": "bybit_rest"}
            return {"available": False, "status": "unavailable", "source": "bybit_rest"}
        if exchange == "okx":
            sym = _lm_symbol_for_exchange(symbol, "okx")
            r = req.get(f"{OKX_API_V5}/api/v5/market/ticker",
                        params={"instId": sym}, timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                data = r.json().get("data") or []
                if data:
                    p = float(data[0].get("last") or 0)
                    if p > 0:
                        return {"available": True, "price": p,
                                "status": "fresh", "source": "okx_rest"}
            return {"available": False, "status": "unavailable", "source": "okx_rest"}
        if exchange == "mexc":
            t = _lm_rest_cached(f"mexc_tk:{symbol}", 10,
                                 lambda: _lm_fetch_mexc_perp_ticker(symbol))
            if t and t.get("ok") and t.get("last_price", 0) > 0:
                return {"available": True, "price": float(t["last_price"]),
                        "status": "fresh", "source": "mexc_rest"}
            return {"available": False, "status": "unavailable", "source": "mexc_rest"}
    except Exception as _e:
        return {"available": False, "status": "error", "source": exchange,
                "notes": str(_e)[:80]}
    return {"available": False, "status": "unavailable", "source": exchange}


def _lm_fetch_exchange_mark_price(exchange: str, symbol: str) -> dict:
    """Return {available, price, status, source} for mark price."""
    try:
        if exchange == "binance":
            ws_e, ws_s = _lm_ws_get("binance", symbol)
            if ws_e and ws_e.get("mark_price") is not None:
                return {"available": True, "price": float(ws_e["mark_price"]),
                        "status": ws_s, "source": "binance_ws"}
            return {"available": False, "status": "unavailable", "source": "binance_ws"}
        if exchange == "bybit":
            sym = _lm_symbol_for_exchange(symbol, "bybit")
            r = req.get(f"{BYBIT_API_V5}/v5/market/tickers",
                        params={"category": "linear", "symbol": sym}, timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                items = (r.json().get("result") or {}).get("list") or []
                if items:
                    mp = float(items[0].get("markPrice") or 0)
                    if mp > 0:
                        return {"available": True, "price": mp,
                                "status": "fresh", "source": "bybit_rest"}
            return {"available": False, "status": "unavailable", "source": "bybit_rest"}
        if exchange == "okx":
            sym = _lm_symbol_for_exchange(symbol, "okx")
            r = req.get(f"{OKX_API_V5}/api/v5/public/mark-price",
                        params={"instType": "SWAP", "instId": sym}, timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                data = r.json().get("data") or []
                if data:
                    mp = float(data[0].get("markPx") or 0)
                    if mp > 0:
                        return {"available": True, "price": mp,
                                "status": "fresh", "source": "okx_rest"}
            return {"available": False, "status": "unavailable", "source": "okx_rest"}
        if exchange == "mexc":
            # Use last_price as approximation for mark price (MEXC ticker doesn't separate them)
            t = _lm_rest_cached(f"mexc_tk:{symbol}", 10,
                                 lambda: _lm_fetch_mexc_perp_ticker(symbol))
            if t and t.get("ok") and t.get("last_price", 0) > 0:
                return {"available": True, "price": float(t["last_price"]),
                        "status": "fresh", "source": "mexc_rest",
                        "notes": "MEXC: last_price used as mark price approximation"}
            return {"available": False, "status": "unavailable", "source": "mexc_rest"}
    except Exception as _e:
        return {"available": False, "status": "error", "source": exchange,
                "notes": str(_e)[:80]}
    return {"available": False, "status": "unavailable", "source": exchange}


def _lm_fetch_exchange_orderbook(exchange: str, symbol: str) -> dict:
    """Return {available, best_bid, best_ask, bids, asks, status, source}."""
    try:
        if exchange == "binance":
            with _ob_book_lock:
                ob_raw = dict(_ob_books.get(symbol) or {})
            if ob_raw and ob_raw.get("ready"):
                bids = ob_raw.get("bids", {})
                asks = ob_raw.get("asks", {})
                if bids and asks:
                    best_bid = max((float(p) for p in bids), default=0)
                    best_ask = min((float(p) for p in asks), default=0)
                    ob_age = round(time.time() - ob_raw.get("ts", time.time()), 1)
                    return {"available": True, "bids": bids, "asks": asks,
                            "best_bid": best_bid, "best_ask": best_ask,
                            "status": "fresh" if ob_age <= 5 else "stale",
                            "age_sec": ob_age, "source": "binance_ws"}
            return {"available": False, "status": "unavailable", "source": "binance_ws"}
        if exchange == "bybit":
            sym = _lm_symbol_for_exchange(symbol, "bybit")
            r = req.get(f"{BYBIT_API_V5}/v5/market/orderbook",
                        params={"category": "linear", "symbol": sym, "limit": 25},
                        timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                result = r.json().get("result") or {}
                bids = {float(b[0]): float(b[1]) for b in (result.get("b") or []) if len(b) >= 2}
                asks = {float(a[0]): float(a[1]) for a in (result.get("a") or []) if len(a) >= 2}
                if bids and asks:
                    return {"available": True, "bids": bids, "asks": asks,
                            "best_bid": max(bids), "best_ask": min(asks),
                            "status": "fresh", "source": "bybit_rest"}
            return {"available": False, "status": "unavailable", "source": "bybit_rest"}
        if exchange == "okx":
            sym = _lm_symbol_for_exchange(symbol, "okx")
            r = req.get(f"{OKX_API_V5}/api/v5/market/books",
                        params={"instId": sym, "sz": 25}, timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                data = r.json().get("data") or []
                if data:
                    bids = {float(b[0]): float(b[1]) for b in (data[0].get("bids") or []) if len(b) >= 2}
                    asks = {float(a[0]): float(a[1]) for a in (data[0].get("asks") or []) if len(a) >= 2}
                    if bids and asks:
                        return {"available": True, "bids": bids, "asks": asks,
                                "best_bid": max(bids), "best_ask": min(asks),
                                "status": "fresh", "source": "okx_rest"}
            return {"available": False, "status": "unavailable", "source": "okx_rest"}
    except Exception as _e:
        return {"available": False, "status": "error", "source": exchange,
                "notes": str(_e)[:80]}
    return {"available": False, "status": "unavailable",
            "source": exchange, "notes": f"{exchange} OB not supported"}


def _lm_fetch_exchange_open_interest(exchange: str, symbol: str) -> dict:
    """Return {available, oi_contracts, oi_usd, status, source}."""
    try:
        if exchange == "binance":
            d = _lm_rest_cached(f"oi:{symbol}", 30, lambda: _lm_fetch_oi_rest(symbol))
            if d:
                ws_e, _ = _lm_ws_get("binance", symbol)
                mp = float((ws_e or {}).get("mark_price") or 0)
                oi_c = float(d.get("oi_contracts", 0))
                return {"available": True, "oi_contracts": oi_c,
                        "oi_usd": oi_c * mp if mp > 0 else None,
                        "status": "fresh", "source": "binance_rest"}
            return {"available": False, "status": "unavailable", "source": "binance_rest"}
        if exchange == "bybit":
            d = _lm_rest_cached(f"bybit_oi:{symbol}", 30,
                                 lambda: _lm107_bybit_oi(_lm_symbol_for_exchange(symbol, "bybit")))
            if d:
                return {"available": True, **d, "status": "fresh", "source": "bybit_rest"}
            return {"available": False, "status": "unavailable", "source": "bybit_rest"}
        if exchange == "okx":
            d = _lm_rest_cached(f"okx_oi:{symbol}", 30,
                                 lambda: _lm107_okx_oi(_lm_symbol_for_exchange(symbol, "okx")))
            if d:
                return {"available": True, **d, "status": "fresh", "source": "okx_rest"}
            return {"available": False, "status": "unavailable", "source": "okx_rest"}
        if exchange == "mexc":
            t = _lm_rest_cached(f"mexc_tk:{symbol}", 10,
                                 lambda: _lm_fetch_mexc_perp_ticker(symbol))
            if t and t.get("ok") and t.get("volume_24h", 0) > 0:
                # MEXC ticker has holdVol = open interest in contracts
                return {"available": True, "oi_contracts": float(t.get("volume_24h", 0)),
                        "oi_usd": None, "status": "fresh", "source": "mexc_rest",
                        "notes": "MEXC: 24h volume used as OI proxy"}
            return {"available": False, "status": "unavailable", "source": "mexc_rest"}
    except Exception as _e:
        return {"available": False, "status": "error", "source": exchange,
                "notes": str(_e)[:80]}
    return {"available": False, "status": "unavailable", "source": exchange}


def _lm_fetch_exchange_funding(exchange: str, symbol: str) -> dict:
    """Return {available, rate, rate_pct, bias, status, source}."""
    def _bias(fr):
        return "long_crowded" if fr > 0.0003 else "short_crowded" if fr < -0.0003 else "neutral"
    try:
        if exchange == "binance":
            ws_e, ws_s = _lm_ws_get("binance", symbol)
            if ws_e and ws_e.get("funding_rate") is not None:
                fr = float(ws_e["funding_rate"])
                return {"available": True, "rate": fr, "rate_pct": round(fr * 100, 6),
                        "bias": _bias(fr), "status": ws_s, "source": "binance_ws"}
            return {"available": False, "status": "unavailable", "source": "binance_ws"}
        if exchange == "bybit":
            sym = _lm_symbol_for_exchange(symbol, "bybit")
            r = req.get(f"{BYBIT_API_V5}/v5/market/tickers",
                        params={"category": "linear", "symbol": sym}, timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                items = (r.json().get("result") or {}).get("list") or []
                if items:
                    fr = float(items[0].get("fundingRate") or 0)
                    return {"available": True, "rate": fr, "rate_pct": round(fr * 100, 6),
                            "bias": _bias(fr), "status": "fresh", "source": "bybit_rest"}
            return {"available": False, "status": "unavailable", "source": "bybit_rest"}
        if exchange == "okx":
            sym = _lm_symbol_for_exchange(symbol, "okx")
            r = req.get(f"{OKX_API_V5}/api/v5/public/funding-rate",
                        params={"instId": sym}, timeout=_TOUT_EXCHANGE)
            if r.status_code == 200:
                data = r.json().get("data") or []
                if data:
                    fr = float(data[0].get("fundingRate") or 0)
                    return {"available": True, "rate": fr, "rate_pct": round(fr * 100, 6),
                            "bias": _bias(fr), "status": "fresh", "source": "okx_rest"}
            return {"available": False, "status": "unavailable", "source": "okx_rest"}
        if exchange == "mexc":
            t = _lm_rest_cached(f"mexc_tk:{symbol}", 10,
                                 lambda: _lm_fetch_mexc_perp_ticker(symbol))
            if t and t.get("ok") and t.get("funding_rate") is not None:
                fr = float(t["funding_rate"])
                return {"available": True, "rate": fr, "rate_pct": round(fr * 100, 6),
                        "bias": _bias(fr), "status": "fresh", "source": "mexc_rest"}
            return {"available": False, "status": "unavailable", "source": "mexc_rest"}
    except Exception as _e:
        return {"available": False, "status": "error", "source": exchange,
                "notes": str(_e)[:80]}
    return {"available": False, "status": "unavailable", "source": exchange}


def _lm_fetch_exchange_long_short(exchange: str, symbol: str) -> dict:
    """Return {available, long_pct, short_pct, ls_ratio, status, source}."""
    try:
        if exchange == "binance":
            d = _lm_rest_cached(f"ls:{symbol}", 300,
                                 lambda: _lm_fetch_ls_ratio_rest(symbol))
            if d:
                return {"available": True, **d, "status": "interval", "source": "binance_rest"}
            return {"available": False, "status": "unavailable", "source": "binance_rest"}
        if exchange == "bybit":
            sym = _lm_symbol_for_exchange(symbol, "bybit")
            d = _lm_rest_cached(f"bybit_ls:{symbol}", 300,
                                 lambda: _lm107_bybit_ls(sym))
            if d:
                return {"available": True, **d, "status": "interval", "source": "bybit_rest"}
            return {"available": False, "status": "unavailable", "source": "bybit_rest"}
        if exchange == "okx":
            ccy = (symbol or "").upper().replace("USDT", "")
            d = _lm_rest_cached(f"okx_ls:{symbol}", 300,
                                 lambda: _lm107_okx_ls(ccy))
            if d:
                return {"available": True, **d, "status": "interval", "source": "okx_rest"}
            return {"available": False, "status": "unavailable", "source": "okx_rest"}
        # MEXC: no public L/S endpoint
        return {"available": False, "status": "unavailable",
                "source": "mexc", "notes": "MEXC L/S ratio not publicly available"}
    except Exception as _e:
        return {"available": False, "status": "error", "source": exchange,
                "notes": str(_e)[:80]}
    return {"available": False, "status": "unavailable", "source": exchange}


def _lm_fetch_exchange_liquidations(exchange: str, symbol: str) -> dict:
    """Return {available, long_liq_usd_5m, short_liq_usd_5m, total, status, source}.
    Only Binance has a real-time liq stream."""
    if exchange == "binance":
        liq_e, liq_s = _lm_liq_get("binance", symbol)
        if liq_e:
            return {"available": True, **liq_e, "status": liq_s, "source": "binance_ws"}
        return {"available": False, "status": "unavailable", "source": "binance_ws"}
    return {"available": False, "status": "unavailable", "source": exchange,
            "notes": f"{exchange} real-time liquidation stream not available"}


def _lm_fetch_exchange_delta(exchange: str, symbol: str) -> dict:
    """Return {available, delta_pct_60s, buy_vol_60s, sell_vol_60s, ...}.
    Only Binance aggTrade delta is tracked in-process."""
    if exchange == "binance":
        d, ds = _lm_delta_get("binance", symbol)
        if d:
            return {"available": True, **d, "status": ds, "source": "binance_ws"}
        return {"available": False, "status": "unavailable", "source": "binance_ws"}
    return {"available": False, "status": "unavailable", "source": exchange,
            "notes": f"{exchange} aggTrade delta not tracked in this version"}


def _lm_fetch_exchange_oi_change(exchange: str, symbol: str) -> dict:
    """Return {available, change_pct, direction, status, source}."""
    try:
        if exchange == "binance":
            hist = _lm_rest_cached(f"oi_hist:{symbol}", 60,
                                    lambda: _lm_fetch_oi_hist_rest(symbol))
            if hist and isinstance(hist, list) and len(hist) >= 2:
                old_oi = float(hist[-2].get("sumOpenInterest", 0))
                new_oi = float(hist[-1].get("sumOpenInterest", 0))
                if old_oi > 0:
                    pct = round((new_oi - old_oi) / old_oi * 100, 3)
                    return {"available": True, "change_pct": pct,
                            "direction": "increasing" if pct > 0 else "decreasing",
                            "status": "interval", "source": "binance_rest"}
            return {"available": False, "status": "unavailable", "source": "binance_rest"}
        if exchange == "bybit":
            sym = _lm_symbol_for_exchange(symbol, "bybit")
            d = _lm_rest_cached(f"bybit_oih:{symbol}", 60,
                                 lambda: _lm107_bybit_oi_hist(sym))
            if d:
                return {"available": True, **d, "status": "interval", "source": "bybit_rest"}
            return {"available": False, "status": "unavailable", "source": "bybit_rest"}
        return {"available": False, "status": "unavailable", "source": exchange}
    except Exception as _e:
        return {"available": False, "status": "error", "source": exchange,
                "notes": str(_e)[:80]}


# ── Sub-helpers for Bybit/OKX public REST ────────────────────────────────────

def _lm107_bybit_oi(bybit_sym: str):
    try:
        r = req.get(f"{BYBIT_API_V5}/v5/market/tickers",
                    params={"category": "linear", "symbol": bybit_sym}, timeout=_TOUT_EXCHANGE)
        if r.status_code == 200:
            items = (r.json().get("result") or {}).get("list") or []
            if items:
                oi_v = float(items[0].get("openInterest") or 0)
                mp   = float(items[0].get("markPrice") or 0)
                if oi_v > 0:
                    return {"oi_contracts": oi_v, "oi_usd": oi_v * mp if mp > 0 else None}
    except Exception:
        pass
    return None


def _lm107_bybit_ls(bybit_sym: str):
    try:
        r = req.get(f"{BYBIT_API_V5}/v5/market/account-ratio",
                    params={"category": "linear", "symbol": bybit_sym, "period": "1h", "limit": 1},
                    timeout=_TOUT_EXCHANGE)
        if r.status_code == 200:
            items = (r.json().get("result") or {}).get("list") or []
            if items:
                buy  = float(items[0].get("buyRatio",  0.5))
                sell = float(items[0].get("sellRatio", 0.5))
                ls_r = round(buy / sell, 3) if sell > 0 else 1.0
                return {"long_pct": round(buy * 100, 2), "short_pct": round(sell * 100, 2),
                        "ls_ratio": ls_r, "period": "1h"}
    except Exception:
        pass
    return None


def _lm107_bybit_oi_hist(bybit_sym: str):
    try:
        r = req.get(f"{BYBIT_API_V5}/v5/market/open-interest",
                    params={"category": "linear", "symbol": bybit_sym,
                            "intervalTime": "1h", "limit": 2}, timeout=_TOUT_EXCHANGE)
        if r.status_code == 200:
            items = (r.json().get("result") or {}).get("list") or []
            if len(items) >= 2:
                old_oi = float(items[-1].get("openInterest") or 0)
                new_oi = float(items[0].get("openInterest")  or 0)
                if old_oi > 0:
                    pct = round((new_oi - old_oi) / old_oi * 100, 3)
                    return {"change_pct": pct, "direction": "increasing" if pct > 0 else "decreasing"}
    except Exception:
        pass
    return None


def _lm107_okx_oi(okx_sym: str):
    try:
        r = req.get(f"{OKX_API_V5}/api/v5/public/open-interest",
                    params={"instType": "SWAP", "instId": okx_sym}, timeout=_TOUT_EXCHANGE)
        if r.status_code == 200:
            data = r.json().get("data") or []
            if data:
                oi_v = float(data[0].get("oi") or data[0].get("oiCcy") or 0)
                if oi_v > 0:
                    return {"oi_contracts": oi_v, "oi_usd": None}
    except Exception:
        pass
    return None


def _lm107_okx_ls(ccy: str):
    try:
        r = req.get(f"{OKX_API_V5}/api/v5/rubik/stat/contracts/long-short-account-ratio",
                    params={"ccy": ccy, "period": "1H", "limit": 1}, timeout=_TOUT_EXCHANGE)
        if r.status_code == 200:
            data = r.json().get("data") or []
            if data:
                ls_r = float(data[0][1]) if len(data[0]) > 1 else 1.0
                long_pct  = round(ls_r / (1 + ls_r) * 100, 2) if ls_r > 0 else 50.0
                short_pct = round(100 - long_pct, 2)
                return {"long_pct": long_pct, "short_pct": short_pct,
                        "ls_ratio": round(ls_r, 3), "period": "1h"}
    except Exception:
        pass
    return None


# ── Value formatter for metric result display ─────────────────────────────────

def _lm107_format_metric(key: str, r: dict) -> str:
    """Format a fetcher result dict to a human-readable display string."""
    try:
        if key in ("live_price", "mark_price"):
            p = r.get("price")
            return f"{p:.4f}" if p else "—"
        if key == "order_book":
            bb, ba = r.get("best_bid"), r.get("best_ask")
            return f"Bid {bb:.4f} / Ask {ba:.4f}" if bb and ba else "—"
        if key == "liquidations":
            total = r.get("total_liq_usd_5m", 0)
            if not total:
                return "None (5m)"
            lu = r.get("long_liq_usd_5m", 0)
            su = r.get("short_liq_usd_5m", 0)
            return f"L {_fmt_usd_lm(lu)} / S {_fmt_usd_lm(su)} (5m)"
        if key == "open_interest":
            usd = r.get("oi_usd")
            c   = r.get("oi_contracts")
            if usd and usd > 0:
                return _fmt_usd_lm(usd)
            if c and c > 0:
                return f"{c:.0f} contracts"
            return "—"
        if key == "oi_change":
            pct = r.get("change_pct")
            d   = r.get("direction", "")
            return f"{pct:+.3f}% ({d})" if pct is not None else "—"
        if key == "delta":
            d60  = r.get("delta_60s")
            dpct = r.get("delta_pct_60s", 0.0)
            if d60 is not None:
                return f"{_fmt_usd_lm(abs(d60))} {'Buy' if d60>=0 else 'Sell'} ({dpct:+.1f}%) 60s"
            return "—"
        if key == "long_short":
            lp = r.get("long_pct")
            sp = r.get("short_pct")
            return f"L {lp:.1f}% / S {sp:.1f}%" if lp is not None else "—"
        if key == "funding_rate":
            pct = r.get("rate_pct")
            return f"{pct:+.4f}%" if pct is not None else "—"
    except Exception:
        pass
    return "—"


# ── Task 5: True Aggregated Exchange Data Builder ────────────────────────────

def _lm_build_true_aggregated_exchange_data(symbol: str, snapshot=None) -> dict:
    """Combine available metrics across Binance, Bybit, OKX, MEXC.

    Pure read — no writes, no trade logic, never rewrites parent setup levels.
    Returns {symbol, analysis_source, sources_used, sources_skipped, metrics,
             warnings, fetched_at, ai_data_gate}
    """
    now_iso      = datetime.now(timezone.utc).isoformat()
    sources_used:    list = []
    sources_skipped: list = []
    warnings:        list = []
    metrics:         dict = {}

    def _track(exch, available):
        if available:
            if exch not in sources_used:
                sources_used.append(exch)
            if exch in sources_skipped:
                sources_skipped.remove(exch)
        else:
            if exch not in sources_skipped and exch not in sources_used:
                sources_skipped.append(exch)

    # ── Live Price ─────────────────────────────────────────────────────────────
    lp_r = {}
    for _ex in _LM_AGGREGATED_EXCHANGES:
        lp = _lm_rest_cached(f"agg_lp_{_ex}:{symbol}", 5,
                              lambda e=_ex: _lm_fetch_exchange_live_price(e, symbol))
        if lp and lp.get("available"):
            lp_r[_ex] = lp
    if lp_r:
        prices = sorted([v["price"] for v in lp_r.values()])
        med_p  = prices[len(prices) // 2]
        srcs   = list(lp_r.keys())
        for e in srcs: _track(e, True)
        metrics["live_price"] = _lm_metric_result(
            "Live Price", value=f"{med_p:.4f}",
            status="fresh" if len(srcs) >= 2 else "partial",
            source="Aggregated: " + ", ".join(s.title() for s in srcs),
            sources_used=srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in srcs],
            notes="Median across exchanges. Per-exchange: " +
                  "; ".join(f"{e}: {v['price']:.4f}" for e, v in lp_r.items()),
            updated=now_iso, raw={e: v["price"] for e, v in lp_r.items()})
    else:
        for e in _LM_AGGREGATED_EXCHANGES: _track(e, False)
        metrics["live_price"] = _lm_metric_result(
            "Live Price", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES))

    # ── Mark Price ─────────────────────────────────────────────────────────────
    mp_r = {}
    for _ex in _LM_AGGREGATED_EXCHANGES:
        mp = _lm_rest_cached(f"agg_mp_{_ex}:{symbol}", 5,
                              lambda e=_ex: _lm_fetch_exchange_mark_price(e, symbol))
        if mp and mp.get("available"):
            mp_r[_ex] = mp
    if mp_r:
        mps  = sorted([v["price"] for v in mp_r.values()])
        med_m = mps[len(mps) // 2]
        srcs  = list(mp_r.keys())
        for e in srcs: _track(e, True)
        metrics["mark_price"] = _lm_metric_result(
            "Mark Price", value=f"{med_m:.4f}",
            status="fresh" if len(srcs) >= 2 else "partial",
            source="Aggregated: " + ", ".join(s.title() for s in srcs),
            sources_used=srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in srcs],
            notes=f"Median of {len(mps)} exchange(s)",
            updated=now_iso, raw={e: v["price"] for e, v in mp_r.items()})
    else:
        metrics["mark_price"] = _lm_metric_result(
            "Mark Price", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES))

    # ── Order Book ─────────────────────────────────────────────────────────────
    ob_r = {}
    for _ex in ["binance", "bybit", "okx"]:   # MEXC OB REST not available
        ob = _lm_rest_cached(f"agg_ob_{_ex}:{symbol}", 5,
                              lambda e=_ex: _lm_fetch_exchange_orderbook(e, symbol))
        if ob and ob.get("available"):
            ob_r[_ex] = ob
    # Phase 10.8: augment with MX WS order books for bybit/okx/mexc
    _mx_ob_extra_notes = []
    if _LM_MX_WS_ENABLED:
        for _mx_ex in ("bybit", "okx", "mexc"):
            _mx_bk, _mx_bk_st = _lm_mx_get_book(_mx_ex, symbol)
            if _mx_bk and _mx_bk_st in ("fresh", "stale"):
                _bids_mx = _mx_bk.get("bids", {})
                _asks_mx = _mx_bk.get("asks", {})
                _bb_mx = max(_bids_mx.keys()) if _bids_mx else None
                _ba_mx = min(_asks_mx.keys()) if _asks_mx else None
                if _bb_mx and _ba_mx:
                    if _mx_ex not in ob_r:
                        ob_r[_mx_ex] = {"available": True, "best_bid": _bb_mx,
                                        "best_ask": _ba_mx, "status": _mx_bk_st,
                                        "source": "mx_ws"}
                    _mx_ob_extra_notes.append(
                        f"{_mx_ex.title()} WS: Bid {_bb_mx:.4f} / Ask {_ba_mx:.4f} [{_mx_bk_st}]")
                    _track(_mx_ex, True)
    else:
        _mx_ob_extra_notes = ["Multi-exchange WS disabled: set ZYNI_LM_MULTI_EXCHANGE_WS_ENABLED=1"]
    if ob_r:
        srcs   = list(ob_r.keys())
        b_vals = [v["best_bid"] for v in ob_r.values() if v.get("best_bid")]
        a_vals = [v["best_ask"] for v in ob_r.values() if v.get("best_ask")]
        ab  = round(sum(b_vals) / len(b_vals), 4) if b_vals else None
        aa  = round(sum(a_vals) / len(a_vals), 4) if a_vals else None
        for e in srcs: _track(e, True)
        _ob_notes = f"Average best bid/ask from {len(srcs)} exchange(s)"
        if _mx_ob_extra_notes:
            _ob_notes += ". MX WS: " + "; ".join(_mx_ob_extra_notes)
        # Find first OB entry with full bids/asks for imbalance / wall data
        _ob_full = next((v for v in ob_r.values() if v.get("bids") and v.get("asks")), None)
        _ob_raw  = ({"bids": _ob_full["bids"], "asks": _ob_full["asks"],
                     "best_bid": _ob_full.get("best_bid"), "best_ask": _ob_full.get("best_ask"),
                     "status": _ob_full.get("status", "fresh")}
                    if _ob_full
                    else {"best_bid": ab, "best_ask": aa,
                          "status": "fresh" if len(srcs) >= 2 else "partial"})
        metrics["order_book"] = _lm_metric_result(
            "Order Book", value=f"Bid {ab} / Ask {aa}" if ab and aa else "—",
            status="fresh" if len(srcs) >= 2 else "partial",
            source="Aggregated: " + ", ".join(s.title() for s in srcs),
            sources_used=srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in srcs],
            notes=_ob_notes,
            updated=now_iso, raw=_ob_raw)
    else:
        metrics["order_book"] = _lm_metric_result(
            "Order Book", status="unavailable", source="Aggregated",
            sources_skipped=["binance", "bybit", "okx", "mexc"],
            notes="; ".join(_mx_ob_extra_notes) if _mx_ob_extra_notes else "")

    # ── Liquidations ──────────────────────────────────────────────────────────
    liq = _lm_fetch_exchange_liquidations("binance", symbol)
    _track("binance", liq.get("available", False))
    # Phase 10.8: also collect MX WS liq for bybit/okx
    _mx_liq_parts = []
    _mx_liq_srcs  = []
    if _LM_MX_WS_ENABLED:
        for _mx_ex in ("bybit", "okx"):
            _mx_ld, _mx_ls = _lm_mx_get_liq(_mx_ex, symbol)
            if _mx_ld:
                _mx_liq_parts.append(
                    f"{_mx_ex.title()}: L {_fmt_usd_lm(_mx_ld.get('long_liq_usd_5m',0))} "
                    f"/ S {_fmt_usd_lm(_mx_ld.get('short_liq_usd_5m',0))}")
                _mx_liq_srcs.append(_mx_ex)
                _track(_mx_ex, True)
    if liq.get("available"):
        total  = liq.get("total_liq_usd_5m", 0)
        long_u = liq.get("long_liq_usd_5m", 0)
        short_u = liq.get("short_liq_usd_5m", 0)
        _liq_src_note = ("Binance+MX WS" if _mx_liq_srcs
                         else "Binance (partial — Bybit/OKX/MEXC liq not available)")
        _liq_notes = ("Only Binance real-time liq stream is tracked in this version"
                      if not _mx_liq_srcs
                      else "Binance WS + Phase 10.8 MX WS: " + "; ".join(_mx_liq_parts))
        metrics["liquidations"] = _lm_metric_result(
            "Liquidations",
            value=f"L {_fmt_usd_lm(long_u)} / S {_fmt_usd_lm(short_u)} (5m)" if total else "None (5m)",
            status="partial" if not _mx_liq_srcs else "fresh",
            source=_liq_src_note,
            sources_used=["binance"] + _mx_liq_srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES
                             if e not in (["binance"] + _mx_liq_srcs)],
            notes=_liq_notes,
            updated=now_iso,
            raw={"long_liq_usd_5m": long_u, "short_liq_usd_5m": short_u,
                 "total_liq_usd_5m": total})
    elif _mx_liq_parts:
        metrics["liquidations"] = _lm_metric_result(
            "Liquidations",
            value="MX WS only (5m): " + "; ".join(_mx_liq_parts),
            status="partial", source="Phase 10.8 MX WS",
            sources_used=_mx_liq_srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in _mx_liq_srcs],
            notes="Binance liq unavailable; using Phase 10.8 MX WS liq data",
            updated=now_iso)
    else:
        _liq_disabled_note = ("" if _LM_MX_WS_ENABLED
                              else " Multi-exchange WS disabled: set ZYNI_LM_MULTI_EXCHANGE_WS_ENABLED=1")
        metrics["liquidations"] = _lm_metric_result(
            "Liquidations", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES),
            notes=_liq_disabled_note.strip() if _liq_disabled_note else "")

    # ── Open Interest ──────────────────────────────────────────────────────────
    oi_r = {}
    for _ex in _LM_AGGREGATED_EXCHANGES:
        oi = _lm_rest_cached(f"agg_oi_{_ex}:{symbol}", 30,
                              lambda e=_ex: _lm_fetch_exchange_open_interest(e, symbol))
        if oi and oi.get("available"):
            oi_r[_ex] = oi
    if oi_r:
        srcs  = list(oi_r.keys())
        for e in srcs: _track(e, True)
        parts = []
        for e, v in oi_r.items():
            if v.get("oi_usd") is not None and v["oi_usd"] > 0:
                parts.append(f"{e.title()}: {_fmt_usd_lm(v['oi_usd'])}")
            else:
                parts.append(f"{e.title()}: {v.get('oi_contracts', 0):.0f} contracts")
        _oi_contracts = [v["oi_contracts"] for v in oi_r.values()
                         if v.get("oi_contracts") is not None]
        metrics["open_interest"] = _lm_metric_result(
            "Open Interest",
            value=parts[0] if len(parts) == 1 else "multi-exchange (see notes)",
            status="partial" if len(srcs) < 4 else "fresh",
            source="Aggregated: " + ", ".join(s.title() for s in srcs),
            sources_used=srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in srcs],
            notes=" | ".join(parts), updated=now_iso,
            raw={"total_contracts": sum(_oi_contracts) if _oi_contracts else None,
                 "per_exchange": {e: v.get("oi_contracts") for e, v in oi_r.items()}})
    else:
        metrics["open_interest"] = _lm_metric_result(
            "Open Interest", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES))

    # ── OI Change ─────────────────────────────────────────────────────────────
    oic_r = {}
    for _ex in ["binance", "bybit"]:
        oic = _lm_rest_cached(f"agg_oic_{_ex}:{symbol}", 60,
                               lambda e=_ex: _lm_fetch_exchange_oi_change(e, symbol))
        if oic and oic.get("available"):
            oic_r[_ex] = oic
    if oic_r:
        srcs = list(oic_r.keys())
        avg_pct = round(sum(v["change_pct"] for v in oic_r.values()) / len(oic_r), 3)
        for e in srcs: _track(e, True)
        metrics["oi_change"] = _lm_metric_result(
            "OI Change",
            value=f"{avg_pct:+.3f}% avg ({len(srcs)} src)",
            status="interval",
            source="Aggregated: " + ", ".join(s.title() for s in srcs),
            sources_used=srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in srcs],
            notes=" | ".join(f"{e.title()}: {v['change_pct']:+.3f}%" for e, v in oic_r.items()),
            updated=now_iso)
    else:
        metrics["oi_change"] = _lm_metric_result(
            "OI Change", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES))

    # ── Delta — true multi-exchange aggregation ────────────────────────────────
    # Priority: WS cache (Binance aggTrade + MX WS) → REST per exchange → unavailable
    _delta_pool: dict = {}  # exchange → {buy_vol_60s, sell_vol_60s, ..., _src}

    # 1. Binance aggTrade WS cache
    _bin_d, _bin_ds = _lm_delta_get("binance", symbol)
    if _bin_d:
        _delta_pool["binance"] = {**_bin_d, "_src": "binance_ws"}

    # 2. MX WS cache for bybit/okx/mexc
    if _LM_MX_WS_ENABLED:
        for _mx_ex in ("bybit", "okx", "mexc"):
            _mx_dd, _ = _lm_mx_get_delta(_mx_ex, symbol)
            if _mx_dd:
                _delta_pool[_mx_ex] = {**_mx_dd, "_src": f"{_mx_ex}_ws"}

    # 3. REST fallback per exchange (only when WS cache is empty for that exchange)
    if "binance" not in _delta_pool:
        _rb = _lm_rest_cached(f"delta:{symbol}", 30,
                               lambda: _lm_fetch_agg_trades_delta_rest(symbol))
        if _rb:
            _delta_pool["binance"] = {**_rb, "_src": "binance_rest"}
    if "bybit" not in _delta_pool:
        _rby = _lm_rest_cached(f"delta_bybit:{symbol}", 30,
                                lambda: _lm_fetch_bybit_delta_rest(symbol))
        if _rby:
            _delta_pool["bybit"] = {**_rby, "_src": "bybit_rest"}
    if "okx" not in _delta_pool:
        _rokx = _lm_rest_cached(f"delta_okx:{symbol}", 30,
                                 lambda: _lm_fetch_okx_delta_rest(symbol))
        if _rokx:
            _delta_pool["okx"] = {**_rokx, "_src": "okx_rest"}

    # Track sources
    for _dx in _LM_AGGREGATED_EXCHANGES:
        _track(_dx, _dx in _delta_pool)

    if _delta_pool:
        _tb60  = sum(v.get("buy_vol_60s",  0) for v in _delta_pool.values())
        _ts60  = sum(v.get("sell_vol_60s", 0) for v in _delta_pool.values())
        _tb5m  = sum(v.get("buy_vol_5m",   0) for v in _delta_pool.values())
        _ts5m  = sum(v.get("sell_vol_5m",  0) for v in _delta_pool.values())
        _d60   = _tb60 - _ts60
        _d5m   = _tb5m - _ts5m
        _tot60 = _tb60 + _ts60
        _tot5m = _tb5m + _ts5m
        _d_srcs   = list(_delta_pool.keys())
        _d_skip   = [e for e in _LM_AGGREGATED_EXCHANGES if e not in _delta_pool]
        _ws_srcs  = [e for e, v in _delta_pool.items() if "_ws"   in v.get("_src", "")]
        _rest_srcs = [e for e, v in _delta_pool.items() if "_rest" in v.get("_src", "")]
        _fallback_only = not _ws_srcs
        _per_ex   = []
        for _dx in _d_srcs:
            _dv = _delta_pool[_dx].get("delta_60s", 0)
            _per_ex.append(
                f"{_dx.title()}: {'+' if _dv >= 0 else ''}{_fmt_usd_lm(abs(_dv))} {'Buy' if _dv >= 0 else 'Sell'}")
        _src_label = ("Aggregated (REST): " if _fallback_only else "Aggregated: ") + \
                     ", ".join(e.title() for e in _d_srcs)
        _pct60 = round(_d60 / _tot60 * 100, 1) if _tot60 > 0 else 0.0
        _pct5m = round(_d5m / _tot5m * 100, 1) if _tot5m > 0 else 0.0
        _val   = (f"{_fmt_usd_lm(abs(_d60))} {'Buy' if _d60>=0 else 'Sell'} ({_pct60:+.1f}%) 60s"
                  + (f" | {_fmt_usd_lm(abs(_d5m))} {'Buy' if _d5m>=0 else 'Sell'} ({_pct5m:+.1f}%) 5m"
                     if _tot5m > 0 else ""))
        _delta_status = "fresh" if (len(_d_srcs) >= 2 and not _fallback_only) else "partial"
        metrics["delta"] = _lm_metric_result(
            "Delta", value=_val, status=_delta_status, source=_src_label,
            sources_used=_d_srcs, sources_skipped=_d_skip,
            notes="; ".join(_per_ex),
            updated=now_iso,
            raw={"delta_60s":     _d60,
                 "delta_pct_60s": _pct60,
                 "buy_vol_60s":   _tb60,
                 "sell_vol_60s":  _ts60,
                 "delta_5m":      _d5m,
                 "delta_pct_5m":  _pct5m})
        _delta_debug = {
            "delta_sources_used":    _d_srcs,
            "delta_sources_skipped": _d_skip,
            "delta_mode":            ("binance_rest_fallback" if (_fallback_only and _d_srcs == ["binance"])
                                      else "rest_fallback" if _fallback_only
                                      else "multi_exchange_ws_or_rest"),
            "delta_fallback_used":   bool(_rest_srcs),
        }
    else:
        metrics["delta"] = _lm_metric_result(
            "Delta", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES),
            notes="No delta data from any exchange. Enable multi-exchange WS: "
                  "set ZYNI_LM_MULTI_EXCHANGE_WS_ENABLED=1 or ZYNI_LM_MX_WS_ENABLED=1")
        _delta_debug = {
            "delta_sources_used":    [],
            "delta_sources_skipped": list(_LM_AGGREGATED_EXCHANGES),
            "delta_mode":            "unavailable",
            "delta_fallback_used":   False,
        }

    # ── Long/Short Ratio ───────────────────────────────────────────────────────
    ls_r = {}
    for _ex in ["binance", "bybit", "okx"]:
        ls = _lm_rest_cached(f"agg_ls_{_ex}:{symbol}", 300,
                              lambda e=_ex: _lm_fetch_exchange_long_short(e, symbol))
        if ls and ls.get("available"):
            ls_r[_ex] = ls
    if ls_r:
        srcs  = list(ls_r.keys())
        avg_l = round(sum(v["long_pct"]  for v in ls_r.values()) / len(ls_r), 2)
        avg_s = round(sum(v["short_pct"] for v in ls_r.values()) / len(ls_r), 2)
        for e in srcs: _track(e, True)
        metrics["long_short"] = _lm_metric_result(
            "Long/Short Ratio",
            value=f"L {avg_l:.1f}% / S {avg_s:.1f}% (avg {len(srcs)} src)",
            status="interval",
            source="Aggregated: " + ", ".join(s.title() for s in srcs),
            sources_used=srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in srcs],
            notes="Simple average across available exchanges",
            updated=now_iso,
            raw={"long_pct": avg_l, "short_pct": avg_s,
                 "ls_ratio": round(avg_l / avg_s, 3) if avg_s > 0 else None})
    else:
        metrics["long_short"] = _lm_metric_result(
            "Long/Short Ratio", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES))

    # ── Funding Rate ───────────────────────────────────────────────────────────
    fr_r = {}
    for _ex in _LM_AGGREGATED_EXCHANGES:
        fr = _lm_rest_cached(f"agg_fr_{_ex}:{symbol}", 30,
                              lambda e=_ex: _lm_fetch_exchange_funding(e, symbol))
        if fr and fr.get("available"):
            fr_r[_ex] = fr
    if fr_r:
        srcs     = list(fr_r.keys())
        avg_rate = sum(v["rate"] for v in fr_r.values()) / len(fr_r)
        avg_pct  = round(avg_rate * 100, 6)
        biases   = [v.get("bias", "neutral") for v in fr_r.values()]
        dominant = max(set(biases), key=biases.count) if biases else "neutral"
        strongest = max(fr_r.items(), key=lambda x: abs(x[1]["rate"]))
        for e in srcs: _track(e, True)
        metrics["funding_rate"] = _lm_metric_result(
            "Funding Rate",
            value=f"{avg_pct:+.4f}% avg ({len(srcs)} src)",
            status="fresh" if len(srcs) >= 2 else "partial",
            source="Aggregated: " + ", ".join(s.title() for s in srcs),
            sources_used=srcs,
            sources_skipped=[e for e in _LM_AGGREGATED_EXCHANGES if e not in srcs],
            notes=f"Dominant bias: {dominant}. Strongest: {strongest[0].title()} {strongest[1]['rate_pct']:+.4f}%",
            updated=now_iso,
            raw={"rate": avg_rate, "rate_pct": avg_pct, "bias": dominant})
    else:
        metrics["funding_rate"] = _lm_metric_result(
            "Funding Rate", status="unavailable", source="Aggregated",
            sources_skipped=list(_LM_AGGREGATED_EXCHANGES))

    # Mark residual skipped sources
    for e in _LM_AGGREGATED_EXCHANGES:
        if e not in sources_used and e not in sources_skipped:
            sources_skipped.append(e)

    # ── AI gate ────────────────────────────────────────────────────────────────
    lp_m  = metrics.get("live_price", {})
    mp_m  = metrics.get("mark_price", {})
    lp_ok = lp_m.get("status") in ("fresh", "partial") and lp_m.get("sources_used")
    mp_ok = mp_m.get("status") in ("fresh", "partial") and mp_m.get("sources_used")
    gate_allowed  = lp_ok and mp_ok
    gate_reasons  = []
    gate_warnings = []
    if not lp_ok:
        gate_reasons.append("Aggregated Live Price unavailable — no exchange returned price")
    if not mp_ok:
        gate_reasons.append("Aggregated Mark Price unavailable — no exchange returned mark price")
    if gate_allowed and len(sources_used) < 2:
        gate_warnings.append(
            f"Only {sources_used[0] if sources_used else 'unknown'} contributing — not true aggregated")

    _su = sorted(set(sources_used))
    _ss = sorted(set(sources_skipped))
    return {
        "symbol":          symbol,
        "analysis_source": "aggregated",
        "sources_used":    _su,
        "sources_skipped": _ss,
        "metrics":         metrics,
        "warnings":        warnings,
        "fetched_at":      time.time(),
        "delta_debug":     _delta_debug,
        "ai_data_gate": {
            "allowed":         bool(gate_allowed),
            "allowed_sources": _su,
            "blocked_sources": _ss,
            "reasons":         gate_reasons,
            "warnings":        gate_warnings,
        },
    }


# ── Task 6: Specific exchange + Binance fallback ──────────────────────────────

_LM107_METRIC_KEYS = [
    ("live_price",    "Live Price"),
    ("mark_price",    "Mark Price"),
    ("order_book",    "Order Book"),
    ("liquidations",  "Liquidations"),
    ("open_interest", "Open Interest"),
    ("oi_change",     "OI Change"),
    ("delta",         "Delta"),
    ("long_short",    "Long/Short Ratio"),
    ("funding_rate",  "Funding Rate"),
]

_LM107_FETCHERS = {
    "live_price":    _lm_fetch_exchange_live_price,
    "mark_price":    _lm_fetch_exchange_mark_price,
    "order_book":    _lm_fetch_exchange_orderbook,
    "liquidations":  _lm_fetch_exchange_liquidations,
    "open_interest": _lm_fetch_exchange_open_interest,
    "oi_change":     _lm_fetch_exchange_oi_change,
    "delta":         _lm_fetch_exchange_delta,
    "long_short":    _lm_fetch_exchange_long_short,
    "funding_rate":  _lm_fetch_exchange_funding,
}


def _lm_build_specific_exchange_data_with_fallback(
        symbol: str, selected_exchange: str, snapshot=None) -> dict:
    """Fetch all metrics for selected_exchange with per-metric Binance fallback.

    Status: fresh/stale = selected exchange; fallback_fresh/fallback_stale = Binance fallback;
            unavailable = neither source available.
    """
    now_iso       = datetime.now(timezone.utc).isoformat()
    metrics:       dict = {}
    fallback_used: list = []
    warnings:      list = []

    for key, human in _LM107_METRIC_KEYS:
        fetcher = _LM107_FETCHERS.get(key)
        if not fetcher:
            continue
        # Try selected exchange
        try:
            result = _lm_rest_cached(f"spec_{selected_exchange}_{key}:{symbol}", 10,
                                      lambda k=key, e=selected_exchange: _LM107_FETCHERS[k](e, symbol))
        except Exception:
            result = None

        if result and result.get("available"):
            status    = result.get("status", "fresh")
            src_label = selected_exchange.title()
            if selected_exchange == "binance":
                src_label = "Binance"
            # Phase 10.8: augment order_book with MX WS data if available
            _mx_ob_note_spec = ""
            if key == "order_book" and selected_exchange in ("bybit", "okx", "mexc") and _LM_MX_WS_ENABLED:
                _mx_bk_s, _mx_bk_st_s = _lm_mx_get_book(selected_exchange, symbol)
                if _mx_bk_s:
                    _bids_s = _mx_bk_s.get("bids", {})
                    _asks_s = _mx_bk_s.get("asks", {})
                    _bb_s = max(_bids_s.keys()) if _bids_s else None
                    _ba_s = min(_asks_s.keys()) if _asks_s else None
                    if _bb_s and _ba_s:
                        _mx_ob_note_spec = (f" | Phase 10.8 MX WS: Bid {_bb_s:.4f} / Ask {_ba_s:.4f}"
                                            f" [{_mx_bk_st_s}]")
            metrics[key] = _lm_metric_result(
                human, value=_lm107_format_metric(key, result),
                status=status, source=src_label,
                sources_used=[selected_exchange],
                notes=(result.get("notes", "") + _mx_ob_note_spec).strip(),
                updated=now_iso, raw=result)
        else:
            # Phase 10.8: for order_book on bybit/okx/mexc, try MX WS book before Binance fallback
            if key == "order_book" and selected_exchange in ("bybit", "okx", "mexc") and _LM_MX_WS_ENABLED:
                _mx_bk_fb, _mx_bk_fb_st = _lm_mx_get_book(selected_exchange, symbol)
                if _mx_bk_fb:
                    _bids_fb = _mx_bk_fb.get("bids", {})
                    _asks_fb = _mx_bk_fb.get("asks", {})
                    _bb_fb = max(_bids_fb.keys()) if _bids_fb else None
                    _ba_fb = min(_asks_fb.keys()) if _asks_fb else None
                    if _bb_fb and _ba_fb:
                        metrics[key] = _lm_metric_result(
                            human,
                            value=f"Bid {_bb_fb:.4f} / Ask {_ba_fb:.4f}",
                            status=_mx_bk_fb_st,
                            source=f"{selected_exchange.title()} WS (Phase 10.8)",
                            sources_used=[selected_exchange],
                            notes=f"Phase 10.8 MX WS order book for {selected_exchange.title()}",
                            updated=now_iso)
                        continue
            # Binance fallback (only if selected ≠ binance)
            fb_result = None
            if selected_exchange != "binance":
                try:
                    fb_result = _lm_rest_cached(f"spec_binance_{key}:{symbol}", 10,
                                                 lambda k=key: _LM107_FETCHERS[k]("binance", symbol))
                except Exception:
                    fb_result = None

            if fb_result and fb_result.get("available"):
                fb_s     = fb_result.get("status", "fresh")
                fb_label = f"fallback_{fb_s}" if fb_s in ("fresh", "stale") else "fallback_fresh"
                note     = (f"{selected_exchange.title()} missing this metric; Binance fallback used."
                            + (" " + fb_result.get("notes", "") if fb_result.get("notes") else ""))
                fallback_used.append(human)
                warnings.append(f"{human}: {selected_exchange.title()} unavailable → Binance fallback")
                metrics[key] = _lm_metric_result(
                    human, value=_lm107_format_metric(key, fb_result),
                    status=fb_label, source="binance_fallback",
                    sources_used=["binance"], sources_skipped=[selected_exchange],
                    notes=note.strip(), updated=now_iso, raw=fb_result)
            else:
                metrics[key] = _lm_metric_result(
                    human, status="unavailable",
                    source=selected_exchange,
                    sources_skipped=[selected_exchange] + (["binance"] if selected_exchange != "binance" else []),
                    notes=f"Not available from {selected_exchange.title()}" +
                          ("" if selected_exchange == "binance" else " or Binance fallback"),
                    updated=now_iso)

    # AI gate — Phase 10.7 Task 7: only fresh/fallback_fresh open the gate;
    # stale and fallback_stale are NOT sufficient.
    lp_m  = metrics.get("live_price", {})
    mp_m  = metrics.get("mark_price", {})
    lp_ok = lp_m.get("status") in ("fresh", "fallback_fresh")
    mp_ok = mp_m.get("status") in ("fresh", "fallback_fresh")
    gate_allowed  = lp_ok and mp_ok
    gate_reasons  = []
    gate_warnings = []
    if not lp_ok:
        _lp_st = lp_m.get("status", "unavailable")
        gate_reasons.append(
            f"Live Price is {_lp_st} from {selected_exchange.title()} "
            "(and Binance fallback if applicable) — fresh price required"
        )
    if not mp_ok:
        _mp_st = mp_m.get("status", "unavailable")
        gate_reasons.append(
            f"Mark Price is {_mp_st} from {selected_exchange.title()} "
            "(and Binance fallback if applicable) — fresh price required"
        )
    if fallback_used:
        gate_warnings.append(
            f"{selected_exchange.title()} missing: {', '.join(fallback_used[:3])}; Binance fallback used")

    return {
        "symbol":            symbol,
        "analysis_source":   selected_exchange,
        "selected_exchange": selected_exchange,
        "fallback_used":     fallback_used,
        "metrics":           metrics,
        "warnings":          warnings,
        "fetched_at":        time.time(),
        "ai_data_gate": {
            "allowed":        gate_allowed,
            "reasons":        gate_reasons,
            "warnings":       gate_warnings,
        },
    }


# ── Tasks 13-14: Analysis source chat/event helpers ───────────────────────────

_LM107_SOURCE_CHAT_COOLDOWN = 300   # 5 min dedup


def _lm107_maybe_post_source_chat(uid: int, item, new_src: str, old_src: str,
                                   data: dict = None) -> bool:
    """Post one assistant chat when analysis source changes. Deduped per item."""
    if not uid or not item or new_src == old_src:
        return False
    try:
        symbol  = getattr(item, "symbol", "?")
        snap    = _json_loads_safe(getattr(item, "snapshot_json", None), {})
        state   = snap.get("analysis_source_chat_state") or {}
        now     = time.time()
        if state.get("last_source") == new_src and (now - state.get("last_ts", 0)) < _LM107_SOURCE_CHAT_COOLDOWN:
            return False

        used    = (data or {}).get("sources_used") or []
        skipped = (data or {}).get("sources_skipped") or []
        if new_src == "aggregated" and used:
            src_line = f"Using {', '.join(s.title() for s in used)} where available."
            if skipped:
                src_line += f" Skipped: {', '.join(s.title() for s in skipped)} (metrics unavailable)."
        elif new_src == "aggregated":
            src_line = "Attempting to combine Binance, Bybit, OKX, MEXC."
        else:
            src_line = f"Using {new_src.title()} as primary analysis source."

        content = (
            f"AI Data Source Update — {symbol}\n\n"
            f"Analysis source changed to: {new_src.title()}.\n"
            f"{src_line}\n\n"
            f"Important:\nThis affects analysis data only. "
            f"Parent setup OB/FIB zone, SL, TP, and candle-close invalidation "
            f"remain from the parent setup exchange."
        )
        _lm_chat_save(uid, item, "assistant", content,
                      agent_id="smart_entry", agent_label="Smart Entry")
        snap["analysis_source_chat_state"] = {"last_ts": now, "last_source": new_src}
        from models import db as _db107, LiveMonitorItem as _LMI107
        row107 = _LMI107.query.get(getattr(item, "id", None))
        if row107:
            row107.snapshot_json = _json_dumps_safe(snap)
            try: _db107.session.commit()
            except Exception: _db107.session.rollback()
        return True
    except Exception as _e:
        print(f"[107-CHAT] {_e}")
        return False


def _lm107_maybe_log_source_event(uid: int, item, new_src: str, old_src: str,
                                   data: dict = None) -> bool:
    """Log LiveMonitorEvent for source changes and partial/fallback states."""
    if not uid or not item:
        return False
    try:
        used    = (data or {}).get("sources_used") or []
        skipped = (data or {}).get("sources_skipped") or []
        if new_src != old_src:
            ev_type = "analysis_source_changed"
            ev_desc = f"Analysis source changed: {(old_src or 'none').title()} → {new_src.title()}"
        elif new_src == "aggregated" and skipped:
            ev_type = "aggregated_source_partial"
            active  = "+".join(s.title() for s in used)
            missing = "/".join(s.title() for s in skipped)
            ev_desc = f"Aggregated source partial: {active} active, {missing} unavailable"
        else:
            return False
        from models import db as _dbev, LiveMonitorEvent as _LMEev
        ev = _LMEev(
            item_id=getattr(item, "id", None), user_id=uid,
            symbol=getattr(item, "symbol", ""),
            event_type=ev_type, event_description=ev_desc,
            details_json=_json_dumps_safe({"old_source": old_src, "new_source": new_src,
                                           "sources_used": used, "sources_skipped": skipped}),
            price_at_event=getattr(item, "current_price", None),
        )
        _dbev.session.add(ev)
        return True
    except Exception as _e:
        print(f"[107-EVENT] {_e}")
        return False


# ── Phase 10.4: Data Health Context Helper ────────────────────────────────────

def _lm_build_data_health_context(symbol: str, exchange: str,
                                   snap: dict = None, user_id=None) -> dict:
    """Build 11-row Live Monitor Data Health context dict.

    Pure: reads in-memory caches + provided snap dict only.
    Does NOT start WS threads or OB streams — caller is responsible for those
    side effects before calling this function.
    Does NOT use Flask request context.

    Returns:
        {symbol, exchange, ws_enabled, fetched_at, rows, critical_status, ai_data_gate}
    ai_data_gate.allowed is True only when Live Price AND Mark Price are both fresh.
    """
    if snap is None:
        snap = {}

    ws_enabled = os.environ.get("ZYNI_LM_WS_ENABLED") == "1"

    # ── Inner helpers ─────────────────────────────────────────────────────────
    def _age_str(ts_iso: str) -> str:
        if not ts_iso:
            return "—"
        try:
            from datetime import datetime as _dh, timezone as _tzh
            ts    = _dh.fromisoformat(ts_iso.replace("Z", "+00:00"))
            age_s = int((_dh.now(_tzh.utc) - ts).total_seconds())
            if age_s < 60:   return f"{age_s}s ago"
            if age_s < 3600: return f"{age_s // 60}m ago"
            return f"{age_s // 3600}h ago"
        except Exception:
            return ts_iso[:16]

    def _age_status(ts_iso: str, fresh_secs: int = 300) -> str:
        if not ts_iso:
            return "unavailable"
        try:
            from datetime import datetime as _dh, timezone as _tzh
            ts = _dh.fromisoformat(ts_iso.replace("Z", "+00:00"))
            return "fresh" if (_dh.now(_tzh.utc) - ts).total_seconds() < fresh_secs else "stale"
        except Exception:
            return "stale"

    def _ws_disabled_note():
        return "Connecting…" if ws_enabled else "WebSocket disabled: set ZYNI_LM_WS_ENABLED=1"

    def _nc(metric):
        return {"metric": metric, "value": "—", "source": exchange,
                "status": "not_connected_yet", "updated": "—",
                "notes": "Live data available for Binance only"}

    def _metrics_to_rows(metrics_dict: dict, src_label: str) -> list:
        """Convert Phase 10.7 metrics dict → health row list."""
        out = []
        for key, human in _LM107_METRIC_KEYS:
            m = metrics_dict.get(key)
            if m:
                upd = m.get("updated", "—")
                out.append({
                    "metric":  m.get("metric", human),
                    "value":   m.get("value", "—"),
                    "source":  m.get("source", src_label),
                    "status":  m.get("status", "unavailable"),
                    "updated": _age_str(upd) if upd and upd != "—" else "—",
                    "notes":   m.get("notes", ""),
                })
            else:
                out.append({"metric": human, "value": "—", "source": src_label,
                            "status": "unavailable", "updated": "—", "notes": "Not available"})
        return out

    def _append_snapshot_rows(rows_list: list, gate_allowed: bool,
                               gate_reasons: list, src_label: str):
        """Append Candle Status + AI Entry Analysis rows from snapshot."""
        cf_at = snap.get("last_candle_features_at") or ""
        cf    = snap.get("latest_candle_features")  or {}
        cs    = snap.get("candle_store")            or {}  # Phase 10.9B Bias Shift
        if cf_at:
            rows_list.append({"metric": "Candle Status", "value": "computed",
                              "source": "db_snapshot", "status": _age_status(cf_at, 300),
                              "updated": _age_str(cf_at),
                              "notes": cf.get("dominant_tf", "") if isinstance(cf, dict) else ""})
        elif cs and cs.get("status"):
            _cs_st   = cs.get("status", "unknown")
            _dh_st   = ("fresh"       if _cs_st in ("ready", "refreshing")
                        else "stale"  if _cs_st == "partial"
                        else "unavailable")
            _per_tf  = cs.get("per_tf") or {}
            _tf_note = (", ".join(
                f"{tf}:{v.get('count',0)}" for tf, v in sorted(_per_tf.items())
                if isinstance(v, dict) and v.get("count", 0) > 0
            ) or "") if _per_tf else ""
            rows_list.append({"metric": "Candle Status", "value": _cs_st.title(),
                              "source": "candle_store", "status": _dh_st, "updated": "—",
                              "notes": "Phase 10.9B candle store" + (f" | {_tf_note}" if _tf_note else "")})
        else:
            rows_list.append({"metric": "Candle Status", "value": "—", "source": "db_snapshot",
                              "status": "unavailable", "updated": "—", "notes": "No candle refresh yet"})
        if gate_allowed:
            ai_at  = snap.get("last_ai_analysis_at") or ""
            ai_con = snap.get("latest_ai_consensus") or {}
            ai_dir = (ai_con.get("direction") or ai_con.get("bias") or "") if isinstance(ai_con, dict) else ""
            if not ai_at and isinstance(ai_con, dict):
                ai_at = ai_con.get("computed_at") or ""
            if ai_at:
                rows_list.append({"metric": "AI Entry Analysis",
                                  "value":  ai_dir.upper() if ai_dir else "Allowed",
                                  "source": "AI Consensus",
                                  "status": _age_status(ai_at, 600),
                                  "updated": _age_str(ai_at),
                                  "notes":  f"{src_label} live/mark price available"})
            else:
                rows_list.append({"metric": "AI Entry Analysis", "value": "Allowed",
                                  "source": "AI Consensus", "status": "fresh",
                                  "updated": "—", "notes": "No prior AI analysis yet"})
        else:
            rows_list.append({"metric": "AI Entry Analysis", "value": "Blocked",
                              "source": "AI Consensus", "status": "blocked",
                              "updated": "—",
                              "notes": "; ".join(gate_reasons or ["Data not ready"])})

    def _critical_from_lp_mp(metrics_dict: dict) -> str:
        lp_s = (metrics_dict.get("live_price") or {}).get("status", "unavailable")
        mp_s = (metrics_dict.get("mark_price") or {}).get("status", "unavailable")
        cs   = {lp_s, mp_s}
        if "unavailable" in cs:                                  return "unavailable"
        if "stale" in cs or "fallback_stale" in cs:             return "stale"
        if "partial" in cs or "fallback_fresh" in cs:           return "partial"
        return "fresh"

    # ── Aggregated exchange ───────────────────────────────────────────────────
    if exchange == "aggregated":
        agg  = _lm_build_true_aggregated_exchange_data(symbol, snap)
        rows = _metrics_to_rows(agg["metrics"], "Aggregated")
        gate = agg.get("ai_data_gate", {})
        _append_snapshot_rows(rows, gate.get("allowed", False),
                              gate.get("reasons", []), "Aggregated")
        _mx_ws_on  = _lm_multi_exchange_ws_enabled()
        _dd        = agg.get("delta_debug", {})
        return {
            "symbol":                    symbol,
            "exchange":                  exchange,
            "ws_enabled":                _mx_ws_on,
            "single_ws_enabled":         os.environ.get("ZYNI_LM_WS_ENABLED", "").strip().lower() in {"1","true","yes","on"},
            "multi_exchange_ws_enabled": _mx_ws_on,
            "multi_exchange_ws_env": {
                "ZYNI_LM_MULTI_EXCHANGE_WS_ENABLED": (os.environ.get("ZYNI_LM_MULTI_EXCHANGE_WS_ENABLED") or "").strip().lower() in {"1","true","yes","on"},
                "ZYNI_LM_MX_WS_ENABLED":             (os.environ.get("ZYNI_LM_MX_WS_ENABLED") or "").strip().lower() in {"1","true","yes","on"},
            },
            "fetched_at":                time.time(),
            "rows":                      rows,
            "critical_status":           _critical_from_lp_mp(agg["metrics"]),
            "ai_data_gate":              gate,
            "sources_used":              agg.get("sources_used", []),
            "sources_skipped":           agg.get("sources_skipped", []),
            "delta_sources_used":        _dd.get("delta_sources_used", []),
            "delta_sources_skipped":     _dd.get("delta_sources_skipped", []),
            "delta_mode":                _dd.get("delta_mode", "unknown"),
            "delta_fallback_used":       _dd.get("delta_fallback_used", False),
        }

    # ── Non-Binance single exchange (Bybit, OKX, MEXC) ───────────────────────
    if exchange != "binance":
        spec = _lm_build_specific_exchange_data_with_fallback(symbol, exchange, snap)
        rows = _metrics_to_rows(spec["metrics"], exchange.title())
        gate = spec.get("ai_data_gate", {})
        _append_snapshot_rows(rows, gate.get("allowed", False),
                              gate.get("reasons", []), exchange.title())
        # Phase 10.8 Task 10: annotate Live Price and Mark Price rows with parent exchange note
        if _LM_MX_WS_ENABLED:
            _p108_note = (f"Parent setup exchange: {exchange.title()}. "
                          f"Multi-exchange WS data available for analysis but parent price is "
                          f"from {exchange.title()}.")
            for _row in rows:
                if _row.get("metric") in ("Live Price", "Mark Price"):
                    _row["notes"] = ((_row.get("notes") or "") + " | " + _p108_note).strip(" |")
        return {
            "symbol":          symbol,
            "exchange":        exchange,
            "ws_enabled":      False,
            "fetched_at":      time.time(),
            "rows":            rows,
            "critical_status": _critical_from_lp_mp(spec["metrics"]),
            "ai_data_gate":    gate,
            "fallback_used":   spec.get("fallback_used", []),
            "multi_exchange_ws_note": (
                f"Parent setup exchange: {exchange.title()}. "
                f"Multi-exchange WS data available for analysis only."
            ) if _LM_MX_WS_ENABLED else None,
        }

    rows = []
    _live_price_status = "not_connected_yet"
    _mark_price_status = "not_connected_yet"

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 1 — Live Price  (source: websocket, fallback: REST premiumIndex)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        ws_e, ws_s = _lm_ws_get("binance", symbol)
        if ws_e:
            _live_price_status = ws_s
            rows.append({"metric": "Live Price",
                         "value":   f"{ws_e['live_price']:.4f}",
                         "source":  "websocket",
                         "status":  ws_s,
                         "updated": f"{ws_e['data_age_sec']}s ago",
                         "notes":   "Binance Futures markPrice stream"})
        elif ws_enabled:
            # WS not yet populated — use REST premiumIndex as fallback (10s TTL)
            _rest_m = _lm_rest_cached(f"mark:{symbol}", 10,
                                      lambda: _lm_fetch_mark_price_rest(symbol))
            if _rest_m and _rest_m.get("mark_price"):
                _live_price_status = "fresh"
                rows.append({"metric": "Live Price",
                             "value":  f"{_rest_m['mark_price']:.4f}",
                             "source": "rest",
                             "status": "fresh",
                             "updated": "REST ~10s TTL",
                             "notes":  "premiumIndex REST fallback (WS connecting)"})
            else:
                _live_price_status = "unavailable"
                rows.append({"metric": "Live Price", "value": "—",
                             "source": "websocket", "status": "unavailable",
                             "updated": "—", "notes": "Connecting… (REST also unavailable)"})
        else:
            _live_price_status = "unavailable"
            rows.append({"metric": "Live Price", "value": "—",
                         "source": "websocket", "status": "unavailable",
                         "updated": "—", "notes": _ws_disabled_note()})
    else:
        rows.append(_nc("Live Price"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 2 — Mark Price  (source: websocket, fallback: REST premiumIndex)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        ws_e, ws_s = _lm_ws_get("binance", symbol)
        if ws_e and ws_e.get("mark_price") is not None:
            _mark_price_status = ws_s
            rows.append({"metric": "Mark Price",
                         "value":   f"{ws_e['mark_price']:.4f}",
                         "source":  "websocket",
                         "status":  ws_s,
                         "updated": f"{ws_e['data_age_sec']}s ago",
                         "notes":   "Binance Futures markPrice stream"})
        elif ws_enabled:
            # REST fallback shares the same cached result as Live Price above
            _rest_m2 = _lm_rest_cached(f"mark:{symbol}", 10,
                                       lambda: _lm_fetch_mark_price_rest(symbol))
            if _rest_m2 and _rest_m2.get("mark_price"):
                _mark_price_status = "fresh"
                rows.append({"metric": "Mark Price",
                             "value":  f"{_rest_m2['mark_price']:.4f}",
                             "source": "rest",
                             "status": "fresh",
                             "updated": "REST ~10s TTL",
                             "notes":  "premiumIndex REST fallback (WS connecting)"})
            else:
                _mark_price_status = "unavailable"
                rows.append({"metric": "Mark Price", "value": "—",
                             "source": "websocket", "status": "unavailable",
                             "updated": "—", "notes": "Connecting… (REST also unavailable)"})
        else:
            _mark_price_status = "unavailable"
            rows.append({"metric": "Mark Price", "value": "—",
                         "source": "websocket", "status": "unavailable",
                         "updated": "—", "notes": _ws_disabled_note()})
    else:
        rows.append(_nc("Mark Price"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 3 — Order Book  (source: websocket)
    # Caller must invoke ensure_ob_stream() before this function if desired.
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        with _ob_book_lock:
            ob_raw = dict(_ob_books.get(symbol) or {})
        if ws_enabled and ob_raw and ob_raw.get("ready"):
            bids = ob_raw.get("bids", {})
            asks = ob_raw.get("asks", {})
            best_bid = max(bids.keys()) if bids else None
            best_ask = min(asks.keys()) if asks else None
            if best_bid and best_ask:
                ob_age = round(time.time() - ob_raw.get("ts", time.time()), 1)
                ob_status = "fresh" if ob_age <= 5 else "stale"
                spread_pct = (best_ask - best_bid) / best_ask * 100
                top_bids_usd = sum(p * q for p, q in sorted(bids.items(), reverse=True)[:20])
                top_asks_usd = sum(p * q for p, q in sorted(asks.items())[:20])
                tot_depth = top_bids_usd + top_asks_usd
                imb_pct = (top_bids_usd - top_asks_usd) / tot_depth * 100 if tot_depth > 0 else 0
                rows.append({
                    "metric": "Order Book",
                    "value":  f"Bid {best_bid:.2f} / Ask {best_ask:.2f}",
                    "source": "websocket",
                    "status": ob_status,
                    "updated": f"{ob_age}s ago",
                    "notes": (f"Spread {spread_pct:.3f}% | "
                              f"Imbal {imb_pct:+.1f}% | "
                              f"Bid {_fmt_usd_lm(top_bids_usd)} Ask {_fmt_usd_lm(top_asks_usd)} (top-20)"),
                })
            else:
                rows.append({"metric": "Order Book", "value": "—",
                             "source": "websocket", "status": "unavailable",
                             "updated": "—", "notes": "Book empty after snapshot"})
        elif ws_enabled:
            rows.append({"metric": "Order Book", "value": "—",
                         "source": "websocket", "status": "unavailable",
                         "updated": "—", "notes": "Connecting… (auto-started)"})
        else:
            rows.append({"metric": "Order Book", "value": "—",
                         "source": "websocket", "status": "unavailable",
                         "updated": "—", "notes": "WebSocket disabled: set ZYNI_LM_WS_ENABLED=1"})
    else:
        rows.append(_nc("Order Book"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 4 — Liquidations  (source: websocket)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        liq_e, liq_s = _lm_liq_get("binance", symbol)
        if liq_e is not None:
            total   = liq_e["total_liq_usd_5m"]
            long_u  = liq_e["long_liq_usd_5m"]
            short_u = liq_e["short_liq_usd_5m"]
            last_p  = liq_e.get("last_liq_price")
            last_s  = liq_e.get("last_liq_side", "")
            if total == 0:
                liq_val   = "None (5m)"
                liq_notes = "Stream live — no liquidations in last 5 min"
            else:
                liq_val   = f"L {_fmt_usd_lm(long_u)} / S {_fmt_usd_lm(short_u)} (5m)"
                liq_notes = (f"Total {_fmt_usd_lm(total)} | "
                             + (f"Last: {last_s} @ {last_p:.2f}" if last_p else ""))
            rows.append({"metric": "Liquidations",
                         "value":   liq_val,
                         "source":  "websocket",
                         "status":  liq_s,
                         "updated": f"{liq_e['data_age_sec']}s ago",
                         "notes":   liq_notes})
        else:
            rows.append({"metric": "Liquidations", "value": "—",
                         "source": "websocket", "status": "unavailable",
                         "updated": "—", "notes": _ws_disabled_note()})
    else:
        rows.append(_nc("Liquidations"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 5 — Open Interest  (source: rest, TTL 30s)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        oi_data = _lm_rest_cached(f"oi:{symbol}", 30,
                                   lambda: _lm_fetch_oi_rest(symbol))
        if oi_data:
            oi_contracts = oi_data.get("oi_contracts", 0)
            ws_e2, _ = _lm_ws_get("binance", symbol)
            mp2 = ws_e2.get("mark_price") if ws_e2 else None
            if mp2 and oi_contracts:
                oi_usd = oi_contracts * mp2
                oi_val = _fmt_usd_lm(oi_usd)
            else:
                oi_val = f"{oi_contracts:.0f} contracts"
            rows.append({"metric": "Open Interest",
                         "value":   oi_val,
                         "source":  "rest",
                         "status":  "fresh",
                         "updated": "REST (30s TTL)",
                         "notes":   f"{oi_contracts:.0f} contracts | /fapi/v1/openInterest"})
        else:
            rows.append({"metric": "Open Interest", "value": "—",
                         "source": "rest", "status": "unavailable",
                         "updated": "—", "notes": "REST fetch failed or WS off"})
    else:
        rows.append(_nc("Open Interest"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 6 — OI Change  (source: rest/interval, TTL 60s)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        oi_hist = _lm_rest_cached(f"oi_hist:{symbol}", 60,
                                   lambda: _lm_fetch_oi_hist_rest(symbol))
        if oi_hist and isinstance(oi_hist, list) and len(oi_hist) >= 2:
            try:
                newest_val = float(oi_hist[-1].get("sumOpenInterestValue", 0) or
                                   oi_hist[-1].get("sumOpenInterest", 0))
                oldest_val = float(oi_hist[0].get("sumOpenInterestValue", 0) or
                                   oi_hist[0].get("sumOpenInterest", 0))
                if oldest_val > 0:
                    chg_pct = (newest_val - oldest_val) / oldest_val * 100
                    arrow = "▲" if chg_pct >= 0 else "▼"
                    rows.append({"metric": "OI Change",
                                 "value":   f"{arrow} {abs(chg_pct):.2f}%",
                                 "source":  "interval",
                                 "status":  "interval",
                                 "updated": "5m period (REST)",
                                 "notes":   f"From {_fmt_usd_lm(oldest_val)} → {_fmt_usd_lm(newest_val)}"})
                else:
                    rows.append({"metric": "OI Change", "value": "—",
                                 "source": "interval", "status": "unavailable",
                                 "updated": "—", "notes": "OI history unavailable"})
            except Exception:
                rows.append({"metric": "OI Change", "value": "—",
                             "source": "interval", "status": "unavailable",
                             "updated": "—", "notes": "Parse error"})
        else:
            rows.append({"metric": "OI Change", "value": "—",
                         "source": "interval", "status": "unavailable",
                         "updated": "—", "notes": "OI history not available"})
    else:
        rows.append(_nc("OI Change"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 7 — Delta / Taker Pressure  (source: websocket)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        delta_e, delta_s = _lm_delta_get("binance", symbol)
        if delta_e:
            d60    = delta_e["delta_60s"]
            dpct60 = delta_e["delta_pct_60s"]
            buy60  = delta_e["buy_vol_60s"]
            sell60 = delta_e["sell_vol_60s"]
            side_lbl = "Buy" if d60 >= 0 else "Sell"
            rows.append({"metric": "Delta",
                         "value":  f"{'+' if d60>=0 else ''}{_fmt_usd_lm(abs(d60))} {side_lbl} ({dpct60:+.1f}%) 60s",
                         "source": "websocket",
                         "status": delta_s,
                         "updated": f"{delta_e['data_age_sec']}s ago",
                         "notes":  f"Buy {_fmt_usd_lm(buy60)} Sell {_fmt_usd_lm(sell60)} (60s) | aggTrade stream"})
        elif ws_enabled:
            # REST fallback: compute delta from recent aggTrades (30s TTL)
            _rest_dt = _lm_rest_cached(f"delta:{symbol}", 30,
                                       lambda: _lm_fetch_agg_trades_delta_rest(symbol))
            if _rest_dt is not None:
                _d60    = _rest_dt["delta_60s"]
                _dpct60 = _rest_dt["delta_pct_60s"]
                _buy60  = _rest_dt["buy_vol_60s"]
                _sell60 = _rest_dt["sell_vol_60s"]
                _side   = "Buy" if _d60 >= 0 else "Sell"
                rows.append({"metric": "Delta",
                             "value":  f"{'+' if _d60>=0 else ''}{_fmt_usd_lm(abs(_d60))} {_side} ({_dpct60:+.1f}%) 60s",
                             "source": "rest",
                             "status": "fresh",
                             "updated": "REST ~30s TTL",
                             "notes":  f"Buy {_fmt_usd_lm(_buy60)} Sell {_fmt_usd_lm(_sell60)} (60s) | aggTrades REST"})
            else:
                rows.append({"metric": "Delta", "value": "—",
                             "source": "websocket", "status": "unavailable",
                             "updated": "—", "notes": "Collecting… (aggTrade WS + REST starting)"})
        else:
            rows.append({"metric": "Delta", "value": "—",
                         "source": "websocket", "status": "unavailable",
                         "updated": "—", "notes": _ws_disabled_note()})
    else:
        rows.append(_nc("Delta"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 8 — Long/Short Ratio  (source: interval/REST, TTL 5m)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        ls_data = _lm_rest_cached(f"ls:{symbol}", 300,
                                   lambda: _lm_fetch_ls_ratio_rest(symbol))
        if ls_data:
            rows.append({"metric": "Long/Short Ratio",
                         "value":  f"L {ls_data['long_pct']:.1f}% / S {ls_data['short_pct']:.1f}%",
                         "source": "interval",
                         "status": "interval",
                         "updated": "5m interval (REST)",
                         "notes":  f"L/S ratio {ls_data['ls_ratio']:.3f} | globalLongShortAccountRatio"})
        else:
            rows.append({"metric": "Long/Short Ratio", "value": "—",
                         "source": "interval", "status": "unavailable",
                         "updated": "—", "notes": "REST fetch failed"})
    else:
        rows.append(_nc("Long/Short Ratio"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 9 — Funding Rate  (source: websocket, fallback: REST premiumIndex)
    # ═════════════════════════════════════════════════════════════════════════
    if exchange == "binance":
        ws_e, ws_s = _lm_ws_get("binance", symbol)
        if ws_e and ws_e.get("funding_rate") is not None:
            fr_pct = ws_e["funding_rate"] * 100
            rows.append({"metric": "Funding Rate",
                         "value":  f"{fr_pct:+.4f}%",
                         "source": "websocket",
                         "status": ws_s,
                         "updated": f"{ws_e['data_age_sec']}s ago",
                         "notes":  "positive = longs pay shorts | markPrice stream"})
        elif ws_enabled:
            _rest_fr = _lm_rest_cached(f"mark:{symbol}", 10,
                                       lambda: _lm_fetch_mark_price_rest(symbol))
            if _rest_fr and _rest_fr.get("funding_rate") is not None:
                fr_pct2 = _rest_fr["funding_rate"] * 100
                rows.append({"metric": "Funding Rate",
                             "value":  f"{fr_pct2:+.4f}%",
                             "source": "rest",
                             "status": "interval",
                             "updated": "REST ~10s TTL",
                             "notes":  "premiumIndex REST fallback (WS connecting)"})
            else:
                rows.append({"metric": "Funding Rate", "value": "—",
                             "source": "websocket", "status": "unavailable",
                             "updated": "—", "notes": "Connecting… (REST also unavailable)"})
        else:
            rows.append({"metric": "Funding Rate", "value": "—",
                         "source": "websocket", "status": "unavailable",
                         "updated": "—", "notes": _ws_disabled_note()})
    else:
        rows.append(_nc("Funding Rate"))

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 10 — Candle Status  (source: db_snapshot OR candle_store for Bias Shift)
    # ═════════════════════════════════════════════════════════════════════════
    cf_at = snap.get("last_candle_features_at") or ""
    cf    = snap.get("latest_candle_features")  or {}
    cs    = snap.get("candle_store")            or {}  # Phase 10.9B Bias Shift candle store
    if cf_at:
        rows.append({"metric": "Candle Status",
                     "value":  "computed",
                     "source": "db_snapshot",
                     "status": _age_status(cf_at, fresh_secs=300),
                     "updated": _age_str(cf_at),
                     "notes":  cf.get("dominant_tf", "") if isinstance(cf, dict) else ""})
    elif cs and cs.get("status"):
        # Phase 10.9B: Bias Shift Watch item — candle_store not candle_features
        _cs_status = cs.get("status", "unknown")
        _dh_status = ("fresh" if _cs_status in ("ready", "refreshing")
                      else "stale" if _cs_status == "partial"
                      else "unavailable")
        _per_tf = cs.get("per_tf") or {}
        _tf_note = (", ".join(
            f"{tf}:{v.get('count',0)}" for tf, v in sorted(_per_tf.items())
            if isinstance(v, dict) and v.get("count", 0) > 0
        ) or "") if _per_tf else ""
        rows.append({"metric": "Candle Status",
                     "value":  _cs_status.title(),
                     "source": "candle_store",
                     "status": _dh_status,
                     "updated": "—",
                     "notes":  "Phase 10.9B candle store" + (f" | {_tf_note}" if _tf_note else "")})
    else:
        rows.append({"metric": "Candle Status", "value": "—",
                     "source": "db_snapshot", "status": "unavailable",
                     "updated": "—", "notes": "No candle refresh yet"})

    # ═════════════════════════════════════════════════════════════════════════
    # ROW 11 — AI Entry Analysis  (gated: live + mark price must be fresh)
    # ═════════════════════════════════════════════════════════════════════════
    if _live_price_status != "fresh" or _mark_price_status != "fresh":
        block_reason = (f"Requires fresh live price ({_live_price_status}) "
                        f"and mark price ({_mark_price_status})")
        rows.append({"metric": "AI Entry Analysis", "value": "Blocked",
                     "source": "AI Consensus", "status": "blocked",
                     "updated": "—", "notes": block_reason})
    else:
        ai_at  = snap.get("last_ai_analysis_at") or ""
        ai_con = snap.get("latest_ai_consensus") or {}
        ai_dir = (ai_con.get("direction") or ai_con.get("bias") or "") if isinstance(ai_con, dict) else ""
        if not ai_at and isinstance(ai_con, dict):
            ai_at = ai_con.get("computed_at") or ""
        if ai_at:
            rows.append({"metric": "AI Entry Analysis",
                         "value":  ai_dir.upper() if ai_dir else "Allowed",
                         "source": "AI Consensus",
                         "status": _age_status(ai_at, fresh_secs=600),
                         "updated": _age_str(ai_at),
                         "notes":  "Live price and mark price are fresh"})
        else:
            rows.append({"metric": "AI Entry Analysis", "value": "Allowed",
                         "source": "AI Consensus", "status": "fresh",
                         "updated": "—", "notes": "No prior AI analysis yet"})

    # ── Compute ai_data_gate ──────────────────────────────────────────────────
    gate_allowed = (_live_price_status == "fresh" and _mark_price_status == "fresh")
    gate_reasons  = []
    gate_warnings = []

    if _live_price_status != "fresh":
        gate_reasons.append(
            f"Live Price is {_live_price_status} — requires fresh WebSocket feed"
        )
    if _mark_price_status != "fresh":
        gate_reasons.append(
            f"Mark Price is {_mark_price_status} — requires fresh WebSocket feed"
        )
    for r in rows:
        if r["metric"] not in ("Live Price", "Mark Price", "AI Entry Analysis"):
            if r["status"] in ("stale", "unavailable"):
                gate_warnings.append(f"{r['metric']} is {r['status']}")

    # Determine critical_status from live + mark price pair
    _cs = {_live_price_status, _mark_price_status}
    if "unavailable" in _cs or "blocked" in _cs:
        critical_status = "unavailable"
    elif "stale" in _cs:
        critical_status = "stale"
    elif "not_connected_yet" in _cs:
        critical_status = "not_connected_yet"
    else:
        critical_status = "fresh"

    return {
        "symbol":          symbol,
        "exchange":        exchange,
        "ws_enabled":      ws_enabled,
        "fetched_at":      time.time(),
        "rows":            rows,
        "critical_status": critical_status,
        "ai_data_gate": {
            "allowed":        gate_allowed,
            "reasons":        gate_reasons,
            "fresh_required": ["Live Price", "Mark Price"],
            "warnings":       gate_warnings,
        },
    }


# ── Phase 10.6: Smart Entry Refinement Engine ────────────────────────────────

_LM_SE_TF_CHILDREN: dict = {
    "1d":  ["4h", "1h"],
    "4h":  ["1h", "30m", "15m"],
    "1h":  ["30m", "15m"],
    "30m": ["15m"],
    "15m": [],
}
_LM_SE_ZONE_TOLERANCE_PCT  = 0.35   # % of midprice for near-zone tolerance
_LM_SE_MIN_SCORE           = 70     # minimum candidate score for refined mode
_LM_SE_MIN_STRONG_REASONS  = 2      # minimum strong reasons for refined mode
_LM_SE_CHAT_COOLDOWN_S     = 300    # 5-min cooldown (critical events bypass)
_LM_SE_CRITICAL_MODES      = {"invalidated", "blocked", "refined_internal_entry"}


# ── TASK 4: OB wall → structured dict ────────────────────────────────────────

def _lm_score_orderbook_wall_for_zone(symbol: str, exchange: str, direction: str,
                                       zone_low: float, zone_high: float,
                                       analysis_source: str = None,
                                       ob_da_settings: dict = None,
                                       tf: str = None) -> dict:
    """Return structured OB wall evidence for a zone.

    {available, status, wall_side, wall_price, wall_strength, wall_score, notes,
     approaching, approach_threshold_pct}
    Only _ob_books (Binance) is used; non-Binance falls back to Binance stream.
    zones/SL/TP are never modified by this function.
    ob_da_settings: Phase 10.8 OB distance/approach settings dict keyed by tf.
    tf: candidate timeframe — used to select the correct approach_pct.
    """
    unavail = {
        "available":     False,
        "status":        "unavailable",
        "wall_side":     "none",
        "wall_price":    None,
        "wall_strength": "none",
        "wall_score":    0,
        "notes":         "",
    }
    try:
        # Phase 10.7: non-Binance or aggregated → try Binance fallback for OB stream
        _ob_exchange = exchange if exchange in ("binance", "") else "binance"
        _ob_fallback_note = ""
        if _ob_exchange != exchange and exchange:
            _ob_fallback_note = f" [Binance OB fallback — {exchange} OB not available]"
        if not exchange:  # treat empty as binance
            _ob_exchange = "binance"

        # Attempt to start/wake the OB stream on-demand (non-blocking, wait 0.1 s).
        # start_ob_ws guards against duplicate threads so this is safe to call repeatedly.
        try:
            ensure_ob_stream(symbol, wait_sec=0.1)
        except Exception:
            pass

        with _ob_book_lock:
            book = dict(_ob_books.get(symbol) or {})
        if not book:
            return {**unavail, "notes": "order book not loaded"}
        if not book.get("ready"):
            return {**unavail, "status": "not_connected_yet",
                    "notes": "order book stream initialising"}

        # Freshness
        ob_age = time.time() - book.get("ts", time.time())
        ob_status = "fresh" if ob_age <= 5 else "stale"

        side_key = "bids" if direction == "bullish" else "asks"
        side     = book.get(side_key) or {}
        if not side:
            return {**unavail, "status": ob_status, "notes": f"no {side_key} data"}

        lo        = zone_low  * (1.0 - 0.001)
        hi        = zone_high * (1.0 + 0.001)
        zone_items = [(float(p), float(q)) for p, q in side.items()
                      if lo <= float(p) <= hi]
        zone_vol  = sum(q for _, q in zone_items)
        total_vol = sum(float(q) for q in side.values()) or 1.0
        share     = zone_vol / total_vol

        # Best single price level inside zone
        if zone_items:
            best_p = max(zone_items, key=lambda x: x[1])[0]
        else:
            best_p = None

        if share >= 0.15:   wall_score, wall_str = 90, "strong"
        elif share >= 0.08: wall_score, wall_str = 70, "strong"
        elif share >= 0.04: wall_score, wall_str = 50, "medium"
        elif share >= 0.015: wall_score, wall_str = 30, "medium"
        elif zone_vol > 0:  wall_score, wall_str = 10, "none"
        else:               wall_score, wall_str = 0,  "none"

        notes = (f"{share*100:.1f}% of total {side_key} depth in zone"
                 if zone_vol > 0 else "no depth in zone")
        if ob_status == "stale":
            notes += " [stale OB — treat as weak evidence]"
        notes += _ob_fallback_note

        # Phase 10.8: determine approach status using TF-specific approach_pct
        _approach_note    = ""
        _approach_pct_out = None
        if ob_da_settings and best_p and zone_high and zone_low:
            _zone_mid = (zone_high + zone_low) / 2.0
            # Use caller-provided tf for TF-specific threshold; fallback chain
            _tf_norm = (tf or "").lower().replace(" ", "")
            _tf_map  = {"5m": "5m", "15m": "15m", "30m": "30m",
                        "1h": "1h", "1hour": "1h", "4h": "4h", "4hour": "4h",
                        "1d": "1d", "1day": "1d"}
            _tf_key  = _tf_map.get(_tf_norm)
            _tf_cfg  = (ob_da_settings.get(_tf_key) or
                        ob_da_settings.get("4h") or  # sensible fallback
                        {}) if _tf_key else (ob_da_settings.get("4h") or {})
            _approach_pct_val = _tf_cfg.get("approach_pct")
            if _approach_pct_val is not None and _zone_mid > 0:
                _approach_pct_out = float(_approach_pct_val)
                _dist_to_best = abs(best_p - _zone_mid) / _zone_mid * 100.0
                if _dist_to_best <= _approach_pct_out:
                    _approach_note = (f" [OB APPROACHING — within {_approach_pct_out}%"
                                      f" approach threshold for {_tf_key or 'default'}]")
                    notes += _approach_note

        return {
            "available":            True,
            "status":               ob_status,
            "wall_side":            side_key[:3],  # "bid" or "ask"
            "wall_price":           round(best_p, 6) if best_p else None,
            "wall_strength":        wall_str,
            "wall_score":           wall_score,
            "notes":                notes,
            "approaching":          bool(_approach_note),
            "approach_threshold_pct": _approach_pct_out,
        }
    except Exception as _e:
        return {**unavail, "notes": f"error: {_e}"}


# ── TASK 5: Liquidation → structured dict ────────────────────────────────────

def _lm_score_liquidation_for_zone(symbol: str, exchange: str, direction: str,
                                    zone_low: float, zone_high: float,
                                    data_health=None,
                                    analysis_source: str = None) -> dict:
    """Return structured liquidation evidence for a zone.

    {available, status, near_zone, liq_score, last_liq_price, total_liq_usd_5m, notes}
    Phase 10.7: non-Binance exchange → Binance fallback (only Binance liq stream available).
    zones/SL/TP are never modified by this function.
    """
    unavail = {
        "available":        False,
        "status":           "unavailable",
        "near_zone":        False,
        "liq_score":        0,
        "last_liq_price":   None,
        "total_liq_usd_5m": 0,
        "notes":            "",
    }
    try:
        # Phase 10.7: only Binance has real-time liq stream — use as fallback
        _liq_exchange  = "binance"
        _liq_fallback  = exchange and exchange != "binance"
        liq_data, liq_status = _lm_liq_get(_liq_exchange, symbol)
        if not liq_data:
            return {**unavail, "notes": "no liquidation data"}
        if liq_status not in ("fresh", "stale"):
            return {**unavail, "status": liq_status, "notes": "liq feed unavailable"}

        total_liq = float(liq_data.get("total_liq_usd_5m") or 0)
        last_liq_price = liq_data.get("last_liq_price")
        last_liq_side  = liq_data.get("last_liq_side") or ""

        # Near-zone check when price info is available
        near_zone = False
        if last_liq_price and zone_low and zone_high:
            lp = float(last_liq_price)
            band = (zone_high - zone_low) * 1.5   # 1.5× zone width tolerance
            near_zone = (zone_low - band) <= lp <= (zone_high + band)

        if total_liq < 10_000:
            return {
                "available": True, "status": liq_status, "near_zone": near_zone,
                "liq_score": 0, "last_liq_price": last_liq_price,
                "total_liq_usd_5m": total_liq,
                "notes": "total liq < $10k — noise level",
            }

        supporting = (float(liq_data.get("short_liq_usd_5m") or 0)
                      if direction == "bullish"
                      else float(liq_data.get("long_liq_usd_5m") or 0))
        ratio = supporting / max(total_liq, 1)

        # Bonus for near-zone liq
        near_bonus = 10 if near_zone else 0

        if supporting >= 500_000 and ratio >= 0.6:   liq_score = min(85 + near_bonus, 100)
        elif supporting >= 100_000 and ratio >= 0.5: liq_score = min(65 + near_bonus, 100)
        elif supporting >= 30_000  and ratio >= 0.4: liq_score = min(45 + near_bonus, 85)
        elif supporting >= 10_000:                    liq_score = min(25 + near_bonus, 60)
        else:                                         liq_score = near_bonus

        dir_side = "short" if direction == "bullish" else "long"
        notes = (f"${supporting:,.0f} {dir_side} liq 5m ({ratio*100:.0f}% of total)"
                 + (" [near zone]" if near_zone else ""))
        if liq_status == "stale":
            notes += " [stale feed]"
        if _liq_fallback:
            notes += f" [Binance liq fallback — {exchange} liq not available]"

        return {
            "available":        True,
            "status":           liq_status,
            "near_zone":        near_zone,
            "liq_score":        liq_score,
            "last_liq_price":   last_liq_price,
            "total_liq_usd_5m": round(total_liq, 0),
            "notes":            notes,
        }
    except Exception as _e:
        return {**unavail, "notes": f"error: {_e}"}


# ── TASK 6: Flow → structured dict ───────────────────────────────────────────

def _lm_score_flow_context_for_candidate(symbol: str, exchange: str,
                                          direction: str, data_health=None,
                                          analysis_source: str = None) -> dict:
    """Return structured flow evidence.

    {delta_score, oi_score, funding_score, flow_label, notes}
    Uses _lm_delta_get for live delta; Data Health rows for OI/funding/L-S.
    """
    result = {
        "delta_score":   0,
        "oi_score":      0,
        "funding_score": 0,
        "flow_label":    "unavailable",
        "notes":         [],
    }
    try:
        # ── Live delta — Phase 10.7: only Binance has aggTrade delta stream ──
        _delta_exchange = "binance"  # always use Binance for delta; other exchanges unavailable
        _delta_fallback = exchange and exchange not in ("binance", "")
        delta_data, delta_status = _lm_delta_get(_delta_exchange, symbol)
        if delta_data and delta_status in ("fresh", "stale"):
            dpct  = float(delta_data.get("delta_pct_60s") or 0.0)
            dpct5 = float(delta_data.get("delta_pct_5m")  or 0.0)

            if direction == "bullish":
                al60, al5m, mag = dpct > 0, dpct5 > 0, dpct
            else:
                al60, al5m, mag = dpct < 0, dpct5 < 0, -dpct

            if abs(mag) >= 20 and al60 and al5m: delta_s = 80
            elif abs(mag) >= 10 and al60 and al5m: delta_s = 60
            elif abs(mag) >= 5  and al60:           delta_s = 40
            elif al60:                               delta_s = 20
            else:                                    delta_s = 0

            result["delta_score"] = delta_s
            lbl = "aligned" if al60 else "opposed"
            _dfb = f" [Binance delta fallback — {exchange} delta not available]" if _delta_fallback else ""
            result["notes"].append(
                f"delta {dpct:+.1f}% (60s) / {dpct5:+.1f}% (5m) [{lbl}]"
                + (" [stale]" if delta_status == "stale" else "")
                + _dfb
            )
        else:
            result["notes"].append("delta unavailable")

        # ── Data Health rows: OI, Funding, L/S (interval/REST — context only) ─
        dh_rows = (data_health or {}).get("rows") or []
        # Phase 10.7 Task 8: include fallback_fresh/partial as usable context statuses
        _dh_ctx_statuses    = {"fresh", "interval", "partial", "fallback_fresh"}
        _dh_strong_statuses = {"fresh", "fallback_fresh"}
        for row_dh in dh_rows:
            # Phase 10.7 fix: health rows use "metric" key, not "label"
            label  = row_dh.get("metric") or row_dh.get("label") or ""
            val    = row_dh.get("value") or ""
            status = row_dh.get("status") or ""

            if label == "Open Interest" and status in _dh_ctx_statuses:
                _fb_note = " [fallback]" if status == "fallback_fresh" else " [interval/REST — context]"
                result["notes"].append(f"OI: {val}{_fb_note}")
                result["oi_score"] = 10  # context only, not strong signal

            elif label == "Funding Rate" and status in _dh_ctx_statuses:
                # Funding interpretation: negative = longs pay shorts (bearish pressure)
                _fr_strength = 15 if status in _dh_strong_statuses else 8
                try:
                    fr = float(str(val).replace("%", "").strip())
                    if direction == "bullish" and fr < -0.005:
                        result["funding_score"] = _fr_strength
                        result["notes"].append(f"Funding {fr:+.4f}% — negative favours longs"
                                               + (" [fallback]" if status == "fallback_fresh" else ""))
                    elif direction == "bearish" and fr > 0.005:
                        result["funding_score"] = _fr_strength
                        result["notes"].append(f"Funding {fr:+.4f}% — positive favours shorts"
                                               + (" [fallback]" if status == "fallback_fresh" else ""))
                    else:
                        result["notes"].append(f"Funding {fr:+.4f}% — neutral")
                except Exception:
                    result["notes"].append(f"Funding: {val} [parse error]")

            elif label in ("Long/Short Ratio", "L/S Ratio") and status in _dh_ctx_statuses:
                result["notes"].append(f"L/S ratio: {val} [interval — context only]")

        # ── Overall flow_label ───────────────────────────────────────────────
        total = result["delta_score"] + result["oi_score"] + result["funding_score"]
        if total >= 60:    result["flow_label"] = "supports"
        elif total >= 25:  result["flow_label"] = "neutral"
        elif total == 0 and not delta_data:
            result["flow_label"] = "unavailable"
        else:
            result["flow_label"] = "contradicts" if result["delta_score"] == 0 else "neutral"

    except Exception as _e:
        result["notes"].append(f"flow error: {_e}")
        result["flow_label"] = "unavailable"

    return result


# ── TASK 3: Candle-close invalidation helper ──────────────────────────────────

def _lm_check_candle_close_invalidation(direction: str, zone_high: float,
                                          zone_low: float, snapshot: dict) -> dict:
    """Check candle-close based invalidation. Returns {invalidated, reason, close_price, notes}.

    Rules:
      - Bullish: close BELOW zone_low → invalidated.
      - Bearish: close ABOVE zone_high → invalidated.
      - Wick/live price alone does NOT invalidate.
      - If candle data is unavailable: not invalidated but warning added.
    """
    result = {
        "invalidated": False,
        "reason":      None,
        "close_price": None,
        "notes":       [],
    }
    try:
        cf_block  = snapshot.get("latest_candle_features") or {}
        features  = cf_block.get("features") or {}
        last_close = features.get("last_close")

        if last_close is None:
            result["notes"].append("candle close confirmation unavailable")
            return result

        result["close_price"] = float(last_close)
        lc = float(last_close)

        if direction == "bullish" and lc < zone_low:
            result["invalidated"] = True
            result["reason"]      = (f"candle_close_below_zone_low: "
                                     f"close {lc:.4f} < zone_low {zone_low:.4f}")
        elif direction == "bearish" and lc > zone_high:
            result["invalidated"] = True
            result["reason"]      = (f"candle_close_above_zone_high: "
                                     f"close {lc:.4f} > zone_high {zone_high:.4f}")
        else:
            result["notes"].append(
                f"close {lc:.4f} within zone [{zone_low:.4f} – {zone_high:.4f}]")

    except Exception as _e:
        result["notes"].append(f"invalidation check error: {_e}")

    return result


# ── Candidate extractor ───────────────────────────────────────────────────────

def _lm_extract_refinement_candidates(item, snapshot: dict,
                                       scan_result=None,
                                       ob_da_settings: dict = None,
                                       current_price: float = 0.0) -> list:
    """Extract lower-TF OBs/FIBs overlapping/near the parent zone.

    Only extracts when scan_result is provided (requires raw TF data).
    Returns up to 5 candidates ordered by quality desc.

    ob_da_settings: Phase 10.8 distance/approach settings dict {tf: {distance_pct, approach_pct}}.
    current_price:  Live price for computing distance_pct_live.
    Candidates where live distance > distance_pct[tf] are excluded (marked far).
    """
    zone_high = getattr(item, "zone_high", None)
    zone_low  = getattr(item, "zone_low",  None)
    direction = _lm_direction_from_item(item)
    parent_tf = (getattr(item, "timeframe", None) or "4h").lower()

    if not zone_high or not zone_low or zone_high <= zone_low:
        return []
    if not scan_result or not isinstance(scan_result, dict):
        return []

    raw_tfs   = scan_result.get("tfs") or {}
    child_tfs = _LM_SE_TF_CHILDREN.get(parent_tf, [])
    if not child_tfs:
        return []

    zone_range = zone_high - zone_low
    mid        = (zone_high + zone_low) / 2.0
    tol_abs    = mid * _LM_SE_ZONE_TOLERANCE_PCT / 100.0
    search_lo  = zone_low  - tol_abs
    search_hi  = zone_high + tol_abs

    cands: list = []

    for tf in child_tfs:
        tf_data = raw_tfs.get(tf) or {}
        if not tf_data or tf_data.get("error"):
            continue

        # ── OBs ──────────────────────────────────────────────────────────────
        for ob in (tf_data.get("obs") or []):
            ob_top = ob.get("top") or 0
            ob_bot = ob.get("bottom") or 0
            if ob_top <= 0 or ob_bot <= 0 or ob_top <= ob_bot:
                continue
            ob_dir = (ob.get("direction") or "").lower()
            if direction == "bullish" and ob_dir == "bearish":
                continue
            if direction == "bearish" and ob_dir == "bullish":
                continue
            if ob_top < search_lo or ob_bot > search_hi:
                continue
            ob_mid = (ob_top + ob_bot) / 2.0
            ov_lo  = max(ob_bot, zone_low)
            ov_hi  = min(ob_top, zone_high)
            ov_pct = (ov_hi - ov_lo) / zone_range * 100 if ov_hi > ov_lo else 0.0
            quality = int(ob.get("quality") or 0)
            qlabel  = (ob.get("qualityLabel") or
                       ("Elite" if quality >= 85 else
                        "High"  if quality >= 70 else
                        "Medium" if quality >= 50 else "Weak"))
            cands.append({
                "type":          "ob",
                "tf":            tf,
                "direction":     ob_dir or direction,
                "zone_high":     ob_top,
                "zone_low":      ob_bot,
                "mid_price":     round(ob_mid, 8),
                "quality":       quality,
                "quality_label": qlabel,
                "touches":       int(ob.get("touches") or 0),
                "dist":          float(ob.get("dist") or 0),
                "overlap_pct":   round(ov_pct, 1),
                "absorption":    bool(ob.get("absorption", False)),
                "state":         ob.get("state") or "unknown",
                "fib_level":     None,
            })

        # ── FIBs ─────────────────────────────────────────────────────────────
        for fib in (tf_data.get("fibs") or []):
            fp = fib.get("price") or 0
            if fp <= 0 or not (search_lo <= fp <= search_hi):
                continue
            band    = fp * 0.0005
            fib_top = fp + band
            fib_bot = fp - band
            ov_lo   = max(fib_bot, zone_low)
            ov_hi   = min(fib_top, zone_high)
            ov_pct  = (ov_hi - ov_lo) / zone_range * 100 if ov_hi > ov_lo else 0.0
            flvl    = str(fib.get("level") or "")
            fq_map  = {"0.786": 85, "0.705": 80, "0.618": 75, "0.5": 65, "0.382": 55}
            fq      = fq_map.get(flvl, 60)
            cands.append({
                "type":          "fib",
                "tf":            tf,
                "direction":     direction,
                "zone_high":     round(fib_top, 8),
                "zone_low":      round(fib_bot, 8),
                "mid_price":     round(fp, 8),
                "quality":       fq,
                "quality_label": "High" if fq >= 75 else "Medium",
                "touches":       0,
                "dist":          float(fib.get("dist") or 0),
                "overlap_pct":   round(ov_pct, 1),
                "absorption":    False,
                "state":         "fib",
                "fib_level":     flvl,
            })

    # ── Phase 10.8 Task 2: annotate and filter by distance_pct ──────────────
    _tf_norm_map = {"5m": "5m", "15m": "15m", "30m": "30m",
                    "1h": "1h", "1hour": "1h", "4h": "4h", "4hour": "4h",
                    "1d": "1d", "1day": "1d"}
    _price = float(current_price or 0)
    filtered: list = []
    for c in cands:
        c_tf      = (c.get("tf") or "").lower().strip()
        c_tf_key  = _tf_norm_map.get(c_tf)
        da_cfg    = (ob_da_settings or {}).get(c_tf_key, {}) if c_tf_key else {}
        dist_thr  = float(da_cfg.get("distance_pct") or 999.0)
        appr_thr  = float(da_cfg.get("approach_pct") or 999.0)

        # Compute live distance from current price to candidate mid
        c_mid     = float(c.get("mid_price") or 0)
        if _price > 0 and c_mid > 0:
            live_dist = abs(_price - c_mid) / _price * 100.0
        else:
            live_dist = float(c.get("dist") or 0)

        within_d  = (live_dist <= dist_thr)
        approaching = (live_dist <= appr_thr) and within_d

        # Annotate candidate with Phase 10.8 distance fields
        c["distance_pct_live"]       = round(live_dist, 4)
        c["distance_threshold_pct"]  = dist_thr if da_cfg else None
        c["approach_threshold_pct"]  = appr_thr if da_cfg else None
        c["within_distance"]         = within_d
        c["approaching"]             = approaching

        # Filter: exclude candidates beyond distance threshold (only when settings provided)
        if ob_da_settings and c_tf_key and not within_d:
            continue  # too far — not relevant for this TF's threshold
        filtered.append(c)

    cands = filtered
    cands.sort(key=lambda c: (-c["quality"], abs(c["mid_price"] - mid)))
    return cands[:5]


# ── TASK 7: Candidate scorer with evidence dict ───────────────────────────────

def _lm_score_refinement_candidate(candidate: dict, parent_setup: dict,
                                   live_context: dict) -> dict:
    """Score one refinement candidate 0-100 with structured evidence.

    Returns {score, reasons, strong_reasons, reason_summary, evidence, decision_label}.
    Components: overlap(25) + quality(20) + touches(15) + distance(15)
                + ob_wall(10) + liquidations(10) + flow(5) = 100 max.
    """
    sym             = live_context.get("symbol", "")
    exchange        = live_context.get("exchange", "binance")
    analysis_source = live_context.get("analysis_source", exchange)
    direction       = candidate.get("direction") or parent_setup.get("direction", "bullish")
    score     = 0
    reasons: list        = []
    strong_reasons: list = []

    # 1. Parent overlap (0-25)
    overlap = float(candidate.get("overlap_pct") or 0)
    if overlap >= 50:
        score += 25; strong_reasons.append("deep_parent_overlap")
        reasons.append(f"deep parent overlap ({overlap:.0f}%)")
    elif overlap >= 20:
        score += 18; reasons.append(f"good parent overlap ({overlap:.0f}%)")
    elif overlap >= 5:
        score += 10; reasons.append(f"partial parent overlap ({overlap:.0f}%)")
    else:
        score += 5;  reasons.append("near parent zone")

    # 2. Structural quality (0-20)
    quality = int(candidate.get("quality") or 0)
    ctype   = (candidate.get("type") or "OB").upper()
    if quality >= 85:
        score += 20; strong_reasons.append("elite_quality")
        reasons.append(f"elite quality {ctype}")
    elif quality >= 70:
        score += 15; strong_reasons.append("high_quality")
        reasons.append(f"high quality {ctype}")
    elif quality >= 50:
        score += 8;  reasons.append(f"medium quality {ctype}")
    else:
        score += 2;  reasons.append(f"weak quality {ctype}")

    # 3. Touches and absorption (0-15)
    touches    = int(candidate.get("touches") or 0)
    absorption = bool(candidate.get("absorption", False))
    if touches >= 2 and absorption:
        score += 15; strong_reasons.append("touched_and_absorbed")
        reasons.append(f"zone {touches}x touched with absorption")
    elif touches >= 2:
        score += 10; reasons.append(f"zone {touches}x touched")
    elif absorption:
        score += 8;  reasons.append("absorption confirmed")
    elif touches == 1:
        score += 5;  reasons.append("zone touched once")

    # 4. Distance to current price (0-15)
    dist = abs(float(candidate.get("dist") or 0))
    if dist <= 0.3:
        score += 15; strong_reasons.append("price_at_zone")
        reasons.append(f"price at zone ({dist:.2f}%)")
    elif dist <= 0.8:
        score += 12; reasons.append(f"price approaching ({dist:.2f}%)")
    elif dist <= 1.5:
        score += 7;  reasons.append(f"price near zone ({dist:.2f}%)")
    elif dist <= 3.0:
        score += 3;  reasons.append(f"price {dist:.2f}% away")

    # 5. OB wall (0-10) — structured evidence
    zl = float(candidate.get("zone_low")  or 0)
    zh = float(candidate.get("zone_high") or 0)
    ob_wall_ev = {"available": False, "wall_score": 0, "wall_strength": "none", "notes": ""}
    _cand_tf   = candidate.get("tf", "")
    _ob_da_ctx = live_context.get("ob_distance_approach_settings")
    if sym and zl and zh:
        ob_wall_ev = _lm_score_orderbook_wall_for_zone(
            sym, exchange, direction, zl, zh,
            analysis_source=analysis_source,
            ob_da_settings=_ob_da_ctx,
            tf=_cand_tf)
        wall_s     = ob_wall_ev.get("wall_score", 0)
        # Only use OB wall when it's fresh — stale OB is weak evidence
        if ob_wall_ev.get("status") == "fresh":
            score += round(wall_s / 10)
            if wall_s >= 70:
                strong_reasons.append("strong_ob_wall")
                reasons.append(f"strong OB wall ({ob_wall_ev.get('wall_strength')})")
            elif wall_s >= 40:
                reasons.append(f"moderate OB wall ({ob_wall_ev.get('wall_strength')})")
        elif ob_wall_ev.get("available"):
            # Stale OB — add half weight
            score += round(wall_s / 20)
            reasons.append(f"stale OB wall data ({ob_wall_ev.get('wall_strength')})")

    # 6. Liquidations (0-10) — structured evidence
    liq_ev = {"available": False, "liq_score": 0, "notes": ""}
    if sym:
        liq_ev  = _lm_score_liquidation_for_zone(
            sym, exchange, direction, zl, zh,
            data_health=live_context.get("data_health"),
            analysis_source=analysis_source)
        liq_s   = liq_ev.get("liq_score", 0)
        score  += round(liq_s / 10)
        if liq_s >= 65:
            strong_reasons.append("liquidation_support")
            reasons.append(f"strong liq support (score {liq_s})")
        elif liq_s >= 35:
            reasons.append(f"moderate liq support (score {liq_s})")

    # 7. Taker flow (0-5) — structured evidence
    flow_ev = {"delta_score": 0, "flow_label": "unavailable", "notes": []}
    if sym:
        flow_ev    = _lm_score_flow_context_for_candidate(
            sym, exchange, direction,
            data_health=live_context.get("data_health"),
            analysis_source=analysis_source)
        flow_total = (flow_ev.get("delta_score", 0) +
                      flow_ev.get("oi_score", 0) +
                      flow_ev.get("funding_score", 0))
        score += round(flow_total / 20)
        if flow_ev.get("flow_label") == "supports":
            strong_reasons.append("aligned_flow")
            reasons.append(f"aligned market flow (delta+funding)")
        elif flow_ev.get("flow_label") == "neutral":
            reasons.append("neutral market flow")

    # Candidate summary relative to parent
    parent_zone_high = parent_setup.get("zone_high", zh)
    parent_zone_low  = parent_setup.get("zone_low",  zl)
    if zl >= parent_zone_low and zh <= parent_zone_high:
        relation = "inside_parent"
    elif overlap >= 5:
        relation = "overlaps_parent"
    else:
        relation = "near_parent"

    final_score = min(100, max(0, score))

    if final_score >= 85:   decision_label = "entry_candidate"
    elif final_score >= 70: decision_label = "prepare"
    elif final_score >= 40: decision_label = "watch"
    else:                   decision_label = "wait"

    reason_summary = ("; ".join(reasons[:4]) if reasons else "no strong evidence") + "."

    return {
        "score":          final_score,
        "reasons":        reasons,
        "strong_reasons": list(dict.fromkeys(strong_reasons)),
        "reason_summary": reason_summary,
        "relation_to_parent": relation,
        "decision_label": decision_label,
        "evidence": {
            "orderbook":    ob_wall_ev,
            "liquidations": liq_ev,
            "flow":         flow_ev,
        },
    }


# ── Phase 10.9A: Bias Shift Router helpers ───────────────────────────────────

def _lm_is_bias_shift_item(row) -> bool:
    """Return True when item was added from the Bias Shift scanner tab."""
    src = (getattr(row, "source_tab", None) or "").strip().lower()
    if src in ("bias_shift", "bias"):
        return True
    try:
        snap = _json_loads_safe(getattr(row, "snapshot_json", None), {})
        if snap.get("setup_category") == "bias_shift_watch":
            return True
        if (snap.get("addedFrom") or "").strip().lower() in ("bias_shift", "bias"):
            return True
    except Exception:
        pass
    return False


def _lm_setup_category(row) -> str:
    """Return canonical setup_category for a LiveMonitorItem.

    Canonical values:
      "bias_shift_watch" — item added from Bias Shift tab
      "ob_fib_setup"     — standard OB/FVG/FIB scanner item
      "generic_watch"    — manual-add or unknown origin

    Note: "ob_fib_watch" is the previous value; both are accepted by
    _lm_is_bias_shift_item checks so nothing breaks.
    """
    if _lm_is_bias_shift_item(row):
        return "bias_shift_watch"
    src = (getattr(row, "source_tab", None) or "").strip().lower()
    if src in ("manual", "unknown", ""):
        return "generic_watch"
    return "ob_fib_setup"


# ── Phase 10.9B: Bias Shift MTF Candle Fetch + Storage ───────────────────────

# Standard TF stack for Bias Shift Watch items
_LM_BIAS_TF_STACK_CONST = ["1d", "4h", "1h", "30m", "15m", "5m"]

# Milliseconds per TF (for close_time computation)
_LM_TF_MS = {
    "1m":  60_000,      "3m":  180_000,    "5m":  300_000,
    "15m": 900_000,     "30m": 1_800_000,  "1h":  3_600_000,
    "2h":  7_200_000,   "4h":  14_400_000, "6h":  21_600_000,
    "12h": 43_200_000,  "1d":  86_400_000,
}

# Freshness windows per TF (seconds before a re-fetch is allowed)
_LM_CANDLE_FRESHNESS_S = {
    "1d": 14_400, "4h": 7_200, "1h": 3_600,
    "30m": 1_800, "15m": 900,  "5m": 300,
}

# Background thread tracker: item_id → thread (prevents parallel over-fetches)
_lm_bias_candle_threads: dict = {}
_lm_bias_candle_thread_lock = threading.Lock()


def _lm_bias_tf_stack() -> list:
    """Return the canonical MTF TF stack for Bias Shift Watch items."""
    return list(_LM_BIAS_TF_STACK_CONST)


def _lm_bias_candle_limit() -> int:
    """Return target candle count per TF. Override via ZYNI_BIAS_CANDLE_LIMIT. Clamp 300–2000."""
    try:
        v = int(os.environ.get("ZYNI_BIAS_CANDLE_LIMIT", "1500"))
    except (TypeError, ValueError):
        v = 1500
    return max(300, min(v, 2000))


# ── Task 3: Public candle fetch adapter ──────────────────────────────────────

def _lm_fetch_bybit_klines_paged(symbol: str, interval: str,
                                  limit: int = 1500,
                                  market: str = "perpetual") -> list:
    """Fetch Bybit perpetual klines with pagination (200/page → up to 1500).

    Returns list of dicts: {open_time, open, high, low, close, volume, close_time}.
    Returns [] on error. No API key. No order logic.
    """
    iv = INTERVAL_MAP["bybit"].get(interval)
    if not iv:
        return []
    category = "linear" if market == "perpetual" else "spot"
    url = f"{BYBIT_PERP_API}/kline"
    iv_ms = _LM_TF_MS.get(interval, 0)
    all_candles: list = []
    end_time = None
    max_pages = min((limit // 200) + 3, 12)   # cap at 12 pages (~2400 candles max)

    try:
        for _ in range(max_pages):
            if len(all_candles) >= limit:
                break
            batch_size = min(limit - len(all_candles), 200)
            params: dict = {
                "category": category, "symbol": symbol,
                "interval": iv,       "limit": batch_size,
            }
            if end_time is not None:
                params["end"] = end_time
            resp = req.get(url, params=params, timeout=10)
            if resp.status_code != 200:
                break
            data = resp.json().get("result", {}).get("list", [])
            if not data:
                break
            batch = []
            for k in data:
                try:
                    ot = int(k[0])
                    batch.append({
                        "open_time":  ot,
                        "open":       float(k[1]),
                        "high":       float(k[2]),
                        "low":        float(k[3]),
                        "close":      float(k[4]),
                        "volume":     float(k[5]),
                        "close_time": ot + iv_ms - 1 if iv_ms else ot,
                    })
                except (IndexError, TypeError, ValueError):
                    pass
            # Bybit returns newest-first; reverse to ascending
            batch.reverse()
            # Prepend (batch is older than what we have so far)
            all_candles = batch + all_candles
            if len(data) < batch_size:
                break
            # data[-1] is oldest (newest-first list) — move end backwards
            end_time = int(data[-1][0]) - 1
            if end_time <= 0:
                break
            time.sleep(0.15)   # soft rate-limit guard

        # Deduplicate by open_time
        seen: dict = {}
        for c in all_candles:
            seen[c["open_time"]] = c
        result = sorted(seen.values(), key=lambda x: x["open_time"])
        return result[-limit:] if len(result) > limit else result
    except Exception:
        return []


def _lm_fetch_okx_klines_paged(symbol: str, interval: str,
                                limit: int = 1500,
                                market: str = "perpetual") -> list:
    """Fetch OKX perpetual klines with pagination (300/page → up to 1500).

    Uses /market/history-candles for wider history availability.
    Returns list of dicts: {open_time, open, high, low, close, volume, close_time}.
    Returns [] on error. No API key. No order logic.
    """
    iv = INTERVAL_MAP["okx"].get(interval)
    if not iv:
        return []
    # OKX instId: BTCUSDT → BTC-USDT-SWAP (perpetual) or BTC-USDT (spot)
    base = symbol.replace("USDT", "")
    inst_id = f"{base}-USDT-SWAP" if market == "perpetual" else f"{base}-USDT"
    iv_ms = _LM_TF_MS.get(interval, 0)
    # Use history-candles for deeper history
    hist_url = "https://www.okx.com/api/v5/market/history-candles"
    all_candles: list = []
    after_ts = None     # pagination cursor (exclusive end bound → older data)
    max_pages = min((limit // 300) + 3, 8)

    try:
        for _ in range(max_pages):
            if len(all_candles) >= limit:
                break
            batch_size = min(limit - len(all_candles), 300)
            params: dict = {"instId": inst_id, "bar": iv, "limit": batch_size}
            if after_ts is not None:
                params["after"] = str(after_ts)   # OKX: after=ts gets data older than ts
            resp = req.get(hist_url, params=params, timeout=12)
            if resp.status_code != 200:
                break
            data = resp.json().get("data", [])
            if not data:
                break
            batch = []
            for k in data:
                try:
                    ot = int(k[0])
                    batch.append({
                        "open_time":  ot,
                        "open":       float(k[1]),
                        "high":       float(k[2]),
                        "low":        float(k[3]),
                        "close":      float(k[4]),
                        "volume":     float(k[5]),
                        "close_time": ot + iv_ms - 1 if iv_ms else ot,
                    })
                except (IndexError, TypeError, ValueError):
                    pass
            # OKX returns newest-first; reverse to ascending for prepend
            batch.reverse()
            all_candles = batch + all_candles
            if len(data) < batch_size:
                break
            # data[-1] is oldest (newest-first); use its ts as next after cursor
            after_ts = int(data[-1][0])
            if after_ts <= 0:
                break
            time.sleep(0.15)

        seen: dict = {}
        for c in all_candles:
            seen[c["open_time"]] = c
        result = sorted(seen.values(), key=lambda x: x["open_time"])
        return result[-limit:] if len(result) > limit else result
    except Exception:
        return []


def _lm_fetch_public_klines(exchange: str, symbol: str, timeframe: str,
                             limit: int = 1500,
                             market: str = "perpetual") -> list:
    """Fetch candles from public endpoint for the given exchange.

    Normalises to: {open_time, open, high, low, close, volume, close_time}.
    Does NOT fall back to another exchange — caller sees empty list and marks
    that TF unavailable.
    No API key. No order logic. No S/R flip. No candle pattern engine.
    """
    if timeframe not in _LM_ALLOWED_CANDLE_INTERVALS:
        return []
    ex = (exchange or "binance").lower()
    sym = symbol.upper()
    lim = max(1, min(limit, 2000))

    if ex == "binance":
        return _lm_fetch_futures_candles(sym, timeframe, limit=lim)
    if ex == "mexc":
        return _lm_fetch_mexc_perp_candles(sym, timeframe, limit=lim)
    if ex == "bybit":
        return _lm_fetch_bybit_klines_paged(sym, timeframe, limit=lim, market=market)
    if ex == "okx":
        return _lm_fetch_okx_klines_paged(sym, timeframe, limit=lim, market=market)
    # Unknown exchange — return empty, caller marks unavailable
    return []


# ── Task 4: Candle store write / read helpers ─────────────────────────────────

def _lm_store_candles(user_id: int, exchange: str, market: str,
                       symbol: str, timeframe: str, candles: list) -> int:
    """Upsert candle rows for one TF. Returns count of rows stored.

    Uses PostgreSQL INSERT ... ON CONFLICT DO UPDATE (upsert) — safe to call
    repeatedly; duplicate open_times are silently merged. No trading logic.
    """
    if not candles:
        return 0
    from models import db as _db, LiveMonitorCandle as _LMC
    from sqlalchemy.dialects.postgresql import insert as _pg_insert
    from datetime import datetime as _dt, timezone as _tz
    now = _dt.now(_tz.utc)
    rows = []
    for c in candles:
        ot = c.get("open_time")
        if ot is None:
            continue
        rows.append({
            "user_id":   user_id,
            "exchange":  exchange.lower(),
            "market":    market.lower(),
            "symbol":    symbol.upper(),
            "timeframe": timeframe,
            "open_time": int(ot),
            "open":      float(c.get("open",  0) or 0),
            "high":      float(c.get("high",  0) or 0),
            "low":       float(c.get("low",   0) or 0),
            "close":     float(c.get("close", 0) or 0),
            "volume":    float(c.get("volume", 0) or 0) if c.get("volume") is not None else None,
            "close_time":int(c["close_time"]) if c.get("close_time") is not None else None,
            "quote_volume":   None,
            "trade_count":    None,
            "taker_buy_base": None,
            "taker_buy_quote":None,
            "raw_json":  None,
            "created_at":now,
            "updated_at":now,
        })
    if not rows:
        return 0
    try:
        stmt = _pg_insert(_LMC).values(rows)
        stmt = stmt.on_conflict_do_update(
            constraint="uq_lm_candle_key",
            set_={
                "open":       stmt.excluded.open,
                "high":       stmt.excluded.high,
                "low":        stmt.excluded.low,
                "close":      stmt.excluded.close,
                "volume":     stmt.excluded.volume,
                "close_time": stmt.excluded.close_time,
                "updated_at": stmt.excluded.updated_at,
            },
        )
        _db.session.execute(stmt)
        _db.session.commit()
        return len(rows)
    except Exception as exc:
        _db.session.rollback()
        print(f"[10.9B] _lm_store_candles error ({symbol}/{timeframe}): {exc}")
        return 0


def _lm_get_stored_candles(user_id: int, exchange: str, market: str,
                            symbol: str, timeframe: str,
                            limit: int = 1500) -> list:
    """Return stored candles as list of dicts (ascending open_time), up to limit."""
    from models import LiveMonitorCandle as _LMC
    try:
        rows = (_LMC.query
                .filter_by(user_id=user_id, exchange=exchange.lower(),
                           market=market.lower(), symbol=symbol.upper(),
                           timeframe=timeframe)
                .order_by(_LMC.open_time.asc())
                .limit(limit)
                .all())
        return [
            {
                "open_time":  r.open_time,
                "open":       r.open,
                "high":       r.high,
                "low":        r.low,
                "close":      r.close,
                "volume":     r.volume,
                "close_time": r.close_time,
            }
            for r in rows
        ]
    except Exception:
        return []


def _lm_get_candle_store_status(user_id: int, exchange: str,
                                 market: str, symbol: str) -> dict:
    """Return candle store status dict for all TFs for this user/symbol.

    Returns: {tf: {"count": N, "last_open_time": ms, "first_open_time": ms}}
    """
    from models import LiveMonitorCandle as _LMC
    from sqlalchemy import func as _func
    result: dict = {}
    try:
        for tf in _LM_BIAS_TF_STACK_CONST:
            row = (_LMC.query
                   .filter_by(user_id=user_id, exchange=exchange.lower(),
                              market=market.lower(), symbol=symbol.upper(),
                              timeframe=tf)
                   .with_entities(
                       _func.count(_LMC.id).label("cnt"),
                       _func.min(_LMC.open_time).label("first_ot"),
                       _func.max(_LMC.open_time).label("last_ot"),
                   )
                   .one())
            result[tf] = {
                "count":           int(row.cnt or 0),
                "first_open_time": int(row.first_ot) if row.first_ot else None,
                "last_open_time":  int(row.last_ot)  if row.last_ot  else None,
            }
    except Exception:
        pass
    return result


def _lm_candle_tf_is_fresh(user_id: int, exchange: str, market: str,
                            symbol: str, timeframe: str) -> bool:
    """Return True if the most-recent stored candle is within the freshness window."""
    from models import LiveMonitorCandle as _LMC
    from sqlalchemy import func as _func
    freshness = _LM_CANDLE_FRESHNESS_S.get(timeframe, 900)
    try:
        row = (_LMC.query
               .filter_by(user_id=user_id, exchange=exchange.lower(),
                          market=market.lower(), symbol=symbol.upper(),
                          timeframe=timeframe)
               .with_entities(_func.max(_LMC.updated_at).label("latest_upd"))
               .one())
        if not row.latest_upd:
            return False
        from datetime import datetime as _dt, timezone as _tz
        age = (_dt.now(_tz.utc) - row.latest_upd.replace(tzinfo=_tz.utc)).total_seconds()
        return age < freshness
    except Exception:
        return False


def _lm_build_candle_store_status(user_id: int, exchange: str,
                                   market: str, symbol: str,
                                   target_limit: int = 1500) -> dict:
    """Build the lightweight candle_store status dict for snapshot_json."""
    from datetime import datetime as _dt, timezone as _tz
    tf_status: dict = {}
    raw = _lm_get_candle_store_status(user_id, exchange, market, symbol)
    for tf in _LM_BIAS_TF_STACK_CONST:
        info = raw.get(tf, {})
        cnt = info.get("count", 0)
        last_ot = info.get("last_open_time")
        if cnt == 0:
            st = "unavailable"
        elif cnt >= target_limit * 0.9:
            st = "ready"
        else:
            st = "partial"
        last_iso = None
        if last_ot:
            try:
                last_iso = _dt.utcfromtimestamp(last_ot / 1000).strftime("%Y-%m-%dT%H:%M:%SZ")
            except Exception:
                pass
        tf_status[tf] = {"status": st, "count": cnt, "updated_at": last_iso}

    counts = [v["count"] for v in tf_status.values()]
    all_ready   = all(v["status"] == "ready"       for v in tf_status.values())
    all_zero    = all(v["count"] == 0              for v in tf_status.values())
    any_partial = any(v["status"] == "partial"     for v in tf_status.values())
    if all_zero:
        overall = "initializing"
    elif all_ready:
        overall = "ready"
    elif any_partial or any(v["status"] == "ready" for v in tf_status.values()):
        overall = "partial"
    else:
        overall = "unavailable"

    return {
        "enabled":      True,
        "phase":        "phase10_9b_mtf_candle_storage",
        "tf_stack":     _LM_BIAS_TF_STACK_CONST,
        "target_limit": target_limit,
        "status":       overall,
        "per_tf":       tf_status,
        "computed_at":  _dt.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ"),
    }


def _lm_refresh_bias_candles_for_item(item, force: bool = False) -> dict:
    """Fetch and store MTF candles for one Bias Shift Watch item.

    Only runs for bias_shift items. For non-bias items returns {"skipped": True}.
    Updates snapshot_json.candle_store with lightweight status (no arrays).
    Safe to call in a background thread — uses app.app_context().
    No trading. No private API. No candle pattern engine.
    """
    if not _lm_is_bias_shift_item(item):
        return {"skipped": True, "reason": "not_bias_shift"}

    with app.app_context():
        from models import db as _db, LiveMonitorItem as _LMI
        uid      = getattr(item, "user_id",  None)
        symbol   = (getattr(item, "symbol",   "") or "").upper()
        exchange = (getattr(item, "exchange", "") or "binance").lower()
        market   = (getattr(item, "market",   "") or "perpetual").lower()
        item_id  = getattr(item, "id", None)
        limit    = _lm_bias_candle_limit()

        if not uid or not symbol:
            return {"skipped": True, "reason": "missing_uid_or_symbol"}

        tf_results: dict = {}
        for tf in _LM_BIAS_TF_STACK_CONST:
            # Freshness gate — skip if already fresh and not force
            if not force and _lm_candle_tf_is_fresh(uid, exchange, market, symbol, tf):
                count_info = _lm_get_candle_store_status(uid, exchange, market, symbol).get(tf, {})
                tf_results[tf] = {
                    "status":   "skipped_fresh",
                    "count":    count_info.get("count", 0),
                    "fetched":  0,
                    "stored":   0,
                }
                continue

            candles = _lm_fetch_public_klines(exchange, symbol, tf,
                                               limit=limit, market=market)
            fetched = len(candles)
            stored  = 0
            if candles:
                stored = _lm_store_candles(uid, exchange, market, symbol, tf, candles)

            tf_results[tf] = {
                "status":  "ready" if stored > 0 else ("unavailable" if fetched == 0 else "partial"),
                "fetched": fetched,
                "stored":  stored,
            }
            print(f"[10.9B] {symbol}/{tf} ({exchange}): fetched={fetched} stored={stored}")

        # Build lightweight status and write to snapshot_json
        candle_store_status = _lm_build_candle_store_status(uid, exchange, market, symbol, limit)
        try:
            row = _LMI.query.filter_by(id=item_id).first()
            if row:
                snap = _json_loads_safe(row.snapshot_json, {})
                snap["candle_store"] = candle_store_status
                row.snapshot_json = _json_dumps_safe(snap)
                _db.session.commit()
        except Exception as exc:
            _db.session.rollback()
            print(f"[10.9B] snapshot update error: {exc}")

        # Task 7 (Phase 10.9C): Trigger feature engine after candle refresh.
        # Works even if candle store is partial — feature engine will process
        # whatever TFs have stored candles.
        any_candles = any(
            r.get("status") in ("ready", "skipped_fresh")
            or r.get("fetched", 0) > 0
            for r in tf_results.values()
        )
        if any_candles and item_id:
            try:
                _lm_ensure_bias_features_bg(item_id, uid, exchange, market,
                                             symbol, "bias_shift")
            except Exception as _fe:
                print(f"[10.9C] feature trigger error after candle refresh: {_fe}")

        return {
            "ok":           True,
            "symbol":       symbol,
            "exchange":     exchange,
            "market":       market,
            "candle_store": candle_store_status,
            "per_tf":       tf_results,
        }


def _lm_ensure_bias_candles_bg(item_id: int, uid: int, exchange: str,
                                market: str, symbol: str,
                                source_tab: str, force: bool = False):
    """Start background candle refresh for a Bias Shift item if not already running."""
    if source_tab not in ("bias_shift", "bias"):
        return
    with _lm_bias_candle_thread_lock:
        t = _lm_bias_candle_threads.get(item_id)
        if t and t.is_alive():
            return   # already fetching — don't double-start
    # Build a lightweight proxy object for _lm_refresh_bias_candles_for_item
    class _ItemProxy:
        pass
    proxy = _ItemProxy()
    proxy.id         = item_id
    proxy.user_id    = uid
    proxy.symbol     = symbol
    proxy.exchange   = exchange
    proxy.market     = market
    proxy.source_tab = source_tab
    proxy.snapshot_json = None   # won't be read in _lm_refresh_bias_candles_for_item

    def _run():
        with _lm_bias_candle_thread_lock:
            _lm_bias_candle_threads[item_id] = threading.current_thread()
        try:
            _lm_refresh_bias_candles_for_item(proxy, force=force)
        except Exception as exc:
            print(f"[10.9B] background candle refresh error item={item_id}: {exc}")
        finally:
            with _lm_bias_candle_thread_lock:
                _lm_bias_candle_threads.pop(item_id, None)

    t = threading.Thread(target=_run, daemon=True,
                         name=f"lm-bias-candles-{item_id}")
    with _lm_bias_candle_thread_lock:
        _lm_bias_candle_threads[item_id] = t
    t.start()


# ═══════════════════════════════════════════════════════════════════════════════
# Phase 10.9C — Bias Shift Candle Pattern Feature Engine
# No trading execution. No order placement. No private API. No API keys.
# No BOS/CHoCH engine. No liquidity sweep engine. No order-flow engine.
# No S/R Flip logic. No AI decision engine.
# Only detects and stores candle-level features from already-stored candles.
# ═══════════════════════════════════════════════════════════════════════════════

# ── Task 2: Candle math helpers ───────────────────────────────────────────────

def _lm_candle_range(candle) -> float:
    """high - low; returns 0.0 if zero or invalid."""
    try:
        r = float(candle.get("high", 0)) - float(candle.get("low", 0))
        return max(r, 0.0)
    except (TypeError, ValueError):
        return 0.0


def _lm_candle_body_pct(candle) -> float:
    """abs(close-open)/range*100; 0.0 if range is zero."""
    r = _lm_candle_range(candle)
    if r == 0.0:
        return 0.0
    try:
        return abs(float(candle.get("close", 0)) - float(candle.get("open", 0))) / r * 100.0
    except (TypeError, ValueError):
        return 0.0


def _lm_candle_upper_wick_pct(candle) -> float:
    """upper wick / range * 100; 0.0 if range is zero."""
    r = _lm_candle_range(candle)
    if r == 0.0:
        return 0.0
    try:
        body_top = max(float(candle.get("open", 0)), float(candle.get("close", 0)))
        upper_wick = float(candle.get("high", 0)) - body_top
        return max(upper_wick, 0.0) / r * 100.0
    except (TypeError, ValueError):
        return 0.0


def _lm_candle_lower_wick_pct(candle) -> float:
    """lower wick / range * 100; 0.0 if range is zero."""
    r = _lm_candle_range(candle)
    if r == 0.0:
        return 0.0
    try:
        body_bot = min(float(candle.get("open", 0)), float(candle.get("close", 0)))
        lower_wick = body_bot - float(candle.get("low", 0))
        return max(lower_wick, 0.0) / r * 100.0
    except (TypeError, ValueError):
        return 0.0


def _lm_candle_close_position_pct(candle) -> float:
    """Where close sits inside low-high range. 0=at low, 100=at high."""
    r = _lm_candle_range(candle)
    if r == 0.0:
        return 50.0
    try:
        return (float(candle.get("close", 0)) - float(candle.get("low", 0))) / r * 100.0
    except (TypeError, ValueError):
        return 50.0


def _lm_candle_direction(candle) -> str:
    """bullish / bearish / neutral."""
    try:
        diff = float(candle.get("close", 0)) - float(candle.get("open", 0))
        if diff > 0:
            return "bullish"
        if diff < 0:
            return "bearish"
        return "neutral"
    except (TypeError, ValueError):
        return "neutral"


# ── Task 3: Pattern detector ──────────────────────────────────────────────────

def _lm_detect_candle_patterns(candle: dict,
                                prev_candle: dict = None,
                                recent_context: dict = None) -> dict:
    """Detect candle-level patterns from a single candle.

    Returns a dict with:
      patterns: list[str] — detected pattern names
      evidence: dict      — per-pattern evidence values

    No BOS/CHoCH. No S/R Flip. No liquidity sweep. No AI. No trading.
    """
    if recent_context is None:
        recent_context = {}

    body_pct         = _lm_candle_body_pct(candle)
    upper_wick_pct   = _lm_candle_upper_wick_pct(candle)
    lower_wick_pct   = _lm_candle_lower_wick_pct(candle)
    close_pos_pct    = _lm_candle_close_position_pct(candle)
    direction        = _lm_candle_direction(candle)
    candle_range     = _lm_candle_range(candle)

    avg_range        = recent_context.get("avg_range",  0.0) or 0.0
    avg_volume       = recent_context.get("avg_volume", 0.0) or 0.0
    recent_high      = recent_context.get("recent_high")
    recent_low       = recent_context.get("recent_low")

    try:
        c_high  = float(candle.get("high",  0))
        c_low   = float(candle.get("low",   0))
        c_open  = float(candle.get("open",  0))
        c_close = float(candle.get("close", 0))
        c_vol   = float(candle.get("volume", 0) or 0)
    except (TypeError, ValueError):
        return {"patterns": [], "evidence": {}}

    patterns: list = []
    evidence: dict = {}

    # 1. Bullish rejection
    if (lower_wick_pct >= 45 and
            close_pos_pct >= 60 and
            (direction == "bullish" or close_pos_pct >= 60)):
        patterns.append("bullish_rejection")
        evidence["bullish_rejection"] = {
            "lower_wick_pct": round(lower_wick_pct, 1),
            "close_pos_pct":  round(close_pos_pct,  1),
            "direction":      direction,
        }

    # 2. Bearish rejection
    if (upper_wick_pct >= 45 and
            close_pos_pct <= 40 and
            (direction == "bearish" or close_pos_pct <= 40)):
        patterns.append("bearish_rejection")
        evidence["bearish_rejection"] = {
            "upper_wick_pct": round(upper_wick_pct, 1),
            "close_pos_pct":  round(close_pos_pct,  1),
            "direction":      direction,
        }

    # 3. Pin bar
    long_wick  = max(upper_wick_pct, lower_wick_pct)
    short_wick = min(upper_wick_pct, lower_wick_pct)
    if long_wick >= 55 and body_pct <= 35 and short_wick <= 25:
        patterns.append("pin_bar")
        evidence["pin_bar"] = {
            "long_wick_pct":  round(long_wick,   1),
            "short_wick_pct": round(short_wick,  1),
            "body_pct":       round(body_pct,    1),
        }

    # 4. Bullish engulfing (requires prev_candle)
    if prev_candle is not None and direction == "bullish":
        prev_dir   = _lm_candle_direction(prev_candle)
        try:
            p_open  = float(prev_candle.get("open",  0))
            p_close = float(prev_candle.get("close", 0))
        except (TypeError, ValueError):
            p_open = p_close = 0.0
        if (prev_dir == "bearish" and
                c_close > p_open and
                c_open <= p_close + abs(p_open - p_close) * 0.1):
            patterns.append("bullish_engulfing")
            evidence["bullish_engulfing"] = {
                "prev_open":  round(p_open,  5),
                "prev_close": round(p_close, 5),
                "curr_open":  round(c_open,  5),
                "curr_close": round(c_close, 5),
            }

    # 5. Bearish engulfing (requires prev_candle)
    if prev_candle is not None and direction == "bearish":
        prev_dir = _lm_candle_direction(prev_candle)
        try:
            p_open  = float(prev_candle.get("open",  0))
            p_close = float(prev_candle.get("close", 0))
        except (TypeError, ValueError):
            p_open = p_close = 0.0
        if (prev_dir == "bullish" and
                c_close < p_open and
                c_open >= p_close - abs(p_open - p_close) * 0.1):
            patterns.append("bearish_engulfing")
            evidence["bearish_engulfing"] = {
                "prev_open":  round(p_open,  5),
                "prev_close": round(p_close, 5),
                "curr_open":  round(c_open,  5),
                "curr_close": round(c_close, 5),
            }

    # 6. Displacement candle
    if (body_pct >= 60 and
            avg_range > 0 and
            candle_range > avg_range * 1.3):
        if direction == "bullish" and close_pos_pct >= 70:
            patterns.append("displacement_bullish")
            evidence["displacement_bullish"] = {
                "body_pct":       round(body_pct,       1),
                "range_vs_avg":   round(candle_range / avg_range, 2),
                "close_pos_pct":  round(close_pos_pct,  1),
            }
        elif direction == "bearish" and close_pos_pct <= 30:
            patterns.append("displacement_bearish")
            evidence["displacement_bearish"] = {
                "body_pct":       round(body_pct,       1),
                "range_vs_avg":   round(candle_range / avg_range, 2),
                "close_pos_pct":  round(close_pos_pct,  1),
            }

    # 7. Failed breakout / failed breakdown (candle-level only; no S/R Flip, no BOS/CHoCH)
    if recent_high is not None:
        try:
            rh = float(recent_high)
            if c_high > rh and c_close < rh:
                patterns.append("failed_breakout")
                evidence["failed_breakout"] = {
                    "candle_high":   round(c_high,  5),
                    "recent_high":   round(rh,      5),
                    "candle_close":  round(c_close, 5),
                }
        except (TypeError, ValueError):
            pass
    if recent_low is not None:
        try:
            rl = float(recent_low)
            if c_low < rl and c_close > rl:
                patterns.append("failed_breakdown")
                evidence["failed_breakdown"] = {
                    "candle_low":    round(c_low,   5),
                    "recent_low":    round(rl,      5),
                    "candle_close":  round(c_close, 5),
                }
        except (TypeError, ValueError):
            pass

    # 8. Strong close
    if direction == "bullish" and close_pos_pct >= 75:
        patterns.append("strong_close_bullish")
        evidence["strong_close_bullish"] = {"close_pos_pct": round(close_pos_pct, 1)}
    elif direction == "bearish" and close_pos_pct <= 25:
        patterns.append("strong_close_bearish")
        evidence["strong_close_bearish"] = {"close_pos_pct": round(close_pos_pct, 1)}

    # 9. Weak close
    if direction == "bullish" and close_pos_pct < 55:
        patterns.append("weak_close_bullish")
        evidence["weak_close_bullish"] = {"close_pos_pct": round(close_pos_pct, 1)}
    elif direction == "bearish" and close_pos_pct > 45:
        patterns.append("weak_close_bearish")
        evidence["weak_close_bearish"] = {"close_pos_pct": round(close_pos_pct, 1)}

    # 10. Volume strength
    if avg_volume > 0:
        try:
            if c_vol > avg_volume * 1.5:
                patterns.append("high_volume")
                evidence["high_volume"] = {
                    "volume":     round(c_vol,       2),
                    "avg_volume": round(avg_volume,  2),
                    "ratio":      round(c_vol / avg_volume, 2),
                }
            elif c_vol < avg_volume * 0.7:
                patterns.append("low_volume")
                evidence["low_volume"] = {
                    "volume":     round(c_vol,       2),
                    "avg_volume": round(avg_volume,  2),
                    "ratio":      round(c_vol / avg_volume, 2),
                }
            else:
                patterns.append("normal_volume")
        except (TypeError, ValueError):
            pass

    return {"patterns": patterns, "evidence": evidence}


# ── Task 4: Recent context builder ────────────────────────────────────────────

def _lm_build_candle_recent_context(candles: list, index: int,
                                     lookback: int = 20) -> dict:
    """Build lookback context from candles *before* index.

    Uses only past candles — no lookahead bias.
    Returns safe partial context when not enough history.
    """
    start = max(0, index - lookback)
    past  = candles[start:index]   # excludes current candle at 'index'

    if not past:
        return {
            "avg_range":          None,
            "avg_volume":         None,
            "recent_high":        None,
            "recent_low":         None,
            "previous_candle":    None,
            "recent_candle_count": 0,
        }

    ranges  = []
    volumes = []
    highs   = []
    lows    = []
    for c in past:
        try:
            ranges.append(_lm_candle_range(c))
            h = float(c.get("high", 0))
            l = float(c.get("low",  0))
            highs.append(h)
            lows.append(l)
            v = float(c.get("volume", 0) or 0)
            if v > 0:
                volumes.append(v)
        except (TypeError, ValueError):
            pass

    avg_range  = sum(ranges)  / len(ranges)  if ranges  else None
    avg_volume = sum(volumes) / len(volumes) if volumes else None
    recent_high = max(highs) if highs else None
    recent_low  = min(lows)  if lows  else None

    return {
        "avg_range":           avg_range,
        "avg_volume":          avg_volume,
        "recent_high":         recent_high,
        "recent_low":          recent_low,
        "previous_candle":     past[-1] if past else None,
        "recent_candle_count": len(past),
    }


# ── Task 5: Feature engine processor ─────────────────────────────────────────

def _lm_compute_candle_features_for_tf(user_id: int, exchange: str, market: str,
                                        symbol: str, timeframe: str,
                                        limit: int = 1500) -> dict:
    """Read stored candles, compute features, upsert into LiveMonitorCandleFeature.

    Returns status dict: {status, candles_processed, features_count, error}.
    No external API calls. Reads LiveMonitorCandle rows only.
    """
    from models import db as _db, LiveMonitorCandleFeature as _LMCF
    from sqlalchemy.dialects.postgresql import insert as pg_insert

    try:
        candle_rows = _lm_get_stored_candles(user_id, exchange, market, symbol,
                                              timeframe, limit)
        if not candle_rows:
            return {"status": "unavailable", "candles_processed": 0,
                    "features_count": 0, "timeframe": timeframe}

        # Normalise to plain dicts sorted ascending by open_time
        candles = sorted(
            [
                {
                    "open_time": c.open_time,
                    "open":      c.open,
                    "high":      c.high,
                    "low":       c.low,
                    "close":     c.close,
                    "volume":    c.volume or 0.0,
                }
                for c in candle_rows
            ],
            key=lambda x: x["open_time"],
        )

        upsert_rows = []
        for i, candle in enumerate(candles):
            ctx  = _lm_build_candle_recent_context(candles, i, lookback=20)
            prev = ctx.get("previous_candle")

            body_pct       = _lm_candle_body_pct(candle)
            upper_wick_pct = _lm_candle_upper_wick_pct(candle)
            lower_wick_pct = _lm_candle_lower_wick_pct(candle)
            close_pos_pct  = _lm_candle_close_position_pct(candle)
            direction      = _lm_candle_direction(candle)
            result         = _lm_detect_candle_patterns(candle, prev_candle=prev,
                                                         recent_context=ctx)
            patterns       = result.get("patterns", [])
            evidence       = result.get("evidence", {})

            feature_summary = {
                "body_pct":          round(body_pct,       2),
                "upper_wick_pct":    round(upper_wick_pct, 2),
                "lower_wick_pct":    round(lower_wick_pct, 2),
                "close_pos_pct":     round(close_pos_pct,  2),
                "direction":         direction,
                "candle_range":      round(_lm_candle_range(candle), 8),
                "avg_range_context": round(ctx["avg_range"], 8) if ctx.get("avg_range") else None,
                "patterns":          patterns,
                "evidence":          evidence,
            }

            upsert_rows.append({
                "user_id":              user_id,
                "exchange":             exchange,
                "market":               market,
                "symbol":               symbol,
                "timeframe":            timeframe,
                "open_time":            candle["open_time"],
                "candle_open":          candle["open"],
                "candle_high":          candle["high"],
                "candle_low":           candle["low"],
                "candle_close":         candle["close"],
                "candle_volume":        candle["volume"],
                "body_pct":             round(body_pct,       4),
                "upper_wick_pct":       round(upper_wick_pct, 4),
                "lower_wick_pct":       round(lower_wick_pct, 4),
                "close_position_pct":   round(close_pos_pct,  4),
                "candle_direction":     direction,
                "detected_patterns_json": _json_dumps_safe(patterns),
                "feature_summary_json":   _json_dumps_safe(feature_summary),
            })

        # Batch upsert using PostgreSQL ON CONFLICT DO UPDATE
        if upsert_rows:
            stmt = pg_insert(_LMCF.__table__).values(upsert_rows)
            stmt = stmt.on_conflict_do_update(
                constraint="uq_lm_cfeature_key",
                set_={
                    "candle_open":             stmt.excluded.candle_open,
                    "candle_high":             stmt.excluded.candle_high,
                    "candle_low":              stmt.excluded.candle_low,
                    "candle_close":            stmt.excluded.candle_close,
                    "candle_volume":           stmt.excluded.candle_volume,
                    "body_pct":                stmt.excluded.body_pct,
                    "upper_wick_pct":          stmt.excluded.upper_wick_pct,
                    "lower_wick_pct":          stmt.excluded.lower_wick_pct,
                    "close_position_pct":      stmt.excluded.close_position_pct,
                    "candle_direction":        stmt.excluded.candle_direction,
                    "detected_patterns_json":  stmt.excluded.detected_patterns_json,
                    "feature_summary_json":    stmt.excluded.feature_summary_json,
                    "updated_at":              _db.func.now(),
                },
            )
            _db.session.execute(stmt)
            _db.session.commit()

        features_count = len(upsert_rows)
        return {
            "status":            "ready" if features_count > 0 else "unavailable",
            "candles_processed": len(candles),
            "features_count":    features_count,
            "timeframe":         timeframe,
        }

    except Exception as exc:
        try:
            from models import db as _db2
            _db2.session.rollback()
        except Exception:
            pass
        print(f"[10.9C] feature compute error {symbol}/{timeframe}: {exc}")
        return {"status": "error", "candles_processed": 0,
                "features_count": 0, "timeframe": timeframe, "error": str(exc)}


def _lm_get_latest_feature_summary(user_id: int, exchange: str, market: str,
                                    symbol: str, timeframe: str,
                                    limit: int = 5) -> list:
    """Return the N most recent LiveMonitorCandleFeature rows as plain dicts."""
    from models import LiveMonitorCandleFeature as _LMCF
    try:
        rows = (
            _LMCF.query
            .filter_by(user_id=user_id, exchange=exchange, market=market,
                       symbol=symbol, timeframe=timeframe)
            .order_by(_LMCF.open_time.desc())
            .limit(limit)
            .all()
        )
        result = []
        for r in rows:
            result.append({
                "open_time":   r.open_time,
                "direction":   r.candle_direction,
                "body_pct":    r.body_pct,
                "upper_wick":  r.upper_wick_pct,
                "lower_wick":  r.lower_wick_pct,
                "close_pos":   r.close_position_pct,
                "patterns":    _json_loads_safe(r.detected_patterns_json, []),
                "summary":     _json_loads_safe(r.feature_summary_json, {}),
            })
        return result
    except Exception:
        return []


def _lm_get_feature_count(user_id: int, exchange: str, market: str,
                           symbol: str, timeframe: str) -> int:
    """Return total stored feature row count for one TF."""
    from models import LiveMonitorCandleFeature as _LMCF
    try:
        return _LMCF.query.filter_by(
            user_id=user_id, exchange=exchange, market=market,
            symbol=symbol, timeframe=timeframe
        ).count()
    except Exception:
        return 0


# Task 6 helper: build lightweight feature engine status for snapshot_json
def _lm_build_feature_engine_status(user_id: int, exchange: str, market: str,
                                     symbol: str, per_tf_results: dict) -> dict:
    """Build the lightweight candle_feature_engine status dict for snapshot_json.

    Does NOT store feature arrays — only counts, status, and latest pattern names.
    """
    tf_stack = list(_LM_BIAS_TF_STACK_CONST)
    per_tf_status = {}
    overall_statuses = []

    for tf in tf_stack:
        tf_res = per_tf_results.get(tf, {})
        tf_status = tf_res.get("status", "unavailable")
        overall_statuses.append(tf_status)

        # Latest patterns from most recent 3 feature rows
        latest_rows   = _lm_get_latest_feature_summary(user_id, exchange, market,
                                                         symbol, tf, limit=3)
        latest_pats   = []
        latest_time   = None
        for row in latest_rows:
            latest_pats.extend(row.get("patterns", []))
            if latest_time is None and row.get("open_time"):
                latest_time = row["open_time"]
        # Deduplicate while preserving order
        seen = set()
        deduped = [p for p in latest_pats if not (p in seen or seen.add(p))]

        per_tf_status[tf] = {
            "status":               tf_status,
            "candles_processed":    tf_res.get("candles_processed", 0),
            "features_count":       tf_res.get("features_count",    0),
            "latest_feature_time":  latest_time,
            "latest_patterns":      deduped[:6],
        }

    # Overall status: ready if all ready, partial if some ready, else unavailable
    if all(s == "ready" for s in overall_statuses):
        overall = "ready"
    elif any(s == "ready" for s in overall_statuses):
        overall = "partial"
    elif any(s == "error" for s in overall_statuses):
        overall = "error"
    else:
        overall = "unavailable"

    return {
        "enabled": True,
        "phase":   "phase10_9c_candle_pattern_features",
        "status":  overall,
        "per_tf":  per_tf_status,
    }


# ── Task 5 (cont.): Item-level feature refresh ────────────────────────────────

# Thread registry — prevents parallel over-computation per item
_lm_bias_feature_threads: dict = {}
_lm_bias_feature_thread_lock   = threading.Lock()


def _lm_refresh_bias_candle_features_for_item(item, force: bool = False) -> dict:
    """Compute and store candle pattern features for all TFs of one Bias Shift item.

    Reads stored LiveMonitorCandle rows only — no external API calls.
    Updates snapshot_json.candle_feature_engine with lightweight status only.
    Safe to call from background thread — uses app.app_context().
    No trading. No private API. No BOS/CHoCH. No order-flow.
    """
    if not _lm_is_bias_shift_item(item):
        return {"skipped": True, "reason": "not_bias_shift"}

    with app.app_context():
        from models import db as _db, LiveMonitorItem as _LMI

        uid      = getattr(item, "user_id",  None)
        symbol   = (getattr(item, "symbol",   "") or "").upper()
        exchange = (getattr(item, "exchange", "") or "binance").lower()
        market   = (getattr(item, "market",   "") or "perpetual").lower()
        item_id  = getattr(item, "id", None)

        if not uid or not symbol:
            return {"skipped": True, "reason": "missing_uid_or_symbol"}

        per_tf_results: dict = {}
        for tf in _LM_BIAS_TF_STACK_CONST:
            per_tf_results[tf] = _lm_compute_candle_features_for_tf(
                uid, exchange, market, symbol, tf
            )
            print(f"[10.9C] features {symbol}/{tf} ({exchange}): "
                  f"status={per_tf_results[tf]['status']} "
                  f"count={per_tf_results[tf]['features_count']}")

        # Task 6: build lightweight status and write to snapshot_json
        feature_status = _lm_build_feature_engine_status(
            uid, exchange, market, symbol, per_tf_results
        )
        try:
            row = _LMI.query.filter_by(id=item_id).first()
            if row:
                snap = _json_loads_safe(row.snapshot_json, {})
                snap["candle_feature_engine"] = feature_status
                row.snapshot_json = _json_dumps_safe(snap)
                _db.session.commit()
        except Exception as exc:
            _db.session.rollback()
            print(f"[10.9C] snapshot update error: {exc}")

        # Task 8 (Phase 10.9D): Trigger structure engine after feature engine completes.
        # Works even if some TFs have no features — structure reads raw candles.
        if item_id:
            try:
                _lm_ensure_bias_structure_bg(
                    item_id, uid, exchange, market, symbol,
                    getattr(item, "source_tab", "bias_shift") or "bias_shift"
                )
            except Exception as _se:
                print(f"[10.9D] structure trigger error after feature refresh: {_se}")

        return {
            "ok":                   True,
            "symbol":               symbol,
            "exchange":             exchange,
            "market":               market,
            "candle_feature_engine": feature_status,
            "per_tf":               per_tf_results,
        }


def _lm_ensure_bias_features_bg(item_id: int, uid: int, exchange: str,
                                  market: str, symbol: str,
                                  source_tab: str, force: bool = False):
    """Start background feature computation for a Bias Shift item if not already running."""
    if source_tab not in ("bias_shift", "bias"):
        return
    with _lm_bias_feature_thread_lock:
        t = _lm_bias_feature_threads.get(item_id)
        if t and t.is_alive():
            return   # already running

    class _ItemProxy:
        pass
    proxy = _ItemProxy()
    proxy.id         = item_id
    proxy.user_id    = uid
    proxy.symbol     = symbol
    proxy.exchange   = exchange
    proxy.market     = market
    proxy.source_tab = source_tab
    proxy.snapshot_json = None

    def _run():
        with _lm_bias_feature_thread_lock:
            _lm_bias_feature_threads[item_id] = threading.current_thread()
        try:
            _lm_refresh_bias_candle_features_for_item(proxy, force=force)
        except Exception as exc:
            print(f"[10.9C] background feature error item={item_id}: {exc}")
        finally:
            with _lm_bias_feature_thread_lock:
                _lm_bias_feature_threads.pop(item_id, None)

    t = threading.Thread(target=_run, daemon=True,
                         name=f"lm-bias-features-{item_id}")
    with _lm_bias_feature_thread_lock:
        _lm_bias_feature_threads[item_id] = t
    t.start()


# ═══════════════════════════════════════════════════════════════════════════════
# Phase 10.9D — Bias Shift Structure Context Engine
# CONTEXT ONLY. BOS/CHoCH/sweep are NOT entry signals.
# No trading execution. No order placement. No private API. No API keys.
# No S/R Flip logic. No order-flow alignment. No AI decision engine.
# No Entry Candidate state. No auto-convert to OB/FIB.
# Structure engine reads stored candles only — no external exchange API calls.
# ═══════════════════════════════════════════════════════════════════════════════

# ── Task 2: Structure settings / constants ────────────────────────────────────

_LM_STRUCT_PIVOT_SETTINGS: dict = {
    "1d":  {"left": 3, "right": 3},
    "4h":  {"left": 4, "right": 4},
    "1h":  {"left": 5, "right": 5},
    "30m": {"left": 5, "right": 5},
    "15m": {"left": 5, "right": 5},
    "5m":  {"left": 6, "right": 6},
}

# BOS/CHoCH: candle CLOSE must exceed swing by this % to confirm break.
# Wick-only breaks do NOT count.
_LM_STRUCT_BREAK_THRESHOLD_PCT: dict = {
    "1d":  0.20,
    "4h":  0.15,
    "1h":  0.10,
    "30m": 0.08,
    "15m": 0.06,
    "5m":  0.05,
}

# Sweep: wick must exceed swing by this % AND close must return inside.
_LM_STRUCT_SWEEP_THRESHOLD_PCT: dict = {
    "1d":  0.10,
    "4h":  0.08,
    "1h":  0.06,
    "30m": 0.05,
    "15m": 0.04,
    "5m":  0.03,
}


def _lm_structure_pivot_settings(tf: str) -> dict:
    return _LM_STRUCT_PIVOT_SETTINGS.get(tf, {"left": 5, "right": 5})


def _lm_structure_break_threshold_pct(tf: str) -> float:
    return _LM_STRUCT_BREAK_THRESHOLD_PCT.get(tf, 0.10)


def _lm_structure_sweep_threshold_pct(tf: str) -> float:
    return _LM_STRUCT_SWEEP_THRESHOLD_PCT.get(tf, 0.06)


# ── Task 3: Swing detection helpers ──────────────────────────────────────────

def _lm_is_swing_high(candles: list, index: int, left: int, right: int) -> bool:
    """True if candles[index].high is a confirmed pivot high.

    Requires `left` lower highs before and `right` lower highs after.
    Right-side confirmation is used for historical labelling; the most
    recent `right` candles in the series cannot be confirmed swings.
    """
    if index < left or index + right >= len(candles):
        return False
    pivot = candles[index]["high"]
    for j in range(index - left, index):
        if candles[j]["high"] >= pivot:
            return False
    for j in range(index + 1, index + right + 1):
        if candles[j]["high"] >= pivot:
            return False
    return True


def _lm_is_swing_low(candles: list, index: int, left: int, right: int) -> bool:
    """True if candles[index].low is a confirmed pivot low."""
    if index < left or index + right >= len(candles):
        return False
    pivot = candles[index]["low"]
    for j in range(index - left, index):
        if candles[j]["low"] <= pivot:
            return False
    for j in range(index + 1, index + right + 1):
        if candles[j]["low"] <= pivot:
            return False
    return True


def _lm_find_swing_points(candles: list, left: int = 5, right: int = 5) -> dict:
    """Find all confirmed swing highs and lows in a sorted candle series.

    The `confirmed_at` field is the open_time of the candle that is `right`
    bars after the pivot — i.e., when the swing became confirmed.
    Returns {"swing_highs": [...], "swing_lows": [...]}.
    """
    swing_highs: list = []
    swing_lows:  list = []

    for i in range(len(candles)):
        if _lm_is_swing_high(candles, i, left, right):
            conf_idx = min(i + right, len(candles) - 1)
            swing_highs.append({
                "open_time":    candles[i]["open_time"],
                "confirmed_at": candles[conf_idx]["open_time"],
                "level":        candles[i]["high"],
                "type":         "swing_high",
                "index":        i,
            })
        if _lm_is_swing_low(candles, i, left, right):
            conf_idx = min(i + right, len(candles) - 1)
            swing_lows.append({
                "open_time":    candles[i]["open_time"],
                "confirmed_at": candles[conf_idx]["open_time"],
                "level":        candles[i]["low"],
                "type":         "swing_low",
                "index":        i,
            })

    return {"swing_highs": swing_highs, "swing_lows": swing_lows}


# ── Task 4: BOS / CHoCH detector ─────────────────────────────────────────────

def _lm_detect_structure_events_for_tf(candles: list, timeframe: str,
                                        features=None) -> dict:
    """Detect BOS/CHoCH structure events from a sorted candle series.

    Rules:
    - BOS/CHoCH requires candle CLOSE beyond swing level by break_threshold_pct.
    - Wick-only breaks are NOT BOS/CHoCH.
    - CHoCH occurs when direction flips; BOS when it continues.
    - Once a swing level is broken (consumed), it is not re-used.
    - Avoids generating duplicate events for the same broken level.

    Context only — no entry signals. No S/R flip. No order-flow.
    """
    if not candles or len(candles) < 10:
        return {"events": [], "swings": {"swing_highs": [], "swing_lows": []},
                "structure_direction": "neutral"}

    pivot      = _lm_structure_pivot_settings(timeframe)
    left, right = pivot["left"], pivot["right"]
    break_frac = _lm_structure_break_threshold_pct(timeframe) / 100.0

    swings      = _lm_find_swing_points(candles, left=left, right=right)
    highs_sorted = sorted(swings["swing_highs"], key=lambda x: x["confirmed_at"])
    lows_sorted  = sorted(swings["swing_lows"],  key=lambda x: x["confirmed_at"])

    events: list = []
    structure_direction = "neutral"

    consumed_high_times: set = set()
    consumed_low_times:  set = set()

    h_ptr = 0  # next index into highs_sorted to add to available
    l_ptr = 0
    avail_highs: list = []
    avail_lows:  list = []

    for candle in candles:
        c_time  = candle["open_time"]
        c_close = float(candle.get("close", 0))

        # Advance: include swings confirmed at or before this candle's open_time
        while h_ptr < len(highs_sorted) and highs_sorted[h_ptr]["confirmed_at"] <= c_time:
            avail_highs.append(highs_sorted[h_ptr])
            h_ptr += 1
        while l_ptr < len(lows_sorted) and lows_sorted[l_ptr]["confirmed_at"] <= c_time:
            avail_lows.append(lows_sorted[l_ptr])
            l_ptr += 1

        # --- Bullish break: close above swing high ---
        for sh in reversed(avail_highs[-6:]):
            if sh["open_time"] in consumed_high_times:
                continue
            lvl = sh["level"]
            if lvl <= 0:
                continue
            if c_close >= lvl * (1.0 + break_frac):
                etype = "bullish_choch" if structure_direction == "bearish" else "bullish_bos"
                events.append({
                    "event_time":         c_time,
                    "event_type":         etype,
                    "direction":          "bullish",
                    "level":              lvl,
                    "candle_open_time":   c_time,
                    "confirmation_close": c_close,
                    "swing_left":         left,
                    "swing_right":        right,
                    "threshold_pct":      _lm_structure_break_threshold_pct(timeframe),
                    "context":            "context_only_not_entry_signal",
                })
                consumed_high_times.add(sh["open_time"])
                structure_direction = "bullish"
                break

        # --- Bearish break: close below swing low ---
        for sl in reversed(avail_lows[-6:]):
            if sl["open_time"] in consumed_low_times:
                continue
            lvl = sl["level"]
            if lvl <= 0:
                continue
            if c_close <= lvl * (1.0 - break_frac):
                etype = "bearish_choch" if structure_direction == "bullish" else "bearish_bos"
                events.append({
                    "event_time":         c_time,
                    "event_type":         etype,
                    "direction":          "bearish",
                    "level":              lvl,
                    "candle_open_time":   c_time,
                    "confirmation_close": c_close,
                    "swing_left":         left,
                    "swing_right":        right,
                    "threshold_pct":      _lm_structure_break_threshold_pct(timeframe),
                    "context":            "context_only_not_entry_signal",
                })
                consumed_low_times.add(sl["open_time"])
                structure_direction = "bearish"
                break

    return {
        "events":              events,
        "swings":              swings,
        "structure_direction": structure_direction,
    }


# ── Task 5: Liquidity sweep detector ─────────────────────────────────────────

def _lm_detect_liquidity_sweeps_for_tf(candles: list, timeframe: str,
                                         swings: dict = None) -> list:
    """Detect buy-side / sell-side liquidity sweeps from a sorted candle series.

    Sweep = wick extends beyond swing by sweep_threshold_pct AND close
    returns inside the swing level. This is sweep CONTEXT only:
    - No entry signal.
    - No S/R flip logic.
    - No order-flow alignment.
    """
    if not candles or len(candles) < 10:
        return []

    if swings is None:
        piv    = _lm_structure_pivot_settings(timeframe)
        swings = _lm_find_swing_points(candles, left=piv["left"], right=piv["right"])

    sweep_frac  = _lm_structure_sweep_threshold_pct(timeframe) / 100.0
    piv_s       = _lm_structure_pivot_settings(timeframe)

    highs_sorted = sorted(swings.get("swing_highs", []), key=lambda x: x["confirmed_at"])
    lows_sorted  = sorted(swings.get("swing_lows",  []), key=lambda x: x["confirmed_at"])

    sweeps: list = []
    h_ptr = 0
    l_ptr = 0
    avail_highs: list = []
    avail_lows:  list = []

    for candle in candles:
        c_time  = candle["open_time"]
        c_high  = float(candle.get("high",  0))
        c_low   = float(candle.get("low",   0))
        c_close = float(candle.get("close", 0))

        while h_ptr < len(highs_sorted) and highs_sorted[h_ptr]["confirmed_at"] <= c_time:
            avail_highs.append(highs_sorted[h_ptr])
            h_ptr += 1
        while l_ptr < len(lows_sorted) and lows_sorted[l_ptr]["confirmed_at"] <= c_time:
            avail_lows.append(lows_sorted[l_ptr])
            l_ptr += 1

        # Buy-side sweep: wick above swing high, close back below it
        for sh in reversed(avail_highs[-6:]):
            lvl = sh["level"]
            if lvl <= 0:
                continue
            if c_high >= lvl * (1.0 + sweep_frac) and c_close < lvl:
                sweeps.append({
                    "event_time":         c_time,
                    "event_type":         "buy_side_liquidity_sweep",
                    "direction":          "bearish",
                    "level":              lvl,
                    "candle_open_time":   c_time,
                    "confirmation_close": c_close,
                    "swing_left":         piv_s["left"],
                    "swing_right":        piv_s["right"],
                    "threshold_pct":      _lm_structure_sweep_threshold_pct(timeframe),
                    "context":            "sweep_context_only_not_entry_signal",
                })
                break

        # Sell-side sweep: wick below swing low, close back above it
        for sl in reversed(avail_lows[-6:]):
            lvl = sl["level"]
            if lvl <= 0:
                continue
            if c_low <= lvl * (1.0 - sweep_frac) and c_close > lvl:
                sweeps.append({
                    "event_time":         c_time,
                    "event_type":         "sell_side_liquidity_sweep",
                    "direction":          "bullish",
                    "level":              lvl,
                    "candle_open_time":   c_time,
                    "confirmation_close": c_close,
                    "swing_left":         piv_s["left"],
                    "swing_right":        piv_s["right"],
                    "threshold_pct":      _lm_structure_sweep_threshold_pct(timeframe),
                    "context":            "sweep_context_only_not_entry_signal",
                })
                break

    return sweeps


# ── Task 6: Structure summary builder ────────────────────────────────────────

def _lm_build_structure_summary_for_tf(events: list, timeframe: str) -> dict:
    """Build a lightweight structure summary for one TF from detected events.

    context_weight is always 'low' in Phase 10.9D.
    No entry signal. No S/R flip.
    """
    all_events   = sorted(events, key=lambda x: x.get("event_time", 0))
    bos_events   = [e for e in all_events if "bos"   in e.get("event_type", "")]
    choch_events = [e for e in all_events if "choch" in e.get("event_type", "")]
    sweep_events = [e for e in all_events if "sweep" in e.get("event_type", "")]

    # Structure direction from most recent directional event
    struct_dir = "neutral"
    for e in reversed(all_events):
        if e.get("direction") in ("bullish", "bearish"):
            struct_dir = e["direction"]
            break

    return {
        "timeframe":           timeframe,
        "structure_direction": struct_dir,
        "last_bos":            bos_events[-1]   if bos_events   else {},
        "last_choch":          choch_events[-1] if choch_events else {},
        "last_sweep":          sweep_events[-1] if sweep_events else {},
        "event_count":         len(all_events),
        "context_weight":      "low",
        "notes": [
            "Structure is context only; candle/order-flow agreement required in later phases.",
            "BOS/CHoCH/sweep do NOT create entry signals in Phase 10.9D.",
        ],
    }


# ── Task 7: All-TF structure processor + status builder ──────────────────────

def _lm_store_structure_events(user_id: int, exchange: str, market: str,
                                 symbol: str, timeframe: str,
                                 events: list) -> int:
    """Upsert structure events into LiveMonitorStructureEvent. Returns count stored."""
    from models import db as _db, LiveMonitorStructureEvent as _LMSE
    from sqlalchemy.dialects.postgresql import insert as pg_insert

    if not events:
        return 0

    rows = [
        {
            "user_id":            user_id,
            "exchange":           exchange,
            "market":             market,
            "symbol":             symbol,
            "timeframe":          timeframe,
            "event_time":         e["event_time"],
            "event_type":         e["event_type"],
            "direction":          e.get("direction"),
            "level":              e.get("level"),
            "candle_open_time":   e.get("candle_open_time"),
            "confirmation_close": e.get("confirmation_close"),
            "swing_left":         e.get("swing_left"),
            "swing_right":        e.get("swing_right"),
            "threshold_pct":      e.get("threshold_pct"),
            "strength_score":     e.get("strength_score"),
            "context_json":       _json_dumps_safe({"context": e.get("context", "")}),
        }
        for e in events
    ]

    stmt = pg_insert(_LMSE.__table__).values(rows)
    stmt = stmt.on_conflict_do_update(
        constraint="uq_lm_struct_event",
        set_={
            "direction":          stmt.excluded.direction,
            "level":              stmt.excluded.level,
            "candle_open_time":   stmt.excluded.candle_open_time,
            "confirmation_close": stmt.excluded.confirmation_close,
            "threshold_pct":      stmt.excluded.threshold_pct,
            "strength_score":     stmt.excluded.strength_score,
            "context_json":       stmt.excluded.context_json,
            "updated_at":         _db.func.now(),
        },
    )
    _db.session.execute(stmt)
    _db.session.commit()
    return len(rows)


def _lm_get_structure_events(user_id: int, exchange: str, market: str,
                               symbol: str, timeframe: str,
                               event_type: str = None, limit: int = 50) -> list:
    """Return recent structure events for one TF as plain dicts."""
    from models import LiveMonitorStructureEvent as _LMSE
    try:
        q = _LMSE.query.filter_by(
            user_id=user_id, exchange=exchange, market=market,
            symbol=symbol, timeframe=timeframe,
        )
        if event_type:
            q = q.filter(_LMSE.event_type == event_type)
        rows = q.order_by(_LMSE.event_time.desc()).limit(limit).all()
        return [
            {
                "event_time":         r.event_time,
                "event_type":         r.event_type,
                "direction":          r.direction,
                "level":              r.level,
                "confirmation_close": r.confirmation_close,
                "threshold_pct":      r.threshold_pct,
                "context":            _json_loads_safe(r.context_json, {}),
            }
            for r in rows
        ]
    except Exception:
        return []


def _lm_build_structure_engine_status(user_id: int, exchange: str, market: str,
                                        symbol: str, per_tf_summaries: dict) -> dict:
    """Build the lightweight structure_engine status dict for snapshot_json.

    Stores only status/count/latest summary per TF — no full event arrays.
    """
    tf_stack     = list(_LM_BIAS_TF_STACK_CONST)
    per_tf_status = {}
    all_statuses  = []

    for tf in tf_stack:
        summary    = per_tf_summaries.get(tf, {})
        tf_status  = summary.get("status", "unavailable")
        all_statuses.append(tf_status)
        last_bos   = summary.get("last_bos",   {})
        last_choch = summary.get("last_choch", {})
        last_sweep = summary.get("last_sweep", {})

        per_tf_status[tf] = {
            "status":              tf_status,
            "event_count":         summary.get("event_count", 0),
            "structure_direction": summary.get("structure_direction", "neutral"),
            "last_bos": {
                "type":  last_bos.get("event_type"),
                "level": last_bos.get("level"),
                "time":  last_bos.get("event_time"),
            } if last_bos else {},
            "last_choch": {
                "type":  last_choch.get("event_type"),
                "level": last_choch.get("level"),
                "time":  last_choch.get("event_time"),
            } if last_choch else {},
            "last_sweep": {
                "type":  last_sweep.get("event_type"),
                "level": last_sweep.get("level"),
                "time":  last_sweep.get("event_time"),
            } if last_sweep else {},
            "notes": summary.get("notes", []),
        }

    # Overall status
    ready_count = sum(1 for s in all_statuses if s == "ready")
    if ready_count == len(tf_stack):
        overall = "ready"
    elif ready_count > 0:
        overall = "partial"
    elif any(s == "error" for s in all_statuses):
        overall = "error"
    else:
        overall = "unavailable"

    # Cross-TF contradiction: 1H vs 4H
    dir_1h = per_tf_status.get("1h",  {}).get("structure_direction", "neutral")
    dir_4h = per_tf_status.get("4h",  {}).get("structure_direction", "neutral")
    if dir_1h in ("bullish", "bearish") and dir_4h in ("bullish", "bearish") and dir_1h != dir_4h:
        contradiction_1h4h = f"{dir_1h}_vs_{dir_4h}"
    else:
        contradiction_1h4h = "none"

    return {
        "enabled":      True,
        "phase":        "phase10_9d_structure_context",
        "status":       overall,
        "context_only": True,
        "low_weight":   True,
        "per_tf":       per_tf_status,
        "contradictions": {
            "one_h_vs_four_h": contradiction_1h4h,
        },
    }


# Thread registry for structure engine
_lm_bias_structure_threads: dict = {}
_lm_bias_structure_thread_lock   = threading.Lock()


def _lm_refresh_bias_structure_for_item(item, force: bool = False) -> dict:
    """Detect and store structure events (BOS/CHoCH/sweep) for all TFs.

    Reads stored LiveMonitorCandle rows only — no external API calls.
    Updates snapshot_json.structure_engine with lightweight status only.
    Safe to call from background thread — uses app.app_context().

    CONTEXT ONLY. No entry signals. No S/R Flip. No order-flow. No trading.
    """
    if not _lm_is_bias_shift_item(item):
        return {"skipped": True, "reason": "not_bias_shift"}

    with app.app_context():
        from models import db as _db, LiveMonitorItem as _LMI

        uid      = getattr(item, "user_id",  None)
        symbol   = (getattr(item, "symbol",   "") or "").upper()
        exchange = (getattr(item, "exchange", "") or "binance").lower()
        market   = (getattr(item, "market",   "") or "perpetual").lower()
        item_id  = getattr(item, "id", None)

        if not uid or not symbol:
            return {"skipped": True, "reason": "missing_uid_or_symbol"}

        per_tf_summaries: dict = {}

        for tf in _LM_BIAS_TF_STACK_CONST:
            try:
                candle_rows = _lm_get_stored_candles(uid, exchange, market, symbol, tf, 1500)
                if not candle_rows:
                    per_tf_summaries[tf] = {
                        "status": "unavailable", "event_count": 0,
                        "structure_direction": "neutral",
                    }
                    continue

                candles = sorted(
                    [{"open_time": c.open_time, "open": c.open, "high": c.high,
                      "low": c.low, "close": c.close, "volume": c.volume or 0.0}
                     for c in candle_rows],
                    key=lambda x: x["open_time"],
                )

                bos_result    = _lm_detect_structure_events_for_tf(candles, tf)
                struct_events = bos_result.get("events", [])
                swings        = bos_result.get("swings", {})
                struct_dir    = bos_result.get("structure_direction", "neutral")
                sweep_events  = _lm_detect_liquidity_sweeps_for_tf(candles, tf, swings=swings)
                all_events    = struct_events + sweep_events

                if all_events:
                    try:
                        _lm_store_structure_events(uid, exchange, market, symbol, tf, all_events)
                    except Exception as se:
                        print(f"[10.9D] store error {symbol}/{tf}: {se}")

                summary = _lm_build_structure_summary_for_tf(all_events, tf)
                summary["status"] = "ready" if all_events else "partial"
                per_tf_summaries[tf] = summary

                print(f"[10.9D] structure {symbol}/{tf}: dir={struct_dir} "
                      f"bos/choch={len(struct_events)} sweeps={len(sweep_events)}")

            except Exception as exc:
                print(f"[10.9D] structure error {symbol}/{tf}: {exc}")
                per_tf_summaries[tf] = {
                    "status": "error", "event_count": 0,
                    "structure_direction": "neutral",
                }

        struct_status = _lm_build_structure_engine_status(
            uid, exchange, market, symbol, per_tf_summaries
        )
        try:
            row = _LMI.query.filter_by(id=item_id).first()
            if row:
                snap = _json_loads_safe(row.snapshot_json, {})
                snap["structure_engine"] = struct_status
                row.snapshot_json = _json_dumps_safe(snap)
                _db.session.commit()
        except Exception as exc:
            _db.session.rollback()
            print(f"[10.9D] snapshot update error: {exc}")

        # Task 10 (Phase 10.9E): Trigger order-flow alignment after structure engine completes.
        if item_id:
            try:
                _lm_ensure_bias_orderflow_alignment_bg(
                    item_id, uid, exchange, market, symbol,
                    getattr(item, "source_tab", "bias_shift") or "bias_shift",
                )
            except Exception as _ofe:
                print(f"[10.9E] OF alignment trigger error after structure: {_ofe}")

        return {
            "ok":               True,
            "symbol":           symbol,
            "exchange":         exchange,
            "market":           market,
            "structure_engine": struct_status,
            "per_tf":           per_tf_summaries,
        }


def _lm_ensure_bias_structure_bg(item_id: int, uid: int, exchange: str,
                                   market: str, symbol: str,
                                   source_tab: str, force: bool = False):
    """Start background structure engine for a Bias Shift item if not already running."""
    if source_tab not in ("bias_shift", "bias"):
        return
    with _lm_bias_structure_thread_lock:
        t = _lm_bias_structure_threads.get(item_id)
        if t and t.is_alive():
            return

    class _ItemProxy:
        pass
    proxy = _ItemProxy()
    proxy.id            = item_id
    proxy.user_id       = uid
    proxy.symbol        = symbol
    proxy.exchange      = exchange
    proxy.market        = market
    proxy.source_tab    = source_tab
    proxy.snapshot_json = None

    def _run():
        with _lm_bias_structure_thread_lock:
            _lm_bias_structure_threads[item_id] = threading.current_thread()
        try:
            _lm_refresh_bias_structure_for_item(proxy, force=force)
        except Exception as exc:
            print(f"[10.9D] background structure error item={item_id}: {exc}")
        finally:
            with _lm_bias_structure_thread_lock:
                _lm_bias_structure_threads.pop(item_id, None)

    t = threading.Thread(target=_run, daemon=True,
                         name=f"lm-bias-structure-{item_id}")
    with _lm_bias_structure_thread_lock:
        _lm_bias_structure_threads[item_id] = t
    t.start()


