# ── Phase 9.0: Data Source Config Endpoints ──────────────────────────────────

@app.route("/api/live-monitor/items/<int:item_id>/data-sources", methods=["GET"])
@login_required
def api_lm_items_data_sources_get(item_id):
    """Return current data_source_config for a Live Monitor item.

    If missing or not yet computed, builds from defaults and saves to snapshot.
    No trading. No order logic.
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    from models import db as _db, LiveMonitorItem as _LMI
    row = _LMI.query.filter_by(id=item_id).first()
    if not row:
        return jsonify({"error": "not_found"}), 404
    if row.user_id != uid:
        return jsonify({"error": "forbidden"}), 403
    if not row.is_active:
        return jsonify({"error": "inactive"}), 400

    snap   = _json_loads_safe(row.snapshot_json, {})
    config = _lm_data_source_config(row, snapshot=snap)

    now_iso = datetime.now(timezone.utc).isoformat()
    saved   = snap.get("data_sources") or {}
    stale   = not saved or snap.get("last_data_sources_at") is None

    if stale:
        snap["data_sources"]         = {k: v for k, v in config.items()
                                         if k != "warnings"}
        snap["last_data_sources_at"] = now_iso
        row.snapshot_json = _json_dumps_safe(snap)
        row.updated_at    = datetime.now(timezone.utc)
        try:
            _db.session.commit()
        except Exception:
            _db.session.rollback()

    return jsonify({"ok": True, "item": _live_monitor_item_to_dict(row), "data_sources": config})


@app.route("/api/live-monitor/items/<int:item_id>/data-sources", methods=["POST"])
@login_required
def api_lm_items_data_sources_post(item_id):
    """Update data source configuration for a Live Monitor item.

    Body (all optional):
      execution_exchange, execution_market, candle_source,
      live_price_source, market_context_sources, aggregation_enabled

    Unknown or invalid values fall back to safe defaults.
    No API keys. No trading. No order logic.
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    from models import db as _db, LiveMonitorItem as _LMI
    row = _LMI.query.filter_by(id=item_id).first()
    if not row:
        return jsonify({"error": "not_found"}), 404
    if row.user_id != uid:
        return jsonify({"error": "forbidden"}), 403
    if not row.is_active:
        return jsonify({"error": "inactive"}), 400

    body = (request.get_json(silent=True) or {})
    snap = _json_loads_safe(row.snapshot_json, {})

    existing = snap.get("data_sources") or {}
    if "execution_exchange" in body:
        existing["execution_exchange"]     = _lm_normalize_exchange(body["execution_exchange"])
    if "execution_market" in body:
        existing["execution_market"]       = _lm_normalize_market(body["execution_market"])
    if "candle_source" in body:
        existing["candle_source"]          = _lm_normalize_exchange(body["candle_source"])
    if "live_price_source" in body:
        existing["live_price_source"]      = _lm_normalize_exchange(body["live_price_source"])
    if "market_context_sources" in body:
        raw = body["market_context_sources"]
        if isinstance(raw, list):
            mcs = [s for s in [_lm_normalize_exchange(x) for x in raw]
                   if s in _LM_ALLOWED_EXCHANGES]
            existing["market_context_sources"] = mcs or ["binance"]
    if "aggregation_enabled" in body:
        existing["aggregation_enabled"]    = bool(body["aggregation_enabled"])

    now_iso = datetime.now(timezone.utc).isoformat()

    # Phase 10.7 Tasks 13-14: detect analysis_source change before saving
    _asc_old = _lm_analysis_source_config(row, snapshot=snap)["analysis_source"]
    if "analysis_source" in body:
        existing["analysis_source"] = _lm_normalize_analysis_source(body["analysis_source"])

    snap["data_sources"]         = existing
    snap["last_data_sources_at"] = now_iso
    row.snapshot_json = _json_dumps_safe(snap)
    row.updated_at    = datetime.now(timezone.utc)

    try:
        _db.session.commit()
    except Exception as e:
        _db.session.rollback()
        return jsonify({"error": str(e)}), 500

    # Phase 10.7: log + chat if analysis source changed
    try:
        _asc_new = _lm_analysis_source_config(row, snapshot=snap)["analysis_source"]
        if _asc_new != _asc_old:
            _lm107_maybe_log_source_event(uid, row, _asc_new, _asc_old)
            _lm107_maybe_post_source_chat(uid, row, _asc_new, _asc_old)
    except Exception:
        pass

    config = _lm_data_source_config(row, snapshot=snap)
    return jsonify({"ok": True, "item": _live_monitor_item_to_dict(row), "data_sources": config})


@app.route("/api/live-monitor/items/<int:item_id>/analysis-source", methods=["POST"])
@login_required
def api_lm_items_analysis_source_post(item_id):
    """Persist selected analysis data source for one Live Monitor item.

    Phase 10.7 — analysis source is for confluence/confirmation only.
    Never changes row.exchange, zone values, SL, TP, or parent setup levels.
    No trading. No order logic. No API keys.

    Body: {"analysis_source": "aggregated|binance|bybit|okx|mexc"}
    Returns: {"ok": true, "item": {...}, "analysis_source": "..."}
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    from models import db as _db, LiveMonitorItem as _LMI
    row = _LMI.query.filter_by(id=item_id).first()
    if not row:
        return jsonify({"error": "not_found"}), 404
    if row.user_id != uid:
        return jsonify({"error": "forbidden"}), 403
    if not row.is_active:
        return jsonify({"error": "inactive"}), 400

    body = request.get_json(silent=True) or {}
    raw_src = body.get("analysis_source") or ""
    new_src = _lm_normalize_analysis_source(raw_src)   # unknown → "binance"

    snap    = _json_loads_safe(row.snapshot_json, {})
    old_src = _lm_analysis_source_config(row, snapshot=snap)["analysis_source"]

    # Persist to both top-level and data_sources sub-dict
    snap["analysis_source"] = new_src
    ds = snap.get("data_sources") or {}
    ds["analysis_source"]   = new_src
    snap["data_sources"]    = ds
    snap["last_analysis_source_set_at"] = datetime.now(timezone.utc).isoformat()

    # row.exchange is NOT changed — parent setup exchange stays immutable
    row.snapshot_json = _json_dumps_safe(snap)
    row.updated_at    = datetime.now(timezone.utc)

    try:
        _db.session.commit()
    except Exception as e:
        _db.session.rollback()
        return jsonify({"error": str(e)}), 500

    # Phase 10.7 Tasks 13-14: fire chat + event log on source change (deduped inside helpers)
    if new_src != old_src:
        try:
            _lm107_maybe_log_source_event(uid, row, new_src, old_src)
            _lm107_maybe_post_source_chat(uid, row, new_src, old_src)
        except Exception:
            pass

    return jsonify({
        "ok":             True,
        "item":           _live_monitor_item_to_dict(row),
        "analysis_source": new_src,
        "parent_setup_exchange": getattr(row, "exchange", "binance") or "binance",
        "price_levels_source":   "parent_setup_exchange",
        "changed": new_src != old_src,
    })


