@app.route("/api/live-monitor/items/<int:item_id>/paper-orders/process-fills", methods=["POST"])
@login_required
def api_lm_paper_process_fills(item_id):
    """Phase 11.7C: Check open paper orders against market price and fill qualifying ones.

    SAFETY: DB-only. No Binance API. No Binance Testnet. No exchange calls.
    No auto-execution. Runs only when user manually clicks 'Process Paper Fills'.
    Fill price = order.price (limit price).
    Price source: WS cache → data_health snapshot → item.current_price → snapshot fallbacks.
    """
    import json as _json
    import datetime as _dt117c
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401
    from models import (
        db               as _db117c,
        LiveMonitorItem  as _LMI117c,
        LiveMonitorEvent as _LMEv117c,
    )
    item = _LMI117c.query.filter_by(id=item_id, user_id=uid).first()
    if not item:
        return jsonify({"error": "item_not_found"}), 404

    result = _lm_process_paper_fills_for_item(uid, item_id)

    now_iso = _dt117c.datetime.utcnow().isoformat() + "Z"

    # ── Snapshot: latest_paper_fill_process_summary ───────────────────────────
    try:
        snap = {}
        if item.snapshot_json:
            try:
                snap = _json.loads(item.snapshot_json)
            except Exception:
                snap = {}
        snap["latest_paper_fill_process_summary"] = {
            "ok":             result.get("ok", False),
            "processed":      result.get("processed", 0),
            "filled":         result.get("filled", 0),
            "last_checked_at": now_iso,
            "current_price":  result.get("current_price"),
            "price_source":   result.get("price_source"),
            "source":         "internal_paper",
        }
        item.snapshot_json = _json.dumps(snap, default=str)
        _db117c.session.commit()
    except Exception:
        pass

    # ── Timeline events: one per newly-filled order (no duplicates) ───────────
    try:
        filled_results = [r for r in result.get("results", []) if r.get("filled")]
        for fr in filled_results:
            ev = _LMEv117c(
                user_id=uid,
                item_id=item_id,
                event_type="paper_order_filled",
                event_data=_json.dumps({
                    "order_id":      fr.get("order_id"),
                    "symbol":        fr.get("symbol"),
                    "side":          fr.get("side"),
                    "quantity":      fr.get("filled_qty"),
                    "order_price":   fr.get("order_price"),
                    "current_price": fr.get("current_price"),
                    "fill_price":    fr.get("fill_price"),
                    "notional":      fr.get("notional"),
                    "position_id":   fr.get("position_id"),
                    "fill_id":       fr.get("fill_id"),
                }, default=str),
            )
            _db117c.session.add(ev)
        if filled_results:
            _db117c.session.commit()
    except Exception:
        pass

    return jsonify({
        "ok":            result.get("ok", False),
        "item_id":       item_id,
        "processed":     result.get("processed", 0),
        "filled":        result.get("filled", 0),
        "current_price": result.get("current_price"),
        "price_source":  result.get("price_source"),
        "last_checked_at": now_iso,
        "results":       result.get("results", []),
        "source":        "internal_paper",
        "error":         result.get("error"),
    })


@app.route("/api/live-monitor/items/<int:item_id>/paper-positions/refresh", methods=["POST"])
@login_required
def api_lm_paper_positions_refresh(item_id):
    """Phase 11.8: Mark all open paper positions with current market price and recompute PnL.

    SAFETY: DB-only. No Binance API. No Binance Testnet. No exchange calls.
    No auto-execution. Runs only when user manually clicks 'Refresh PnL'.
    Price source: WS cache → data_health snapshot → item.current_price → snapshot fallbacks.
    """
    import json as _json118
    import datetime as _dt118
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401
    from models import (
        db               as _db118,
        LiveMonitorItem  as _LMI118,
        LiveMonitorEvent as _LMEv118,
    )
    item = _LMI118.query.filter_by(id=item_id, user_id=uid).first()
    if not item:
        return jsonify({"error": "item_not_found"}), 404

    # 1. Update unrealized_pnl on all open positions for this item
    mark_result   = _lm_update_paper_position_marks(uid, item_id=item_id)

    # 2. Recalculate account equity
    equity_result = _lm_recalculate_paper_account_equity(uid)

    # 3. Compact position summary (positions list + totals)
    pos_summary   = _lm_get_paper_position_summary(uid, item_id=item_id)

    now_iso = _dt118.datetime.utcnow().isoformat() + "Z"

    # 4. Snapshot: compact key — no positions array, keep lean
    try:
        snap = {}
        if item.snapshot_json:
            try:
                snap = _json118.loads(item.snapshot_json)
            except Exception:
                snap = {}
        snap["latest_paper_position_mark_summary"] = {
            "ok":                  mark_result.get("ok", False),
            "processed":           mark_result.get("processed", 0),
            "updated":             mark_result.get("updated", 0),
            "skipped":             mark_result.get("skipped", 0),
            "total_unrealized_pnl": equity_result.get("unrealized_pnl", 0.0),
            "last_checked_at":     now_iso,
            "source":              "internal_paper",
        }
        item.snapshot_json = _json118.dumps(snap, default=str)
        _db118.session.commit()
    except Exception:
        pass

    # 5. ONE timeline event per manual refresh (not per position)
    try:
        ev = _LMEv118(
            user_id=uid,
            item_id=item_id,
            event_type="paper_position_updated",
            event_data=_json118.dumps({
                "item_id":             item_id,
                "processed":           mark_result.get("processed", 0),
                "updated":             mark_result.get("updated", 0),
                "skipped":             mark_result.get("skipped", 0),
                "total_unrealized_pnl": equity_result.get("unrealized_pnl", 0.0),
                "last_checked_at":     now_iso,
                "source":              "internal_paper",
            }, default=str),
        )
        _db118.session.add(ev)
        _db118.session.commit()
    except Exception:
        pass

    _ok = mark_result.get("ok", False)
    return jsonify({
        "ok":      _ok,
        "item_id": item_id,
        # Nested objects per spec
        "position_update": {
            "ok":        _ok,
            "processed": mark_result.get("processed", 0),
            "updated":   mark_result.get("updated", 0),
            "skipped":   mark_result.get("skipped", 0),
            "results":   mark_result.get("results", []),
        },
        "position_summary": {
            "open_count":           pos_summary.get("open_count", 0),
            "closed_count":         pos_summary.get("closed_count", 0),
            "total_unrealized_pnl": pos_summary.get("total_unrealized_pnl", 0.0),
            "total_realized_pnl":   pos_summary.get("total_realized_pnl", 0.0),
        },
        "account": {
            "cash_balance":   equity_result.get("cash_balance"),
            "equity":         equity_result.get("equity"),
            "unrealized_pnl": equity_result.get("unrealized_pnl", 0.0),
            "realized_pnl":   equity_result.get("realized_pnl", 0.0),
            "open_positions": equity_result.get("open_positions", 0),
        },
        # Flat convenience keys (backward compat for JS)
        "processed":           mark_result.get("processed", 0),
        "updated":             mark_result.get("updated", 0),
        "skipped":             mark_result.get("skipped", 0),
        "total_unrealized_pnl": equity_result.get("unrealized_pnl", 0.0),
        "equity":              equity_result.get("equity"),
        "cash_balance":        equity_result.get("cash_balance"),
        "last_checked_at":     now_iso,
        "source":              "internal_paper",
        "error":               mark_result.get("error") or equity_result.get("error"),
    })


@app.route("/api/live-monitor/items/<int:item_id>/paper-positions/check-exits", methods=["POST"])
@login_required
def api_lm_paper_check_exits(item_id):
    """Phase 11.9: Check open paper positions for TP/SL hits and close qualifying ones.

    SAFETY: DB-only. No Binance API. No Binance Testnet. No exchange calls.
    No auto-execution. Runs only when user manually clicks 'Check TP/SL'.
    TP/SL levels from execution_intent_json on entry order only.
    Exit price = take_profit (if TP hit) or stop_loss (if SL hit).
    """
    import json as _json119
    import datetime as _dt119
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401
    from models import (
        db               as _db119,
        LiveMonitorItem  as _LMI119,
        LiveMonitorEvent as _LMEv119,
    )
    item = _LMI119.query.filter_by(id=item_id, user_id=uid).first()
    if not item:
        return jsonify({"error": "item_not_found"}), 404

    # 1. Process TP/SL exits for this item
    exit_result  = _lm_process_paper_exits_for_item(uid, item_id)

    # 2. Refresh position summary and account
    pos_summary  = _lm_get_paper_position_summary(uid, item_id=item_id)
    acct_summary = _lm_get_paper_account_summary(uid)

    now_iso = _dt119.datetime.utcnow().isoformat() + "Z"

    # 3. Snapshot: compact key — no results array
    try:
        snap = {}
        if item.snapshot_json:
            try:
                snap = _json119.loads(item.snapshot_json)
            except Exception:
                snap = {}
        snap["latest_paper_exit_check_summary"] = {
            "ok":             exit_result.get("ok", False),
            "processed":      exit_result.get("processed", 0),
            "closed":         exit_result.get("closed", 0),
            "tp_hits":        exit_result.get("tp_hits", 0),
            "sl_hits":        exit_result.get("sl_hits", 0),
            "last_checked_at": now_iso,
            "source":         "internal_paper",
        }
        item.snapshot_json = _json119.dumps(snap, default=str)
        _db119.session.commit()
    except Exception:
        pass

    # 4. ONE timeline event per closed position (tp_hit or sl_hit)
    try:
        closed_results = [r for r in exit_result.get("results", []) if r.get("closed")]
        for cr in closed_results:
            reason = cr.get("close_reason", "")
            evt    = "paper_tp_hit" if reason == "take_profit" else "paper_sl_hit"
            ev = _LMEv119(
                user_id=uid,
                item_id=item_id,
                event_type=evt,
                event_data=_json119.dumps({
                    "item_id":      item_id,
                    "position_id":  cr.get("position_id"),
                    "symbol":       cr.get("symbol"),
                    "side":         cr.get("side"),
                    "quantity":     cr.get("quantity"),
                    "entry_price":  cr.get("entry_price"),
                    "mark_price":   cr.get("mark_price"),
                    "exit_price":   cr.get("exit_price"),
                    "close_price":  cr.get("exit_price"),
                    "realized_pnl": cr.get("realized_pnl"),
                    "close_reason": reason,
                    "exit_fill_id": cr.get("fill_id"),
                    "source":       "internal_paper",
                }, default=str),
            )
            _db119.session.add(ev)
        if closed_results:
            _db119.session.commit()
    except Exception:
        pass

    return jsonify({
        "ok":      exit_result.get("ok", False),
        "item_id": item_id,
        "exit_check": {
            "processed":  exit_result.get("processed", 0),
            "closed":     exit_result.get("closed", 0),
            "tp_hits":    exit_result.get("tp_hits", 0),
            "sl_hits":    exit_result.get("sl_hits", 0),
            "results":    exit_result.get("results", []),
        },
        "position_summary": {
            "open_count":           pos_summary.get("open_count", 0),
            "closed_count":         pos_summary.get("closed_count", 0),
            "total_unrealized_pnl": pos_summary.get("total_unrealized_pnl", 0.0),
            "total_realized_pnl":   pos_summary.get("total_realized_pnl", 0.0),
        },
        "account": acct_summary,
        "last_checked_at": now_iso,
        "source":  "internal_paper",
        "error":   exit_result.get("error"),
    })


