@app.route("/api/live-monitor/trades/<trade_uid>/demo-submit", methods=["POST"])
@login_required
def api_lm_trade_demo_submit(trade_uid):
    """Safety-gated demo order submission for a risk_approved trade.

    Phase 9.6: All safety gates are checked. Since MEXC demo order submission
    endpoint is not confirmed, this endpoint defaults to returning blocked with
    reason 'mexc_demo_submit_not_confirmed'. No real or demo orders are placed.
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    # Gate 1: demo trading env flags
    gate = _lm_demo_trading_enabled()
    if gate["blocked"]:
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": gate["blocked_reason"],
        }), 400

    from models import db as _db, LiveMonitorTrade as _LMT, LiveMonitorItem as _LMI
    trade = _LMT.query.filter_by(trade_uid=trade_uid).first()
    if not trade:
        return jsonify({"error": "not_found"}), 404
    if trade.user_id != uid:
        return jsonify({"error": "forbidden"}), 403

    # Gate 2: trade must be risk_approved
    if trade.status != "risk_approved":
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": f"trade_status_not_risk_approved:{trade.status}",
        }), 400

    # Gate 3: execution exchange must be mexc perpetual
    ex_ex  = (getattr(trade, "execution_exchange", "") or "").lower()
    ex_mkt = (getattr(trade, "execution_market",   "") or "").lower()
    if ex_ex != "mexc" or ex_mkt != "perpetual":
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": f"execution_exchange_not_mexc_perpetual:{ex_ex}/{ex_mkt}",
        }), 400

    # Gate 4: Risk Guard must have approved
    rg = _json_loads_safe(getattr(trade, "risk_guard_json", None), {})
    if not rg.get("approved"):
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": "risk_guard_not_approved",
            "risk_guard":     rg,
        }), 400

    # Gate 5: mode must be demo
    if (getattr(trade, "mode", "") or "").lower() not in ("demo", "proposal_only"):
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": "trade_mode_not_demo",
        }), 400

    # Gate 6: validate order payload can be built
    row = _LMI.query.filter_by(id=trade.live_monitor_item_id).first()
    payload_r = _lm_prepare_demo_order_payload(trade, row=row)
    if not payload_r["ok"]:
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": payload_r.get("blocked_reason", "payload_build_failed"),
        }), 400

    # Gate 7 (terminal safety gate): MEXC demo order submit endpoint not confirmed.
    # Per Phase 9.6 spec: if MEXC demo order submission is uncertain, do not submit.
    # Return blocked — payload is valid but submission is not attempted.
    return jsonify({
        "ok":             False,
        "blocked":        True,
        "blocked_reason": "mexc_demo_submit_not_confirmed",
        "message": (
            "MEXC demo perpetual order submission endpoint is not confirmed. "
            "All safety gates passed. Payload is ready but no order was placed. "
            "This block will be lifted when MEXC demo order submit is verified."
        ),
        "payload_preview": {
            "symbol":        payload_r.get("mx_symbol"),
            "order_side":    payload_r.get("order_side"),
            "notional_usdt": payload_r.get("notional_usdt"),
            "leverage":      payload_r.get("leverage"),
        },
        "trade": _lm_trade_to_dict(trade),
    })


# ── Phase 9.7: Demo Trade Sync + Post-Trade Review Endpoints ──────────────────


@app.route("/api/live-monitor/trades/<trade_uid>/demo-sync", methods=["POST"])
@login_required
def api_lm_trade_demo_sync(trade_uid):
    """Sync demo trade status from MEXC. Read-only — never places or cancels orders."""
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    from models import db as _db, LiveMonitorTrade as _LMT
    trade = _LMT.query.filter_by(trade_uid=trade_uid).first()
    if not trade:
        return jsonify({"error": "not_found"}), 404
    if trade.user_id != uid:
        return jsonify({"error": "forbidden"}), 403

    # Endpoint-level safety: only demo_exchange trades may be synced
    if (getattr(trade, "mode", "") or "") != "demo_exchange":
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": f"trade_mode_not_demo_exchange:{trade.mode}",
        }), 400

    # Endpoint-level safety: only submitted/open trades are syncable
    if trade.status not in ("submitted", "open"):
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": f"trade_status_{trade.status}_not_syncable",
        }), 400

    sync_r = _lm_sync_mexc_demo_trade(trade)
    if sync_r.get("blocked"):
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": sync_r.get("blocked_reason"),
        }), 400
    if not sync_r.get("ok"):
        return jsonify({
            "ok":    False,
            "error": sync_r.get("error"),
            "synced": False,
        }), 502

    if sync_r.get("synced"):
        try:
            _db.session.commit()
        except Exception as e:
            _db.session.rollback()
            return jsonify({"error": str(e)}), 500

    return jsonify({
        "ok":      True,
        "synced":  sync_r.get("synced"),
        "changes": sync_r.get("changes"),
        "note":    sync_r.get("note"),
        "trade":   _lm_trade_to_dict(trade),
    })


@app.route("/api/live-monitor/trades/<trade_uid>/post-trade-review", methods=["POST"])
@login_required
def api_lm_trade_post_trade_review(trade_uid):
    """Build and store deterministic post-trade review. No AI, no exchange calls."""
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    from models import db as _db, LiveMonitorTrade as _LMT
    trade = _LMT.query.filter_by(trade_uid=trade_uid).first()
    if not trade:
        return jsonify({"error": "not_found"}), 404
    if trade.user_id != uid:
        return jsonify({"error": "forbidden"}), 403

    _LM_REVIEWABLE_STATUSES = {"closed", "failed", "risk_rejected", "cancelled"}
    if trade.status not in _LM_REVIEWABLE_STATUSES:
        return jsonify({
            "ok":             False,
            "blocked":        True,
            "blocked_reason": f"trade_status_not_reviewable:{trade.status}",
        }), 400

    review = _lm_build_post_trade_review(trade)

    trade.post_trade_review_json = _json_dumps_safe(review)
    if review.get("outcome") and review["outcome"] != "unknown":
        trade.outcome = review["outcome"]
    trade.updated_at = datetime.now(timezone.utc)

    try:
        _db.session.commit()
    except Exception as e:
        _db.session.rollback()
        return jsonify({"error": str(e)}), 500

    return jsonify({
        "ok":     True,
        "review": review,
        "trade":  _lm_trade_to_dict(trade),
    })


# ── Phase 10.3: Data Health endpoint (full market data pack) ─────────────────

def _lm_inject_parent_price_rows(symbol: str, parent_exchange: str,
                                  analysis_source: str, rows: list) -> list:
    """Replace Live Price / Mark Price rows with parent setup exchange data.

    Split-source contract: price rows always come from parent_setup_exchange,
    market context rows come from selected analysis_source.
    Never changes parent zone values. No trading. No order placement.
    """
    ws_enabled = os.environ.get("ZYNI_LM_WS_ENABLED") == "1"
    lp_row = mp_row = None
    _note = f"Parent setup: {parent_exchange.title()} | Analysis: {analysis_source.title()}"

    if parent_exchange == "binance":
        ws_e, ws_s = _lm_ws_get("binance", symbol)
        if ws_e:
            lp_row = {
                "metric": "Live Price", "value": f"{ws_e['live_price']:.4f}",
                "source": "binance (parent setup)", "status": ws_s,
                "updated": f"{ws_e['data_age_sec']}s ago", "notes": _note,
            }
            if ws_e.get("mark_price") is not None:
                mp_row = {
                    "metric": "Mark Price", "value": f"{ws_e['mark_price']:.4f}",
                    "source": "binance (parent setup)", "status": ws_s,
                    "updated": f"{ws_e['data_age_sec']}s ago", "notes": _note,
                }
        elif ws_enabled:
            _rest_m = _lm_rest_cached(f"mark:{symbol}", 10,
                                      lambda: _lm_fetch_mark_price_rest(symbol))
            if _rest_m and _rest_m.get("mark_price"):
                _rv = f"{_rest_m['mark_price']:.4f}"
                lp_row = {"metric": "Live Price", "value": _rv,
                          "source": "binance-rest (parent setup)", "status": "fresh",
                          "updated": "REST ~10s TTL", "notes": _note + " (REST fallback)"}
                mp_row = {"metric": "Mark Price", "value": _rv,
                          "source": "binance-rest (parent setup)", "status": "fresh",
                          "updated": "REST ~10s TTL", "notes": _note + " (REST fallback)"}

    if not lp_row and not mp_row:
        # No override data — annotate existing rows with source note
        for _r in rows:
            _m = (_r.get("metric") or "").lower()
            if _m in ("live price", "mark price"):
                _r = dict(_r)
                _r["notes"] = ((_r.get("notes") or "") + f" | {_note}").strip(" |")
        return rows

    new_rows = []
    for _r in rows:
        _m = (_r.get("metric") or "").lower()
        if _m == "live price" and lp_row:
            new_rows.append(lp_row)
        elif _m == "mark price" and mp_row:
            new_rows.append(mp_row)
        else:
            new_rows.append(_r)
    return new_rows


@app.route("/api/live-monitor/liquidations/debug", methods=["GET"])
@login_required
def api_lm_liq_debug():
    """Debug endpoint: inspect liquidation WS state and cache for a symbol.
    Read-only. Does not affect trading, safety gates, or any execution path.

    connected = WS thread is alive AND has successfully connected at least once.
    Events in cache can be 0 even when connected (no liquidations happened yet).
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    symbol      = (request.args.get("symbol")   or "").upper().strip()
    exchange    = (request.args.get("exchange") or "aggregated").lower().strip()
    try:
        lookback_min = int(request.args.get("lookback_min") or 240)
    except ValueError:
        lookback_min = 240

    if not symbol:
        return jsonify({"error": "symbol_required"}), 400

    now_s    = time.time()
    cutoff_s = now_s - lookback_min * 60.0

    # ── Env var / enablement state ────────────────────────────────────────────
    _bin_ws_enabled = os.environ.get("ZYNI_LM_WS_ENABLED") == "1"
    _mx_ws_enabled  = _LM_MX_WS_ENABLED

    def _fmt_age(ts):
        if ts is None:
            return None
        diff = now_s - ts
        if diff < 60:   return f"{int(diff)}s ago"
        if diff < 3600: return f"{int(diff/60)}m ago"
        return f"{diff/3600:.1f}h ago"

    def _exch_info(exch_name: str, raw_events, ws_state: dict,
                   thread_obj, enabled: bool, not_impl: bool = False) -> dict:
        if not_impl:
            return {
                "enabled": False, "ws_enabled_env": False,
                "ws_thread_started": False, "connected": False,
                "events_seen": 0, "events_in_lookback": 0,
                "latest_event_time": None, "latest_event": None,
                "reason_if_empty": "adapter_not_implemented",
            }

        thread_alive = bool(thread_obj and thread_obj.is_alive())
        # Binance seeds the cache entry on WS connect; Bybit/OKX don't seed.
        cache_seeded = (exch_name == "binance" and bool(raw_events is not None))

        # connected = thread is alive AND has produced a last_connected_at timestamp
        connected = thread_alive and (ws_state.get("last_connected_at") is not None)

        in_lb  = [e for e in raw_events if e[0] >= cutoff_s] if raw_events else []
        latest = max(raw_events, key=lambda e: e[0]) if raw_events else None

        if not enabled:
            reason = (
                "ZYNI_LM_WS_ENABLED not set to 1"
                if exch_name == "binance"
                else "ZYNI_LM_MULTI_EXCHANGE_WS_ENABLED not set to 1"
            )
        elif not thread_alive:
            reason = "thread_not_running"
        elif not connected:
            reason = "thread_running_but_not_yet_connected"
        elif not raw_events:
            reason = "connected_no_events_yet"
        elif not in_lb:
            reason = "no_events_in_lookback_window"
        else:
            reason = None

        return {
            "enabled":           enabled,
            "ws_enabled_env":    enabled,
            "ws_thread_started": thread_alive,
            "connected":         connected,
            "events_seen":       len(raw_events) if raw_events else 0,
            "events_in_lookback": len(in_lb),
            "latest_event_time": int(latest[0] * 1000) if latest else None,
            "latest_event":      {
                "ts_ms": int(latest[0] * 1000),
                "side":  latest[1],
                "usd":   round(latest[2]),
                "age":   _fmt_age(latest[0]),
            } if latest else None,
            "reason_if_empty":   reason,
            "ws_state": {
                "thread_started_at":    _fmt_age(ws_state.get("thread_started_at")),
                "last_connect_attempt": _fmt_age(ws_state.get("last_connect_attempt")),
                "last_connected_at":    _fmt_age(ws_state.get("last_connected_at")),
                "last_message_at":      _fmt_age(ws_state.get("last_message_at")),
                "last_error":           ws_state.get("last_error"),
                "subscribed_symbols_count":  len(ws_state.get("subscribed_symbols") or []),
                "subscribed_symbols_sample": (ws_state.get("subscribed_symbols") or [])[:5],
            },
        }

    # ── Read caches ───────────────────────────────────────────────────────────
    _bin_key = f"binance:{symbol}"
    with _lm_liq_lock:
        _bin_entry = dict(_lm_liq_cache.get(_bin_key) or {})
    _bin_raw  = list(_bin_entry.get("events") or [])    # 4-tuples (ts, side, usd, price)
    _bin_norm = [(e[0], e[1], e[2]) for e in _bin_raw]

    _bybit_key = f"bybit:{symbol}"
    with _lm_mx_liq_lock:
        _bybit_entry = dict(_lm_mx_liq.get(_bybit_key) or {})
    _bybit_raw = list(_bybit_entry.get("events") or [])  # 3-tuples

    _okx_key = f"okx:{symbol}"
    with _lm_mx_liq_lock:
        _okx_entry = dict(_lm_mx_liq.get(_okx_key) or {})
    _okx_raw = list(_okx_entry.get("events") or [])      # 3-tuples

    sources_info = {
        "binance": _exch_info(
            "binance", _bin_norm, _lm_liq_ws_state,
            _lm_liq_thread, _bin_ws_enabled,
        ),
        "bybit": _exch_info(
            "bybit", _bybit_raw, _lm_mx_ws_state.get("bybit", {}),
            _lm_mx_threads.get("bybit"), _mx_ws_enabled,
        ),
        "okx": _exch_info(
            "okx", _okx_raw, _lm_mx_ws_state.get("okx", {}),
            _lm_mx_threads.get("okx"), _mx_ws_enabled,
        ),
        "mexc": _exch_info("mexc", [], {}, None, False, not_impl=True),
    }

    # ── Aggregate for lookback totals ────────────────────────────────────────
    all_events: list = []
    if exchange in ("aggregated", "binance"):
        all_events.extend(_bin_norm)
    if exchange in ("aggregated", "bybit"):
        all_events.extend(_bybit_raw)
    if exchange in ("aggregated", "okx"):
        all_events.extend(_okx_raw)

    in_lb        = [e for e in all_events if e[0] >= cutoff_s]
    total_long   = sum(e[2] for e in in_lb if e[1] == "long")
    total_short  = sum(e[2] for e in in_lb if e[1] == "short")
    latest_events = sorted(in_lb, key=lambda e: e[0], reverse=True)[:10]

    return jsonify({
        "ok":           True,
        "symbol":       symbol,
        "exchange":     exchange,
        "lookback_min": lookback_min,
        "env_vars": {
            "ZYNI_LM_WS_ENABLED":                  _bin_ws_enabled,
            "ZYNI_LM_MULTI_EXCHANGE_WS_ENABLED":   _mx_ws_enabled,
        },
        "sources":      sources_info,
        "total_events_in_lookback": len(in_lb),
        "total_long_liq_usd":  round(total_long),
        "total_short_liq_usd": round(total_short),
        "latest_events": [
            {
                "ts_ms": int(e[0] * 1000),
                "side":  e[1],
                "usd":   round(e[2]),
                "age_s": round(now_s - e[0], 1),
            }
            for e in latest_events
        ],
    })


@app.route("/api/live-monitor/data-health", methods=["GET"])
@login_required
def api_lm_data_health():
    """Return 11-row Data Health snapshot. Read-only. Phase 10.4 refactored.
    Split-source contract: Live/Mark Price from parent_setup_exchange,
    market context (OB/Delta/OI/Funding/etc.) from selected analysis_source.
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    symbol   = (request.args.get("symbol")   or "").upper().strip()
    exchange = (request.args.get("exchange") or "binance").lower().strip()

    if not symbol:
        return jsonify({"error": "symbol_required"}), 400

    # Load snapshot + resolve parent setup exchange
    snap = {}
    parent_exchange = exchange  # default same as analysis source
    try:
        from models import LiveMonitorItem as _LMIDH
        _lm_snap_row = _LMIDH.query.filter_by(
            symbol=symbol, is_active=True, user_id=uid).first()
        if _lm_snap_row:
            snap = _json_loads_safe(_lm_snap_row.snapshot_json, {})
            parent_exchange = _lm_normalize_exchange(
                getattr(_lm_snap_row, "exchange", None)
            ) or exchange
    except Exception as e:
        print(f"[LM-DH] snapshot error: {e}")

    # Start WS for parent exchange (needed for price rows regardless of analysis source)
    ws_enabled = os.environ.get("ZYNI_LM_WS_ENABLED") == "1"
    if ws_enabled and parent_exchange == "binance":
        _lm_ws_ensure_adhoc(symbol)
        _ensure_lm_ws_thread()
        _ensure_lm_liq_thread()
        _ensure_lm_delta_thread()
        _ob_wait = 3.0 if exchange == "binance" else 0.5
        ensure_ob_stream(symbol, wait_sec=_ob_wait)
        _ws_has  = f"binance:{symbol}" in _lm_ws_cache
        _liq_has = f"binance:{symbol}" in _lm_liq_cache
        _dlt_has = f"binance:{symbol}" in _lm_delta_cache
        _ob_has  = bool((_ob_books.get(symbol) or {}).get("ready"))
        print(f"[LM-WS] ensure {symbol}/{parent_exchange} subscriptions "
              f"(analysis={exchange}): "
              f"price={_ws_has} liq={_liq_has} delta={_dlt_has} ob={_ob_has} "
              f"adhoc={sorted(_lm_ws_adhoc_syms)} build={_BUILD_COMMIT}")

    ctx = _lm_build_data_health_context(symbol, exchange, snap=snap, user_id=uid)

    # Split-source: override price rows with parent exchange data when sources differ
    if parent_exchange and parent_exchange != exchange:
        ctx["rows"] = _lm_inject_parent_price_rows(
            symbol, parent_exchange, exchange, list(ctx.get("rows", []))
        )

    # Add source contract metadata
    ctx["parent_setup_exchange"] = parent_exchange
    ctx["analysis_source"]       = exchange
    ctx["price_source_exchange"] = parent_exchange
    ctx["market_context_source"] = exchange

    # Build structured panels (non-blocking; errors return ok=False)
    try:
        _ob_wall = _lm_build_ob_wall_map(symbol, exchange)
    except Exception as _e:
        _ob_wall = {"ok": False, "status": "error", "bids": [], "asks": [], "summary": {},
                    "message": str(_e)[:120]}
    try:
        _sweep_rekt = _lm_build_sweep_rekt_map(symbol, exchange)
    except Exception as _e:
        _sweep_rekt = {"ok": False, "status": "error", "events": [], "message": str(_e)[:120]}

    return jsonify({"ok": True, "build_commit": _BUILD_COMMIT,
                    "order_book_wall_map": _ob_wall,
                    "sweep_rekt_map": _sweep_rekt,
                    **ctx})


@app.route("/api/live-monitor/price", methods=["GET"])
@login_required
def api_lm_price():
    """Lightweight live-price endpoint for 1s UI timer.
    Supports exchange=binance|bybit|okx|mexc|aggregated.
    Reuses agg_lp_* cache from aggregated builder (TTL=5s). < 100ms.
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    symbol   = (request.args.get("symbol")   or "").upper().strip()
    exchange = (request.args.get("exchange") or "binance").lower().strip()

    if not symbol:
        return jsonify({"error": "symbol_required"}), 400

    # Ensure Binance WS is subscribed for this symbol regardless of exchange param.
    # The WS subscription is normally triggered by api_lm_data_health, but the 1s
    # price timer may fire before the first DH response returns.
    ws_enabled = os.environ.get("ZYNI_LM_WS_ENABLED") == "1"
    if ws_enabled:
        _lm_ws_ensure_adhoc(symbol)
        _ensure_lm_ws_thread()

    def _ret(payload: dict):
        payload["build_commit"] = _BUILD_COMMIT
        print(f"[LM-PRICE-API] symbol={symbol} exchange={exchange} "
              f"ok={bool(payload.get('live_price'))} "
              f"price={payload.get('live_price')} source={payload.get('source')}")
        return jsonify(payload)

    # Fast path: Binance WS cache (in-memory, < 1ms)
    if exchange == "binance":
        ws_e, ws_s = _lm_ws_get("binance", symbol)
        if ws_e and ws_e.get("live_price"):
            mp = ws_e.get("mark_price")
            return _ret({
                "ok":         True,
                "symbol":     symbol,
                "exchange":   "binance",
                "live_price": f"{ws_e['live_price']:.4f}",
                "mark_price": f"{mp:.4f}" if mp is not None else None,
                "status":     ws_s,
                "age_sec":    ws_e.get("data_age_sec", 0),
                "source":     "binance_ws",
            })

    # Aggregated: read-only cache pass — NEVER block on REST calls from the 1s timer.
    # The DH 4s timer pre-warms agg_lp_* cache; this endpoint only reads what's warm.
    # Sequential REST calls across 4 exchanges (4s×4 = 16s) would hang the worker.
    if exchange == "aggregated":
        agg_prices  = []
        agg_srcs    = []
        _now_agg    = time.time()

        # Binance WS direct: in-memory, instant
        _ws_a, _ = _lm_ws_get("binance", symbol)
        if _ws_a and _ws_a.get("live_price"):
            agg_prices.append(float(_ws_a["live_price"]))
            agg_srcs.append("binance")

        # Non-Binance: read existing cache entries only (no fetch_fn call)
        with _lm_rest_lock:
            for _ex_a in ("bybit", "okx", "mexc"):
                _e = _lm_rest_cache.get(f"agg_lp_{_ex_a}:{symbol}")
                if _e and (_now_agg - _e["ts"]) < 10:
                    _lp_a = _e["data"]
                    if _lp_a and _lp_a.get("available") and _lp_a.get("price", 0) > 0:
                        agg_prices.append(float(_lp_a["price"]))
                        agg_srcs.append(_ex_a)

        agg_skip = [e for e in _LM_AGGREGATED_EXCHANGES if e not in agg_srcs]

        if agg_prices:
            agg_prices.sort()
            _mid = len(agg_prices) // 2
            agg_val = (agg_prices[_mid] if len(agg_prices) % 2
                       else (agg_prices[_mid - 1] + agg_prices[_mid]) / 2)
            pf = f"{agg_val:.4f}"
            return _ret({
                "ok":              True,
                "symbol":          symbol,
                "exchange":        "aggregated",
                "live_price":      pf,
                "mark_price":      pf,
                "status":          "fresh" if len(agg_srcs) >= 2 else "partial",
                "age_sec":         0,
                "source":          "aggregated",
                "sources_used":    agg_srcs,
                "sources_skipped": agg_skip,
            })
        # Cache cold — fall through to Binance REST fallback below
        # (DH 4s timer will warm the agg_lp_* cache within seconds)

    # Single non-Binance exchange: reuse agg_lp_* cache (TTL=5s, shared with aggregated builder)
    if exchange in ("bybit", "okx", "mexc"):
        lp = _lm_rest_cached(
            f"agg_lp_{exchange}:{symbol}", 5,
            lambda: _lm_fetch_exchange_live_price(exchange, symbol)
        )
        if lp and lp.get("available") and lp.get("price", 0) > 0:
            pf = f"{float(lp['price']):.4f}"
            return _ret({
                "ok":         True,
                "symbol":     symbol,
                "exchange":   exchange,
                "live_price": pf,
                "mark_price": pf,
                "status":     lp.get("status", "fresh"),
                "age_sec":    0,
                "source":     lp.get("source", f"{exchange}_rest"),
            })

    # Final fallback: Binance REST mark-price cache (works even without WS).
    # This is the 1s price hot-path — use a dedicated short-TTL (3s) key so the
    # live price stays fresh when the WebSocket is disabled, without disturbing
    # the shared 10s `mark:` cache that the 4s Data Health rows rely on.
    rest_m = _lm_rest_cached(
        f"pxfast:{symbol}", 3, lambda: _lm_fetch_mark_price_rest(symbol)
    )
    if rest_m and rest_m.get("mark_price"):
        rv = f"{rest_m['mark_price']:.4f}"
        return _ret({
            "ok":         True,
            "symbol":     symbol,
            "exchange":   exchange,
            "live_price": rv,
            "mark_price": rv,
            "status":     "fresh",
            "age_sec":    0,
            "source":     "binance_mark_rest",
        })

    return _ret({
        "ok": True, "symbol": symbol, "exchange": exchange,
        "live_price": None, "mark_price": None,
        "status": "unavailable", "source": "none",
    })


@app.route("/api/live-monitor/ws-debug", methods=["GET"])
@login_required
def api_lm_ws_debug():
    """Compact read-only WebSocket cache debug.
    GET /api/live-monitor/ws-debug?symbol=WLDUSDT&exchange=binance
    No DB mutation. No trading. No order placement. No private API."""
    symbol   = (request.args.get("symbol")   or "").upper().strip()
    exchange = (request.args.get("exchange") or "binance").lower().strip()

    now = time.time()

    def _age(ts):
        if not ts:
            return None
        return round(now - ts, 1)

    ws_entry, _ws_s = _lm_ws_get(exchange, symbol) if symbol else (None, None)
    liq_entry, _liq_s = _lm_liq_get(exchange, symbol) if symbol else (None, None)
    delta_entry, _delta_s = _lm_delta_get(exchange, symbol) if symbol else (None, None)

    with _ob_book_lock:
        ob_raw = dict(_ob_books.get(symbol) or {})

    ws_enabled = os.environ.get("ZYNI_LM_WS_ENABLED") == "1"
    with _lm_ws_adhoc_lock:
        adhoc = sorted(_lm_ws_adhoc_syms)

    return jsonify({
        "ok": True,
        "symbol": symbol,
        "exchange": exchange,
        "ws_enabled": ws_enabled,
        "adhoc_symbols": adhoc,
        "threads": {
            "markprice_alive": bool(_lm_ws_manager_thread and _lm_ws_manager_thread.is_alive()),
            "liq_alive":       bool(_lm_liq_thread and _lm_liq_thread.is_alive()),
            "delta_alive":     bool(_lm_delta_thread and _lm_delta_thread.is_alive()),
        },
        "cache": {
            "live_price_age_sec":  _age(ws_entry.get("last_update_ts")) if ws_entry else None,
            "mark_price_age_sec":  _age(ws_entry.get("last_update_ts")) if ws_entry else None,
            "live_price":          ws_entry.get("live_price") if ws_entry else None,
            "mark_price":          ws_entry.get("mark_price") if ws_entry else None,
            "funding_rate":        ws_entry.get("funding_rate") if ws_entry else None,
            "delta_age_sec":       _age(delta_entry.get("last_update_ts")) if delta_entry else None,
            "liq_age_sec":         _age(liq_entry.get("last_update_ts")) if liq_entry else None,
            "orderbook_ready":     ob_raw.get("ready", False),
            "orderbook_age_sec":   _age(ob_raw.get("ts")) if ob_raw else None,
        },
    })


@app.route("/api/live-monitor/analysis-source/debug", methods=["GET"])
@login_required
def api_lm_analysis_source_debug():
    """Read-only debug endpoint — Phase 10.7 aggregated/specific exchange metric data.

    GET /api/live-monitor/analysis-source/debug?symbol=BTCUSDT&source=aggregated
    GET /api/live-monitor/analysis-source/debug?symbol=BTCUSDT&source=bybit&item_id=42

    No DB mutation. No snapshot write. No trading. No order placement. No private API.
    """
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    # ── symbol: uppercase, must be non-empty USDT pair ──────────────────────
    symbol = (request.args.get("symbol") or "").upper().strip()
    if not symbol:
        return jsonify({"error": "symbol_required",
                        "detail": "Provide ?symbol=BTCUSDT"}), 400
    if not symbol.endswith("USDT") or len(symbol) < 6:
        return jsonify({"error": "invalid_symbol",
                        "detail": "Symbol must be an uppercase USDT pair, e.g. BTCUSDT"}), 400

    # ── source: normalise; unknown → binance ────────────────────────────────
    source = _lm_normalize_analysis_source(
        (request.args.get("source") or "aggregated").lower().strip()
    )

    # ── optional item_id: ownership check, snapshot load ────────────────────
    item_id_raw = request.args.get("item_id")
    row  = None
    snap = {}
    if item_id_raw is not None:
        try:
            item_id_int = int(item_id_raw)
        except (ValueError, TypeError):
            return jsonify({"error": "invalid_item_id"}), 400
        try:
            from models import LiveMonitorItem as _LMIDbg
            row = _LMIDbg.query.filter_by(id=item_id_int, is_active=True).first()
        except Exception:
            row = None
        if row is None:
            return jsonify({"error": "item_not_found"}), 404
        if getattr(row, "user_id", None) != uid:
            return jsonify({"error": "forbidden"}), 403
        snap = _json_loads_safe(getattr(row, "snapshot_json", None), {})

    # ── resolve analysis source config (no DB write) ─────────────────────────
    asc = _lm_analysis_source_config(row, snapshot=snap, selected_source=source)

    # ── fetch exchange data (read-only) ──────────────────────────────────────
    try:
        if source == "aggregated":
            data = _lm_build_true_aggregated_exchange_data(symbol, snap)
        else:
            data = _lm_build_specific_exchange_data_with_fallback(symbol, source, snap)
    except Exception as _exc:
        return jsonify({"ok": False, "symbol": symbol, "analysis_source": source,
                        "error": str(_exc)}), 500

    # ── data health (read-only) ───────────────────────────────────────────────
    try:
        dh = _lm_build_data_health_context(symbol, source, snap=snap)
    except Exception:
        dh = {}

    return jsonify({
        "ok":                   True,
        "phase":                "phase10_7_true_aggregated_exchange_data",
        "symbol":               symbol,
        "analysis_source":      data.get("analysis_source", source),
        "parent_setup_exchange": asc["parent_setup_exchange"],
        "price_levels_source":  "parent_setup_exchange",
        "execution_exchange":   "not_in_scope_phase10_7",
        "metrics":              data.get("metrics", {}),
        "sources_used":         data.get("sources_used", []),
        "sources_skipped":      data.get("sources_skipped", []),
        "ai_data_gate":         data.get("ai_data_gate", {}),
        "data_health":          dh,
        "warnings":             data.get("warnings", []),
        "fetched_at":           data.get("fetched_at"),
        "debug_note":           (
            "Read-only debug endpoint. Analysis source is confirmation only; "
            "parent setup exchange remains source of truth for zones/SL/TP."
        ),
    })


# ── Phase 10.8: OB Distance/Approach Settings ────────────────────────────────

_LM_OB_SETTINGS_DEFAULTS = {
    "5m":  {"distance_pct": 0.50, "approach_pct": 0.15},
    "15m": {"distance_pct": 0.80, "approach_pct": 0.25},
    "30m": {"distance_pct": 1.00, "approach_pct": 0.35},
    "1h":  {"distance_pct": 1.50, "approach_pct": 0.50},
    "4h":  {"distance_pct": 2.50, "approach_pct": 0.80},
    "1d":  {"distance_pct": 4.00, "approach_pct": 1.20},
}

_LM_OB_VALID_TFS = set(_LM_OB_SETTINGS_DEFAULTS.keys())


def _lm_ob_settings_load(uid) -> dict:
    """Load persisted OB distance/approach settings for uid.

    Primary: UserPreference.ob_da_settings_json (DB, survives redeploy).
    Fallback: /tmp file (ephemeral, for local dev / DB unavailable).
    """
    try:
        from models import UserPreference as _UP
        row = _UP.query.filter_by(user_id=uid).first()
        if row and row.ob_da_settings_json:
            return _json_loads_safe(row.ob_da_settings_json, {})
    except Exception:
        pass
    # Fallback: /tmp (ephemeral, not reliable on Koyeb but better than nothing)
    try:
        path = f"/tmp/zyni_ob_settings_{uid}.json"
        if os.path.exists(path):
            with open(path) as f:
                return json.load(f)
    except Exception:
        pass
    return {}


def _lm_ob_settings_save(uid, settings: dict):
    """Persist OB distance/approach settings for uid.

    Primary: UserPreference.ob_da_settings_json (DB, survives redeploy).
    Also writes /tmp as a local fallback.
    """
    raw = _json_dumps_safe(settings)
    # Primary: DB
    try:
        from models import UserPreference as _UP, db as _db
        row = _UP.query.filter_by(user_id=uid).first()
        if row is None:
            row = _UP(user_id=uid)
            _db.session.add(row)
        row.ob_da_settings_json = raw
        _db.session.commit()
    except Exception:
        pass
    # Also write /tmp as ephemeral fallback
    try:
        path = f"/tmp/zyni_ob_settings_{uid}.json"
        with open(path, "w") as f:
            f.write(raw)
    except Exception:
        pass


@app.route("/api/live-monitor/ob-settings", methods=["GET"])
@login_required
def api_lm_ob_settings_get():
    """Return current OB distance/approach settings merged with defaults. Read-only."""
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401
    saved  = _lm_ob_settings_load(uid)
    merged = {tf: {**_LM_OB_SETTINGS_DEFAULTS.get(tf, {}), **saved.get(tf, {})}
              for tf in _LM_OB_SETTINGS_DEFAULTS}
    return jsonify({"ok": True, "settings": merged, "defaults": _LM_OB_SETTINGS_DEFAULTS})


@app.route("/api/live-monitor/ob-settings", methods=["POST"])
@login_required
def api_lm_ob_settings_post():
    """Save OB distance/approach settings. Accepts {settings:{...}} or {reset:true}."""
    uid, _ = _current_user_id_and_user()
    if not uid:
        return jsonify({"error": "no_user"}), 401

    body = request.get_json(force=True, silent=True) or {}

    # Reset path
    if body.get("reset"):
        _lm_ob_settings_save(uid, {})
        merged = {tf: dict(v) for tf, v in _LM_OB_SETTINGS_DEFAULTS.items()}
        return jsonify({"ok": True, "reset": True, "settings": merged,
                        "defaults": _LM_OB_SETTINGS_DEFAULTS})

    incoming = body.get("settings")
    if not isinstance(incoming, dict):
        return jsonify({"error": "settings_required",
                        "detail": "Provide {settings: {<tf>: {distance_pct, approach_pct}}}"}), 400

    errors   = []
    validated = {}
    for tf, vals in incoming.items():
        if tf not in _LM_OB_VALID_TFS:
            errors.append(f"Unknown timeframe: {tf!r}. Valid: {sorted(_LM_OB_VALID_TFS)}")
            continue
        if not isinstance(vals, dict):
            errors.append(f"{tf}: expected dict with distance_pct and approach_pct")
            continue
        entry = {}
        for field in ("distance_pct", "approach_pct"):
            v = vals.get(field)
            if v is None:
                continue
            try:
                fv = float(v)
            except (TypeError, ValueError):
                errors.append(f"{tf}.{field}: must be a float, got {v!r}")
                continue
            if not (0.01 <= fv <= 20.0):
                errors.append(f"{tf}.{field}: must be between 0.01 and 20.0, got {fv}")
                continue
            entry[field] = fv
        if entry:
            validated[tf] = entry

    if errors:
        return jsonify({"error": "validation_failed", "detail": errors}), 400

    # Merge with existing saved
    current = _lm_ob_settings_load(uid)
    for tf, entry in validated.items():
        current.setdefault(tf, {}).update(entry)
    _lm_ob_settings_save(uid, current)

    merged = {tf: {**_LM_OB_SETTINGS_DEFAULTS.get(tf, {}), **current.get(tf, {})}
              for tf in _LM_OB_SETTINGS_DEFAULTS}
    return jsonify({"ok": True, "settings": merged, "defaults": _LM_OB_SETTINGS_DEFAULTS,
                    "saved_tfs": sorted(validated.keys())})


# mobile UA fragments — keep small, case-insensitive
_MOBILE_UA_KEYS = (
    "iphone", "ipod", "android", "blackberry", "opera mini",
    "windows phone", "iemobile", "mobile safari", "mobile/",
)


def _is_mobile_ua(ua):
    """Heuristic mobile detection by User-Agent string. Modern iPadOS reports
    as desktop Mac — that's intentional (an iPad has the screen for the
    desktop view)."""
    ua = (ua or "").lower()
    return any(k in ua for k in _MOBILE_UA_KEYS)


def _detect_mobile(req):
    """Decide if a request should get the mobile UI.

    Priority:
      1. Sec-CH-UA-Mobile Client Hint (the reliable signal). Chrome &
         Edge — including Android Chrome in "Desktop site" mode —
         flip this from "?1" (mobile) to "?0" (desktop). Safari /
         Firefox don't send it, so we fall back.
      2. User-Agent sniff.
    """
    ch = (req.headers.get("Sec-CH-UA-Mobile") or "").strip().lower()
    if ch == "?0":
        return False     # explicit desktop request
    if ch == "?1":
        return True      # explicit mobile request
    return _is_mobile_ua(req.headers.get("User-Agent"))


_VIEW_COOKIE = "zyni-view"
_VIEW_COOKIE_MAX_AGE = 60 * 60 * 24 * 365   # 1 year


@app.route("/")
def index():
    # Anonymous → homepage (login screen). No cookies needed here.
    if not session.get("logged_in"):
        return render_template("homepage.html")

    username = session.get("username", "Trader")
    display_name = " ".join(w.capitalize() for w in username.strip().split())

    # Priority: explicit ?view= (and remember it via cookie) →
    # cookie set by a previous ?view= → UA sniff.
    forced = (request.args.get("view") or "").lower()
    set_cookie_to = None
    if forced in ("mobile", "desktop"):
        mobile = forced == "mobile"
        set_cookie_to = forced
    else:
        cookie_v = (request.cookies.get(_VIEW_COOKIE) or "").lower()
        if cookie_v in ("mobile", "desktop"):
            mobile = cookie_v == "mobile"
        else:
            mobile = _detect_mobile(request)

    tmpl = "index.html" if mobile else "preview.html"
    resp = make_response(render_template(tmpl, username=display_name))
    if set_cookie_to:
        resp.set_cookie(
            _VIEW_COOKIE, set_cookie_to,
            max_age=_VIEW_COOKIE_MAX_AGE, samesite="Lax", path="/",
        )
    return resp


