# ══════════════════════════════════════════════════════════════════════════════
# Phase 14 — Stability Lab Endpoint
# ══════════════════════════════════════════════════════════════════════════════

@app.route("/api/backtest/ob-historical/threshold-stability", methods=["POST"])
@login_required
def api_backtest_ob_historical_threshold_stability():
    err = _guest_tab_check("backtest")
    if err is not None:
        return err

    import time as _t14
    payload = request.get_json(force=True) or {}

    # Reject client-provided cell results
    if "cell_results" in payload:
        return jsonify({
            "ok": False,
            "error": "client_supplied_cell_results_not_allowed"
        }), 400

    # Parse symbols
    raw_syms = payload.get("symbols", ["BTCUSDT","ETHUSDT","BNBUSDT","SOLUSDT","XRPUSDT"])
    if not isinstance(raw_syms, list):
        raw_syms = [str(raw_syms)]
    seen_syms: set = set()
    symbols: List[str] = []
    for s in raw_syms:
        s = str(s).strip().upper()
        if not s:
            return jsonify({"ok": False, "error": "blank symbol not allowed"}), 400
        if not s.endswith("USDT"):
            s = s + "USDT"
        if s in seen_syms:
            continue  # deduplicate
        seen_syms.add(s)
        symbols.append(s)
    if not symbols:
        return jsonify({"ok": False, "error": "at least one symbol required"}), 400
    if len(symbols) > _STAB_MAX_SYMBOLS:
        return jsonify({"ok": False, "error": f"max {_STAB_MAX_SYMBOLS} symbols"}), 400

    # Parse timeframes
    raw_tfs = payload.get("timeframes", ["1h","4h"])
    if not isinstance(raw_tfs, list):
        raw_tfs = [str(raw_tfs)]
    seen_tfs: set = set()
    timeframes: List[str] = []
    allowed_tfs = {"1h","4h"}
    for tf in raw_tfs:
        tf = str(tf).strip()
        if tf not in allowed_tfs:
            return jsonify({"ok": False, "error": f"timeframe '{tf}' not allowed; use 1h or 4h"}), 400
        if tf in seen_tfs:
            continue
        seen_tfs.add(tf)
        timeframes.append(tf)
    if not timeframes:
        return jsonify({"ok": False, "error": "at least one timeframe required"}), 400
    if len(timeframes) > _STAB_MAX_TIMEFRAMES:
        return jsonify({"ok": False, "error": f"max {_STAB_MAX_TIMEFRAMES} timeframes"}), 400

    if len(symbols) * len(timeframes) > _STAB_MAX_CELLS:
        return jsonify({"ok": False, "error": f"max {_STAB_MAX_CELLS} cells"}), 400

    # Parse candle_count
    try:
        candle_count = int(payload.get("candle_count", 500))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "candle_count must be integer"}), 400
    candle_count = max(500, min(4000, candle_count))

    # Parse rr_values
    rr_values = _bt_parse_rr_values(payload.get("rr_values", [1,2,3]))

    ambiguity_mode = str(payload.get("ambiguity_mode", "mark")).strip() or "mark"
    include_parity = True  # always run parity server-side

    primary_metric = str(payload.get("primary_metric", "before_first_touch")).strip()
    if primary_metric not in ("before_first_touch", "at_formation"):
        primary_metric = "before_first_touch"

    t0 = _t14.time()

    # Run all cells server-side
    cell_results, exec_diag = _bt_run_threshold_stability_cells(
        symbols=symbols,
        timeframes=timeframes,
        candle_count=candle_count,
        rr_values=rr_values,
        ambiguity_mode=ambiguity_mode,
        include_parity=include_parity,
        primary_metric=primary_metric,
    )

    stability = _bt_build_tv_ob_pct_stability_analysis(
        cell_results=cell_results,
        thresholds=list(range(0, 105, 20)),  # 0,20,40,60,80,100
        rr_values=rr_values,
        primary_metric=primary_metric,
    )

    elapsed_total_ms = round((_t14.time() - t0) * 1000, 1)

    response_body = {
        "ok": True,
        "authoritative_execution": True,
        "client_results_accepted": False,
        "mode": "tv_ob_pct_threshold_stability_v1",
        "elapsed_total_ms": elapsed_total_ms,
        **exec_diag,
        "stability": stability,
    }

    import json as _json_size
    response_body["response_size_bytes"] = len(_json_size.dumps(response_body, default=str))

    return jsonify(response_body), 200


# ══════════════════════════════════════════════════════════════════════════════
# Phase 15 — Chronological Walk-Forward Validation (research only)
#
# Builds expanding-window train/test folds over a single candle history, selects
# (or locks) a TV OB% threshold candidate using TRAINING data only, then measures
# out-of-sample (test-only) realized performance. Never activates any threshold in
# Scanner / Live Monitor / alerts / paper trading / automation / execution.
# Reuses the Phase 13 threshold-analysis core and the Phase 14 aggregation/selection
# logic so train selection and test scoring share identical, audited code.
# ══════════════════════════════════════════════════════════════════════════════

_WF_BOOTSTRAP_ITERS:   int   = 5000
_WF_BOOTSTRAP_SEED:    int   = 15015
_WF_MIN_FOLDS:         int   = 3
_WF_MAX_FOLDS:         int   = 5
_WF_MIN_TRAIN_PCT:     float = 35.0
_WF_MAX_TRAIN_PCT:     float = 60.0
_WF_MIN_TEST_PCT:      float = 10.0
_WF_MAX_TEST_PCT:      float = 20.0
_WF_MIN_OOS_TRADES:    int   = 100
_WF_MIN_RETENTION:     float = 20.0
_WF_MIN_POSITIVE_FOLDS:float = 60.0
_WF_MIN_BEAT_FOLDS:    float = 60.0
_WF_MIN_POS_CELL_FOLD: float = 55.0
_WF_MIN_BEAT_CELL_FOLD:float = 55.0
_WF_WORST_FOLD_FLOOR:  float = -0.30
_WF_ALLOWED_TF:        set   = {"1h", "4h"}
_WF_ALLOWED_THRESHOLDS:list  = [0, 20, 40, 60, 80]
_WF_CANDIDATE_THRESHOLDS: list = [20, 40, 60, 80]
_WF_BUILD_COMMIT:      str   = "7215f6e"  # Phase 14B
_WF_MIN_SYMBOLS:       int   = 4
_WF_MIN_TF_CELL_FOLDS: int   = 2
_WF_15B_COMMIT:        str   = "708b769"  # Phase 15


def _bt_build_walk_forward_folds(
    candle_count: int,
    fold_count: int,
    initial_train_pct: float,
    test_pct: float,
) -> List[Dict]:
    """
    Build expanding-window walk-forward folds over [0, candle_count).

    Each fold trains on [0, train_end) and tests on [test_start, test_end), where
    train_end grows by `test_size` candles per fold. Training always ends exactly
    where testing begins (no overlap, no look-ahead). Test windows never overlap.

    Returns up to `fold_count` folds; stops early if candles run out. Time fields
    are filled later by the caller once candles are fetched.
    """
    train_size_base = int(candle_count * initial_train_pct / 100)
    test_size = int(candle_count * test_pct / 100)
    folds: List[Dict] = []
    if test_size < 1 or train_size_base < 1:
        return folds
    for i in range(fold_count):
        train_end = train_size_base + i * test_size
        test_start = train_end
        test_end = test_start + test_size
        if test_end > candle_count:
            break  # not enough candles for a complete test window
        folds.append({
            "fold": i + 1,
            "train_start_index": 0,
            "train_end_index_exclusive": train_end,
            "test_start_index": test_start,
            "test_end_index_exclusive": test_end,
            "train_candle_count": train_end,
            "test_candle_count": test_size,
            "train_start_time": None,
            "train_end_time": None,
            "test_start_time": None,
            "test_end_time": None,
        })
    return folds


def _bt_wf_first_touch_index(event: Dict):
    """Index of the candle where price first touched the OB zone (or None)."""
    return event.get("first_touch_bar")


def _bt_wf_event_id(sym: str, tf: str, event: Dict) -> str:
    """Stable event id: sym_tf_direction_formationBar_firstTouchBar."""
    direction = "bull" if str(event.get("type", "")).startswith("bull") else "bear"
    ob_formed = event.get("formation_bar")
    ft = _bt_wf_first_touch_index(event)
    return f"{sym}_{tf}_{direction}_{ob_formed}_{ft}"


def _bt_wf_filter_test_events(events: List[Dict], test_start: int, test_end: int) -> List[Dict]:
    """Keep events whose first touch falls inside [test_start, test_end)."""
    out: List[Dict] = []
    for e in events:
        ft = _bt_wf_first_touch_index(e)
        if ft is None:
            continue
        if test_start <= ft < test_end:
            out.append(e)
    return out


def _bt_wf_build_params(sym: str, tf: str, candle_count: int, rr_values: List) -> Dict:
    return {
        "symbol":          sym,
        "timeframe":       tf,
        "candle_count":    candle_count,
        "exchange":        "binance",
        "market":          "perpetual",
        "rr_values":       rr_values,
        "entry_rule":      "zone_high",
        "stop_rule":       "close_beyond_zone",
        "include_parity":  True,
    }


def _bt_wf_run_prefix_backtest(
    candles_full: List[Dict],
    end_index_exclusive: int,
    sym: str,
    tf: str,
    rr_values: List,
    primary_metric: str,
    stage: str,
    fold_num: int,
) -> Dict:
    """
    Physically slice candles to end_index_exclusive and run the full backtest
    pipeline (detector → outcomes → TV OB% snapshots → parity → threshold
    analysis) on the prefix.  The slice is the ONLY candle data any downstream
    helper receives — there is no full-array path.

    Returns events, parity, threshold_analysis, and a prefix_audit dict that
    proves physical isolation.
    """
    prefix = candles_full[:end_index_exclusive]
    params  = _bt_wf_build_params(sym, tf, len(prefix), rr_values)

    events = _bt_extract_ob_replay_events(prefix, params)
    _bt_apply_outcomes_to_events(events, prefix, params)
    _bt_attach_tv_ob_pct_snapshots(events, prefix, params)
    parity = _bt_run_tv_ob_pct_snapshot_parity(prefix, events, params)
    trusted = bool(parity.get("trusted", False))
    thr = _bt_build_tv_ob_pct_threshold_analysis(
        events, rr_values, trusted,
        metric=primary_metric,
        thresholds=_WF_ALLOWED_THRESHOLDS,
    )

    contract_passed = (len(prefix) == end_index_exclusive)
    audit = {
        "fold":                         fold_num,
        "symbol":                       sym,
        "timeframe":                    tf,
        "stage":                        stage,
        "allowed_end_index_exclusive":  end_index_exclusive,
        "input_candle_count":           len(prefix),
        "detector_input_candle_count":  len(prefix),
        "snapshot_input_candle_count":  len(prefix),
        "outcome_input_candle_count":   len(prefix),
        "max_detector_index_read":      len(prefix) - 1 if prefix else None,
        "max_snapshot_index_read":      len(prefix) - 1 if prefix else None,
        "max_outcome_index_read":       len(prefix) - 1 if prefix else None,
        "prefix_contract_passed":       contract_passed,
        "violations":                   [] if contract_passed else ["prefix_length_mismatch"],
    }

    return {
        "events":              events,
        "parity":              parity,
        "trusted":             trusted,
        "threshold_analysis":  {primary_metric: thr},
        "prefix_audit":        audit,
    }


def _bt_wf_future_candle_invariance(
    candles_full: List[Dict],
    test_end: int,
    sym: str,
    tf: str,
    rr_values: List,
    primary_metric: str,
    fold_num: int,
    original_event_ids: List[str],
    original_metrics_snapshot: Dict,
) -> Dict:
    """
    Appends extreme future candles to the full array and reruns with the SAME
    test_end boundary.  If any fold output differs, future-candle leakage is
    detected.  Returns a dict with invariance result.
    """
    n_future = 20
    future_high = 9_999_999.0
    future_low  = 0.001
    last_t = (candles_full[-1].get("open_time") or 0) if candles_full else 0
    future = [
        {
            "open_time":  last_t + (i + 1) * 3_600_000,
            "close_time": last_t + (i + 2) * 3_600_000 - 1,
            "open":  50_000.0, "high": future_high,
            "low":   future_low, "close": 50_000.0,
            "volume": 10_000.0,
        }
        for i in range(n_future)
    ]
    candles_with_future = candles_full + future

    result2 = _bt_wf_run_prefix_backtest(
        candles_with_future, test_end,
        sym, tf, rr_values, primary_metric, "invariance_check", fold_num,
    )

    events2 = result2["events"]
    ids2 = sorted(_bt_wf_event_id(sym, tf, e) for e in events2)
    ids1 = sorted(original_event_ids)

    invariant = (ids1 == ids2)
    violations = []
    if not invariant:
        violations.append(f"event_ids_changed_after_future_candles: fold={fold_num}")

    return {
        "passed":               invariant,
        "original_event_count": len(ids1),
        "rerun_event_count":    len(ids2),
        "future_candles_added": n_future,
        "violations":           violations,
    }


def _bt_wf_count_censored(test_events: List[Dict]) -> int:
    """Count eligible test events whose first outcome never resolved within range."""
    n = 0
    for e in test_events:
        sim = e.get("simulation") or {}
        if sim.get("eligible") and sim.get("first_outcome") in (None, "unresolved"):
            n += 1
    return n


def _bt_wf_extract_test_metrics(
    test_events: List[Dict],
    candidate_threshold_pct: int,
    candidate_rr: str,
    primary_metric: str,
    parity_trusted: bool,
    rr_values: List,
) -> Dict:
    """
    Run the Phase 13 threshold core on the test-window events and extract the
    candidate (threshold/rr) and baseline (threshold 0 / same rr) realized rows.
    """
    analysis = _bt_build_tv_ob_pct_threshold_analysis(
        test_events, rr_values, parity_trusted, metric=primary_metric,
        thresholds=_WF_ALLOWED_THRESHOLDS,
    )
    results = analysis.get("results", {}) or {}
    cand_key = str(int(candidate_threshold_pct))
    rrk = str(candidate_rr)
    cand_row = ((results.get(cand_key) or {}).get("realized_summary_by_rr") or {}).get(rrk) or {}
    base_row = ((results.get("0") or {}).get("realized_summary_by_rr") or {}).get(rrk) or {}

    cand_trades = int(cand_row.get("trades", 0) or 0)
    base_trades = int(base_row.get("trades", 0) or 0)
    cand_exp = cand_row.get("expectancy_r")
    base_exp = base_row.get("expectancy_r")
    exp_delta = (round(cand_exp - base_exp, 6)
                 if cand_exp is not None and base_exp is not None else None)
    retention = (round(cand_trades / base_trades * 100, 2) if base_trades else None)

    def _norm(row):
        return {
            "trades": int(row.get("trades", 0) or 0),
            "wins": int(row.get("wins", 0) or 0),
            "losses": int(row.get("losses", 0) or 0),
            "ambiguous": int(row.get("ambiguous", 0) or 0),
            "unresolved": int(row.get("unresolved", 0) or 0),
            "invalid_loss_r": int(row.get("invalid_loss_r", 0) or 0),
            "gross_profit_r": float(row.get("gross_profit_r", 0.0) or 0.0),
            "gross_loss_r": float(row.get("gross_loss_r", 0.0) or 0.0),
            "net_r": row.get("net_r"),
            "expectancy_r": row.get("expectancy_r"),
            "profit_factor_r": row.get("profit_factor_r"),
            "profit_factor_infinite": bool(row.get("profit_factor_infinite", False)),
            "win_rate_pct": row.get("win_rate_pct"),
        }

    return {
        "candidate_threshold_pct": int(candidate_threshold_pct),
        "candidate_rr": rrk,
        "candidate": _norm(cand_row),
        "baseline": _norm(base_row),
        "expectancy_delta_vs_baseline": exp_delta,
        "trade_retention_pct": retention,
    }


def _bt_select_walk_forward_training_candidate(
    training_cell_results: List[Dict],
    thresholds: List[int],
    rr_values: List,
) -> Tuple[Optional[Dict], Dict]:
    """
    Pick a candidate (threshold/rr) from TRAINING data only by reusing the Phase 14
    stability aggregation/selection on the per-cell training threshold analyses.
    Returns (candidate_or_None, full_stability_dict). No raw-winner fallback: if the
    training robustness gates fail, the recommendation is None and no candidate is
    selected for that fold.
    """
    stab = _bt_build_tv_ob_pct_stability_analysis(
        cell_results=training_cell_results,
        thresholds=sorted(set([0] + list(_WF_CANDIDATE_THRESHOLDS))),
        rr_values=rr_values,
        primary_metric="before_first_touch",
    )
    rec = stab.get("recommendation")
    if rec is None:
        return None, stab
    return {
        "threshold_pct": int(rec.get("threshold_pct")),
        "rr": str(rec.get("rr")),
    }, stab


def _bt_run_walk_forward_cell(
    sym: str,
    tf: str,
    candles_normalized: List[Dict],
    folds: List[Dict],
    rr_values: List,
    candidate_threshold_pct,
    candidate_rr,
    candidate_mode: str,
    thresholds: List[int],
    primary_metric: str = "before_first_touch",
) -> List[Dict]:
    """
    Run one symbol×timeframe cell across all folds.  For each fold the backtest
    engine receives ONLY a physically-sliced candle prefix — the full array is
    never passed downstream.  Returns per-fold dicts with prefix audit data and
    a future-candle invariance flag.
    """
    cell_results: List[Dict] = []

    for fold in folds:
        fold_num  = fold["fold"]
        train_end = fold["train_end_index_exclusive"]
        test_start = fold["test_start_index"]
        test_end  = fold["test_end_index_exclusive"]
        try:
            # ── Training prefix ───────────────────────────────────────────────
            train_result = _bt_wf_run_prefix_backtest(
                candles_normalized, train_end,
                sym, tf, rr_values, primary_metric, "training", fold_num,
            )
            train_events   = train_result["events"]
            train_parity   = train_result["parity"]
            train_trusted  = train_result["trusted"]
            train_thr      = train_result["threshold_analysis"]
            train_audit    = train_result["prefix_audit"]

            # ── Test prefix ───────────────────────────────────────────────────
            test_result  = _bt_wf_run_prefix_backtest(
                candles_normalized, test_end,
                sym, tf, rr_values, primary_metric, "test", fold_num,
            )
            test_all     = test_result["events"]
            test_parity  = test_result["parity"]
            test_trusted = test_result["trusted"]
            test_audit   = test_result["prefix_audit"]

            # ── Filter to test window by first touch ──────────────────────────
            test_events   = _bt_wf_filter_test_events(test_all, test_start, test_end)
            test_event_ids = [_bt_wf_event_id(sym, tf, e) for e in test_events]
            censored      = _bt_wf_count_censored(test_events)

            # Count resolved vs censored
            resolved_inside = sum(
                1 for e in test_events
                if (e.get("simulation") or {}).get("first_outcome") not in (None, "unresolved")
            )

            # Events outside window (those from test_all whose first touch != in window)
            events_outside_window = len(test_all) - len(
                _bt_wf_filter_test_events(test_all, 0, test_end)
            )
            # Simpler: events in test_all with first_touch NOT in [test_start, test_end)
            n_outside = sum(
                1 for e in test_all
                if _bt_wf_first_touch_index(e) is not None
                and not (test_start <= _bt_wf_first_touch_index(e) < test_end)
            )

            # ── Future-candle invariance ──────────────────────────────────────
            all_test_event_ids = [_bt_wf_event_id(sym, tf, e) for e in test_all]
            invariance = _bt_wf_future_candle_invariance(
                candles_normalized, test_end,
                sym, tf, rr_values, primary_metric, fold_num,
                all_test_event_ids, {},
            )

            # ── Locked-mode candidate metrics (computed now) ──────────────────
            metrics = None
            if candidate_mode == "locked" and candidate_threshold_pct is not None:
                metrics = _bt_wf_extract_test_metrics(
                    test_events, int(candidate_threshold_pct), str(candidate_rr),
                    primary_metric, test_trusted, rr_values,
                )

            cell_results.append({
                "ok":                       True,
                "symbol":                   sym,
                "timeframe":                tf,
                "fold":                     fold_num,
                "train_end_index_exclusive": train_end,
                "test_start_index":         test_start,
                "test_end_index_exclusive": test_end,
                "train_parity_trusted":     train_trusted,
                "test_parity_trusted":      test_trusted,
                "train_threshold_analysis": train_thr,
                "test_event_ids":           test_event_ids,
                "test_event_count":         len(test_events),
                "censored_unresolved":      censored,
                "resolved_inside_window":   resolved_inside,
                "events_outside_window":    n_outside,
                "metrics":                  metrics,
                "prefix_audits":            [train_audit, test_audit],
                "prefix_contract_passed":   (train_audit["prefix_contract_passed"]
                                             and test_audit["prefix_contract_passed"]),
                "future_candle_invariance": invariance["passed"],
                "_test_events":             test_events,   # stripped before response
                "_train_events":            train_events,  # stripped before response
            })
        except Exception as _e:
            traceback.print_exc()
            cell_results.append({
                "ok":                       False,
                "symbol":                   sym,
                "timeframe":                tf,
                "fold":                     fold_num,
                "error":                    f"wf_cell_exception: {_e}",
                "train_parity_trusted":     False,
                "test_parity_trusted":      False,
                "train_threshold_analysis": None,
                "test_event_ids":           [],
                "test_event_count":         0,
                "censored_unresolved":      0,
                "resolved_inside_window":   0,
                "events_outside_window":    0,
                "metrics":                  None,
                "prefix_audits":            [],
                "prefix_contract_passed":   False,
                "future_candle_invariance": False,
                "_test_events":             [],
                "_train_events":            [],
            })
    return cell_results


def _bt_aggregate_wf_fold(
    fold_cell_results: List[Dict],
    fold_info: Dict,
    candidate_threshold_pct,
    candidate_rr,
) -> Dict:
    """Aggregate all per-cell test metrics for a single fold (test-only)."""
    cand_gp = cand_gl = base_gp = base_gl = 0.0
    cand_trades = cand_wins = cand_losses = 0
    base_trades = base_wins = base_losses = 0
    cand_amb = cand_unres = cand_invalid = 0
    censored = resolved_inside = 0
    completed_cells = trusted_cells = 0
    cell_rows: List[Dict] = []
    symbols_in_fold: set = set()
    tfs_in_fold: set = set()

    for c in fold_cell_results:
        sym_c = c.get("symbol", "")
        tf_c  = c.get("timeframe", "")
        if not c.get("ok"):
            cell_rows.append({
                "symbol": sym_c, "timeframe": tf_c,
                "ok": False, "error": c.get("error"),
                "baseline_trades": 0, "trades": 0,
                "wins": 0, "losses": 0, "ambiguous": 0, "unresolved": 0,
                "censored_unresolved": 0, "invalid_loss_r": 0,
                "expectancy_r": None, "net_r": None,
                "baseline_expectancy_r": None, "expectancy_delta_vs_baseline": None,
                "trade_retention_pct": None,
                "baseline_profit_factor_r": None, "baseline_profit_factor_infinite": False,
                "candidate_profit_factor_r": None, "candidate_profit_factor_infinite": False,
                "baseline_net_r": None, "net_r_delta": None,
                "resolved_inside_window": 0,
                "prefix_contract_passed": False,
                "eligible": False, "rejection_reasons": ["cell_failed"],
            })
            continue

        m    = c.get("metrics") or {}
        cand = m.get("candidate") or {}
        base = m.get("baseline") or {}
        completed_cells += 1
        if c.get("test_parity_trusted"):
            trusted_cells += 1
        censored       += int(c.get("censored_unresolved", 0) or 0)
        resolved_inside += int(c.get("resolved_inside_window", 0) or 0)

        cand_gp    += float(cand.get("gross_profit_r", 0.0) or 0.0)
        cand_gl    += float(cand.get("gross_loss_r",   0.0) or 0.0)
        cand_trades += int(cand.get("trades", 0) or 0)
        cand_wins   += int(cand.get("wins",   0) or 0)
        cand_losses += int(cand.get("losses", 0) or 0)
        cand_amb    += int(cand.get("ambiguous",  0) or 0)
        cand_unres  += int(cand.get("unresolved", 0) or 0)
        cand_invalid += int(cand.get("invalid_loss_r", 0) or 0)

        base_gp    += float(base.get("gross_profit_r", 0.0) or 0.0)
        base_gl    += float(base.get("gross_loss_r",   0.0) or 0.0)
        base_trades += int(base.get("trades", 0) or 0)
        base_wins   += int(base.get("wins",   0) or 0)
        base_losses += int(base.get("losses", 0) or 0)

        cell_cand_t = int(cand.get("trades", 0) or 0)
        cell_elig   = cell_cand_t >= _MIN_AUTHORITATIVE_TRADES and int(cand.get("invalid_loss_r", 0) or 0) == 0 and c.get("test_parity_trusted", False)
        if cell_elig:
            symbols_in_fold.add(sym_c)
            tfs_in_fold.add(tf_c)

        c_pf, c_pf_inf = _stab_aggregate_pf(
            float(cand.get("gross_profit_r", 0.0) or 0.0),
            float(cand.get("gross_loss_r",   0.0) or 0.0),
        )
        b_pf, b_pf_inf = _stab_aggregate_pf(
            float(base.get("gross_profit_r", 0.0) or 0.0),
            float(base.get("gross_loss_r",   0.0) or 0.0),
        )
        cell_exp   = cand.get("expectancy_r")
        base_exp_c = base.get("expectancy_r")
        cell_delta = m.get("expectancy_delta_vs_baseline")
        cell_ret   = m.get("trade_retention_pct")
        c_net      = cand.get("net_r")
        b_net      = base.get("net_r")
        net_delta  = (round(float(c_net) - float(b_net), 4)
                      if c_net is not None and b_net is not None else None)

        rejection_reasons: List[str] = []
        if not c.get("test_parity_trusted"):
            rejection_reasons.append("parity_not_trusted")
        if cell_cand_t < _MIN_AUTHORITATIVE_TRADES:
            rejection_reasons.append("insufficient_trades")
        if int(cand.get("invalid_loss_r", 0) or 0) > 0:
            rejection_reasons.append("invalid_loss_r")

        cell_rows.append({
            "symbol": sym_c, "timeframe": tf_c,
            "ok": True, "error": None,
            "baseline_trades":               int(base.get("trades", 0) or 0),
            "trades":                        cell_cand_t,
            "wins":                          int(cand.get("wins",   0) or 0),
            "losses":                        int(cand.get("losses", 0) or 0),
            "ambiguous":                     int(cand.get("ambiguous",  0) or 0),
            "unresolved":                    int(cand.get("unresolved", 0) or 0),
            "censored_unresolved":           int(c.get("censored_unresolved", 0) or 0),
            "invalid_loss_r":                int(cand.get("invalid_loss_r", 0) or 0),
            "expectancy_r":                  cell_exp,
            "net_r":                         c_net,
            "baseline_expectancy_r":         base_exp_c,
            "expectancy_delta_vs_baseline":  cell_delta,
            "trade_retention_pct":           cell_ret,
            "candidate_profit_factor_r":     c_pf,
            "candidate_profit_factor_infinite": c_pf_inf,
            "baseline_profit_factor_r":      b_pf,
            "baseline_profit_factor_infinite": b_pf_inf,
            "baseline_net_r":                b_net,
            "net_r_delta":                   net_delta,
            "resolved_inside_window":        int(c.get("resolved_inside_window", 0) or 0),
            "prefix_contract_passed":        bool(c.get("prefix_contract_passed", False)),
            "eligible":                      cell_elig,
            "rejection_reasons":             rejection_reasons,
        })

    cand_net = round(cand_gp - cand_gl, 4)
    base_net = round(base_gp - base_gl, 4)
    cand_exp_micro = round(cand_net / cand_trades, 6) if cand_trades else None
    base_exp_micro = round(base_net / base_trades, 6) if base_trades else None
    cand_pf, cand_pf_inf = _stab_aggregate_pf(cand_gp, cand_gl)
    base_pf, base_pf_inf = _stab_aggregate_pf(base_gp, base_gl)

    micro_delta = (round(cand_exp_micro - base_exp_micro, 6)
                   if cand_exp_micro is not None and base_exp_micro is not None else None)
    retention   = round(cand_trades / base_trades * 100, 2) if base_trades else None

    eligible_rows = [r for r in cell_rows if r.get("eligible")]
    usable_cells  = len(eligible_rows)
    pos_cells     = sum(1 for r in eligible_rows if (r.get("expectancy_r") or 0) > 0)
    beat_rows     = [r for r in eligible_rows if r.get("expectancy_delta_vs_baseline") is not None]
    beat_cells    = sum(1 for r in beat_rows if r["expectancy_delta_vs_baseline"] > 0)
    pos_cell_pct  = round(pos_cells  / usable_cells * 100, 1) if usable_cells else None
    beat_cell_pct = round(beat_cells / len(beat_rows) * 100, 1) if beat_rows else None

    # Macro expectancy = mean of eligible cell expectancies
    cell_exps = [r["expectancy_r"] for r in eligible_rows if r.get("expectancy_r") is not None]
    cand_exp_macro = round(sum(cell_exps) / len(cell_exps), 6) if cell_exps else None
    base_exps = [r["baseline_expectancy_r"] for r in eligible_rows if r.get("baseline_expectancy_r") is not None]
    base_exp_macro = round(sum(base_exps) / len(base_exps), 6) if base_exps else None
    macro_delta    = (round(cand_exp_macro - base_exp_macro, 6)
                      if cand_exp_macro is not None and base_exp_macro is not None else None)

    # Worst eligible cell expectancy
    worst_cell = min((r["expectancy_r"] for r in eligible_rows if r.get("expectancy_r") is not None), default=None)

    # Training expectancy for this fold (populated later by caller)
    pf_nd_ok, pf_nd_reason = _stab_pf_non_degraded(
        cand_pf, cand_pf_inf, base_pf, base_pf_inf,
        candidate_trades=cand_trades, baseline_trades=base_trades,
        baseline_gross_profit=round(base_gp, 4), baseline_gross_loss=round(base_gl, 4),
    )

    eligible_fold = (cand_trades >= _MIN_AUTHORITATIVE_TRADES and cand_invalid == 0)

    return {
        "fold":                          fold_info["fold"],
        "train_start_index":             fold_info.get("train_start_index", 0),
        "train_end_index_exclusive":     fold_info["train_end_index_exclusive"],
        "test_start_index":              fold_info["test_start_index"],
        "test_end_index_exclusive":      fold_info["test_end_index_exclusive"],
        "train_candle_count":            fold_info["train_candle_count"],
        "test_candle_count":             fold_info["test_candle_count"],
        "train_start_time":              fold_info.get("train_start_time"),
        "train_end_time":                fold_info.get("train_end_time"),
        "test_start_time":               fold_info.get("test_start_time"),
        "test_end_time":                 fold_info.get("test_end_time"),
        "candidate_threshold_pct":       (int(candidate_threshold_pct)
                                          if candidate_threshold_pct is not None else None),
        "candidate_rr":                  str(candidate_rr) if candidate_rr is not None else None,
        "requested_cells":               len(fold_cell_results),
        "completed_cells":               completed_cells,
        "trusted_cells":                 trusted_cells,
        "usable_cells":                  usable_cells,
        "symbols_represented":           sorted(symbols_in_fold),
        "timeframes_represented":        sorted(tfs_in_fold),
        "baseline_trades":               base_trades,
        "oos_trades":                    cand_trades,
        "oos_wins":                      cand_wins,
        "oos_losses":                    cand_losses,
        "oos_ambiguous":                 cand_amb,
        "oos_unresolved":                cand_unres,
        "oos_invalid_loss_r":            cand_invalid,
        "censored_unresolved":           censored,
        "resolved_inside_window":        resolved_inside,
        "oos_gross_profit_r":            round(cand_gp, 4),
        "oos_gross_loss_r":              round(cand_gl, 4),
        "oos_net_r":                     cand_net,
        "oos_expectancy_r":              cand_exp_micro,
        "candidate_micro_expectancy_r":  cand_exp_micro,
        "candidate_macro_expectancy_r":  cand_exp_macro,
        "baseline_expectancy_r":         base_exp_micro,
        "baseline_gross_profit_r":       round(base_gp, 4),
        "baseline_gross_loss_r":         round(base_gl, 4),
        "baseline_net_r":                base_net,
        "baseline_profit_factor_r":      base_pf,
        "baseline_profit_factor_infinite": base_pf_inf,
        "oos_profit_factor_r":           cand_pf,
        "oos_profit_factor_infinite":    cand_pf_inf,
        "pf_non_degradation_passed":     pf_nd_ok,
        "pf_non_degradation_reason":     pf_nd_reason,
        "expectancy_delta_vs_baseline":  micro_delta,
        "micro_expectancy_delta":        micro_delta,
        "macro_expectancy_delta":        macro_delta,
        "trade_retention_pct":           retention,
        "positive_cell_pct":             pos_cell_pct,
        "beat_baseline_cell_pct":        beat_cell_pct,
        "worst_cell_expectancy_r":       worst_cell,
        "training_expectancy_r":         None,  # filled by caller
        "eligible":                      eligible_fold,
        "cells":                         cell_rows,
    }


def _bt_wf_locked_candidate_constancy_audit(
    fold_aggregates: List[Dict],
    requested_threshold_pct,
    requested_rr,
) -> Dict:
    """
    Verify that every evaluable fold used exactly the requested locked threshold
    and RR.  Any variation is a constancy failure.
    """
    req_thr = int(requested_threshold_pct) if requested_threshold_pct is not None else None
    req_rr  = str(requested_rr) if requested_rr is not None else None

    thresholds_by_fold = []
    rrs_by_fold        = []
    fallback_used      = False

    for f in fold_aggregates:
        if not f.get("eligible"):
            continue
        t = f.get("candidate_threshold_pct")
        r = f.get("candidate_rr")
        thresholds_by_fold.append({"fold": f["fold"], "threshold_pct": t})
        rrs_by_fold.append({"fold": f["fold"], "rr": r})
        if t != req_thr or r != req_rr:
            fallback_used = True

    unique_thrs = set(x["threshold_pct"] for x in thresholds_by_fold)
    unique_rrs  = set(x["rr"] for x in rrs_by_fold)

    thr_constant = (len(unique_thrs) <= 1) and (not fallback_used)
    rr_constant  = (len(unique_rrs)  <= 1) and (not fallback_used)
    passed = thr_constant and rr_constant and (not fallback_used)

    return {
        "locked_candidate_audit": {
            "requested_threshold_pct":   req_thr,
            "requested_rr":              req_rr,
            "thresholds_observed_by_fold": thresholds_by_fold,
            "rrs_observed_by_fold":        rrs_by_fold,
            "threshold_constant":          thr_constant,
            "rr_constant":                 rr_constant,
            "fallback_candidate_used":     fallback_used,
            "passed":                      passed,
        }
    }


def _bt_wf_training_selection_timestamp_audit(
    folds: List[Dict],
    training_selection: List[Dict],
) -> List[Dict]:
    """
    Prove per fold that the training-data candidate was selected before the test
    window begins.  Uses data-boundary indices, not wall-clock times.
    """
    result = []
    for fold in folds:
        fold_num = fold["fold"]
        sel_entry = next(
            (s for s in training_selection if s.get("fold") == fold_num),
            None,
        )
        selected = sel_entry.get("selected") if sel_entry else None
        fallback = selected is None

        # Selection is point-in-time if train_end <= test_start (always true by construction)
        train_end  = fold["train_end_index_exclusive"]
        test_start = fold["test_start_index"]
        sel_before_test = (train_end <= test_start)

        result.append({
            "fold":                          fold_num,
            "training_end_index_exclusive":  train_end,
            "test_start_index":              test_start,
            "selection_completed_before_test": sel_before_test,
            "selected_threshold_pct":        int(selected["threshold_pct"]) if selected else None,
            "selected_rr":                   str(selected["rr"]) if selected else None,
            "fallback_used":                 fallback,
            "training_selection_passed":     sel_before_test and (not fallback),
        })
    return result


def _bt_wf_bootstrap_delta(evaluable_fold_deltas: List[float]) -> Dict:
    """
    Resample fold-level expectancy deltas with replacement.
    5000 iterations, seed 15015. Returns 2.5th/97.5th percentile CI.
    Returns null CI when fewer than _WF_MIN_FOLDS evaluable deltas.
    """
    deltas = [d for d in (evaluable_fold_deltas or []) if d is not None]
    if len(deltas) < _WF_MIN_FOLDS:
        return {
            "expectancy_delta_low":  None,
            "expectancy_delta_high": None,
            "iterations": _WF_BOOTSTRAP_ITERS,
            "seed":       _WF_BOOTSTRAP_SEED,
            "insufficient_folds": True,
        }
    rng = _random.Random(_WF_BOOTSTRAP_SEED)
    n = len(deltas)
    means = []
    for _ in range(_WF_BOOTSTRAP_ITERS):
        sample = [deltas[rng.randrange(n)] for _ in range(n)]
        means.append(sum(sample) / n)
    means.sort()
    low_idx  = int(_WF_BOOTSTRAP_ITERS * 0.025)   # 125
    high_idx = int(_WF_BOOTSTRAP_ITERS * 0.975)   # 4875
    return {
        "expectancy_delta_low":  round(means[low_idx],  6),
        "expectancy_delta_high": round(means[high_idx], 6),
        "iterations": _WF_BOOTSTRAP_ITERS,
        "seed":       _WF_BOOTSTRAP_SEED,
        "insufficient_folds": False,
    }


def _bt_wf_lookahead_audit(
    folds: List[Dict],
    all_fold_test_event_ids: Dict,
    cell_fold_results: Dict,   # keyed by "sym_tf"
) -> Dict:
    """
    Comprehensive look-ahead integrity audit.  Returns a 'passed' boolean that
    is derived from actual execution metadata — no hardcoded values.
    """
    violations: List[str] = []

    # ── 1. Fold boundaries: train ends exactly at test start ──────────────────
    boundaries_valid = True
    for f in folds:
        if f["train_end_index_exclusive"] != f["test_start_index"]:
            boundaries_valid = False
            violations.append(
                f"fold {f['fold']}: train_end {f['train_end_index_exclusive']} "
                f"!= test_start {f['test_start_index']}"
            )

    # ── 2. Training ends before test starts (train_end <= test_start) ─────────
    train_before_test = True
    for f in folds:
        if not (f["train_end_index_exclusive"] <= f["test_start_index"]):
            train_before_test = False
            violations.append(f"fold {f['fold']}: train overlaps test")

    # ── 3. Test windows non-overlapping ───────────────────────────────────────
    windows = sorted(
        [(f["test_start_index"], f["test_end_index_exclusive"]) for f in folds],
        key=lambda w: w[0],
    )
    overlap = False
    for i in range(1, len(windows)):
        if windows[i][0] < windows[i - 1][1]:
            overlap = True
            violations.append(
                f"test windows overlap: [{windows[i-1][0]},{windows[i-1][1]}) "
                f"and [{windows[i][0]},{windows[i][1]})"
            )

    # ── 4. Events assigned by first touch (not formation bar) ─────────────────
    events_assigned_by_first_touch = True  # structural: filter uses first_touch_bar

    # ── 5. Training prefix isolated ───────────────────────────────────────────
    # Proved by physical slicing: collect all training prefix audits
    train_prefix_isolated = True
    n_prefix_checked = 0
    n_prefix_failed  = 0
    for key, fold_rows in cell_fold_results.items():
        for row in fold_rows:
            for pa in row.get("prefix_audits", []):
                if pa.get("stage") == "training":
                    n_prefix_checked += 1
                    if not pa.get("prefix_contract_passed", False):
                        train_prefix_isolated = False
                        n_prefix_failed += 1
                        violations.append(
                            f"training prefix contract failed: "
                            f"{pa.get('symbol')} {pa.get('timeframe')} fold {pa.get('fold')}"
                        )

    # ── 6. Test prefix isolated ────────────────────────────────────────────────
    test_prefix_isolated = True
    for key, fold_rows in cell_fold_results.items():
        for row in fold_rows:
            for pa in row.get("prefix_audits", []):
                if pa.get("stage") == "test":
                    n_prefix_checked += 1
                    if not pa.get("prefix_contract_passed", False):
                        test_prefix_isolated = False
                        n_prefix_failed += 1
                        violations.append(
                            f"test prefix contract failed: "
                            f"{pa.get('symbol')} {pa.get('timeframe')} fold {pa.get('fold')}"
                        )

    # ── 7. Outcomes capped at fold end ─────────────────────────────────────────
    # Proved by physical prefix slicing: outcomes can only see candles up to test_end
    outcomes_capped = train_prefix_isolated and test_prefix_isolated

    # ── 8. Percentages point-in-time ──────────────────────────────────────────
    # TV OB% snapshots are attached on the prefix → point-in-time by construction
    percentages_point_in_time = test_prefix_isolated

    # ── 9. Future-candle invariance ───────────────────────────────────────────
    future_candle_invariance = True
    future_reads_detected = 0
    for key, fold_rows in cell_fold_results.items():
        for row in fold_rows:
            if not row.get("future_candle_invariance", True):
                future_candle_invariance = False
                future_reads_detected += 1
                violations.append(
                    f"future candle invariance failed: "
                    f"{row.get('symbol')} {row.get('timeframe')} fold {row.get('fold')}"
                )

    # ── 10. Duplicate event IDs ────────────────────────────────────────────────
    seen: set = set()
    dup = 0
    for _fold, ids in (all_fold_test_event_ids or {}).items():
        for eid in ids:
            if eid in seen:
                dup += 1
            else:
                seen.add(eid)
    if dup > 0:
        violations.append(f"duplicate_test_event_ids: {dup}")

    # ── 11. Events outside test window ────────────────────────────────────────
    n_outside_total = 0
    for key, fold_rows in cell_fold_results.items():
        for row in fold_rows:
            n_outside_total += int(row.get("events_outside_window", 0) or 0)

    passed = (
        boundaries_valid
        and train_before_test
        and (not overlap)
        and events_assigned_by_first_touch
        and train_prefix_isolated
        and test_prefix_isolated
        and outcomes_capped
        and percentages_point_in_time
        and future_candle_invariance
        and dup == 0
        and n_outside_total == 0
        and n_prefix_failed == 0
    )

    return {
        "passed":                          passed,
        "fold_boundaries_valid":           boundaries_valid,
        "training_ends_before_test_starts": train_before_test,
        "test_windows_non_overlapping":    (not overlap),
        "events_assigned_by_first_touch":  events_assigned_by_first_touch,
        "training_prefix_isolated":        train_prefix_isolated,
        "test_prefix_isolated":            test_prefix_isolated,
        "outcomes_capped_at_fold_end":     outcomes_capped,
        "percentages_point_in_time":       percentages_point_in_time,
        "future_candle_invariance":        future_candle_invariance,
        "duplicate_test_event_ids":        dup,
        "events_outside_test_window":      n_outside_total,
        "future_candle_reads_detected":    future_reads_detected,
        "prefix_audits_checked":           n_prefix_checked,
        "prefix_audits_failed":            n_prefix_failed,
        "violations":                      violations,
    }


def _bt_aggregate_wf_summary(
    fold_aggregates: List[Dict],
    candidate_mode: str,
    training_expectancy_by_fold: List,
    symbols_requested: List[str],
    timeframes_requested: List[str],
) -> Dict:
    """Aggregate test-only metrics across all folds. Training trades excluded."""
    evaluable = [f for f in fold_aggregates if f.get("eligible")]

    cand_gp = cand_gl = base_gp = base_gl = 0.0
    oos_trades = oos_wins = oos_losses = oos_amb = oos_unres = oos_invalid = 0
    censored = base_trades = 0
    fold_deltas: List[float] = []
    pos_folds = beat_folds = beat_eval = 0
    worst_fold = None

    # Cell-fold level counters
    total_cell_folds = pos_cell_folds = beat_cell_folds = 0
    eligible_1h_cell_folds = eligible_4h_cell_folds = 0
    sym_represented: set = set()
    tf_represented:  set = set()
    locked_thrs: set = set()
    locked_rrs:  set = set()

    for f in fold_aggregates:
        oos_trades += int(f.get("oos_trades", 0) or 0)
        oos_wins   += int(f.get("oos_wins",   0) or 0)
        oos_losses += int(f.get("oos_losses", 0) or 0)
        oos_amb    += int(f.get("oos_ambiguous",  0) or 0)
        oos_unres  += int(f.get("oos_unresolved", 0) or 0)
        oos_invalid += int(f.get("oos_invalid_loss_r", 0) or 0)
        censored   += int(f.get("censored_unresolved", 0) or 0)
        base_trades += int(f.get("baseline_trades", 0) or 0)
        cand_gp += float(f.get("oos_gross_profit_r",  0.0) or 0.0)
        cand_gl += float(f.get("oos_gross_loss_r",    0.0) or 0.0)
        base_gp += float(f.get("baseline_gross_profit_r", 0.0) or 0.0)
        base_gl += float(f.get("baseline_gross_loss_r",   0.0) or 0.0)

        for sym in (f.get("symbols_represented") or []):
            sym_represented.add(sym)
        for tf in (f.get("timeframes_represented") or []):
            tf_represented.add(tf)

        # Per-cell-fold counting (across all eligible cells in this fold)
        for cell in (f.get("cells") or []):
            if not cell.get("eligible"):
                continue
            total_cell_folds += 1
            tf_c = cell.get("timeframe", "")
            if tf_c == "1h":
                eligible_1h_cell_folds += 1
            elif tf_c == "4h":
                eligible_4h_cell_folds += 1
            if (cell.get("expectancy_r") or 0) > 0:
                pos_cell_folds += 1
            delta_c = cell.get("expectancy_delta_vs_baseline")
            if delta_c is not None and delta_c > 0:
                beat_cell_folds += 1

        if f.get("eligible"):
            if (f.get("oos_expectancy_r") or 0) > 0:
                pos_folds += 1
            d = f.get("expectancy_delta_vs_baseline")
            if d is not None:
                beat_eval += 1
                fold_deltas.append(d)
                if d > 0:
                    beat_folds += 1
            fe = f.get("oos_expectancy_r")
            if fe is not None:
                worst_fold = fe if worst_fold is None else min(worst_fold, fe)
            thr_f = f.get("candidate_threshold_pct")
            rr_f  = f.get("candidate_rr")
            if thr_f is not None: locked_thrs.add(thr_f)
            if rr_f  is not None: locked_rrs.add(rr_f)

    oos_net_r       = round(cand_gp - cand_gl, 4)
    baseline_net_r  = round(base_gp - base_gl, 4)
    oos_expectancy  = round(oos_net_r / oos_trades, 6) if oos_trades else None
    base_expectancy = round(baseline_net_r / base_trades, 6) if base_trades else None
    oos_exp_delta   = (round(oos_expectancy - base_expectancy, 6)
                       if oos_expectancy is not None and base_expectancy is not None else None)
    retention       = round(oos_trades / base_trades * 100, 2) if base_trades else None
    oos_pf,  oos_pf_inf  = _stab_aggregate_pf(cand_gp, cand_gl)
    base_pf, base_pf_inf = _stab_aggregate_pf(base_gp, base_gl)

    pos_fold_pct   = round(pos_folds  / len(evaluable) * 100, 1) if evaluable else None
    beat_fold_pct  = round(beat_folds / beat_eval * 100, 1)      if beat_eval  else None
    pos_cell_pct_  = round(pos_cell_folds  / total_cell_folds * 100, 1) if total_cell_folds else None
    beat_cell_pct_ = round(beat_cell_folds / total_cell_folds * 100, 1) if total_cell_folds else None

    locked_thr_constant = (len(locked_thrs) <= 1)
    locked_rr_constant  = (len(locked_rrs)  <= 1)

    # Annotate fold_aggregates with training expectancy
    for i, f in enumerate(fold_aggregates):
        te = training_expectancy_by_fold[i] if i < len(training_expectancy_by_fold) else None
        f["training_expectancy_r"] = te
        if te is not None and f.get("oos_expectancy_r") is not None:
            f["train_test_gap_r"] = round(float(te) - float(f["oos_expectancy_r"]), 6)
        else:
            f["train_test_gap_r"] = None

    return {
        "candidate_mode":                   candidate_mode,
        "requested_symbols":                len(symbols_requested),
        "symbols_represented":              len(sym_represented),
        "symbol_list_represented":          sorted(sym_represented),
        "requested_timeframes":             sorted(timeframes_requested),
        "timeframes_represented":           sorted(tf_represented),
        "eligible_1h_cell_folds":           eligible_1h_cell_folds,
        "eligible_4h_cell_folds":           eligible_4h_cell_folds,
        "total_eligible_cell_folds":        total_cell_folds,
        "positive_cell_folds":              pos_cell_folds,
        "beat_baseline_cell_folds":         beat_cell_folds,
        "positive_cell_fold_pct":           pos_cell_pct_,
        "beat_baseline_cell_fold_pct":      beat_cell_pct_,
        "locked_threshold_constant":        locked_thr_constant,
        "locked_rr_constant":               locked_rr_constant,
        "training_trades_in_oos":           0,  # structural guarantee: different prefixes
        "total_folds":                      len(fold_aggregates),
        "evaluable_folds":                  len(evaluable),
        "oos_trades":                       oos_trades,
        "oos_wins":                         oos_wins,
        "oos_losses":                       oos_losses,
        "oos_ambiguous":                    oos_amb,
        "oos_unresolved":                   oos_unres,
        "oos_invalid_loss_r":               oos_invalid,
        "censored_unresolved":              censored,
        "baseline_trades":                  base_trades,
        "oos_gross_profit_r":               round(cand_gp, 4),
        "oos_gross_loss_r":                 round(cand_gl, 4),
        "oos_net_r":                        oos_net_r,
        "baseline_net_r":                   baseline_net_r,
        "oos_expectancy_r":                 oos_expectancy,
        "baseline_expectancy_r":            base_expectancy,
        "oos_expectancy_delta_vs_baseline": oos_exp_delta,
        "oos_profit_factor_r":              oos_pf,
        "oos_profit_factor_infinite":       oos_pf_inf,
        "baseline_profit_factor_r":         base_pf,
        "baseline_profit_factor_infinite":  base_pf_inf,
        "oos_trade_retention_pct":          retention,
        "positive_folds":                   pos_folds,
        "positive_fold_pct":                pos_fold_pct,
        "beat_baseline_folds":              beat_folds,
        "beat_baseline_fold_pct":           beat_fold_pct,
        "worst_fold_expectancy_r":          worst_fold,
        "evaluable_fold_deltas":            fold_deltas,
        "training_expectancy_by_fold":      training_expectancy_by_fold,
    }


def _bt_wf_check_pass_gates(
    summary: Dict,
    fold_aggregates: List[Dict],
    lookahead_audit: Dict,
    authoritative: bool,
    candidate_mode: str,
    bootstrap: Dict,
    constancy_audit: Dict,
    candidate_threshold_pct,
    timeframes_requested: List[str],
) -> Tuple[bool, List[str]]:
    """
    Evaluate 30 locked-mode pass gates.  Returns (passes, sorted_failed_gates).
    train_selected mode never returns authoritative PASS here.
    """
    failed: List[str] = []

    # 1. Server authority
    if not authoritative:
        failed.append("not_server_authoritative")
    # 2. Look-ahead integrity (full audit)
    if not lookahead_audit.get("passed"):
        failed.append("lookahead_violation")
    # 3. Minimum evaluable folds (≥3)
    if summary.get("evaluable_folds", 0) < _WF_MIN_FOLDS:
        failed.append("insufficient_evaluable_folds")
    # 4. Minimum 4 distinct symbols in eligible OOS cells
    if summary.get("symbols_represented", 0) < _WF_MIN_SYMBOLS:
        failed.append("insufficient_symbols_represented")
    # 5. Both 1h and 4h represented in eligible OOS cells
    tfs_rep = set(summary.get("timeframes_represented") or [])
    if "1h" not in tfs_rep or "4h" not in tfs_rep:
        failed.append("missing_1h_or_4h_coverage")
    # 6. At least 2 eligible 1h cell-fold observations
    if summary.get("eligible_1h_cell_folds", 0) < _WF_MIN_TF_CELL_FOLDS:
        failed.append("insufficient_1h_cell_folds")
    # 7. At least 2 eligible 4h cell-fold observations
    if summary.get("eligible_4h_cell_folds", 0) < _WF_MIN_TF_CELL_FOLDS:
        failed.append("insufficient_4h_cell_folds")
    # 8. Total OOS trades ≥ 100
    if summary.get("oos_trades", 0) < _WF_MIN_OOS_TRADES:
        failed.append("insufficient_oos_trades")
    # 9. OOS retention ≥ 20%
    if (summary.get("oos_trade_retention_pct") or 0) < _WF_MIN_RETENTION:
        failed.append("retention_below_floor")
    # 10. OOS micro expectancy > baseline
    d = summary.get("oos_expectancy_delta_vs_baseline")
    if d is None or d <= 0:
        failed.append("oos_micro_expectancy_not_above_baseline")
    # 11. Macro fold expectancy delta > 0 (mean of fold deltas)
    fold_deltas = summary.get("evaluable_fold_deltas") or []
    macro_delta = sum(fold_deltas) / len(fold_deltas) if fold_deltas else None
    if macro_delta is None or macro_delta <= 0:
        failed.append("oos_macro_fold_delta_not_positive")
    # 12. OOS net R > 0
    if (summary.get("oos_net_r") or 0) <= 0:
        failed.append("oos_net_r_not_positive")
    # 13. Positive folds ≥ 60%
    if (summary.get("positive_fold_pct") or 0) < _WF_MIN_POSITIVE_FOLDS:
        failed.append("positive_folds_below_floor")
    # 14. Beat-baseline folds ≥ 60%
    if (summary.get("beat_baseline_fold_pct") or 0) < _WF_MIN_BEAT_FOLDS:
        failed.append("beat_baseline_folds_below_floor")
    # 15. Positive eligible cell-fold observations ≥ 55%
    if (summary.get("positive_cell_fold_pct") or 0) < _WF_MIN_POS_CELL_FOLD:
        failed.append("positive_cell_fold_pct_below_floor")
    # 16. Beat-baseline eligible cell-fold observations ≥ 55%
    if (summary.get("beat_baseline_cell_fold_pct") or 0) < _WF_MIN_BEAT_CELL_FOLD:
        failed.append("beat_baseline_cell_fold_pct_below_floor")
    # 17. Worst fold expectancy ≥ -0.30R
    wf_e = summary.get("worst_fold_expectancy_r")
    if wf_e is None or wf_e < _WF_WORST_FOLD_FLOOR:
        failed.append("worst_fold_below_floor")
    # 18. Bootstrap CI lower bound ≥ 0
    ci_low = bootstrap.get("expectancy_delta_low")
    if bootstrap.get("insufficient_folds") or ci_low is None or ci_low <= 0:
        failed.append("bootstrap_ci_low_not_positive")
    # 19. PF non-degradation (checked per eligible fold)
    pf_deg = False
    for f in fold_aggregates:
        if not f.get("eligible"):
            continue
        if not f.get("pf_non_degradation_passed", False):
            pf_deg = True
    if pf_deg:
        failed.append("profit_factor_degraded")
    # 20. No invalid loss R
    if summary.get("oos_invalid_loss_r", 0) > 0:
        failed.append("invalid_loss_r_present")
    # 21. No duplicate event IDs
    if lookahead_audit.get("duplicate_test_event_ids", 0) > 0:
        failed.append("duplicate_event_ids")
    # 22. No events outside test window
    if lookahead_audit.get("events_outside_test_window", 0) > 0:
        failed.append("events_outside_test_window")
    # 23. No prefix audit failure
    if lookahead_audit.get("prefix_audits_failed", 0) > 0:
        failed.append("prefix_audit_failed")
    # 24. Locked threshold constant across all evaluable folds
    ca = (constancy_audit.get("locked_candidate_audit") or {})
    if not ca.get("threshold_constant", True):
        failed.append("locked_threshold_not_constant")
    # 25. Locked RR constant across all evaluable folds
    if not ca.get("rr_constant", True):
        failed.append("locked_rr_not_constant")
    # 26. Candidate threshold must not be 0
    req_thr = ca.get("requested_threshold_pct")
    if req_thr is not None and int(req_thr) == 0:
        failed.append("candidate_threshold_is_zero")
    # 27. At least one eligible fold exists for every requested timeframe
    for req_tf in (timeframes_requested or []):
        has_tf = any(
            req_tf in (f.get("timeframes_represented") or [])
            for f in fold_aggregates if f.get("eligible")
        )
        if not has_tf:
            failed.append("timeframe_not_fully_covered")
            break
    # 28. No fabricated fallback candidate used
    if ca.get("fallback_candidate_used", False):
        failed.append("fallback_candidate_used")
    # 29. No training trades in OOS metrics
    if summary.get("training_trades_in_oos", 0) > 0:
        failed.append("training_trades_in_oos")
    # 30. train_selected mode never gets authoritative locked PASS
    if candidate_mode == "train_selected":
        failed.append("train_selected_not_authoritative_locked")

    passes = (len(failed) == 0)
    return passes, sorted(set(failed))


def _bt_wf_adaptive_process_check(
    summary: Dict,
    fold_aggregates: List[Dict],
    lookahead_audit: Dict,
    bootstrap: Dict,
    training_selection_audit: List[Dict],
    timeframes_requested: List[str],
) -> Dict:
    """
    Evaluate train-selected mode adaptive-process gates (research-only).
    Returns a separate verdict; never replaces the locked authoritative verdict.
    """
    failed: List[str] = []

    # Leakage and prefix gates (same as locked)
    if not lookahead_audit.get("passed"):
        failed.append("lookahead_violation")
    if lookahead_audit.get("duplicate_test_event_ids", 0) > 0:
        failed.append("duplicate_event_ids")
    if lookahead_audit.get("prefix_audits_failed", 0) > 0:
        failed.append("prefix_audit_failed")
    if lookahead_audit.get("events_outside_test_window", 0) > 0:
        failed.append("events_outside_test_window")

    # OOS gates
    if summary.get("evaluable_folds", 0) < _WF_MIN_FOLDS:
        failed.append("insufficient_evaluable_folds")
    if summary.get("oos_trades", 0) < _WF_MIN_OOS_TRADES:
        failed.append("insufficient_oos_trades")
    if (summary.get("oos_trade_retention_pct") or 0) < _WF_MIN_RETENTION:
        failed.append("retention_below_floor")
    if (summary.get("oos_net_r") or 0) <= 0:
        failed.append("oos_net_r_not_positive")
    if summary.get("oos_invalid_loss_r", 0) > 0:
        failed.append("invalid_loss_r_present")
    d = summary.get("oos_expectancy_delta_vs_baseline")
    if d is None or d <= 0:
        failed.append("oos_micro_expectancy_not_above_baseline")
    ci_low = bootstrap.get("expectancy_delta_low")
    if bootstrap.get("insufficient_folds") or ci_low is None or ci_low <= 0:
        failed.append("bootstrap_ci_low_not_positive")

    # Training selection gates (Part I)
    valid_sel = sum(
        1 for s in (training_selection_audit or [])
        if s.get("training_selection_passed")
    )
    if valid_sel < _WF_MIN_FOLDS:
        failed.append("insufficient_valid_training_selections")
    for s in (training_selection_audit or []):
        if s.get("fallback_used"):
            failed.append("fallback_candidate_used_in_train_selected")
            break
    # Every selection must be completed before test starts (verified by index)
    for s in (training_selection_audit or []):
        if not s.get("selection_completed_before_test", True):
            failed.append("selection_not_before_test")
            break

    n_folds = len(training_selection_audit or [])
    oos_evaluable = summary.get("evaluable_folds", 0)
    status = "insufficient" if oos_evaluable < _WF_MIN_FOLDS else (
        "passed" if not failed else "failed"
    )

    return {
        "passes":                            not bool(failed),
        "authoritative_for_adaptive_process": not bool(failed),
        "status":                            status,
        "failed_gates":                      sorted(set(failed)),
        "valid_training_selections":         valid_sel,
        "total_folds_with_selection_audit":  n_folds,
    }


def _bt_run_walk_forward(
    symbols: List[str],
    timeframes: List[str],
    candle_count: int,
    rr_values: List,
    thresholds: List[int],
    candidate_mode: str,
    candidate_threshold_pct: Optional[int],
    candidate_rr: Optional[str],
    fold_count: int,
    initial_train_pct: float,
    test_pct: float,
    primary_metric: str = "before_first_touch",
) -> Dict:
    """
    Orchestrate chronological walk-forward validation. Research only —
    never activates any threshold in production systems.
    """
    import time as _t_wf
    t0 = _t_wf.time()

    folds = _bt_build_walk_forward_folds(
        candle_count, fold_count, initial_train_pct, test_pct
    )

    cell_fold_results: Dict[str, List[Dict]] = {}
    candle_meta:       Dict[str, Dict]       = {}
    cells_failed:      List[Dict]            = []
    cell_elapsed_ms:   Dict[str, float]      = {}
    network_fetch_count = 0
    training_prefix_runs = test_prefix_runs = 0

    needed = folds[-1]["test_end_index_exclusive"] if folds else candle_count
    folds_time_filled = False

    for sym in symbols:
        for tf in timeframes:
            key = f"{sym}_{tf}"
            t_cell = _t_wf.time()
            try:
                raw = get_klines(sym, tf, candle_count, "perpetual")
                network_fetch_count += 1
                candles = _bt_normalize_candles(raw or [])
            except Exception as _e:
                traceback.print_exc()
                cells_failed.append({"symbol": sym, "timeframe": tf,
                                     "error": f"fetch_failed: {_e}"})
                candles = []
            candle_meta[key] = {"fetched": len(candles)}
            if len(candles) < needed:
                cells_failed.append({"symbol": sym, "timeframe": tf,
                                     "error": "insufficient_candles_for_folds",
                                     "fetched": len(candles)})
                cell_fold_results[key] = []
                cell_elapsed_ms[key] = round((_t_wf.time() - t_cell) * 1000, 1)
                continue

            if not folds_time_filled and folds:
                for fold in folds:
                    tr_end_idx = fold["train_end_index_exclusive"] - 1
                    te_start_i = fold["test_start_index"]
                    te_end_idx = fold["test_end_index_exclusive"] - 1
                    fold["train_start_time"] = str(candles[0].get("open_time") or "")
                    fold["train_end_time"]   = str(candles[tr_end_idx].get("open_time") or "")
                    fold["test_start_time"]  = str(candles[te_start_i].get("open_time") or "")
                    fold["test_end_time"]    = str(candles[te_end_idx].get("open_time") or "")
                folds_time_filled = True

            cell_fold_results[key] = _bt_run_walk_forward_cell(
                sym, tf, candles, folds, rr_values,
                candidate_threshold_pct, candidate_rr, candidate_mode,
                thresholds, primary_metric,
            )
            # Each cell runs 2 prefix backtests per fold (train + test)
            n_folds_run = len(cell_fold_results[key])
            training_prefix_runs += n_folds_run
            test_prefix_runs     += n_folds_run
            cell_elapsed_ms[key] = round((_t_wf.time() - t_cell) * 1000, 1)

    # ── Resolve candidate per fold ────────────────────────────────────────────
    training_selection: List[Dict] = []
    training_expectancy_by_fold:   List = []
    resolved_candidate = None
    if candidate_mode == "locked":
        resolved_candidate = {
            "threshold_pct": int(candidate_threshold_pct),
            "rr":            str(candidate_rr),
        }

    for fold in folds:
        fold_num   = fold["fold"]
        train_cells = []
        for sym in symbols:
            for tf in timeframes:
                key  = f"{sym}_{tf}"
                rows = cell_fold_results.get(key, [])
                row  = next((r for r in rows if r.get("fold") == fold_num and r.get("ok")), None)
                if row is None:
                    continue
                train_cells.append({
                    "ok": True, "symbol": sym, "timeframe": tf,
                    "candle_count":              fold["train_candle_count"],
                    "parity_trusted":            row.get("train_parity_trusted", False),
                    "threshold_analysis":        row.get("train_threshold_analysis"),
                    "threshold_analysis_present": row.get("train_threshold_analysis") is not None,
                })

        fold_candidate = resolved_candidate
        fold_train_exp = None
        if candidate_mode == "train_selected":
            sel, stab = _bt_select_walk_forward_training_candidate(
                train_cells, thresholds, rr_values
            )
            fold_candidate = sel
            training_selection.append({
                "fold": fold_num, "selected": sel,
                "recommendation_present": sel is not None,
            })
            if sel is not None:
                aggk = f"{int(sel['threshold_pct'])}_{str(sel['rr'])}"
                agg  = (stab.get("aggregate_by_thr_rr") or {}).get(aggk) or {}
                fold_train_exp = agg.get("micro_expectancy_r")
        else:
            gp = gl = 0.0; tr_trades = 0
            for tc in train_cells:
                ta  = ((tc.get("threshold_analysis") or {}).get(primary_metric) or {})
                row = ((ta.get("results") or {}).get(str(int(candidate_threshold_pct))) or {})
                rz  = (row.get("realized_summary_by_rr") or {}).get(str(candidate_rr)) or {}
                gp  += float(rz.get("gross_profit_r", 0.0) or 0.0)
                gl  += float(rz.get("gross_loss_r",   0.0) or 0.0)
                tr_trades += int(rz.get("trades", 0) or 0)
            fold_train_exp = round((gp - gl) / tr_trades, 6) if tr_trades else None
        training_expectancy_by_fold.append(fold_train_exp)

        for sym in symbols:
            for tf in timeframes:
                key  = f"{sym}_{tf}"
                rows = cell_fold_results.get(key, [])
                row  = next((r for r in rows if r.get("fold") == fold_num and r.get("ok")), None)
                if row is None:
                    continue
                if fold_candidate is None:
                    row["metrics"] = None
                    continue
                if candidate_mode == "train_selected" or row.get("metrics") is None:
                    row["metrics"] = _bt_wf_extract_test_metrics(
                        row.get("_test_events", []),
                        int(fold_candidate["threshold_pct"]),
                        str(fold_candidate["rr"]),
                        primary_metric,
                        row.get("test_parity_trusted", False),
                        rr_values,
                    )

    # ── Aggregate folds ───────────────────────────────────────────────────────
    fold_aggregates: List[Dict]  = []
    all_fold_test_event_ids: Dict = {}

    for fold in folds:
        fold_num  = fold["fold"]
        fold_cells = []; ids: List[str] = []
        for sym in symbols:
            for tf in timeframes:
                key  = f"{sym}_{tf}"
                rows = cell_fold_results.get(key, [])
                row  = next((r for r in rows if r.get("fold") == fold_num), None)
                if row is None: continue
                fold_cells.append(row)
                ids.extend(row.get("test_event_ids", []))
        all_fold_test_event_ids[fold_num] = ids
        fc_thr = int(candidate_threshold_pct) if candidate_mode == "locked" else None
        fc_rr  = str(candidate_rr)            if candidate_mode == "locked" else None
        if candidate_mode == "train_selected":
            sel = next((s["selected"] for s in training_selection if s["fold"] == fold_num), None)
            fc_thr = int(sel["threshold_pct"]) if sel else None
            fc_rr  = str(sel["rr"])            if sel else None
        fold_aggregates.append(_bt_aggregate_wf_fold(fold_cells, fold, fc_thr, fc_rr))

    # Strip internal arrays before any further use
    for key, rows in cell_fold_results.items():
        for r in rows:
            r.pop("_test_events",  None)
            r.pop("_train_events", None)

    # ── Audits and summary ────────────────────────────────────────────────────
    summary = _bt_aggregate_wf_summary(
        fold_aggregates, candidate_mode, training_expectancy_by_fold,
        symbols, timeframes,
    )
    bootstrap = _bt_wf_bootstrap_delta(summary.get("evaluable_fold_deltas", []))
    lookahead = _bt_wf_lookahead_audit(folds, all_fold_test_event_ids, cell_fold_results)

    # Constancy audit (locked mode)
    constancy_audit = _bt_wf_locked_candidate_constancy_audit(
        fold_aggregates,
        candidate_threshold_pct if candidate_mode == "locked" else None,
        candidate_rr            if candidate_mode == "locked" else None,
    ) if candidate_mode == "locked" else {
        "locked_candidate_audit": {
            "requested_threshold_pct": None, "requested_rr": None,
            "thresholds_observed_by_fold": [], "rrs_observed_by_fold": [],
            "threshold_constant": True, "rr_constant": True,
            "fallback_candidate_used": False, "passed": True,
        }
    }

    # Timestamp audit (train-selected)
    timestamp_audit = (
        _bt_wf_training_selection_timestamp_audit(folds, training_selection)
        if candidate_mode == "train_selected" else []
    )

    # PF non-degradation summary
    pf_nd_ok, pf_nd_reason = _stab_pf_non_degraded(
        summary.get("oos_profit_factor_r"),
        summary.get("oos_profit_factor_infinite", False),
        summary.get("baseline_profit_factor_r"),
        summary.get("baseline_profit_factor_infinite", False),
        candidate_trades=summary.get("oos_trades", 0) or 0,
        baseline_trades=summary.get("baseline_trades", 0) or 0,
        baseline_gross_profit=summary.get("oos_gross_profit_r", 0.0) or 0.0,
        baseline_gross_loss=summary.get("oos_gross_loss_r", 0.0) or 0.0,
    )
    pf_non_degradation = {
        "passed":                     pf_nd_ok,
        "reason":                     pf_nd_reason,
        "candidate_pf":               summary.get("oos_profit_factor_r"),
        "candidate_pf_infinite":      summary.get("oos_profit_factor_infinite", False),
        "baseline_pf":                summary.get("baseline_profit_factor_r"),
        "baseline_pf_infinite":       summary.get("baseline_profit_factor_infinite", False),
        "candidate_trades":           summary.get("oos_trades", 0),
        "baseline_trades":            summary.get("baseline_trades", 0),
    }

    # Locked-mode pass gates
    passes, failed_gates = _bt_wf_check_pass_gates(
        summary, fold_aggregates, lookahead, True, candidate_mode, bootstrap,
        constancy_audit, candidate_threshold_pct, timeframes,
    )

    # Walk-forward result (locked authoritative)
    walk_forward_result = {
        "passes":       passes,
        "authoritative": (candidate_mode == "locked"),
    }

    # Adaptive-process result (train-selected)
    adaptive_process_result = None
    if candidate_mode == "train_selected":
        adaptive_process_result = _bt_wf_adaptive_process_check(
            summary, fold_aggregates, lookahead, bootstrap,
            timestamp_audit, timeframes,
        )

    # Status
    if candidate_mode == "train_selected":
        status = "ADVISORY"
    elif (summary.get("evaluable_folds", 0) < _WF_MIN_FOLDS
          or summary.get("oos_trades", 0) < _WF_MIN_OOS_TRADES):
        status = "INSUFFICIENT"
    else:
        status = "PASS" if passes else "FAIL"

    # Selection stability
    selection_stability = None
    if candidate_mode == "train_selected":
        sels   = [s["selected"] for s in training_selection if s["selected"] is not None]
        keys   = [f"{s['threshold_pct']}_{s['rr']}" for s in sels]
        unique = sorted(set(keys))
        selection_stability = {
            "folds_with_candidate": len(sels),
            "unique_candidates":    len(unique),
            "candidate_keys":       unique,
            "stable":               len(unique) <= 1,
        }

    elapsed_ms = round((_t_wf.time() - t0) * 1000, 1)
    prefix_runs = training_prefix_runs + test_prefix_runs
    expected_fetch = len(symbols) * len(timeframes)
    slowest = (max(cell_elapsed_ms, key=lambda k: cell_elapsed_ms[k])
               if cell_elapsed_ms else None)

    return {
        "status":                  status,
        "passes_all_gates":        passes,
        "failed_gates":            failed_gates,
        "candidate_mode":          candidate_mode,
        "resolved_candidate":      resolved_candidate,
        "fold_definitions":        folds,
        "fold_count_built":        len(folds),
        "summary":                 summary,
        "fold_aggregates":         fold_aggregates,
        "bootstrap":               bootstrap,
        "lookahead_audit":         lookahead,
        "locked_candidate_audit":  constancy_audit.get("locked_candidate_audit"),
        "training_selection":      training_selection,
        "training_selection_audit": timestamp_audit,
        "selection_stability":     selection_stability,
        "pf_non_degradation":      pf_non_degradation,
        "walk_forward_result":     walk_forward_result,
        "adaptive_process_result": adaptive_process_result,
        "cells_failed":            cells_failed,
        "candle_meta":             candle_meta,
        "constants": {
            "bootstrap_iters":   _WF_BOOTSTRAP_ITERS,
            "bootstrap_seed":    _WF_BOOTSTRAP_SEED,
            "min_folds":         _WF_MIN_FOLDS,
            "min_oos_trades":    _WF_MIN_OOS_TRADES,
            "min_retention":     _WF_MIN_RETENTION,
            "min_positive_folds": _WF_MIN_POSITIVE_FOLDS,
            "min_beat_folds":    _WF_MIN_BEAT_FOLDS,
            "worst_fold_floor":  _WF_WORST_FOLD_FLOOR,
            "min_symbols":       _WF_MIN_SYMBOLS,
            "min_tf_cell_folds": _WF_MIN_TF_CELL_FOLDS,
            "build_commit":      _WF_BUILD_COMMIT,
            "build_15b_commit":  _WF_15B_COMMIT,
        },
        "performance": {
            "candles_fetched_once_per_cell":    True,
            "network_fetch_count":              network_fetch_count,
            "expected_network_fetch_count":     expected_fetch,
            "prefix_runs":                      prefix_runs,
            "training_prefix_runs":             training_prefix_runs,
            "test_prefix_runs":                 test_prefix_runs,
            "prefix_cache_hits":                0,
            "prefix_cache_misses":              prefix_runs,
            "total_elapsed_ms":                 elapsed_ms,
            "cell_elapsed_ms":                  cell_elapsed_ms,
            "slowest_cell":                     slowest,
        },
        "elapsed_ms": elapsed_ms,
    }


@app.route("/api/backtest/ob-historical/threshold-walk-forward", methods=["POST"])
@login_required
def api_backtest_ob_historical_threshold_walk_forward():
    err = _guest_tab_check("backtest")
    if err is not None:
        return err

    import time as _t_wf_ep
    payload = request.get_json(force=True) or {}

    # Reject client-supplied results — server is authoritative for everything.
    for banned in ("folds", "cell_results", "trade_results",
                   "training_results", "test_results", "recommendation"):
        if banned in payload:
            return jsonify({
                "ok": False,
                "error": "client_supplied_walk_forward_results_not_allowed",
            }), 400

    # Symbols (max 5)
    raw_syms = payload.get("symbols", ["BTCUSDT", "ETHUSDT", "BNBUSDT", "SOLUSDT", "XRPUSDT"])
    if not isinstance(raw_syms, list):
        raw_syms = [str(raw_syms)]
    seen_syms: set = set()
    symbols: List[str] = []
    for s in raw_syms:
        s = str(s).strip().upper()
        if not s:
            return jsonify({"ok": False, "error": "blank symbol not allowed"}), 400
        if not s.endswith("USDT"):
            s = s + "USDT"
        if s in seen_syms:
            continue
        seen_syms.add(s)
        symbols.append(s)
    if not symbols:
        return jsonify({"ok": False, "error": "at least one symbol required"}), 400
    if len(symbols) > 5:
        return jsonify({"ok": False, "error": "max 5 symbols"}), 400

    # Timeframes (1h/4h only, max 2)
    raw_tfs = payload.get("timeframes", ["1h", "4h"])
    if not isinstance(raw_tfs, list):
        raw_tfs = [str(raw_tfs)]
    seen_tfs: set = set()
    timeframes: List[str] = []
    for tf in raw_tfs:
        tf = str(tf).strip()
        if tf not in _WF_ALLOWED_TF:
            return jsonify({"ok": False, "error": f"timeframe '{tf}' not allowed; use 1h or 4h"}), 400
        if tf in seen_tfs:
            continue
        seen_tfs.add(tf)
        timeframes.append(tf)
    if not timeframes:
        return jsonify({"ok": False, "error": "at least one timeframe required"}), 400
    if len(timeframes) > 2:
        return jsonify({"ok": False, "error": "max 2 timeframes"}), 400

    # candle_count (500-4000)
    try:
        candle_count = int(payload.get("candle_count", 1000))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "candle_count must be integer"}), 400
    candle_count = max(500, min(4000, candle_count))

    rr_values = _bt_parse_rr_values(payload.get("rr_values", [1, 2, 3]))
    thresholds = _WF_ALLOWED_THRESHOLDS

    candidate_mode = str(payload.get("candidate_mode", "locked")).strip()
    if candidate_mode not in ("locked", "train_selected"):
        return jsonify({"ok": False, "error": "candidate_mode must be 'locked' or 'train_selected'"}), 400

    candidate_threshold_pct = None
    candidate_rr = None
    if candidate_mode == "locked":
        try:
            candidate_threshold_pct = int(payload.get("candidate_threshold_pct"))
        except (TypeError, ValueError):
            return jsonify({"ok": False, "error": "candidate_threshold_pct required for locked mode"}), 400
        if candidate_threshold_pct not in _WF_CANDIDATE_THRESHOLDS:
            return jsonify({"ok": False, "error": "candidate_threshold_pct must be one of 20,40,60,80"}), 400
        candidate_rr_raw = payload.get("candidate_rr", "2")
        try:
            candidate_rr = _bt_rr_key(float(candidate_rr_raw))
        except (TypeError, ValueError):
            return jsonify({"ok": False, "error": "candidate_rr invalid"}), 400
        if candidate_rr not in ("1", "2", "3"):
            return jsonify({"ok": False, "error": "candidate_rr must be 1, 2, or 3"}), 400

    # fold_count (3-5)
    try:
        fold_count = int(payload.get("fold_count", 4))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "fold_count must be integer"}), 400
    if fold_count < _WF_MIN_FOLDS or fold_count > _WF_MAX_FOLDS:
        return jsonify({"ok": False, "error": f"fold_count must be {_WF_MIN_FOLDS}-{_WF_MAX_FOLDS}"}), 400

    # initial_train_pct (35-60)
    try:
        initial_train_pct = float(payload.get("initial_train_pct", 40.0))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "initial_train_pct must be number"}), 400
    if initial_train_pct < _WF_MIN_TRAIN_PCT or initial_train_pct > _WF_MAX_TRAIN_PCT:
        return jsonify({"ok": False, "error": f"initial_train_pct must be {_WF_MIN_TRAIN_PCT}-{_WF_MAX_TRAIN_PCT}"}), 400

    # test_pct (10-20)
    try:
        test_pct = float(payload.get("test_pct", 15.0))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "test_pct must be number"}), 400
    if test_pct < _WF_MIN_TEST_PCT or test_pct > _WF_MAX_TEST_PCT:
        return jsonify({"ok": False, "error": f"test_pct must be {_WF_MIN_TEST_PCT}-{_WF_MAX_TEST_PCT}"}), 400

    primary_metric = str(payload.get("primary_metric", "before_first_touch")).strip()
    if primary_metric not in ("before_first_touch", "at_formation"):
        primary_metric = "before_first_touch"

    # Fold feasibility
    train_base = int(candle_count * initial_train_pct / 100)
    test_size = int(candle_count * test_pct / 100)
    required = train_base + fold_count * test_size
    if required > candle_count:
        return jsonify({"ok": False,
                        "error": f"Folds don't fit: need {required} candles but only {candle_count} available"}), 400

    t0 = _t_wf_ep.time()
    walk_forward = _bt_run_walk_forward(
        symbols=symbols,
        timeframes=timeframes,
        candle_count=candle_count,
        rr_values=rr_values,
        thresholds=thresholds,
        candidate_mode=candidate_mode,
        candidate_threshold_pct=candidate_threshold_pct,
        candidate_rr=candidate_rr,
        fold_count=fold_count,
        initial_train_pct=initial_train_pct,
        test_pct=test_pct,
        primary_metric=primary_metric,
    )
    elapsed_total_ms = round((_t_wf_ep.time() - t0) * 1000, 1)

    response_body = {
        "ok":                      True,
        "authoritative_execution": True,
        "client_results_accepted": False,
        "mode":                    "tv_ob_pct_threshold_walk_forward_v1",
        "request": {
            "symbols":                  symbols,
            "timeframes":               timeframes,
            "candle_count":             candle_count,
            "rr_values":                [_bt_rr_key(r) for r in rr_values],
            "candidate_mode":           candidate_mode,
            "candidate_threshold_pct":  candidate_threshold_pct,
            "candidate_rr":             candidate_rr,
            "fold_count":               fold_count,
            "initial_train_pct":        initial_train_pct,
            "test_pct":                 test_pct,
            "primary_metric":           primary_metric,
        },
        "walk_forward":            walk_forward,
        "performance": {
            "elapsed_total_ms":         elapsed_total_ms,
            "symbols":                  symbols,
            "timeframes":               timeframes,
            "candle_count":             candle_count,
            "fold_count":               fold_count,
        },
    }

    import json as _json_wf_size
    response_body["response_size_bytes"] = len(
        _json_wf_size.dumps(response_body, default=str))

    return jsonify(response_body), 200


# ══════════════════════════════════════════════════════════════════════════════
# Phase 16 — Advanced Trade Explorer: first/second/third/fourth+ touch analysis
# Research only. No production filter activation. No DB writes.
# ══════════════════════════════════════════════════════════════════════════════

_TE_MAX_SYMBOLS:    int = 5
_TE_MAX_TIMEFRAMES: int = 2
_TE_MAX_CELLS:      int = 10
_TE_MAX_PAGE_SIZE:  int = 250
_TE_CANDLE_WINDOW:  int = 200   # max candles returned by trade detail endpoint
_TE_ALLOWED_RR          = (1, 2, 3)
_TE_BUILD_COMMIT:   str = "37b465a"  # Phase 15B


def _te_in_zone(c: Dict, zh: float, zl: float) -> bool:
    """Candle wick intersects [zl, zh] — same condition as _bt_build_event."""
    return float(c["high"]) >= zl and float(c["low"]) <= zh


def _te_outside_zone(c: Dict, zh: float, zl: float) -> bool:
    """Candle entirely outside [zl, zh]."""
    return float(c["high"]) < zl or float(c["low"]) > zh


def _te_touch_bucket(n: int) -> str:
    if n == 1:
        return "first"
    if n == 2:
        return "second"
    if n == 3:
        return "third"
    return "fourth_plus"


def _te_ob_id(event: Dict) -> str:
    """Deterministic OB identity from canonical formation data."""
    return "te_ob:{}:{}:{}:{}:{}".format(
        event.get("symbol", ""), event.get("timeframe", ""),
        event.get("type", ""), event.get("formation_bar", 0),
        event.get("formation_time", ""))


def _te_touch_trade_id(event: Dict, touch_number: int, touch_index: int, rr_key: str) -> str:
    """Deterministic touch-trade identity: same touch → same ID on every run."""
    raw = f"{_te_ob_id(event)}:t{touch_number}:i{touch_index}:rr{rr_key}"
    return "tte_" + hashlib.sha256(raw.encode()).hexdigest()[:16]


def _te_session(ms) -> Optional[str]:
    """UTC session bucket from a ms timestamp."""
    if ms is None:
        return None
    try:
        h = datetime.fromtimestamp(int(ms) / 1000, tz=timezone.utc).hour
        if h < 8:
            return "Asia"
        if h < 13:
            return "London"
        if h < 21:
            return "NewYork"
        return "Other"
    except Exception:
        return None


def _te_weekday(ms) -> Optional[str]:
    if ms is None:
        return None
    try:
        return datetime.fromtimestamp(int(ms) / 1000, tz=timezone.utc).strftime("%A")
    except Exception:
        return None


def _te_sample_size_status(n_trades: int) -> str:
    if n_trades < 20:
        return "insufficient"
    if n_trades < 50:
        return "small"
    if n_trades < 100:
        return "usable"
    return "strong"


def _te_detect_touch_episodes(candles: List[Dict], event: Dict) -> List[Dict]:
    """Detect chronological touch episodes for one OB event.

    Rules (spec Parts A-C):
    - Scan strictly after formation_bar (formation candle never counts).
    - Consecutive intersecting candles form ONE episode.
    - An episode ends only when a later candle is fully outside the zone.
    - A new episode starts when price re-enters after being fully outside.
    - Scanning stops at the canonical mitigation bar (inclusive — the
      mitigation candle itself may intersect the zone); no touches exist
      after canonical invalidation.  No new invalidation rule is invented.
    """
    if event.get("touch_status") != "touched":
        return []

    zh = float(event["zone_high"])
    zl = float(event["zone_low"])
    formation_bar = int(event["formation_bar"])
    mitigation_bar = event.get("mitigation_bar")

    if mitigation_bar is not None:
        scan_end = min(int(mitigation_bar) + 1, len(candles))
    else:
        scan_end = len(candles)

    episodes: List[Dict] = []
    in_episode = False
    touch_number = 0

    for i in range(formation_bar + 1, scan_end):
        c = candles[i]
        if _te_in_zone(c, zh, zl):
            if not in_episode:
                touch_number += 1
                in_episode = True
                episodes.append({
                    "touch_number":                touch_number,
                    "touch_bucket":                _te_touch_bucket(touch_number),
                    "episode_start_index":         i,
                    "episode_end_index_exclusive": None,
                    "touch_index":                 i,
                    "touch_time":                  c.get("open_time"),
                    "touch_price":                 c.get("close"),
                    "candles_since_formation":     i - formation_bar,
                    "ob_valid_before_touch":       True,
                    "ob_state_before_touch":       "active",
                    "touch_rejected_reason":       None,
                    "generated_server_side":       True,
                })
        else:
            if in_episode and _te_outside_zone(c, zh, zl):
                episodes[-1]["episode_end_index_exclusive"] = i
                in_episode = False

    if in_episode and episodes:
        episodes[-1]["episode_end_index_exclusive"] = scan_end

    return episodes


def _te_simulate_touch_outcome(entry_bar: int, event: Dict, candles: List[Dict],
                               rr_values: list) -> dict:
    """Simulate one trade outcome starting from an arbitrary entry bar.

    Identical rules to the canonical _bt_simulate_first_touch_outcome:
      entry = zone_high (both directions), risk = zone size,
      SL close-based only, TP wick-based, same-candle TP+SL = ambiguous.
    The only difference is the scan starts at entry_bar instead of the
    event's first_touch_bar, enabling independent later-touch variants.
    """
    ob_type   = event["type"]
    zone_high = float(event["zone_high"])
    zone_low  = float(event["zone_low"])
    n         = len(candles)

    entry_price = zone_high
    risk_amount = zone_high - zone_low

    _ineligible = {
        "eligible":            False,
        "entry_price":         None,
        "entry_bar":           entry_bar,
        "entry_time":          None,
        "stop_boundary":       None,
        "risk_amount":         None,
        "rr_values":           rr_values,
        "tp_prices":           {},
        "hit_rr":              {_bt_rr_key(r): False for r in rr_values},
        "candles_to_rr":       {_bt_rr_key(r): None  for r in rr_values},
        "first_tp_rr":         None,
        "first_tp_bar":        None,
        "first_tp_time":       None,
        "stop_hit":            False,
        "stop_bar":            None,
        "stop_time":           None,
        "first_outcome":       "unresolved",
        "same_candle_event":   False,
        "max_r_reached":       0.0,
        "max_adverse_r":       0.0,
        "max_favorable_price": None,
        "max_adverse_price":   None,
        "stop_close_price":    None,
        "stop_loss_r":         None,
        "stop_loss_abs":       None,
        "stop_loss_pct":       None,
        "realized_by_rr":      {},
    }

    if risk_amount <= 0 or entry_bar is None or entry_bar >= n:
        return _ineligible

    if ob_type == "bullish":
        stop_boundary = zone_low
        tp_prices = {_bt_rr_key(rv): round(entry_price + risk_amount * rv, 8)
                     for rv in rr_values}
    else:
        stop_boundary = zone_high
        tp_prices = {_bt_rr_key(rv): round(entry_price - risk_amount * rv, 8)
                     for rv in rr_values}

    sorted_rr     = sorted(rr_values)
    hit_rr        = {_bt_rr_key(rv): False for rv in rr_values}
    candles_to_rr = {_bt_rr_key(rv): None  for rv in rr_values}
    first_tp_rr   = None
    first_tp_bar  = None
    first_tp_time = None
    stop_hit      = False
    stop_bar      = None
    stop_time     = None
    max_fav_price = None
    max_adv_price = None
    times = [c.get("open_time") for c in candles]

    for j in range(entry_bar, n):
        h  = float(candles[j]["high"])
        l  = float(candles[j]["low"])
        cl = float(candles[j]["close"])

        if ob_type == "bullish":
            max_fav_price = h if max_fav_price is None else max(max_fav_price, h)
            max_adv_price = l if max_adv_price is None else min(max_adv_price, l)
            for rv in sorted_rr:
                rk = _bt_rr_key(rv)
                if not hit_rr[rk] and h >= tp_prices[rk]:
                    hit_rr[rk]        = True
                    candles_to_rr[rk] = j - entry_bar
                    if first_tp_bar is None:
                        first_tp_rr, first_tp_bar = rv, j
                        first_tp_time = times[j] if j < n else None
        else:
            max_fav_price = l if max_fav_price is None else min(max_fav_price, l)
            max_adv_price = h if max_adv_price is None else max(max_adv_price, h)
            for rv in sorted_rr:
                rk = _bt_rr_key(rv)
                if not hit_rr[rk] and l <= tp_prices[rk]:
                    hit_rr[rk]        = True
                    candles_to_rr[rk] = j - entry_bar
                    if first_tp_bar is None:
                        first_tp_rr, first_tp_bar = rv, j
                        first_tp_time = times[j] if j < n else None

        if not stop_hit:
            sl_hit = (ob_type == "bullish" and cl < zone_low) or \
                     (ob_type == "bearish" and cl > zone_high)
            if sl_hit:
                stop_hit  = True
                stop_bar  = j
                stop_time = times[j] if j < n else None

        if stop_hit:
            break

    same_candle = (first_tp_bar is not None and stop_bar is not None
                   and first_tp_bar == stop_bar)
    if same_candle:
        first_outcome = "ambiguous"
    elif first_tp_bar is not None and (stop_bar is None or first_tp_bar < stop_bar):
        first_outcome = "tp"
    elif stop_hit:
        first_outcome = "sl"
    else:
        first_outcome = "unresolved"

    if ob_type == "bullish":
        max_r = max(0.0, (max_fav_price - entry_price) / risk_amount) \
                if max_fav_price is not None else 0.0
        adv_r = max(0.0, (entry_price  - max_adv_price) / risk_amount) \
                if max_adv_price is not None else 0.0
    else:
        max_r = max(0.0, (entry_price  - max_fav_price) / risk_amount) \
                if max_fav_price is not None else 0.0
        adv_r = max(0.0, (max_adv_price - entry_price) / risk_amount) \
                if max_adv_price is not None else 0.0

    stop_close_price = None
    stop_loss_r      = None
    stop_loss_abs    = None
    stop_loss_pct    = None
    if stop_hit and stop_bar is not None:
        _scp = float(candles[stop_bar]["close"])
        if ob_type == "bullish":
            _raw = max(0.0, (entry_price - _scp) / risk_amount)
        else:
            _raw = max(0.0, (_scp - entry_price) / risk_amount)
        stop_loss_r      = round(_raw, 4)
        stop_loss_abs    = round(abs(entry_price - _scp), 8)
        stop_loss_pct    = round(stop_loss_abs / entry_price * 100, 4) if entry_price else None
        stop_close_price = round(_scp, 8)

    realized_by_rr: Dict[str, dict] = {}
    for _rv in sorted_rr:
        _rk     = _bt_rr_key(_rv)
        _rr_hit = hit_rr[_rk]
        _tp_rel = candles_to_rr[_rk]
        _tp_abs = (entry_bar + _tp_rel) if _tp_rel is not None else None

        if _rr_hit and _tp_abs is not None:
            if stop_bar is None or _tp_abs < stop_bar:
                _rz_out = "win";  _rz_r = float(_rv); _rz_eb = _tp_abs
                _rz_et  = times[_tp_abs] if _tp_abs < n else None
                _rz_ep  = round(tp_prices[_rk], 8)
                _rz_cl  = _tp_rel
            else:
                _rz_out = "ambiguous"; _rz_r = None; _rz_eb = stop_bar
                _rz_et  = stop_time;   _rz_ep = None
                _rz_cl  = stop_bar - entry_bar
        elif stop_hit:
            _rz_out = "loss"
            _rz_r   = (-stop_loss_r) if stop_loss_r is not None else None
            _rz_eb  = stop_bar; _rz_et = stop_time; _rz_ep = stop_close_price
            _rz_cl  = (stop_bar - entry_bar) if stop_bar is not None else None
        else:
            _rz_out = "unresolved"
            _rz_r = None; _rz_eb = None; _rz_et = None; _rz_ep = None; _rz_cl = None

        realized_by_rr[_rk] = {
            "target_rr":        float(_rv),
            "outcome":          _rz_out,
            "realized_r":       round(_rz_r, 4) if _rz_r is not None else None,
            "exit_bar":         _rz_eb,
            "exit_time":        _rz_et,
            "exit_price":       _rz_ep,
            "target_price":     round(tp_prices[_rk], 8),
            "stop_close_price": stop_close_price,
            "stop_loss_r":      stop_loss_r,
            "candles_to_exit":  _rz_cl,
        }

    return {
        "eligible":            True,
        "entry_price":         round(entry_price, 8),
        "entry_bar":           entry_bar,
        "entry_time":          times[entry_bar] if entry_bar < n else None,
        "stop_boundary":       round(stop_boundary, 8),
        "risk_amount":         round(risk_amount, 8),
        "rr_values":           rr_values,
        "tp_prices":           {k: round(v, 8) for k, v in tp_prices.items()},
        "hit_rr":              hit_rr,
        "candles_to_rr":       candles_to_rr,
        "first_tp_rr":         first_tp_rr,
        "first_tp_bar":        first_tp_bar,
        "first_tp_time":       first_tp_time,
        "stop_hit":            stop_hit,
        "stop_bar":            stop_bar,
        "stop_time":           stop_time,
        "first_outcome":       first_outcome,
        "same_candle_event":   same_candle,
        "max_r_reached":       round(max_r, 4),
        "max_adverse_r":       round(adv_r, 4),
        "max_favorable_price": round(max_fav_price, 8) if max_fav_price is not None else None,
        "max_adverse_price":   round(max_adv_price, 8) if max_adv_price is not None else None,
        "stop_close_price":    stop_close_price,
        "stop_loss_r":         stop_loss_r,
        "stop_loss_abs":       stop_loss_abs,
        "stop_loss_pct":       stop_loss_pct,
        "realized_by_rr":      realized_by_rr,
    }


def _te_build_touch_trade_rows(event: Dict, episodes: List[Dict],
                               candles: List[Dict], rr_values: list) -> List[Dict]:
    """Build one compact trade row per (touch episode, RR) combination.

    Each touch variant is simulated independently — an earlier touch's
    outcome never changes a later touch's simulation.  Overlap with the
    previous touch's still-open variant is recorded as a diagnostic only.
    """
    rows: List[Dict] = []

    sims: List[Dict] = [
        _te_simulate_touch_outcome(ep["touch_index"], event, candles, rr_values)
        for ep in episodes
    ]

    zh  = float(event["zone_high"])
    zl  = float(event["zone_low"])
    fb  = int(event["formation_bar"])
    ft  = event.get("formation_time")
    sym = event.get("symbol", "")
    tf  = event.get("timeframe", "")
    direction = event.get("type", "")
    ob_id = _te_ob_id(event)
    zone_size_pct = event.get("zone_size_pct")
    tv_pct = event.get("tv_ob_pct_before_touch")

    for ep_idx, (ep, sim) in enumerate(zip(episodes, sims)):
        touch_idx  = ep["touch_index"]
        touch_time = ep.get("touch_time")
        touch_num  = ep["touch_number"]

        session = _te_session(touch_time)
        weekday = _te_weekday(touch_time)

        for rr in rr_values:
            rk = _bt_rr_key(rr)
            rb = (sim.get("realized_by_rr") or {}).get(rk, {})
            outcome = rb.get("outcome", "unresolved")

            eligible = bool(sim.get("eligible", False))
            rejection_reasons: List[str] = []
            if not eligible:
                rejection_reasons.append("simulation_ineligible")
            realized_r = rb.get("realized_r")
            if outcome == "loss" and realized_r is None:
                outcome = "invalid_loss_r"
                rejection_reasons.append("invalid_loss_r")
                eligible = False

            overlaps = False
            if ep_idx > 0:
                prev_rb   = (sims[ep_idx - 1].get("realized_by_rr") or {}).get(rk, {})
                prev_exit = prev_rb.get("exit_bar")
                if prev_exit is None or prev_exit >= touch_idx:
                    overlaps = True

            rows.append({
                "touch_trade_id":              _te_touch_trade_id(event, touch_num, touch_idx, rk),
                "ob_id":                       ob_id,
                "symbol":                      sym,
                "timeframe":                   tf,
                "direction":                   direction,
                "touch_number":                touch_num,
                "touch_bucket":                ep["touch_bucket"],
                "formation_time":              ft,
                "touch_time":                  touch_time,
                "candles_since_formation":     ep.get("candles_since_formation", touch_idx - fb),
                "session":                     session,
                "weekday":                     weekday,
                "zone_high":                   zh,
                "zone_low":                    zl,
                "zone_size_pct":               zone_size_pct,
                "zone_size_atr":               None,
                "entry_price":                 sim.get("entry_price"),
                "stop_price":                  sim.get("stop_boundary"),
                "stop_loss_r":                 sim.get("stop_loss_r"),
                "rr":                          rk,
                "outcome":                     outcome,
                "realized_r":                  realized_r,
                "mfe_r":                       sim.get("max_r_reached"),
                "mae_r":                       sim.get("max_adverse_r"),
                "fvg_overlap":                 "unknown",
                "higher_timeframe_alignment":  "unknown",
                "tv_ob_pct_before_touch":      tv_pct,
                "tv_ob_pct_exchange_specific": True,
                "overlaps_previous_touch_trade": overlaps,
                "eligible":                    eligible,
                "rejection_reasons":           rejection_reasons,
                "ob_valid_before_touch":       ep.get("ob_valid_before_touch", True),
                "ob_state_before_touch":       ep.get("ob_state_before_touch", "active"),
                "formation_bar":               fb,
                "touch_index":                 touch_idx,
            })

    return rows


def _te_compute_aggregate(rows: List[Dict], rr_key: str) -> Dict:
    """Authoritative aggregate for one RR: trades = wins + losses only.

    Ambiguous, unresolved and invalid_loss_r never enter trades, are never
    converted to losses, and no -1R value is fabricated for them.
    """
    rr_rows = [r for r in rows if r.get("rr") == rr_key]

    wins   = sum(1 for r in rr_rows if r["outcome"] == "win")
    losses = sum(1 for r in rr_rows if r["outcome"] == "loss")
    amb    = sum(1 for r in rr_rows if r["outcome"] == "ambiguous")
    unres  = sum(1 for r in rr_rows if r["outcome"] == "unresolved")
    inv    = sum(1 for r in rr_rows if r["outcome"] == "invalid_loss_r")
    trades = wins + losses

    gp = sum(r["realized_r"] for r in rr_rows
             if r["outcome"] == "win" and r.get("realized_r") is not None)
    gl = abs(sum(r["realized_r"] for r in rr_rows
                 if r["outcome"] == "loss" and r.get("realized_r") is not None))
    net_r = round(gp - gl, 4)
    pf, pf_inf = _stab_aggregate_pf(gp, gl)

    sl_vals  = [r["stop_loss_r"] for r in rr_rows
                if r["outcome"] == "loss" and r.get("stop_loss_r") is not None]
    mfe_vals = [r["mfe_r"] for r in rr_rows if r.get("mfe_r") is not None]
    mae_vals = [r["mae_r"] for r in rr_rows if r.get("mae_r") is not None]

    return {
        "rr":                     rr_key,
        "trades":                 trades,
        "wins":                   wins,
        "losses":                 losses,
        "ambiguous":              amb,
        "unresolved":             unres,
        "invalid_loss_r":         inv,
        "win_rate_pct":           round(wins / trades * 100, 2) if trades else None,
        "expectancy_r":           round(net_r / trades, 6) if trades else None,
        "gross_profit_r":         round(gp, 4),
        "gross_loss_r":           round(gl, 4),
        "profit_factor_r":        pf,
        "profit_factor_infinite": pf_inf,
        "net_r":                  net_r,
        "avg_win_r":              round(gp / wins, 4) if wins else None,
        "avg_loss_r":             round(-gl / losses, 4) if losses else None,
        "avg_stop_loss_r":        round(sum(sl_vals) / len(sl_vals), 4) if sl_vals else None,
        "avg_mfe_r":              round(sum(mfe_vals) / len(mfe_vals), 4) if mfe_vals else None,
        "avg_mae_r":              round(sum(mae_vals) / len(mae_vals), 4) if mae_vals else None,
        "sample_size_status":     _te_sample_size_status(trades),
    }


def _te_touch_bucket_comparison(rows: List[Dict], rr_key: str) -> List[Dict]:
    """Same-RR aggregates for first / second / third / fourth_plus buckets."""
    buckets = [("first", 1, 1), ("second", 2, 2), ("third", 3, 3),
               ("fourth_plus", 4, None)]
    out = []
    for name, mn, mx in buckets:
        b_rows = [r for r in rows
                  if r.get("rr") == rr_key
                  and r.get("touch_number", 0) >= mn
                  and (mx is None or r.get("touch_number", 0) <= mx)]
        agg = _te_compute_aggregate(b_rows, rr_key)
        agg.update({
            "touch_bucket":     name,
            "touch_number_min": mn,
            "touch_number_max": mx,
            "opportunities":    len(b_rows),
        })
        out.append(agg)
    return out


def _te_apply_filters(rows: List[Dict], filters: Dict) -> List[Dict]:
    """AND across categories; OR within one multi-select category.

    Unknown/None metadata values are INCLUDED by default; set
    include_unknown=false to exclude them from metadata-based filters.
    """
    if not filters:
        return rows
    out = rows
    include_unknown = filters.get("include_unknown", True)

    tnums = filters.get("touch_numbers")
    if tnums:
        tset = set(int(t) for t in tnums)
        has_4plus = any(int(t) >= 4 for t in tnums)
        out = [r for r in out
               if r.get("touch_number") in tset
               or (has_4plus and (r.get("touch_number") or 0) >= 4)]

    dirs = filters.get("directions")
    if dirs:
        out = [r for r in out if r.get("direction") in dirs]

    outcomes = filters.get("outcomes")
    if outcomes:
        out = [r for r in out if r.get("outcome") in outcomes]

    syms = filters.get("symbols")
    if syms:
        out = [r for r in out if r.get("symbol") in syms]

    tfs = filters.get("timeframes")
    if tfs:
        out = [r for r in out if r.get("timeframe") in tfs]

    sess = filters.get("sessions")
    if sess:
        out = [r for r in out
               if r.get("session") in sess
               or (include_unknown and r.get("session") is None)]

    wdays = filters.get("weekdays")
    if wdays:
        out = [r for r in out
               if r.get("weekday") in wdays
               or (include_unknown and r.get("weekday") is None)]

    age_min = filters.get("ob_age_candles_min")
    if age_min is not None:
        out = [r for r in out
               if r.get("candles_since_formation") is not None
               and r["candles_since_formation"] >= age_min]
    age_max = filters.get("ob_age_candles_max")
    if age_max is not None:
        out = [r for r in out
               if r.get("candles_since_formation") is not None
               and r["candles_since_formation"] <= age_max]

    slr_min = filters.get("stop_loss_r_min")
    if slr_min is not None:
        out = [r for r in out
               if r.get("stop_loss_r") is not None and r["stop_loss_r"] >= slr_min
               or (include_unknown and r.get("stop_loss_r") is None)]
    slr_max = filters.get("stop_loss_r_max")
    if slr_max is not None:
        out = [r for r in out
               if r.get("stop_loss_r") is not None and r["stop_loss_r"] <= slr_max
               or (include_unknown and r.get("stop_loss_r") is None)]

    fvg = filters.get("fvg_overlap")
    if fvg and fvg != "all":
        if include_unknown:
            out = [r for r in out if r.get("fvg_overlap") in (fvg, "unknown", None)]
        else:
            out = [r for r in out if r.get("fvg_overlap") == fvg]

    htf = filters.get("higher_timeframe_alignment")
    if htf and htf != "all":
        if include_unknown:
            out = [r for r in out
                   if r.get("higher_timeframe_alignment") in (htf, "unknown", None)]
        else:
            out = [r for r in out if r.get("higher_timeframe_alignment") == htf]

    # TV OB% range — optional exchange-specific metadata; disabled (None) by default
    tv_min = filters.get("tv_ob_pct_min")
    if tv_min is not None:
        out = [r for r in out
               if r.get("tv_ob_pct_before_touch") is not None
               and r["tv_ob_pct_before_touch"] >= tv_min
               or (include_unknown and r.get("tv_ob_pct_before_touch") is None)]
    tv_max = filters.get("tv_ob_pct_max")
    if tv_max is not None:
        out = [r for r in out
               if r.get("tv_ob_pct_before_touch") is not None
               and r["tv_ob_pct_before_touch"] <= tv_max
               or (include_unknown and r.get("tv_ob_pct_before_touch") is None)]

    return out


def _te_filter_availability() -> Dict:
    """Which filter facets are backed by real canonical data right now."""
    return {
        "touch_numbers":  {"available": True},
        "directions":     {"available": True},
        "outcomes":       {"available": True},
        "symbols":        {"available": True},
        "timeframes":     {"available": True},
        "rr":             {"available": True},
        "ob_age_candles": {"available": True},
        "stop_loss_r":    {"available": True},
        "sessions":       {"available": True, "note": "UTC session boundaries"},
        "weekdays":       {"available": True, "note": "UTC weekday"},
        "fvg_overlap":    {"available": False,
                           "note": "FVG overlap not computed by the historical replay engine yet"},
        "higher_timeframe_alignment": {"available": False,
                           "note": "HTF alignment not computed by the historical replay engine yet"},
        "zone_size_atr":  {"available": False,
                           "note": "ATR normalization not computed in this phase; zone_size_pct available on rows"},
        "mfe_r":          {"available": False,
                           "note": "MFE returned as row metadata; range filter not active this phase"},
        "mae_r":          {"available": False,
                           "note": "MAE returned as row metadata; range filter not active this phase"},
        "tv_ob_pct":      {"available": True, "enabled_by_default": False,
                           "exchange_specific": True,
                           "note": "Optional exchange-specific metadata. Not comparable across exchanges."},
    }


def _te_process_cell(sym: str, tf: str, candles_normalized: List[Dict],
                     rr_values: list, params: Dict) -> Dict:
    """Build all touch trade rows for one symbol/timeframe cell."""
    t0 = time.monotonic()

    events = _bt_extract_ob_replay_events(candles_normalized, params)
    _bt_apply_outcomes_to_events(events, candles_normalized, params)

    all_rows: List[Dict] = []
    episode_count = 0
    for ev in events:
        if ev.get("touch_status") != "touched":
            continue
        episodes = _te_detect_touch_episodes(candles_normalized, ev)
        episode_count += len(episodes)
        all_rows.extend(_te_build_touch_trade_rows(ev, episodes,
                                                   candles_normalized, rr_values))

    return {
        "ok":            True,
        "symbol":        sym,
        "timeframe":     tf,
        "rows":          all_rows,
        "ob_count":      len(events),
        "episode_count": episode_count,
        "elapsed_ms":    round((time.monotonic() - t0) * 1000),
    }


_TE_SORTABLE_FIELDS = {
    "touch_time", "formation_time", "symbol", "timeframe", "direction",
    "touch_number", "candles_since_formation", "stop_loss_r", "realized_r",
    "mfe_r", "mae_r", "outcome", "entry_price",
}

_TE_ROW_DISPLAY_KEYS = [
    "touch_trade_id", "ob_id", "symbol", "timeframe", "direction",
    "touch_number", "touch_bucket", "formation_time", "touch_time",
    "candles_since_formation", "session", "weekday",
    "zone_high", "zone_low", "zone_size_pct", "zone_size_atr",
    "entry_price", "stop_price", "stop_loss_r", "rr", "outcome", "realized_r",
    "mfe_r", "mae_r", "fvg_overlap", "higher_timeframe_alignment",
    "tv_ob_pct_before_touch", "tv_ob_pct_exchange_specific",
    "overlaps_previous_touch_trade", "eligible", "rejection_reasons",
    "ob_valid_before_touch", "ob_state_before_touch",
]


def _te_sort_rows(rows: List[Dict], sort_field: str, sort_dir: str) -> List[Dict]:
    """Stable server-side sort with deterministic touch_trade_id tiebreak."""
    if sort_field not in _TE_SORTABLE_FIELDS:
        sort_field = "touch_time"
    reverse = (str(sort_dir).lower() != "asc")

    def _key(r):
        v = r.get(sort_field)
        # None sorts last regardless of direction; tiebreak on trade id
        return (v is None, v if v is not None else 0, r.get("touch_trade_id", ""))

    try:
        return sorted(rows, key=_key, reverse=reverse)
    except TypeError:
        return sorted(rows, key=lambda r: (r.get(sort_field) is None,
                                           str(r.get(sort_field) or ""),
                                           r.get("touch_trade_id", "")),
                      reverse=reverse)


def _bt_run_trade_explorer(req: Dict) -> Dict:
    """Server-authoritative Trade Explorer orchestrator (research only)."""
    t_start = time.monotonic()

    symbols      = req.get("symbols", [])
    timeframes   = req.get("timeframes", [])
    candle_count = int(req.get("candle_count", 1000))
    rr_raw       = req.get("rr", 2)
    filters      = req.get("filters") or {}
    page         = max(1, int(req.get("page", 1)))
    page_size    = max(1, min(int(req.get("page_size", 100)), _TE_MAX_PAGE_SIZE))
    sort_cfg     = req.get("sort") or {}
    sort_field   = str(sort_cfg.get("field", "touch_time"))
    sort_dir     = str(sort_cfg.get("direction", "desc"))

    rr_values = [1, 2, 3]
    rr_key    = _bt_rr_key(int(rr_raw))

    all_rows: List[Dict] = []
    failures: List[Dict] = []
    network_fetch_count = 0
    completed_cells = 0
    total_ob_count = 0
    total_episode_count = 0
    slowest_cell = None
    slowest_ms   = -1

    for sym in symbols:
        for tf in timeframes:
            try:
                raw = get_klines(sym, tf, limit=candle_count)
                network_fetch_count += 1
                candles_norm = _bt_normalize_candles(raw)
                if not candles_norm:
                    failures.append({"symbol": sym, "timeframe": tf,
                                     "stage": "normalize", "error": "no_candles"})
                    continue
                params = _bt_wf_build_params(sym, tf, len(candles_norm), rr_values)
                cell = _te_process_cell(sym, tf, candles_norm, rr_values, params)
                completed_cells += 1
                all_rows.extend(cell["rows"])
                total_ob_count      += cell["ob_count"]
                total_episode_count += cell["episode_count"]
                if cell["elapsed_ms"] > slowest_ms:
                    slowest_ms   = cell["elapsed_ms"]
                    slowest_cell = f"{sym}:{tf}"
            except Exception as e:
                failures.append({"symbol": sym, "timeframe": tf,
                                 "stage": "run", "error": str(e)[:200]})

    # ── Duplicate-ID guard ────────────────────────────────────────────────────
    _seen_ids: set = set()
    deduped: List[Dict] = []
    for r in all_rows:
        tid = r.get("touch_trade_id")
        if tid in _seen_ids:
            continue
        _seen_ids.add(tid)
        deduped.append(r)
    all_rows = deduped

    # ── Baseline vs filtered (same RR only) ───────────────────────────────────
    baseline_rows = [r for r in all_rows if r.get("rr") == rr_key]
    baseline_summary = _te_compute_aggregate(baseline_rows, rr_key)
    filtered_rows = _te_apply_filters(baseline_rows, filters)
    filtered_summary = _te_compute_aggregate(filtered_rows, rr_key)

    bt_n = baseline_summary["trades"]
    ft_n = filtered_summary["trades"]
    bwr, fwr = baseline_summary["win_rate_pct"], filtered_summary["win_rate_pct"]
    bex, fex = baseline_summary["expectancy_r"], filtered_summary["expectancy_r"]
    bpf, fpf = baseline_summary["profit_factor_r"], filtered_summary["profit_factor_r"]
    comparison = {
        "trade_count_delta":   ft_n - bt_n,
        "trade_retention_pct": round(ft_n / bt_n * 100, 2) if bt_n else None,
        "win_rate_delta_pct":  round(fwr - bwr, 2) if fwr is not None and bwr is not None else None,
        "expectancy_delta_r":  round(fex - bex, 6) if fex is not None and bex is not None else None,
        "profit_factor_delta": round(fpf - bpf, 4) if fpf is not None and bpf is not None else None,
        "net_r_delta":         round(filtered_summary["net_r"] - baseline_summary["net_r"], 4),
        "sample_size_warning": ("insufficient_filtered_sample" if ft_n < 20 else None),
    }

    # ── Sort + paginate (stable, deterministic) ──────────────────────────────
    sorted_rows    = _te_sort_rows(filtered_rows, sort_field, sort_dir)
    total_filtered = len(sorted_rows)
    start_idx      = (page - 1) * page_size
    page_rows      = sorted_rows[start_idx:start_idx + page_size]
    page_rows_out  = [{k: r.get(k) for k in _TE_ROW_DISPLAY_KEYS} for r in page_rows]

    result = {
        "ok":                      True,
        "authoritative_execution": True,
        "client_results_accepted": False,
        "mode":                    "trade_explorer_v1",
        "request": {
            "symbols":      symbols,
            "timeframes":   timeframes,
            "candle_count": candle_count,
            "rr":           rr_key,
            "filters":      filters,
            "page":         page,
            "page_size":    page_size,
            "sort":         {"field": sort_field, "direction": sort_dir},
        },
        "filter_availability":     _te_filter_availability(),
        "baseline_summary":        baseline_summary,
        "filtered_summary":        filtered_summary,
        "comparison":              comparison,
        "touch_bucket_comparison":          _te_touch_bucket_comparison(baseline_rows, rr_key),
        "filtered_touch_bucket_comparison": _te_touch_bucket_comparison(filtered_rows, rr_key),
        "trade_rows":              page_rows_out,
        "total_trade_count":       total_filtered,
        "total_opportunities":     len(baseline_rows),
        "page":                    page,
        "page_size":               page_size,
        "total_pages":             max(1, (total_filtered + page_size - 1) // page_size),
        "failures":                failures,
        "performance": {
            "requested_cells":              len(symbols) * len(timeframes),
            "completed_cells":              completed_cells,
            "failed_cells":                 len(failures),
            "network_fetch_count":          network_fetch_count,
            "expected_network_fetch_count": len(symbols) * len(timeframes),
            "candles_fetched_once_per_cell": network_fetch_count <= len(symbols) * len(timeframes),
            "ob_count":                     total_ob_count,
            "touch_episode_count":          total_episode_count,
            "touch_trade_count":            len(all_rows),
            "total_elapsed_ms":             round((time.monotonic() - t_start) * 1000),
            "response_size_bytes":          None,
            "slowest_cell":                 slowest_cell,
        },
        "constants": {
            "max_symbols":     _TE_MAX_SYMBOLS,
            "max_timeframes":  _TE_MAX_TIMEFRAMES,
            "max_cells":       _TE_MAX_CELLS,
            "max_page_size":   _TE_MAX_PAGE_SIZE,
            "candle_window":   _TE_CANDLE_WINDOW,
            "build_commit":    _TE_BUILD_COMMIT,
            "phase":           "16",
        },
        "notice": "Research only. Filters do not affect Scanner, Live Monitor, alerts or execution.",
    }
    return result


def _bt_run_trade_explorer_detail(touch_trade_id: str, req: Dict) -> Dict:
    """Re-derive one touch trade deterministically and return an audit view.

    Candle window is capped at _TE_CANDLE_WINDOW — never the full history.
    """
    symbols      = req.get("symbols", [])
    timeframes   = req.get("timeframes", [])
    candle_count = int(req.get("candle_count", 1000))
    rr_values    = [1, 2, 3]

    for sym in symbols:
        for tf in timeframes:
            try:
                raw = get_klines(sym, tf, limit=candle_count)
                candles_norm = _bt_normalize_candles(raw)
                if not candles_norm:
                    continue
                params = _bt_wf_build_params(sym, tf, len(candles_norm), rr_values)
                events = _bt_extract_ob_replay_events(candles_norm, params)
                _bt_apply_outcomes_to_events(events, candles_norm, params)
                for ev in events:
                    if ev.get("touch_status") != "touched":
                        continue
                    episodes = _te_detect_touch_episodes(candles_norm, ev)
                    for ep_i, ep in enumerate(episodes):
                        for rv in rr_values:
                            rk  = _bt_rr_key(rv)
                            tid = _te_touch_trade_id(ev, ep["touch_number"],
                                                     ep["touch_index"], rk)
                            if tid != touch_trade_id:
                                continue
                            sim = _te_simulate_touch_outcome(
                                ep["touch_index"], ev, candles_norm, rr_values)
                            fb        = int(ev["formation_bar"])
                            touch_idx = ep["touch_index"]
                            exit_bar  = (sim.get("realized_by_rr") or {}) \
                                .get(rk, {}).get("exit_bar")
                            w_start = max(0, fb - 30)
                            w_end_target = (exit_bar + 10) if exit_bar is not None \
                                else (touch_idx + 50)
                            w_end = min(len(candles_norm),
                                        max(w_end_target, touch_idx + 5),
                                        w_start + _TE_CANDLE_WINDOW)
                            window = candles_norm[w_start:w_end]
                            return {
                                "ok":             True,
                                "touch_trade_id": tid,
                                "ob_id":          _te_ob_id(ev),
                                "symbol":         sym,
                                "timeframe":      tf,
                                "direction":      ev.get("type"),
                                "rr":             rk,
                                "touch_number":   ep["touch_number"],
                                "touch_bucket":   ep["touch_bucket"],
                                "zone_high":      ev.get("zone_high"),
                                "zone_low":       ev.get("zone_low"),
                                "formation_bar":  fb,
                                "formation_time": ev.get("formation_time"),
                                "touch_index":    touch_idx,
                                "touch_time":     ep.get("touch_time"),
                                "episode":        ep,
                                "previous_touch": episodes[ep_i - 1] if ep_i > 0 else None,
                                "next_touch":     (episodes[ep_i + 1]
                                                   if ep_i + 1 < len(episodes) else None),
                                "all_touch_episodes": episodes,
                                "simulation":     sim,
                                "candle_window":  window,
                                "candle_window_start_index": w_start,
                                "candle_window_size": len(window),
                                "candle_window_limit": _TE_CANDLE_WINDOW,
                            }
            except Exception:
                continue
    return {"ok": False, "error": "touch_trade_id_not_found",
            "touch_trade_id": touch_trade_id}


_TE_FORBIDDEN_REQUEST_KEYS = (
    "trades", "outcomes", "metrics", "touch_histories", "event_results",
    "summaries", "comparison_results", "trade_rows", "baseline_summary",
    "filtered_summary", "touch_bucket_comparison", "win_rate", "expectancy",
)


@app.route("/api/backtest/ob-historical/trade-explorer", methods=["POST"])
@login_required
def api_backtest_ob_historical_trade_explorer():
    err = _guest_tab_check("backtest")
    if err is not None:
        return err

    payload = request.get_json(force=True) or {}

    # Server is authoritative — reject any client-supplied results.
    for banned in _TE_FORBIDDEN_REQUEST_KEYS:
        if banned in payload:
            return jsonify({
                "ok": False,
                "error": "client_supplied_trade_results_not_allowed",
            }), 400

    # Symbols (max 5, no blanks, no duplicates)
    raw_syms = payload.get("symbols",
                           ["BTCUSDT", "ETHUSDT", "BNBUSDT", "SOLUSDT", "XRPUSDT"])
    if not isinstance(raw_syms, list):
        raw_syms = [str(raw_syms)]
    seen_syms: set = set()
    symbols: List[str] = []
    for s in raw_syms:
        s = str(s or "").strip().upper()
        if not s:
            return jsonify({"ok": False, "error": "blank symbol not allowed"}), 400
        if not s.endswith("USDT"):
            s = s + "USDT"
        if s in seen_syms:
            return jsonify({"ok": False, "error": "duplicate symbols not allowed"}), 400
        seen_syms.add(s)
        symbols.append(s)
    if not symbols:
        return jsonify({"ok": False, "error": "at least one symbol required"}), 400
    if len(symbols) > _TE_MAX_SYMBOLS:
        return jsonify({"ok": False, "error": f"max {_TE_MAX_SYMBOLS} symbols"}), 400

    # Timeframes (max 2, existing allowed set, no duplicates)
    raw_tfs = payload.get("timeframes", ["1h", "4h"])
    if not isinstance(raw_tfs, list):
        raw_tfs = [str(raw_tfs)]
    seen_tfs: set = set()
    timeframes: List[str] = []
    for tf in raw_tfs:
        tf = str(tf).strip()
        if tf not in _BT_ALLOWED_TIMEFRAMES:
            return jsonify({"ok": False,
                            "error": f"timeframe '{tf}' not allowed. "
                                     f"Allowed: {sorted(_BT_ALLOWED_TIMEFRAMES)}"}), 400
        if tf in seen_tfs:
            return jsonify({"ok": False, "error": "duplicate timeframes not allowed"}), 400
        seen_tfs.add(tf)
        timeframes.append(tf)
    if not timeframes:
        return jsonify({"ok": False, "error": "at least one timeframe required"}), 400
    if len(timeframes) > _TE_MAX_TIMEFRAMES:
        return jsonify({"ok": False, "error": f"max {_TE_MAX_TIMEFRAMES} timeframes"}), 400

    if len(symbols) * len(timeframes) > _TE_MAX_CELLS:
        return jsonify({"ok": False,
                        "error": f"max {_TE_MAX_CELLS} symbol/timeframe cells"}), 400

    # candle_count within existing historical limits (500-4000)
    try:
        candle_count = int(payload.get("candle_count", 1000))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "candle_count must be integer"}), 400
    candle_count = max(500, min(4000, candle_count))

    # RR limited to 1, 2 or 3
    try:
        rr = int(payload.get("rr", 2))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "rr must be 1, 2 or 3"}), 400
    if rr not in _TE_ALLOWED_RR:
        return jsonify({"ok": False, "error": "rr must be 1, 2 or 3"}), 400

    # page / page_size
    try:
        page = max(1, int(payload.get("page", 1)))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "page must be integer"}), 400
    try:
        page_size = int(payload.get("page_size", 100))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "page_size must be integer"}), 400
    if page_size < 1 or page_size > _TE_MAX_PAGE_SIZE:
        return jsonify({"ok": False,
                        "error": f"page_size must be 1-{_TE_MAX_PAGE_SIZE}"}), 400

    filters = payload.get("filters") or {}
    if not isinstance(filters, dict):
        return jsonify({"ok": False, "error": "filters must be an object"}), 400

    sort_cfg = payload.get("sort") or {}
    if not isinstance(sort_cfg, dict):
        sort_cfg = {}

    try:
        result = _bt_run_trade_explorer({
            "symbols":      symbols,
            "timeframes":   timeframes,
            "candle_count": candle_count,
            "rr":           rr,
            "filters":      filters,
            "page":         page,
            "page_size":    page_size,
            "sort":         sort_cfg,
        })
        import json as _json_te_size
        result["performance"]["response_size_bytes"] = len(
            _json_te_size.dumps(result, default=str))
        return jsonify(result), 200
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)[:500]}), 500


@app.route("/api/backtest/ob-historical/trade-explorer/trade/<touch_trade_id>",
           methods=["POST"])
@login_required
def api_backtest_ob_historical_trade_explorer_detail(touch_trade_id: str):
    err = _guest_tab_check("backtest")
    if err is not None:
        return err

    payload = request.get_json(force=True) or {}
    for banned in _TE_FORBIDDEN_REQUEST_KEYS:
        if banned in payload:
            return jsonify({
                "ok": False,
                "error": "client_supplied_trade_results_not_allowed",
            }), 400

    raw_syms = payload.get("symbols", [])
    if not isinstance(raw_syms, list) or not raw_syms:
        return jsonify({"ok": False, "error": "symbols required"}), 400
    symbols = [str(s or "").strip().upper() for s in raw_syms][: _TE_MAX_SYMBOLS]
    symbols = [s if s.endswith("USDT") else s + "USDT" for s in symbols if s]

    raw_tfs = payload.get("timeframes", ["1h", "4h"])
    if not isinstance(raw_tfs, list):
        raw_tfs = [str(raw_tfs)]
    timeframes = [str(t).strip() for t in raw_tfs
                  if str(t).strip() in _BT_ALLOWED_TIMEFRAMES][: _TE_MAX_TIMEFRAMES]
    if not timeframes:
        return jsonify({"ok": False, "error": "at least one valid timeframe required"}), 400

    try:
        candle_count = max(500, min(4000, int(payload.get("candle_count", 1000))))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "candle_count must be integer"}), 400

    try:
        result = _bt_run_trade_explorer_detail(str(touch_trade_id), {
            "symbols":      symbols,
            "timeframes":   timeframes,
            "candle_count": candle_count,
        })
        status = 200 if result.get("ok") else 404
        return jsonify(result), status
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)[:500]}), 500



# ══════════════════════════════════════════════════════════════════════════════
# Phase 18 — Autopsy Agent: deterministic per-trade failure analysis
# Research only. No AI API in the core — every reason code is a computed fact.
# No production filter activation. No DB writes.
# ══════════════════════════════════════════════════════════════════════════════

_AP_MAX_SYMBOLS:    int   = 5
_AP_MAX_TIMEFRAMES: int   = 2
_AP_MAX_CELLS:      int   = 10
_AP_ATR_PERIOD:     int   = 14
_AP_WEAK_DISPLACEMENT_ATR: float = 1.0   # formation move below this many ATRs = weak
_AP_OVERSIZED_ZONE_ATR:    float = 2.0   # zone bigger than this many ATRs = oversized
_AP_STALE_ZONE_CANDLES:    int   = 50    # touch later than this after formation = stale
_AP_LATE_TOUCH_NUMBER:     int   = 3     # touch number >= this = late touch
_AP_SLOW_BLEED_CANDLES:    int   = 20    # loss taking at least this many candles = slow bleed
_AP_MIN_PROFILE_TRADES:    int   = 5     # profiles below this are reported but flagged

# Higher-timeframe map for HTF trend context (fixed, documented).
_AP_HTF_MAP: Dict[str, Optional[str]] = {
    "5m": "1h", "15m": "1h", "30m": "4h", "1h": "4h", "4h": "1d", "1d": None,
}

# Predictive features ranked in 18B (computed for BOTH winners and losers).
# Phase 19 adds FVG_CONFLUENCE, IN_PREMIUM_HALF, HIGH_VOL_REGIME.
# Phase 20 adds the four volume-context features.
_AP_FEATURE_KEYS = (
    "AGAINST_HTF_TREND", "AGAINST_TF_TREND", "COUNTER_SWING",
    "LATE_TOUCH", "WEAK_DISPLACEMENT", "OVERSIZED_ZONE", "STALE_ZONE",
    "SESSION_ASIA", "SESSION_LONDON", "SESSION_NEWYORK", "SESSION_OTHER",
    "FVG_CONFLUENCE", "IN_PREMIUM_HALF", "HIGH_VOL_REGIME",
    "HIGH_FORMATION_VOLUME", "LOW_FORMATION_VOLUME",
    "HIGH_TOUCH_VOLUME", "LOW_TOUCH_VOLUME",
    # Phase 20B Chunk 3 — primary divergence signals at touch
    "RSI_DIVERGENCE_AT_TOUCH", "CVD_DIVERGENCE_AT_TOUCH",
    "RSI_OVERSOLD_AT_TOUCH", "RSI_OVERBOUGHT_AT_TOUCH",
    # Phase 20B Chunk 4 — open-interest context (last-30-days window)
    "OI_RISING_AT_TOUCH", "OI_FALLING_AT_TOUCH",
    # Phase 20B Chunk 5 — structure & flow
    "LIQUIDITY_SWEEP_INTO_ZONE", "OB_REVERSAL", "OB_CONTINUATION",
    "AGAINST_BTC_TREND", "DEEP_ZONE_PENETRATION", "ABSORPTION_AT_TOUCH",
)

# ── Phase 20: Bad-Trade Filter Lab (labels only — trades are NEVER removed) ──
_FL_CLEAN_WIN_MAX_MAE:      float = 0.5   # win with MAE <= this = clean win
_FL_REVERSAL_LOSS_MIN_MFE:  float = 1.0   # loss that first reached this MFE = reversal loss
_FL_PAUSE_MIN_MFE:          float = 1.0   # unresolved above this MFE = paused positive
_FL_VOL_SMA_WINDOW:         int   = 20    # trailing volume average window
_FL_VOL_MIN_SAMPLES:        int   = 5     # min trailing volume values for a ratio
_FL_HIGH_VOL_RATIO:         float = 1.5   # volume >= 1.5x trailing avg = high
_FL_LOW_VOL_RATIO:          float = 0.7   # volume <  0.7x trailing avg = low
_FL_TRADE_LOG_CAP:          int   = 1000  # max trade-log rows in the response

# Performance grades — the user's mental model made deterministic:
#   clean_win       — worked very well (win, never went deeper than 0.5R against)
#   stressed_win    — worked, but went >0.5R against first
#   reversal_loss   — performed (reached >=1R in favor) then failed
#   hard_loss       — failed without ever performing (<1R MFE)
#   paused_positive — unfinished at data end but already >=1R in favor
#   paused_flat     — unfinished and not performing
#   ambiguous       — same-candle TP/SL, unclassifiable
_FL_GRADES = ("clean_win", "stressed_win", "reversal_loss", "hard_loss",
              "paused_positive", "paused_flat", "ambiguous")
_FL_WORKING_GRADES = ("clean_win", "stressed_win")
_FL_FAILING_GRADES = ("reversal_loss", "hard_loss")

# ── Phase 20B Chunk 2: "respect" framing (the user's language) ───────────────
# A LABEL over the existing grade — did price REACT to the zone?
#   respected     — price reacted and paid (clean_win / stressed_win)
#   partial       — price reacted (reached >=1R in favor) but did not fully pay
#                   (reversal_loss) or is still open in profit (paused_positive)
#   not_respected — price sliced through without reacting (hard_loss)
#   neutral       — inconclusive: unfinished-flat, or same-candle ambiguous
_FL_RESPECT_CLASSES = ("respected", "partial", "not_respected", "neutral")
_FL_GRADE_TO_RESPECT = {
    "clean_win":       "respected",
    "stressed_win":    "respected",
    "reversal_loss":   "partial",
    "paused_positive": "partial",
    "hard_loss":       "not_respected",
    "paused_flat":     "neutral",
    "ambiguous":       "neutral",
}


def _bt_fl_respect_class(grade: str) -> str:
    """Map a performance grade to a respect class (label only)."""
    return _FL_GRADE_TO_RESPECT.get(grade, "neutral")


def _bt_fl_htf_joint_state(alignments: Dict) -> str:
    """Combine per-trend-TF alignments into ONE joint HTF state.

    `alignments` maps each mapped trend TF (e.g. 1h, 4h for a 15m OB) to
    with / against / neutral / unknown. Returns a single categorical:
      all_with            — every trend TF aligned with the trade
      all_against         — every trend TF against
      conflicting         — at least one with AND at least one against
      with_some_neutral   — some with, none against (rest neutral)
      against_some_neutral— some against, none with (rest neutral)
      all_neutral         — every trend TF neutral
      unknown             — any trend TF unknown (or no trend TFs)
    """
    vals = list(alignments.values()) if alignments else []
    if not vals or any(v == "unknown" for v in vals):
        return "unknown"
    w = sum(1 for v in vals if v == "with")
    a = sum(1 for v in vals if v == "against")
    n = sum(1 for v in vals if v == "neutral")
    total = len(vals)
    if w == total:
        return "all_with"
    if a == total:
        return "all_against"
    if w > 0 and a > 0:
        return "conflicting"
    if w > 0 and a == 0:
        return "with_some_neutral"
    if a > 0 and w == 0:
        return "against_some_neutral"
    return "all_neutral"


# ── Phase 20B Chunk 3: RSI + CVD divergence at touch (PRIMARY signals) ───────
_FL_RSI_PERIOD:     int   = 14
_FL_RSI_OVERSOLD:   float = 30.0
_FL_RSI_OVERBOUGHT: float = 70.0


def _bt_fl_cvd_series(candles: List[Dict]) -> List[Optional[float]]:
    """Cumulative Volume Delta per bar (running sum of per-bar delta).

    Per-bar delta = taker_buy_base - (volume - taker_buy_base)
                  = 2*taker_buy_base - volume  (buy volume minus sell volume).
    Requires taker_buy_base (Binance kline field 9). When it is missing on a
    bar, that bar contributes 0 to the running sum and its CVD value is still
    emitted (so the series stays aligned), but bars with NO taker data anywhere
    yield an all-None series → divergence returns not-evaluable. No look-ahead:
    cvd[i] uses only bars 0..i.
    """
    n = len(candles)
    out: List[Optional[float]] = [None] * n
    have_any = any(c.get("taker_buy_base") is not None for c in candles)
    if not have_any:
        return out
    running = 0.0
    for i in range(n):
        tb = candles[i].get("taker_buy_base")
        vol = candles[i].get("volume")
        if tb is not None and vol is not None:
            running += (2.0 * float(tb) - float(vol))
        out[i] = round(running, 4)
    return out


def _bt_fl_bar_delta(candle: Dict) -> Optional[float]:
    """Single-bar delta (buy minus sell volume) or None when taker data missing."""
    tb = candle.get("taker_buy_base")
    vol = candle.get("volume")
    if tb is None or vol is None:
        return None
    return round(2.0 * float(tb) - float(vol), 4)


def _bt_fl_divergence_at_touch(direction: str, touch_idx: int,
                               candles: List[Dict], series: List[Optional[float]],
                               trend_idx: Dict) -> Optional[bool]:
    """Divergence between price and an indicator series at the touch bar.

    Bullish OB (price falling into the zone): divergence = the touch bar makes
    a LOWER LOW than the last confirmed pivot low, while the indicator makes a
    HIGHER low (price weaker, momentum/flow stronger → reversal fuel).
    Bearish OB: mirror (higher high in price, lower high in indicator).

    Reference = last pivot CONFIRMED before the touch (pivot bar <= touch_idx -
    pivot_len), same no-look-ahead rule as the trend queries. Returns
    True / False / None (None when there is no prior confirmed pivot or the
    indicator value is missing at either point).
    """
    import bisect as _bisect
    if touch_idx is None or touch_idx < 0 or touch_idx >= len(candles):
        return None
    if not series or touch_idx >= len(series):
        return None
    p_len  = trend_idx.get("pivot_len", _BT_PIVOT_LEN)
    cutoff = touch_idx - p_len
    if direction == "bullish":
        bars = trend_idx.get("low_bars", [])
        i = _bisect.bisect_right(bars, cutoff) - 1
        if i < 0:
            return None
        piv = bars[i]
        s_now, s_piv = series[touch_idx], series[piv]
        if s_now is None or s_piv is None:
            return None
        price_now = float(candles[touch_idx]["low"])
        price_piv = float(candles[piv]["low"])
        return bool(price_now < price_piv and s_now > s_piv)
    else:
        bars = trend_idx.get("high_bars", [])
        i = _bisect.bisect_right(bars, cutoff) - 1
        if i < 0:
            return None
        piv = bars[i]
        s_now, s_piv = series[touch_idx], series[piv]
        if s_now is None or s_piv is None:
            return None
        price_now = float(candles[touch_idx]["high"])
        price_piv = float(candles[piv]["high"])
        return bool(price_now > price_piv and s_now < s_piv)


# ── Phase 20B Chunk 4: Open Interest context (last-30-days window) ───────────
# Binance's free OI-history endpoint only serves the last ~30 days. Trades
# older than the fetched window are labelled OI "not available" — never
# guessed, never removed from the log.
_FL_OI_PERIOD_MAP: Dict[str, str] = {
    "5m": "5m", "15m": "15m", "30m": "30m", "1h": "1h",
    "2h": "2h", "4h": "4h", "1d": "1d",
}
_FL_OI_PAGE_ROWS:   int   = 500     # Binance per-request cap
_FL_OI_MAX_ROWS:    int   = 3000    # backtest cap (bounds pagination)
_FL_OI_WINDOW_DAYS: int   = 30      # endpoint hard limit
_FL_OI_LOOKBACK:    int   = 6       # OI periods before touch for the change calc
_FL_OI_RISE_PCT:    float = 2.0     # |change| above this = rising / falling


def _bt_fl_fetch_oi_history(symbol: str, period: str,
                            now_ms: Optional[int] = None) -> List[Tuple[int, float]]:
    """Fetch Binance futures OI history (last ~30 days), sorted oldest→newest.

    Returns [(timestamp_ms, sum_open_interest), ...] or [] on any failure /
    unsupported period. Paginates backward with endTime, capped at
    _FL_OI_MAX_ROWS and _FL_OI_WINDOW_DAYS. Network-only — in environments
    without outbound access this returns [] and every trade's OI shows
    "not available" (honest, never fabricated).
    """
    if period not in _FL_OI_PERIOD_MAP.values():
        return []
    collected: Dict[int, float] = {}
    end_time: Optional[int] = None
    pages = 0
    max_pages = max(1, _FL_OI_MAX_ROWS // _FL_OI_PAGE_ROWS)
    oldest_allowed = None
    if now_ms is not None:
        oldest_allowed = int(now_ms) - _FL_OI_WINDOW_DAYS * 86_400_000
    try:
        while pages < max_pages and len(collected) < _FL_OI_MAX_ROWS:
            pages += 1
            params: Dict[str, Any] = {"symbol": symbol, "period": period,
                                      "limit": _FL_OI_PAGE_ROWS}
            if end_time is not None:
                params["endTime"] = end_time
            r = req.get(f"{BINANCE_FUTURES_API}/futures/data/openInterestHist",
                        params=params, timeout=15)
            if r.status_code != 200:
                break
            rows = r.json()
            if not isinstance(rows, list) or not rows:
                break
            added = 0
            earliest_ts = None
            for row in rows:
                try:
                    ts = int(row["timestamp"])
                    oi = float(row["sumOpenInterest"])
                except (KeyError, TypeError, ValueError):
                    continue
                earliest_ts = ts if earliest_ts is None else min(earliest_ts, ts)
                if ts not in collected:
                    collected[ts] = oi
                    added += 1
            if added == 0 or earliest_ts is None:
                break
            if oldest_allowed is not None and earliest_ts <= oldest_allowed:
                break
            end_time = earliest_ts - 1   # page backward
    except Exception:
        return sorted(collected.items())
    return sorted(collected.items())


def _bt_fl_oi_at(oi_list: List[Tuple[int, float]], touch_time) -> Tuple[Optional[float], bool]:
    """OI at the last period whose timestamp <= touch_time.

    Returns (oi_value, available). available is False when there is no OI data
    or the touch is older than the earliest fetched point (beyond the 30-day
    window) — that trade is labelled "not available", never guessed.
    """
    import bisect as _bisect
    if not oi_list or touch_time is None:
        return None, False
    ts_list = [t for t, _ in oi_list]
    tt = int(touch_time)
    if tt < ts_list[0]:
        return None, False               # older than the fetched window
    i = _bisect.bisect_right(ts_list, tt) - 1
    if i < 0:
        return None, False
    return oi_list[i][1], True


def _bt_fl_oi_context(oi_list: List[Tuple[int, float]], touch_time) -> Dict:
    """OI value + rising/falling context at the touch (no look-ahead).

    Change is measured from the OI point _FL_OI_LOOKBACK periods before the
    touch to the point at the touch — both at/before touch_time. When the
    touch is outside the fetched window, everything is not-available.
    """
    import bisect as _bisect
    oi_now, available = _bt_fl_oi_at(oi_list, touch_time)
    out = {"oi_at_touch": oi_now, "available": available,
           "oi_change_pct": None, "rising": None, "falling": None}
    if not available:
        return out
    ts_list = [t for t, _ in oi_list]
    i = _bisect.bisect_right(ts_list, int(touch_time)) - 1
    j = i - _FL_OI_LOOKBACK
    if j >= 0:
        oi_prev = oi_list[j][1]
        if oi_prev and oi_prev > 0:
            chg = (oi_now - oi_prev) / oi_prev * 100.0
            out["oi_change_pct"] = round(chg, 3)
            out["rising"]  = chg >= _FL_OI_RISE_PCT
            out["falling"] = chg <= -_FL_OI_RISE_PCT
    return out


# ── Phase 20B Chunk 5: structure & flow features ────────────────────────────
_FL_RANGE_SMA_WINDOW:  int   = 20    # trailing window for the candle-range average
_FL_ABSORPTION_RANGE:  float = 0.7   # touch range < this * avg range = small candle
_FL_DEEP_PENETRATION:  float = 0.5   # MAE_r >= this = price reached >50% into zone


def _bt_fl_range_ratio(candles: List[Dict], bar: Optional[int],
                       window: int = _FL_RANGE_SMA_WINDOW) -> Optional[float]:
    """Candle (high-low) range at `bar` / trailing average range. No look-ahead."""
    if bar is None or bar <= 0 or bar >= len(candles):
        return None
    trailing = []
    for c in candles[max(0, bar - window):bar]:
        rng = float(c["high"]) - float(c["low"])
        if rng > 0:
            trailing.append(rng)
    if len(trailing) < _FL_VOL_MIN_SAMPLES:
        return None
    avg = sum(trailing) / len(trailing)
    cur = float(candles[bar]["high"]) - float(candles[bar]["low"])
    if avg <= 0 or cur <= 0:
        return None
    return round(cur / avg, 3)


def _bt_fl_liquidity_sweep(direction: str, touch_idx: int, candles: List[Dict],
                           trend_idx: Dict) -> Optional[bool]:
    """Did the touch sweep liquidity beyond the last confirmed pivot?

    Bullish OB: the touch bar's low prints BELOW the last confirmed pivot low
    (sell-side stop hunt) before reacting from the zone. Bearish: touch bar's
    high prints ABOVE the last confirmed pivot high. Reference pivot uses the
    same confirmed-only rule (cutoff = touch_idx - pivot_len). None when there
    is no prior confirmed pivot.
    """
    import bisect as _bisect
    if touch_idx is None or touch_idx < 0 or touch_idx >= len(candles):
        return None
    p_len  = trend_idx.get("pivot_len", _BT_PIVOT_LEN)
    cutoff = touch_idx - p_len
    if direction == "bullish":
        bars = trend_idx.get("low_bars", [])
        i = _bisect.bisect_right(bars, cutoff) - 1
        if i < 0:
            return None
        piv_low = trend_idx["l"][bars[i]] if bars[i] < len(trend_idx.get("l", [])) else None
        if piv_low is None:
            return None
        return bool(float(candles[touch_idx]["low"]) < piv_low)
    else:
        bars = trend_idx.get("high_bars", [])
        i = _bisect.bisect_right(bars, cutoff) - 1
        if i < 0:
            return None
        piv_high = trend_idx["h"][bars[i]] if bars[i] < len(trend_idx.get("h", [])) else None
        if piv_high is None:
            return None
        return bool(float(candles[touch_idx]["high"]) > piv_high)


def _bt_fl_grade(outcome: str, mfe_r, mae_r) -> str:
    """Deterministic performance grade for one trade (labels, never filters)."""
    mfe = float(mfe_r) if mfe_r is not None else 0.0
    mae = float(mae_r) if mae_r is not None else 0.0
    if outcome == "win":
        return "clean_win" if mae <= _FL_CLEAN_WIN_MAX_MAE else "stressed_win"
    if outcome == "loss":
        return "reversal_loss" if mfe >= _FL_REVERSAL_LOSS_MIN_MFE else "hard_loss"
    if outcome == "ambiguous":
        return "ambiguous"
    return "paused_positive" if mfe >= _FL_PAUSE_MIN_MFE else "paused_flat"


def _bt_fl_excursions_to_exit(event: Dict, candles: List[Dict],
                              entry_bar: int, exit_bar: int) -> Tuple[Optional[float], Optional[float]]:
    """(MFE_R, MAE_R) measured ONLY over [entry_bar, exit_bar] inclusive.

    The Phase 16 simulation tracks excursions from the touch until the STOP
    or the end of data — for a winning trade that exits at TP, its raw MAE
    keeps accumulating after the trade is already closed. Grades must use
    the excursion up to the actual exit, so wins are re-measured here.
    """
    try:
        zone_high = float(event["zone_high"])
        zone_low  = float(event["zone_low"])
    except (KeyError, TypeError, ValueError):
        return None, None
    risk = zone_high - zone_low
    if risk <= 0 or entry_bar is None or exit_bar is None:
        return None, None
    entry = zone_high
    end = min(int(exit_bar), len(candles) - 1)
    if end < entry_bar:
        return None, None
    lo = None
    hi = None
    for j in range(int(entry_bar), end + 1):
        l = float(candles[j]["low"])
        h = float(candles[j]["high"])
        lo = l if lo is None else min(lo, l)
        hi = h if hi is None else max(hi, h)
    if event.get("type") == "bullish":
        mfe = max(0.0, (hi - entry) / risk) if hi is not None else 0.0
        mae = max(0.0, (entry - lo) / risk) if lo is not None else 0.0
    else:
        mfe = max(0.0, (entry - lo) / risk) if lo is not None else 0.0
        mae = max(0.0, (hi - entry) / risk) if hi is not None else 0.0
    return round(mfe, 4), round(mae, 4)


def _bt_fl_volume_ratio(candles: List[Dict], bar: Optional[int],
                        window: int = _FL_VOL_SMA_WINDOW) -> Optional[float]:
    """Volume at `bar` (numerator) divided by the trailing simple average of
    the previous `window` bars' volumes (denominator).

    All inputs are known at the bar's close — no look-ahead. None when the
    bar is out of range, volume data is missing/zero, or fewer than
    _FL_VOL_MIN_SAMPLES trailing values exist.
    """
    if bar is None or bar <= 0 or bar >= len(candles):
        return None
    trailing = [float(c.get("volume") or 0.0) for c in candles[max(0, bar - window):bar]]
    trailing = [v for v in trailing if v > 0]
    if len(trailing) < _FL_VOL_MIN_SAMPLES:
        return None
    avg = sum(trailing) / len(trailing)
    cur = float(candles[bar].get("volume") or 0.0)
    if avg <= 0 or cur <= 0:
        return None
    return round(cur / avg, 3)

# ── Phase 19: Alignment matrix + zone feature enrichment ─────────────────────
# Which trend timeframes each OB timeframe is tested against (frozen roadmap:
# 15m→{1h,4h}, 1h→{4h,1d}, 4h→{1d}; 5m/30m get their nearest sensible pair).
_AL_MATRIX_MAP: Dict[str, List[str]] = {
    "5m":  ["1h"],
    "15m": ["1h", "4h"],
    "30m": ["4h"],
    "1h":  ["4h", "1d"],
    "4h":  ["1d"],
    "1d":  [],
}
_AL_FVG_FORMATION_WINDOW: int   = 5     # FVGs formed in [fb-5, fb] count as confluence
_AL_ATR_PERCENTILE_WINDOW: int  = 100   # trailing ATR window for the volatility regime
_AL_HIGH_VOL_PERCENTILE: float  = 70.0  # ATR percentile above this = high-vol regime


def _bt_al_detect_fvgs(candles: List[Dict], start: int, end_inclusive: int) -> List[Dict]:
    """Fair value gaps formed at bars start..end_inclusive (3-candle rule).

    Bullish FVG at bar i: low[i] > high[i-2] → gap zone [high[i-2], low[i]].
    Bearish FVG at bar i: high[i] < low[i-2] → gap zone [high[i], low[i-2]].
    Uses only bars <= i — a gap "formed at i" is fully known at bar i's close.
    """
    out: List[Dict] = []
    n = len(candles)
    lo_bound = max(2, start)
    hi_bound = min(end_inclusive, n - 1)
    for i in range(lo_bound, hi_bound + 1):
        h2 = float(candles[i - 2]["high"])
        l2 = float(candles[i - 2]["low"])
        hi_i = float(candles[i]["high"])
        lo_i = float(candles[i]["low"])
        if lo_i > h2:
            out.append({"type": "bullish", "bar": i, "lo": h2, "hi": lo_i})
        elif hi_i < l2:
            out.append({"type": "bearish", "bar": i, "lo": hi_i, "hi": l2})
    return out


def _bt_al_fvg_confluence(candles: List[Dict], formation_bar: int,
                          zone_high: float, zone_low: float) -> Optional[bool]:
    """True when an FVG formed at bars [fb-window, fb] overlaps the OB zone.

    Only bars at or before formation are inspected — every input is known at
    formation time (no look-ahead). Returns None when the window has fewer
    than 3 bars (FVG undefined).
    """
    if formation_bar < 2:
        return None
    fvgs = _bt_al_detect_fvgs(candles,
                              formation_bar - _AL_FVG_FORMATION_WINDOW,
                              formation_bar)
    for f in fvgs:
        if f["lo"] <= zone_high and f["hi"] >= zone_low:
            return True
    return False


def _bt_al_range_position(trend_idx: Dict, formation_bar: int,
                          zone_mid: float) -> Optional[float]:
    """Zone-mid position inside the last confirmed pivot dealing range, 0-100.

    Range = [last confirmed pivot low, last confirmed pivot high] before the
    formation bar (confirmed = pivot bar <= formation_bar - pivot_len, same
    no-look-ahead rule as the trend queries). 0 = at the range low (deep
    discount), 100 = at the range high (deep premium). Values outside the
    range are clamped to 0/100. None when no confirmed pivot pair exists.
    """
    import bisect as _bisect
    if formation_bar is None or formation_bar < 0:
        return None
    p_len  = trend_idx["pivot_len"]
    cutoff = formation_bar - p_len
    hb = trend_idx["high_bars"]
    lb = trend_idx["low_bars"]
    hi = _bisect.bisect_right(hb, cutoff)
    li = _bisect.bisect_right(lb, cutoff)
    if hi < 1 or li < 1:
        return None
    range_high = trend_idx["h"][hb[hi - 1]]
    range_low  = trend_idx["l"][lb[li - 1]]
    if range_high <= range_low:
        return None
    pos = (zone_mid - range_low) / (range_high - range_low) * 100.0
    return round(min(100.0, max(0.0, pos)), 2)


def _bt_al_atr_percentile(atr: List[Optional[float]], formation_bar: int,
                          window: int = _AL_ATR_PERCENTILE_WINDOW) -> Optional[float]:
    """Percentile rank of ATR[fb] within the trailing window ending at fb.

    Uses atr[fb-window .. fb] only (no look-ahead). None when ATR is missing
    or fewer than 10 trailing values exist.
    """
    if formation_bar is None or formation_bar < 0 or formation_bar >= len(atr):
        return None
    cur = atr[formation_bar]
    if cur is None:
        return None
    vals = [a for a in atr[max(0, formation_bar - window):formation_bar + 1]
            if a is not None]
    if len(vals) < 10:
        return None
    below = sum(1 for v in vals if v < cur)
    return round(below / len(vals) * 100.0, 2)


def _bt_ap_atr_series(candles: List[Dict], period: int = _AP_ATR_PERIOD) -> List[Optional[float]]:
    """Simple-moving-average ATR per bar. atr[i] uses bars 0..i only (no look-ahead).

    Definition (deterministic, documented): TR[0] = high-low; TR[i] =
    max(high-low, |high-prev_close|, |low-prev_close|). ATR[i] is the plain
    mean of the last `period` TRs (expanding mean before `period` bars).
    """
    n = len(candles)
    if n == 0:
        return []
    trs: List[float] = [0.0] * n
    for i in range(n):
        h = float(candles[i]["high"])
        l = float(candles[i]["low"])
        if i == 0:
            trs[i] = h - l
        else:
            pc = float(candles[i - 1]["close"])
            trs[i] = max(h - l, abs(h - pc), abs(l - pc))
    atr: List[Optional[float]] = [None] * n
    running = 0.0
    for i in range(n):
        running += trs[i]
        if i < period:
            atr[i] = running / (i + 1)
        else:
            running -= trs[i - period]
            atr[i] = running / period
    return atr


def _bt_ap_build_trend_index(candles: List[Dict], pivot_len: int) -> Dict:
    """Precompute confirmed-pivot arrays for O(log n) HH/HL trend queries."""
    h_arr = [float(c["high"]) for c in candles]
    l_arr = [float(c["low"])  for c in candles]
    if len(candles) < pivot_len * 2 + 1:
        return {"high_bars": [], "low_bars": [], "h": h_arr, "l": l_arr,
                "pivot_len": pivot_len}
    ph, pl = detect_pivots(h_arr, l_arr, pivot_len, pivot_len)
    return {
        "high_bars": [j for j in range(len(candles)) if ph[j]],
        "low_bars":  [j for j in range(len(candles)) if pl[j]],
        "h": h_arr, "l": l_arr, "pivot_len": pivot_len,
    }


def _bt_ap_trend_at(trend_idx: Dict, bar_index: int) -> str:
    """HH/HL structure trend using only pivots CONFIRMED by bar_index.

    A pivot at bar j is confirmed at bar j + pivot_len — pivots that need
    future bars to settle are never used (no look-ahead).

    Returns "up" (HH+HL), "down" (LH+LL), "neutral" (mixed), or "unknown"
    (fewer than 2 confirmed pivot highs/lows).
    """
    import bisect as _bisect
    if bar_index is None or bar_index < 0:
        return "unknown"
    p_len  = trend_idx["pivot_len"]
    cutoff = bar_index - p_len          # last pivot bar confirmed by bar_index
    hb = trend_idx["high_bars"]
    lb = trend_idx["low_bars"]
    hi = _bisect.bisect_right(hb, cutoff)
    li = _bisect.bisect_right(lb, cutoff)
    if hi < 2 or li < 2:
        return "unknown"
    h1 = trend_idx["h"][hb[hi - 2]]
    h2 = trend_idx["h"][hb[hi - 1]]
    l1 = trend_idx["l"][lb[li - 2]]
    l2 = trend_idx["l"][lb[li - 1]]
    if h2 > h1 and l2 > l1:
        return "up"
    if h2 < h1 and l2 < l1:
        return "down"
    return "neutral"


def _bt_ap_alignment(direction: str, trend: str) -> str:
    """Trade direction vs trend state → with / against / neutral / unknown."""
    if trend == "unknown":
        return "unknown"
    if trend == "neutral":
        return "neutral"
    if (direction == "bullish" and trend == "up") or \
       (direction == "bearish" and trend == "down"):
        return "with"
    return "against"


def _bt_ap_htf_bar_index(htf_candles: List[Dict], touch_time) -> Optional[int]:
    """Largest HTF bar index whose open_time <= touch_time (binary search)."""
    import bisect as _bisect
    if not htf_candles or touch_time is None:
        return None
    opens = [c.get("open_time") or 0 for c in htf_candles]
    idx = _bisect.bisect_right(opens, int(touch_time)) - 1
    return idx if idx >= 0 else None


def _bt_ap_failure_mode(sim: Dict, rr_key: str) -> Optional[str]:
    """Descriptive failure mode for a LOSING trade (None for non-losses).

    INSTANT_MITIGATION — the entry candle itself closed through the zone.
    SLOW_BLEED         — the loss took >= _AP_SLOW_BLEED_CANDLES candles.
    STANDARD_STOP      — any other close-based stop.
    """
    rb = (sim.get("realized_by_rr") or {}).get(rr_key) or {}
    if rb.get("outcome") != "loss":
        return None
    entry_bar = sim.get("entry_bar")
    stop_bar  = sim.get("stop_bar")
    if stop_bar is not None and entry_bar is not None and stop_bar == entry_bar:
        return "INSTANT_MITIGATION"
    cte = rb.get("candles_to_exit")
    if cte is not None and cte >= _AP_SLOW_BLEED_CANDLES:
        return "SLOW_BLEED"
    return "STANDARD_STOP"


def _bt_ap_build_trade_records(
    events: List[Dict],
    candles: List[Dict],
    rr_key: str,
    ob_class: str,
    tf_trend_idx: Dict,
    swing_trend_idx: Dict,
    htf_candles: Optional[List[Dict]],
    htf_trend_idx: Optional[Dict],
    atr: List[Optional[float]],
    multi_trend: Optional[Dict[str, Dict]] = None,
    rsi_series: Optional[List[Optional[float]]] = None,
    cvd_series: Optional[List[Optional[float]]] = None,
    oi_list: Optional[List[Tuple[int, float]]] = None,
    btc_candles: Optional[List[Dict]] = None,
    btc_trend_idx: Optional[Dict] = None,
) -> List[Dict]:
    """Build one autopsy record per touch trade at the selected RR.

    Reuses the canonical Phase 16 touch-episode detection and touch
    simulation so autopsy trades are the same trades the Trade Explorer
    reports. Every feature is computed from data available at or before
    the touch bar — no look-ahead.

    Phase 19: `multi_trend` maps trend timeframe → {"candles": [...],
    "trend_idx": {...}}. When provided, each record gains an
    `alignments` dict (trend_tf → with/against/neutral/unknown) using
    the same closed-HTF-bar rule as the single-HTF feature, plus the
    FVG_CONFLUENCE / IN_PREMIUM_HALF / HIGH_VOL_REGIME features.
    """
    records: List[Dict] = []
    for ev in events:
        if ev.get("touch_status") != "touched":
            continue
        episodes = _te_detect_touch_episodes(candles, ev)
        if not episodes:
            continue
        fb        = int(ev["formation_bar"])
        direction = ev.get("type", "")
        zone_size = float(ev.get("zone_size") or 0.0)
        atr_fb    = atr[fb] if fb < len(atr) else None

        # Displacement proxy v1: formation-candle body size in ATRs.
        disp_atr = None
        if atr_fb and atr_fb > 0 and fb < len(candles):
            body = abs(float(candles[fb]["close"]) - float(candles[fb]["open"]))
            disp_atr = round(body / atr_fb, 3)
        zone_atr = (round(zone_size / atr_fb, 3)
                    if atr_fb and atr_fb > 0 and zone_size > 0 else None)

        # ── Phase 19 formation-time zone features (constant per OB) ─────────
        zone_mid = float(ev.get("zone_mid") or
                         ((float(ev["zone_high"]) + float(ev["zone_low"])) / 2.0))
        fvg_confluence = _bt_al_fvg_confluence(
            candles, fb, float(ev["zone_high"]), float(ev["zone_low"]))
        range_pos      = _bt_al_range_position(tf_trend_idx, fb, zone_mid)
        atr_pct        = _bt_al_atr_percentile(atr, fb)
        # Chunk 5: continuation vs reversal — own-TF trend at FORMATION
        formation_trend = _bt_ap_trend_at(tf_trend_idx, fb)
        formation_align = _bt_ap_alignment(direction, formation_trend)

        for ep in episodes:
            touch_idx  = ep["touch_index"]
            touch_time = ep.get("touch_time")
            sim = _te_simulate_touch_outcome(touch_idx, ev, candles,
                                             [1, 2, 3])
            rb  = (sim.get("realized_by_rr") or {}).get(rr_key) or {}
            outcome = rb.get("outcome", "unresolved")
            if not sim.get("eligible", False):
                continue

            tf_trend    = _bt_ap_trend_at(tf_trend_idx, touch_idx)
            swing_trend = _bt_ap_trend_at(swing_trend_idx, touch_idx)
            htf_trend   = "unknown"
            if htf_trend_idx is not None and htf_candles:
                hbar = _bt_ap_htf_bar_index(htf_candles, touch_time)
                # The HTF bar containing the touch is still IN PROGRESS at the
                # touch — its final high/low are unknowable then. Query the
                # trend at the last fully CLOSED HTF bar (hbar - 1) so a pivot
                # confirming on the in-progress bar can never leak in.
                if hbar is not None and hbar >= 1:
                    htf_trend = _bt_ap_trend_at(htf_trend_idx, hbar - 1)

            tf_align    = _bt_ap_alignment(direction, tf_trend)
            swing_align = _bt_ap_alignment(direction, swing_trend)
            htf_align   = _bt_ap_alignment(direction, htf_trend)

            # ── Phase 19: per-trend-TF alignments (closed-bar rule) ──────────
            alignments: Dict[str, str] = {}
            if multi_trend:
                for ttf, tdata in multi_trend.items():
                    t_candles = tdata.get("candles")
                    t_idx     = tdata.get("trend_idx")
                    t_trend   = "unknown"
                    if t_idx is not None and t_candles:
                        tbar = _bt_ap_htf_bar_index(t_candles, touch_time)
                        if tbar is not None and tbar >= 1:
                            t_trend = _bt_ap_trend_at(t_idx, tbar - 1)
                    alignments[ttf] = _bt_ap_alignment(direction, t_trend)

            session = _te_session(touch_time)
            weekday = _te_weekday(touch_time)
            candles_since = ep.get("candles_since_formation", touch_idx - fb)
            touch_num = ep["touch_number"]

            # ── Phase 20: volume context + performance grade (labels only) ───
            formation_vol_ratio = _bt_fl_volume_ratio(candles, fb)
            touch_vol_ratio     = _bt_fl_volume_ratio(candles, touch_idx)
            # Wins exit at TP — the sim's raw excursions keep running until
            # the stop or data end, so re-measure them up to the actual exit
            # bar; otherwise a post-exit wick would flip a clean win to
            # "stressed_win" (grades must describe the trade, not the after).
            mfe_r = sim.get("max_r_reached")
            mae_r = sim.get("max_adverse_r")
            if outcome == "win" and rb.get("exit_bar") is not None:
                _bmfe, _bmae = _bt_fl_excursions_to_exit(
                    ev, candles, touch_idx, rb.get("exit_bar"))
                if _bmfe is not None:
                    mfe_r, mae_r = _bmfe, _bmae
            grade = _bt_fl_grade(outcome, mfe_r, mae_r)

            # ── Phase 20B Chunk 3: RSI + CVD divergence at the touch bar ─────
            rsi_at_touch = (rsi_series[touch_idx]
                            if rsi_series is not None and touch_idx < len(rsi_series)
                            else None)
            cvd_at_touch = (cvd_series[touch_idx]
                            if cvd_series is not None and touch_idx < len(cvd_series)
                            else None)
            delta_at_touch     = _bt_fl_bar_delta(candles[touch_idx]) if touch_idx < len(candles) else None
            delta_at_formation = _bt_fl_bar_delta(candles[fb]) if fb < len(candles) else None
            rsi_divergence = (_bt_fl_divergence_at_touch(direction, touch_idx, candles,
                                                         rsi_series, tf_trend_idx)
                              if rsi_series is not None else None)
            cvd_divergence = (_bt_fl_divergence_at_touch(direction, touch_idx, candles,
                                                         cvd_series, tf_trend_idx)
                              if cvd_series is not None else None)

            # ── Phase 20B Chunk 4: OI context (30-day window; else not-avail) ─
            oi_ctx = (_bt_fl_oi_context(oi_list, touch_time)
                      if oi_list else {"oi_at_touch": None, "available": False,
                                       "oi_change_pct": None, "rising": None,
                                       "falling": None})

            # ── Phase 20B Chunk 5: structure & flow at the touch ─────────────
            liq_sweep = _bt_fl_liquidity_sweep(direction, touch_idx, candles, tf_trend_idx)
            # zone penetration: MAE_r is (entry - deepest adverse)/zone_size,
            # so mae_r*100 = % of zone depth price reached before reacting
            penetration_pct = (round(mae_r * 100.0, 1) if mae_r is not None else None)
            touch_range_ratio = _bt_fl_range_ratio(candles, touch_idx)
            absorption = None
            if touch_vol_ratio is not None and touch_range_ratio is not None:
                absorption = bool(touch_vol_ratio >= _FL_HIGH_VOL_RATIO
                                  and touch_range_ratio < _FL_ABSORPTION_RANGE)
            # BTC trend for altcoins (skip when the symbol itself is BTC)
            btc_trend = "unknown"
            btc_align = "unknown"
            _is_btc = str(ev.get("symbol", "")).upper().startswith("BTC")
            if not _is_btc and btc_trend_idx is not None and btc_candles:
                _bbar = _bt_ap_htf_bar_index(btc_candles, touch_time)
                if _bbar is not None:
                    btc_trend = _bt_ap_trend_at(btc_trend_idx, _bbar)
                    btc_align = _bt_ap_alignment(direction, btc_trend)

            # Predictive features — None = unknown, excluded from ranking
            # denominators for that feature.
            features: Dict[str, Optional[bool]] = {
                "AGAINST_HTF_TREND": (None if htf_align == "unknown"
                                      else htf_align == "against"),
                "AGAINST_TF_TREND":  (None if tf_align == "unknown"
                                      else tf_align == "against"),
                "COUNTER_SWING":     (None if swing_align == "unknown"
                                      else swing_align == "against"),
                "LATE_TOUCH":        touch_num >= _AP_LATE_TOUCH_NUMBER,
                "WEAK_DISPLACEMENT": (None if disp_atr is None
                                      else disp_atr < _AP_WEAK_DISPLACEMENT_ATR),
                "OVERSIZED_ZONE":    (None if zone_atr is None
                                      else zone_atr > _AP_OVERSIZED_ZONE_ATR),
                "STALE_ZONE":        candles_since > _AP_STALE_ZONE_CANDLES,
                "SESSION_ASIA":      (None if session is None else session == "Asia"),
                "SESSION_LONDON":    (None if session is None else session == "London"),
                "SESSION_NEWYORK":   (None if session is None else session == "NewYork"),
                "SESSION_OTHER":     (None if session is None else session == "Other"),
                "FVG_CONFLUENCE":    fvg_confluence,
                "IN_PREMIUM_HALF":   (None if range_pos is None
                                      else range_pos > 50.0),
                "HIGH_VOL_REGIME":   (None if atr_pct is None
                                      else atr_pct > _AL_HIGH_VOL_PERCENTILE),
                "HIGH_FORMATION_VOLUME": (None if formation_vol_ratio is None
                                          else formation_vol_ratio >= _FL_HIGH_VOL_RATIO),
                "LOW_FORMATION_VOLUME":  (None if formation_vol_ratio is None
                                          else formation_vol_ratio < _FL_LOW_VOL_RATIO),
                "HIGH_TOUCH_VOLUME":     (None if touch_vol_ratio is None
                                          else touch_vol_ratio >= _FL_HIGH_VOL_RATIO),
                "LOW_TOUCH_VOLUME":      (None if touch_vol_ratio is None
                                          else touch_vol_ratio < _FL_LOW_VOL_RATIO),
                "RSI_DIVERGENCE_AT_TOUCH": rsi_divergence,
                "CVD_DIVERGENCE_AT_TOUCH": cvd_divergence,
                "RSI_OVERSOLD_AT_TOUCH":   (None if rsi_at_touch is None
                                            else rsi_at_touch < _FL_RSI_OVERSOLD),
                "RSI_OVERBOUGHT_AT_TOUCH": (None if rsi_at_touch is None
                                            else rsi_at_touch > _FL_RSI_OVERBOUGHT),
                "OI_RISING_AT_TOUCH":      (None if not oi_ctx["available"]
                                            or oi_ctx["rising"] is None
                                            else bool(oi_ctx["rising"])),
                "OI_FALLING_AT_TOUCH":     (None if not oi_ctx["available"]
                                            or oi_ctx["falling"] is None
                                            else bool(oi_ctx["falling"])),
                "LIQUIDITY_SWEEP_INTO_ZONE": liq_sweep,
                "OB_REVERSAL":     (None if formation_align == "unknown"
                                    else formation_align == "against"),
                "OB_CONTINUATION": (None if formation_align == "unknown"
                                    else formation_align == "with"),
                "AGAINST_BTC_TREND": (None if btc_align == "unknown"
                                      else btc_align == "against"),
                "DEEP_ZONE_PENETRATION": (None if penetration_pct is None
                                          else penetration_pct >= _FL_DEEP_PENETRATION * 100),
                "ABSORPTION_AT_TOUCH":   absorption,
            }

            records.append({
                "touch_trade_id":  _te_touch_trade_id(ev, touch_num, touch_idx, rr_key),
                "ob_id":           _te_ob_id(ev),
                "symbol":          ev.get("symbol", ""),
                "timeframe":       ev.get("timeframe", ""),
                "ob_class":        ob_class,
                "direction":       direction,
                "rr":              rr_key,
                "touch_number":    touch_num,
                "touch_bucket":    ep["touch_bucket"],
                "outcome":         outcome,
                "realized_r":      rb.get("realized_r"),
                "stop_loss_r":     sim.get("stop_loss_r"),
                "entry_bar":       sim.get("entry_bar"),
                "exit_bar":        rb.get("exit_bar"),
                "candles_to_exit": rb.get("candles_to_exit"),
                "session":         session,
                "weekday":         weekday,
                "touch_time":      touch_time,
                "candles_since_formation": candles_since,
                "zone_size_atr":   zone_atr,
                "displacement_atr": disp_atr,
                "mfe_r":           mfe_r,   # exit-bounded for wins (grade-consistent)
                "mae_r":           mae_r,
                "tf_trend":        tf_trend,
                "swing_trend":     swing_trend,
                "htf_trend":       htf_trend,
                "tf_alignment":    tf_align,
                "swing_alignment": swing_align,
                "htf_alignment":   htf_align,
                "alignments":      alignments,
                "range_position_pct": range_pos,
                "atr_percentile":  atr_pct,
                "formation_volume_ratio": formation_vol_ratio,
                "touch_volume_ratio":     touch_vol_ratio,
                "rsi_at_touch":           rsi_at_touch,
                "cvd_at_touch":           cvd_at_touch,
                "delta_at_touch":         delta_at_touch,
                "delta_at_formation":     delta_at_formation,
                "rsi_divergence":         rsi_divergence,
                "cvd_divergence":         cvd_divergence,
                "oi_at_touch":            oi_ctx["oi_at_touch"],
                "oi_change_pct":          oi_ctx["oi_change_pct"],
                "oi_available":           oi_ctx["available"],
                "liquidity_sweep":        liq_sweep,
                "formation_trend":        formation_trend,
                "ob_kind":                ("reversal" if formation_align == "against"
                                           else "continuation" if formation_align == "with"
                                           else "neutral" if formation_align == "neutral"
                                           else "unknown"),
                "btc_trend":              btc_trend,
                "btc_alignment":          btc_align,
                "zone_penetration_pct":   penetration_pct,
                "absorption":             absorption,
                "performance_grade":      grade,
                "respect_class":          _bt_fl_respect_class(grade),
                "htf_joint_state":        _bt_fl_htf_joint_state(alignments),
                "features":        features,
                "failure_mode":    _bt_ap_failure_mode(sim, rr_key),
            })
    return records


def _bt_al_build_matrix(records: List[Dict]) -> List[Dict]:
    """Phase 19 — timeframe alignment matrix for one OB class.

    One cell per (ob_timeframe, trend_timeframe) pair; each cell reports the
    authoritative outcome contract (trades = wins + losses; ambiguous /
    unresolved excluded) separately for with / against / neutral / unknown
    alignment, sample-size labeled. Cells never pool OB classes — the caller
    passes a single class's records.
    """
    cells: Dict[Tuple[str, str], List[Tuple[str, Dict]]] = {}
    for r in records:
        for ttf, align in (r.get("alignments") or {}).items():
            cells.setdefault((r.get("timeframe", ""), ttf), []).append((align, r))

    out: List[Dict] = []
    for (ob_tf, ttf) in sorted(cells.keys()):
        pairs = cells[(ob_tf, ttf)]
        entry: Dict = {"ob_timeframe": ob_tf, "trend_timeframe": ttf,
                       "alignments": {}}
        for align in ("with", "against", "neutral", "unknown"):
            rows = [r for a, r in pairs if a == align]
            wins   = sum(1 for r in rows if r["outcome"] == "win")
            losses = sum(1 for r in rows if r["outcome"] == "loss")
            amb    = sum(1 for r in rows if r["outcome"] == "ambiguous")
            unres  = sum(1 for r in rows if r["outcome"] == "unresolved")
            trades = wins + losses
            gp = sum(r["realized_r"] for r in rows
                     if r["outcome"] == "win" and r.get("realized_r") is not None)
            gl = abs(sum(r["realized_r"] for r in rows
                         if r["outcome"] == "loss" and r.get("realized_r") is not None))
            net = round(gp - gl, 4)
            pf, pf_inf = _stab_aggregate_pf(gp, gl)
            entry["alignments"][align] = {
                "opportunities":      len(rows),
                "trades":             trades,
                "wins":               wins,
                "losses":             losses,
                "ambiguous":          amb,
                "unresolved":         unres,
                "win_rate_pct":       round(wins / trades * 100, 2) if trades else None,
                "expectancy_r":       round(net / trades, 6) if trades else None,
                "profit_factor_r":    pf,
                "profit_factor_infinite": pf_inf,
                "net_r":              net,
                "sample_size_status": _te_sample_size_status(trades),
            }
        # Headline: with-vs-against expectancy edge for quick reading.
        w_exp = entry["alignments"]["with"]["expectancy_r"]
        a_exp = entry["alignments"]["against"]["expectancy_r"]
        entry["with_minus_against_expectancy_r"] = (
            round(w_exp - a_exp, 6)
            if w_exp is not None and a_exp is not None else None)
        out.append(entry)
    return out


def _bt_ap_rank_reasons(records: List[Dict]) -> List[Dict]:
    """18B — per-feature loser-vs-winner frequency comparison.

    For each predictive feature: how often it is present among losers vs
    winners (trades with unknown/None value excluded from that feature's
    denominators). delta_pct > 0 means the feature is more common in losers.
    """
    losers  = [r for r in records if r["outcome"] == "loss"]
    winners = [r for r in records if r["outcome"] == "win"]
    out: List[Dict] = []
    for feat in _AP_FEATURE_KEYS:
        l_known = [r for r in losers  if r["features"].get(feat) is not None]
        w_known = [r for r in winners if r["features"].get(feat) is not None]
        l_with  = sum(1 for r in l_known if r["features"][feat])
        w_with  = sum(1 for r in w_known if r["features"][feat])
        l_pct = round(l_with / len(l_known) * 100, 2) if l_known else None
        w_pct = round(w_with / len(w_known) * 100, 2) if w_known else None
        delta = (round(l_pct - w_pct, 2)
                 if l_pct is not None and w_pct is not None else None)
        lift  = (round(l_pct / w_pct, 3)
                 if l_pct is not None and w_pct not in (None, 0) else None)
        out.append({
            "feature":            feat,
            "losers_with":        l_with,
            "losers_known":       len(l_known),
            "loser_pct":          l_pct,
            "winners_with":       w_with,
            "winners_known":      len(w_known),
            "winner_pct":         w_pct,
            "delta_pct":          delta,
            "lift":               lift,
            "sample_size_status": _te_sample_size_status(len(l_known) + len(w_known)),
        })
    out.sort(key=lambda r: (r["delta_pct"] is None,
                            -(r["delta_pct"] or 0.0)))
    return out


def _bt_ap_failure_mode_distribution(records: List[Dict]) -> Dict:
    """Distribution of descriptive failure modes across losing trades."""
    losers = [r for r in records if r["outcome"] == "loss"]
    dist: Dict[str, int] = {"INSTANT_MITIGATION": 0, "SLOW_BLEED": 0,
                            "STANDARD_STOP": 0}
    for r in losers:
        fm = r.get("failure_mode")
        if fm in dist:
            dist[fm] += 1
    total = len(losers)
    return {
        "total_losses": total,
        "counts": dist,
        "pcts": {k: (round(v / total * 100, 1) if total else None)
                 for k, v in dist.items()},
    }


def _bt_ap_build_profiles(records: List[Dict], rr_key: str) -> List[Dict]:
    """18C — setup-profile table.

    Profile key = HTF alignment | touch bucket | session. Every profile
    reports the authoritative outcome contract (trades = wins + losses;
    ambiguous / unresolved excluded) at the selected RR, sample-size
    labeled, sorted by win rate then trade count.
    """
    groups: Dict[str, List[Dict]] = {}
    for r in records:
        key = f"{r['htf_alignment']}|{r['touch_bucket']}|{r['session'] or 'unknown'}"
        groups.setdefault(key, []).append(r)

    profiles: List[Dict] = []
    for key, rows in groups.items():
        wins   = sum(1 for r in rows if r["outcome"] == "win")
        losses = sum(1 for r in rows if r["outcome"] == "loss")
        amb    = sum(1 for r in rows if r["outcome"] == "ambiguous")
        unres  = sum(1 for r in rows if r["outcome"] == "unresolved")
        trades = wins + losses
        gp = sum(r["realized_r"] for r in rows
                 if r["outcome"] == "win" and r.get("realized_r") is not None)
        gl = abs(sum(r["realized_r"] for r in rows
                     if r["outcome"] == "loss" and r.get("realized_r") is not None))
        net = round(gp - gl, 4)
        pf, pf_inf = _stab_aggregate_pf(gp, gl)
        htf_align, bucket, session = key.split("|", 2)
        profiles.append({
            "profile_key":        key,
            "htf_alignment":      htf_align,
            "touch_bucket":       bucket,
            "session":            session,
            "opportunities":      len(rows),
            "trades":             trades,
            "wins":               wins,
            "losses":             losses,
            "ambiguous":          amb,
            "unresolved":         unres,
            "win_rate_pct":       round(wins / trades * 100, 2) if trades else None,
            "expectancy_r":       round(net / trades, 6) if trades else None,
            "profit_factor_r":    pf,
            "profit_factor_infinite": pf_inf,
            "net_r":              net,
            "rr":                 rr_key,
            "sample_size_status": _te_sample_size_status(trades),
            "below_min_trades":   trades < _AP_MIN_PROFILE_TRADES,
        })
    profiles.sort(key=lambda p: (p["win_rate_pct"] is None,
                                 -(p["win_rate_pct"] or 0.0),
                                 -p["trades"]))
    return profiles


# ══════════════════════════════════════════════════════════════════════════════
# Phase 20 — Bad-Trade Filter Lab analysis (labels only; trades never removed)
# ══════════════════════════════════════════════════════════════════════════════

def _bt_fl_aggregate(rows: List[Dict]) -> Dict:
    """Authoritative aggregate for a labeled group (contract: trades = W+L)."""
    wins   = sum(1 for r in rows if r["outcome"] == "win")
    losses = sum(1 for r in rows if r["outcome"] == "loss")
    amb    = sum(1 for r in rows if r["outcome"] == "ambiguous")
    unres  = sum(1 for r in rows if r["outcome"] == "unresolved")
    trades = wins + losses
    gp = sum(r["realized_r"] for r in rows
             if r["outcome"] == "win" and r.get("realized_r") is not None)
    gl = abs(sum(r["realized_r"] for r in rows
                 if r["outcome"] == "loss" and r.get("realized_r") is not None))
    net = round(gp - gl, 4)
    pf, pf_inf = _stab_aggregate_pf(gp, gl)
    return {
        "opportunities":      len(rows),
        "trades":             trades,
        "wins":               wins,
        "losses":             losses,
        "ambiguous":          amb,
        "unresolved":         unres,
        "win_rate_pct":       round(wins / trades * 100, 2) if trades else None,
        "expectancy_r":       round(net / trades, 6) if trades else None,
        "profit_factor_r":    pf,
        "profit_factor_infinite": pf_inf,
        "net_r":              net,
        "sample_size_status": _te_sample_size_status(trades),
    }


def _bt_fl_grade_distribution(records: List[Dict]) -> Dict:
    """How the OB performed across the whole log: works / pauses / fails."""
    counts = {g: 0 for g in _FL_GRADES}
    for r in records:
        g = r.get("performance_grade")
        if g in counts:
            counts[g] += 1
    total = len(records)
    working = sum(counts[g] for g in _FL_WORKING_GRADES)
    failing = sum(counts[g] for g in _FL_FAILING_GRADES)
    paused  = counts["paused_positive"] + counts["paused_flat"]
    return {
        "total":        total,
        "counts":       counts,
        "pcts":         {g: (round(c / total * 100, 1) if total else None)
                         for g, c in counts.items()},
        "working":      working,
        "failing":      failing,
        "paused":       paused,
        "working_pct":  round(working / total * 100, 1) if total else None,
        "failing_pct":  round(failing / total * 100, 1) if total else None,
    }


def _bt_fl_pattern_book(records: List[Dict]) -> List[Dict]:
    """When the OB works vs fails, per pattern.

    For every feature: grade mix (working / failing / paused pcts) when the
    feature is PRESENT vs ABSENT. Unknown (None) trades are excluded from
    that feature's comparison but never from the log itself.
    """
    out: List[Dict] = []
    for feat in _AP_FEATURE_KEYS:
        present = [r for r in records if r["features"].get(feat) is True]
        absent  = [r for r in records if r["features"].get(feat) is False]

        def _mix(rows: List[Dict]) -> Dict:
            n = len(rows)
            working = sum(1 for r in rows
                          if r.get("performance_grade") in _FL_WORKING_GRADES)
            failing = sum(1 for r in rows
                          if r.get("performance_grade") in _FL_FAILING_GRADES)
            hard    = sum(1 for r in rows
                          if r.get("performance_grade") == "hard_loss")
            return {
                "count":        n,
                "working_pct":  round(working / n * 100, 1) if n else None,
                "failing_pct":  round(failing / n * 100, 1) if n else None,
                "hard_loss_pct": round(hard / n * 100, 1) if n else None,
            }

        p_mix = _mix(present)
        a_mix = _mix(absent)
        delta = (round(p_mix["failing_pct"] - a_mix["failing_pct"], 1)
                 if p_mix["failing_pct"] is not None
                 and a_mix["failing_pct"] is not None else None)
        out.append({
            "feature":            feat,
            "present":            p_mix,
            "absent":             a_mix,
            "failing_delta_pct":  delta,   # >0 = feature makes OBs fail more
            "unknown_count":      len(records) - len(present) - len(absent),
            "sample_size_status": _te_sample_size_status(len(present) + len(absent)),
        })
    out.sort(key=lambda r: (r["failing_delta_pct"] is None,
                            -(r["failing_delta_pct"] or 0.0)))
    return out


def _bt_fl_volume_by_grade(records: List[Dict]) -> List[Dict]:
    """Volume context per performance grade — 'what was the volume when the
    OB failed / paused / behaved very well'."""
    out: List[Dict] = []
    for grade in _FL_GRADES:
        rows = [r for r in records if r.get("performance_grade") == grade]
        f_vols = [r["formation_volume_ratio"] for r in rows
                  if r.get("formation_volume_ratio") is not None]
        t_vols = [r["touch_volume_ratio"] for r in rows
                  if r.get("touch_volume_ratio") is not None]
        mfes = [r["mfe_r"] for r in rows if r.get("mfe_r") is not None]
        maes = [r["mae_r"] for r in rows if r.get("mae_r") is not None]
        out.append({
            "grade":                      grade,
            "count":                      len(rows),
            "avg_formation_volume_ratio": (round(sum(f_vols) / len(f_vols), 3)
                                           if f_vols else None),
            "avg_touch_volume_ratio":     (round(sum(t_vols) / len(t_vols), 3)
                                           if t_vols else None),
            "avg_mfe_r":                  (round(sum(mfes) / len(mfes), 3)
                                           if mfes else None),
            "avg_mae_r":                  (round(sum(maes) / len(maes), 3)
                                           if maes else None),
        })
    return out


# Candidate pass-rules — each is a LABEL over existing features. A trade
# failing a rule stays in the log with pass=False; nothing is ever removed.
# None = rule not evaluable for that trade (unknown inputs).
def _bt_fl_rule_predicates() -> List[Dict]:
    def _feat(rec, key):
        return rec["features"].get(key)

    def _not_feat(rec, key):
        v = _feat(rec, key)
        return None if v is None else (not v)

    return [
        {"id": "with_htf_trend",
         "label": "HTF trend not against",
         "fn": lambda r: (None if r.get("htf_alignment") == "unknown"
                          else r.get("htf_alignment") != "against")},
        {"id": "with_tf_trend",
         "label": "Own-TF trend not against",
         "fn": lambda r: (None if r.get("tf_alignment") == "unknown"
                          else r.get("tf_alignment") != "against")},
        {"id": "not_counter_swing",
         "label": "Not against swing structure",
         "fn": lambda r: _not_feat(r, "COUNTER_SWING")},
        {"id": "first_touch_only",
         "label": "First touch only",
         "fn": lambda r: r.get("touch_number") == 1},
        {"id": "early_touch",
         "label": "Touch 1 or 2 only",
         "fn": lambda r: (r.get("touch_number") or 99) <= 2},
        {"id": "fresh_zone",
         "label": "Zone not stale",
         "fn": lambda r: _not_feat(r, "STALE_ZONE")},
        {"id": "not_oversized",
         "label": "Zone not oversized",
         "fn": lambda r: _not_feat(r, "OVERSIZED_ZONE")},
        {"id": "strong_displacement",
         "label": "Displacement not weak",
         "fn": lambda r: _not_feat(r, "WEAK_DISPLACEMENT")},
        {"id": "formation_volume_above_avg",
         "label": "Formation volume >= trailing average",
         "fn": lambda r: (None if r.get("formation_volume_ratio") is None
                          else r["formation_volume_ratio"] >= 1.0)},
        {"id": "fvg_confluence",
         "label": "FVG confluence present",
         "fn": lambda r: _feat(r, "FVG_CONFLUENCE")},
        {"id": "combo_htf_first_touch",
         "label": "HTF-aligned + first touch",
         "fn": lambda r: (None if r.get("htf_alignment") == "unknown"
                          else (r.get("htf_alignment") != "against"
                                and r.get("touch_number") == 1))},
        {"id": "combo_quality",
         "label": "HTF-aligned + touch<=2 + strong displacement + fresh zone",
         "fn": lambda r: (
             None if (r.get("htf_alignment") == "unknown"
                      or _feat(r, "WEAK_DISPLACEMENT") is None)
             else (r.get("htf_alignment") != "against"
                   and (r.get("touch_number") or 99) <= 2
                   and not _feat(r, "WEAK_DISPLACEMENT")
                   and not _feat(r, "STALE_ZONE")))},
    ]


def _bt_fl_evaluate_rules(records: List[Dict]) -> Dict:
    """Evaluate every candidate rule as a label overlay.

    Returns per-rule pass-group vs fail-group vs baseline aggregates, and
    attaches rule_passes to every record IN PLACE — no record is ever
    dropped. Retention shows how much of the baseline a rule would keep.
    """
    rules = _bt_fl_rule_predicates()
    baseline = _bt_fl_aggregate(records)

    for r in records:
        r["rule_passes"] = {}
    rule_reports: List[Dict] = []

    for rule in rules:
        passed:  List[Dict] = []
        failed:  List[Dict] = []
        unknown = 0
        for r in records:
            try:
                verdict = rule["fn"](r)
            except Exception:
                verdict = None
            r["rule_passes"][rule["id"]] = verdict
            if verdict is True:
                passed.append(r)
            elif verdict is False:
                failed.append(r)
            else:
                unknown += 1

        p_agg = _bt_fl_aggregate(passed)
        f_agg = _bt_fl_aggregate(failed)
        b_tr  = baseline["trades"]
        exp_delta = (round(p_agg["expectancy_r"] - baseline["expectancy_r"], 6)
                     if p_agg["expectancy_r"] is not None
                     and baseline["expectancy_r"] is not None else None)
        wr_delta  = (round(p_agg["win_rate_pct"] - baseline["win_rate_pct"], 2)
                     if p_agg["win_rate_pct"] is not None
                     and baseline["win_rate_pct"] is not None else None)
        rule_reports.append({
            "rule_id":            rule["id"],
            "label":              rule["label"],
            "pass":               p_agg,
            "fail":               f_agg,
            "unknown_count":      unknown,
            "trade_retention_pct": (round(p_agg["trades"] / b_tr * 100, 2)
                                    if b_tr else None),
            "expectancy_delta_vs_baseline": exp_delta,
            "win_rate_delta_vs_baseline":   wr_delta,
        })

    rule_reports.sort(key=lambda r: (r["expectancy_delta_vs_baseline"] is None,
                                     -(r["expectancy_delta_vs_baseline"] or 0.0)))
    return {
        "baseline":     baseline,
        "rules":        rule_reports,
        "note": ("Rules are labels, not deletions — every trade stays in the "
                 "log with its pass/fail/unknown verdict per rule. High "
                 "expectancy delta with low retention or a small sample is "
                 "NOT evidence; validate survivors via walk-forward."),
    }


def _bt_fl_trade_log(records: List[Dict]) -> Dict:
    """Compact labeled trade log — the full population, never filtered.

    Capped at _FL_TRADE_LOG_CAP rows (chronological by touch_time) purely to
    bound the response size; the cap is reported so truncation is explicit.
    """
    ordered = sorted(records, key=lambda r: (r.get("touch_time") or 0,
                                             r.get("touch_trade_id") or ""))
    truncated = len(ordered) > _FL_TRADE_LOG_CAP
    rows = []
    for r in ordered[:_FL_TRADE_LOG_CAP]:
        pattern_tags = [k for k, v in (r.get("features") or {}).items() if v is True]
        rows.append({
            "touch_trade_id":   r.get("touch_trade_id"),
            "symbol":           r.get("symbol"),
            "timeframe":        r.get("timeframe"),
            "direction":        r.get("direction"),
            "touch_number":     r.get("touch_number"),
            "touch_time":       r.get("touch_time"),
            "outcome":          r.get("outcome"),
            "performance_grade": r.get("performance_grade"),
            "respect_class":    r.get("respect_class"),
            "htf_joint_state":  r.get("htf_joint_state"),
            "realized_r":       r.get("realized_r"),
            "mfe_r":            r.get("mfe_r"),
            "mae_r":            r.get("mae_r"),
            "stop_loss_r":      r.get("stop_loss_r"),
            "formation_volume_ratio": r.get("formation_volume_ratio"),
            "touch_volume_ratio":     r.get("touch_volume_ratio"),
            "rsi_at_touch":     r.get("rsi_at_touch"),
            "cvd_at_touch":     r.get("cvd_at_touch"),
            "delta_at_touch":   r.get("delta_at_touch"),
            "rsi_divergence":   r.get("rsi_divergence"),
            "cvd_divergence":   r.get("cvd_divergence"),
            "oi_at_touch":      r.get("oi_at_touch"),
            "oi_change_pct":    r.get("oi_change_pct"),
            "oi_available":     r.get("oi_available"),
            "liquidity_sweep":  r.get("liquidity_sweep"),
            "ob_kind":          r.get("ob_kind"),
            "btc_alignment":    r.get("btc_alignment"),
            "zone_penetration_pct": r.get("zone_penetration_pct"),
            "absorption":       r.get("absorption"),
            "htf_alignment":    r.get("htf_alignment"),
            "tf_alignment":     r.get("tf_alignment"),
            "swing_alignment":  r.get("swing_alignment"),
            "session":          r.get("session"),
            "failure_mode":     r.get("failure_mode"),
            "pattern_tags":     pattern_tags,
            "rule_passes":      r.get("rule_passes") or {},
        })
    return {
        "rows":       rows,
        "total":      len(ordered),
        "returned":   len(rows),
        "truncated":  truncated,
        "cap":        _FL_TRADE_LOG_CAP,
        "note":       "Labels only — no trade is ever removed from this log.",
    }


def _bt_fl_respect_counts(rows: List[Dict]) -> Dict:
    """Respect-class tally for a group of records (label counts, no removal)."""
    counts = {c: 0 for c in _FL_RESPECT_CLASSES}
    for r in rows:
        rc = r.get("respect_class")
        if rc in counts:
            counts[rc] += 1
    total = len(rows)
    # Denominator for respect rate = classified (exclude neutral/inconclusive)
    classified = counts["respected"] + counts["partial"] + counts["not_respected"]
    return {
        "total":             total,
        "counts":            counts,
        "pcts":              {c: (round(counts[c] / total * 100, 1) if total else None)
                              for c in _FL_RESPECT_CLASSES},
        "classified":        classified,
        "respected_rate_pct": (round(counts["respected"] / classified * 100, 1)
                               if classified else None),
        "not_respected_rate_pct": (round(counts["not_respected"] / classified * 100, 1)
                                   if classified else None),
        "sample_size_status": _te_sample_size_status(classified),
    }


def _bt_fl_respect_summary(records: List[Dict]) -> Dict:
    """Overall respect tally + per-touch-number breakdown.

    First touch is the primary lens; second / third / fourth+ are reported
    alongside so the user can see 'on which OBs does the 2nd/3rd touch also
    get respected'. Buckets never pool — each is that touch number's own rows.
    """
    buckets = [("first", 1, 1), ("second", 2, 2), ("third", 3, 3),
               ("fourth_plus", 4, None)]
    by_touch = []
    for name, mn, mx in buckets:
        rows = [r for r in records
                if r.get("touch_number", 0) >= mn
                and (mx is None or r.get("touch_number", 0) <= mx)]
        entry = {"touch_bucket": name, "touch_number_min": mn,
                 "touch_number_max": mx}
        entry.update(_bt_fl_respect_counts(rows))
        by_touch.append(entry)
    return {
        "overall":  _bt_fl_respect_counts(records),
        "by_touch": by_touch,
        "primary_view": "first",
        "note": ("respect = did price react to the zone. respected rate excludes "
                 "neutral/inconclusive touches from its denominator."),
    }


def _bt_fl_respect_by_htf_state(records: List[Dict]) -> List[Dict]:
    """Joint HTF state x respect, per OB timeframe.

    Answers directly: 'when a 15m OB was respected, was the higher timeframe
    aligned; when it was not respected, was the HTF against?' One row per
    (OB timeframe, joint HTF state); respect tally per cell, sample-size
    labelled. Only OB timeframes that actually have mapped trend TFs appear.
    """
    _JOINT_ORDER = ("all_with", "with_some_neutral", "all_neutral",
                    "conflicting", "against_some_neutral", "all_against",
                    "unknown")
    groups: Dict[Tuple[str, str], List[Dict]] = {}
    for r in records:
        # only records that carry a joint HTF state (i.e. had mapped trend TFs)
        if not r.get("alignments"):
            continue
        key = (r.get("timeframe", ""), r.get("htf_joint_state", "unknown"))
        groups.setdefault(key, []).append(r)

    out: List[Dict] = []
    for (ob_tf, state) in sorted(
            groups.keys(),
            key=lambda k: (k[0], _JOINT_ORDER.index(k[1])
                           if k[1] in _JOINT_ORDER else 99)):
        entry = {"ob_timeframe": ob_tf, "htf_joint_state": state}
        entry.update(_bt_fl_respect_counts(groups[(ob_tf, state)]))
        out.append(entry)
    return out


def _bt_fl_penetration_by_respect(records: List[Dict]) -> List[Dict]:
    """Chunk 5 — how deep price penetrates the zone, per respect class.

    Answers 'where should the entry sit?': if respected zones are typically
    penetrated to ~60% before reacting, an edge-of-zone entry misses many
    good trades. Reports avg / median penetration % per respect class.
    """
    out = []
    for rc in _FL_RESPECT_CLASSES:
        vals = sorted(r["zone_penetration_pct"] for r in records
                      if r.get("respect_class") == rc
                      and r.get("zone_penetration_pct") is not None)
        n = len(vals)
        med = None
        if n:
            med = vals[n // 2] if n % 2 else round((vals[n // 2 - 1] + vals[n // 2]) / 2, 1)
        out.append({
            "respect_class":       rc,
            "count":               n,
            "avg_penetration_pct": round(sum(vals) / n, 1) if n else None,
            "median_penetration_pct": med,
            "max_penetration_pct": max(vals) if n else None,
        })
    return out


def _bt_ap_class_report(records: List[Dict], rr_key: str) -> Dict:
    """Full 18A-18C + Phase 20 report for one OB class."""
    wins   = sum(1 for r in records if r["outcome"] == "win")
    losses = sum(1 for r in records if r["outcome"] == "loss")
    amb    = sum(1 for r in records if r["outcome"] == "ambiguous")
    unres  = sum(1 for r in records if r["outcome"] == "unresolved")
    trades = wins + losses

    # Phase 20 — labels only, trades never removed. rule_evaluation MUST run
    # before the trade log is built: it attaches rule_passes to every record
    # in place, and the log rows carry those verdicts.
    rule_evaluation = _bt_fl_evaluate_rules(records)
    trade_log       = _bt_fl_trade_log(records)

    # Chunk 4 — OI coverage (how many trades fell inside the 30-day OI window)
    oi_avail = sum(1 for r in records if r.get("oi_available"))
    oi_coverage = {
        "available":     oi_avail,
        "total":         len(records),
        "coverage_pct":  round(oi_avail / len(records) * 100, 1) if records else None,
        "note": ("Binance OI history covers only the last ~30 days (and ≤500 rows "
                 "per page). Trades older than that show OI 'not available' — never "
                 "guessed. Low timeframes reach fewer days of coverage."),
    }

    return {
        "rr":                 rr_key,
        "records_total":      len(records),
        "trades":             trades,
        "wins":               wins,
        "losses":             losses,
        "ambiguous":          amb,
        "unresolved":         unres,
        "win_rate_pct":       round(wins / trades * 100, 2) if trades else None,
        "sample_size_status": _te_sample_size_status(trades),
        "failure_modes":      _bt_ap_failure_mode_distribution(records),
        "reason_ranking":     _bt_ap_rank_reasons(records),
        "setup_profiles":     _bt_ap_build_profiles(records, rr_key),
        "alignment_matrix":   _bt_al_build_matrix(records),
        "rule_evaluation":    rule_evaluation,
        "grade_distribution": _bt_fl_grade_distribution(records),
        "respect_summary":    _bt_fl_respect_summary(records),
        "respect_by_htf_state": _bt_fl_respect_by_htf_state(records),
        "penetration_by_respect": _bt_fl_penetration_by_respect(records),
        "pattern_book":       _bt_fl_pattern_book(records),
        "volume_by_grade":    _bt_fl_volume_by_grade(records),
        "oi_coverage":        oi_coverage,
        "trade_log":          trade_log,
    }


def _bt_run_autopsy(req: Dict) -> Dict:
    """Server-authoritative Autopsy Agent orchestrator (research only).

    Runs the full-range dual-class touch-trade backtest per cell, computes
    deterministic autopsy features for every trade, and reports
    loser-vs-winner reason rankings and setup profiles per OB class —
    internal and swing are never pooled.
    """
    t_start = time.monotonic()

    symbols      = req.get("symbols", [])
    timeframes   = req.get("timeframes", [])
    candle_count = int(req.get("candle_count", 1000))
    rr_key       = _bt_rr_key(int(req.get("rr", 2)))
    ob_classes   = req.get("ob_classes") or ["internal", "swing"]

    failures: List[Dict] = []
    records_by_class: Dict[str, List[Dict]] = {c: [] for c in ob_classes}
    network_fetch_count = 0
    htf_fetch_count     = 0
    oi_fetch_count      = 0
    btc_fetch_count     = 0
    completed_cells     = 0
    _htf_cache: Dict = {}
    _btc_cache: Dict = {}   # Chunk 5: BTCUSDT trend per timeframe (shared)

    for sym in symbols:
        for tf in timeframes:
            try:
                # extended=True carries taker-buy volume through for delta/CVD
                raw = get_klines(sym, tf, limit=candle_count, extended=True)
                network_fetch_count += 1
                candles = _bt_normalize_candles(raw)
                if not candles:
                    failures.append({"symbol": sym, "timeframe": tf,
                                     "stage": "normalize", "error": "no_candles"})
                    continue

                atr             = _bt_ap_atr_series(candles)
                tf_trend_idx    = _bt_ap_build_trend_index(candles, _BT_PIVOT_LEN)
                swing_trend_idx = _bt_ap_build_trend_index(candles, _BT_SWING_PIVOT_LEN)
                # Chunk 3: RSI + CVD once per cell (no look-ahead by construction)
                _closes    = [float(c["close"]) for c in candles]
                rsi_series = calc_rsi(_closes, _FL_RSI_PERIOD)
                cvd_series = _bt_fl_cvd_series(candles)
                # Chunk 4: Open Interest history once per cell (last ~30 days;
                # empty when unsupported TF or no network → all "not available")
                oi_list = []
                _oi_period = _FL_OI_PERIOD_MAP.get(tf)
                if _oi_period:
                    oi_list = _bt_fl_fetch_oi_history(sym, _oi_period)
                    if oi_list:
                        oi_fetch_count += 1

                # Chunk 5: BTCUSDT trend at this TF (shared cache; alts only).
                # For BTC cells we reuse the cell's own candles as the BTC ref.
                btc_candles = None
                btc_trend_idx = None
                if str(sym).upper().startswith("BTC"):
                    btc_candles, btc_trend_idx = candles, tf_trend_idx
                else:
                    if tf not in _btc_cache:
                        try:
                            _braw = get_klines("BTCUSDT", tf, limit=candle_count)
                            _bc = _bt_normalize_candles(_braw) or None
                            _btc_cache[tf] = (
                                _bc,
                                _bt_ap_build_trend_index(_bc, _BT_PIVOT_LEN) if _bc else None,
                            )
                            if _bc:
                                btc_fetch_count += 1
                        except Exception:
                            _btc_cache[tf] = (None, None)
                    btc_candles, btc_trend_idx = _btc_cache[tf]

                # ── Trend-TF fetches: single-HTF feature + Phase 19 matrix ───
                # One shared per-symbol cache; each (sym, trend_tf) fetched at
                # most once no matter how many features/classes consume it.
                def _get_trend_tf(_ttf: str):
                    ck = (sym, _ttf)
                    if ck not in _htf_cache:
                        try:
                            _raw = get_klines(sym, _ttf, limit=candle_count)
                            _htf_cache[ck] = _bt_normalize_candles(_raw) or None
                            return _htf_cache[ck], _htf_cache[ck] is not None
                        except Exception:
                            _htf_cache[ck] = None
                            return None, False   # failed attempts don't count as fetches
                    return _htf_cache[ck], False

                htf_tf = _AP_HTF_MAP.get(tf)
                htf_candles = None
                htf_trend_idx = None
                if htf_tf:
                    htf_candles, fetched = _get_trend_tf(htf_tf)
                    if fetched:
                        htf_fetch_count += 1
                    if htf_candles:
                        htf_trend_idx = _bt_ap_build_trend_index(
                            htf_candles, _BT_PIVOT_LEN)

                # Phase 19: matrix trend timeframes for this OB timeframe.
                multi_trend: Dict[str, Dict] = {}
                for ttf in _AL_MATRIX_MAP.get(tf, []):
                    t_candles, fetched = _get_trend_tf(ttf)
                    if fetched:
                        htf_fetch_count += 1
                    if t_candles:
                        multi_trend[ttf] = {
                            "candles":   t_candles,
                            "trend_idx": _bt_ap_build_trend_index(
                                t_candles, _BT_PIVOT_LEN),
                        }

                for ob_class in ob_classes:
                    params = _bt_wf_build_params(sym, tf, len(candles), [1, 2, 3])
                    params["ob_class"] = ob_class
                    events = _bt_extract_ob_replay_events(candles, params)
                    # (record building runs its own per-touch simulations;
                    #  the first-touch outcome pass is not needed here)
                    recs = _bt_ap_build_trade_records(
                        events, candles, rr_key, ob_class,
                        tf_trend_idx, swing_trend_idx,
                        htf_candles, htf_trend_idx, atr,
                        multi_trend=multi_trend,
                        rsi_series=rsi_series, cvd_series=cvd_series,
                        oi_list=oi_list,
                        btc_candles=btc_candles, btc_trend_idx=btc_trend_idx)
                    records_by_class[ob_class].extend(recs)

                completed_cells += 1
            except Exception as e:
                failures.append({"symbol": sym, "timeframe": tf,
                                 "stage": "run", "error": str(e)[:200]})

    reports = {cls: _bt_ap_class_report(records_by_class[cls], rr_key)
               for cls in ob_classes}

    return {
        "ok":                      True,
        "authoritative_execution": True,
        "client_results_accepted": False,
        "mode":                    "autopsy_agent_v1",
        "request": {
            "symbols":      symbols,
            "timeframes":   timeframes,
            "candle_count": candle_count,
            "rr":           rr_key,
            "ob_classes":   ob_classes,
        },
        "reports_by_class":  reports,
        "failures":          failures,
        "definitions": {
            "trend":             "HH/HL pivot structure; pivot confirmed only after pivot_len bars (no look-ahead)",
            "htf_map":           {k: v for k, v in _AP_HTF_MAP.items()},
            "atr":               f"SMA ATR, period {_AP_ATR_PERIOD}, no look-ahead",
            "displacement":      f"formation-candle body / ATR; weak < {_AP_WEAK_DISPLACEMENT_ATR}",
            "oversized_zone":    f"zone size / ATR > {_AP_OVERSIZED_ZONE_ATR}",
            "stale_zone":        f"touch > {_AP_STALE_ZONE_CANDLES} candles after formation",
            "late_touch":        f"touch number >= {_AP_LATE_TOUCH_NUMBER}",
            "slow_bleed":        f"loss taking >= {_AP_SLOW_BLEED_CANDLES} candles",
            "sessions":          "UTC: Asia 0-8, London 8-13, NewYork 13-21, Other 21-24",
            "note": ("BAD_SESSION is not a hard-coded reason — session lift emerges "
                     "from the ranking (SESSION_* features) instead of being assumed."),
            "matrix_map":        {k: v for k, v in _AL_MATRIX_MAP.items()},
            "fvg_confluence":    (f"3-candle FVG formed in [formation-{_AL_FVG_FORMATION_WINDOW}, "
                                  "formation] overlapping the OB zone — known at formation"),
            "in_premium_half":   ("OB zone-mid above 50% of the last confirmed pivot "
                                  "dealing range at formation"),
            "high_vol_regime":   (f"formation ATR percentile > {_AL_HIGH_VOL_PERCENTILE} within "
                                  f"trailing {_AL_ATR_PERCENTILE_WINDOW}-bar window"),
            "alignment_matrix":  ("per (OB timeframe, trend timeframe) pair: outcomes split "
                                  "by with/against/neutral/unknown HH/HL alignment at the "
                                  "last CLOSED trend-TF bar before the touch"),
            "performance_grades": ("clean_win: win, MAE<=0.5R | stressed_win: win, MAE>0.5R | "
                                   "reversal_loss: loss after reaching >=1R MFE | hard_loss: "
                                   "loss with <1R MFE | paused_positive: unresolved, >=1R MFE | "
                                   "paused_flat: unresolved, <1R MFE | ambiguous"),
            "volume_ratio":      (f"bar volume / trailing {_FL_VOL_SMA_WINDOW}-bar average; "
                                  f"high >= {_FL_HIGH_VOL_RATIO}x, low < {_FL_LOW_VOL_RATIO}x; "
                                  "no look-ahead. Touch-bar volume is the bar's FINAL volume "
                                  "(known at bar close, consistent with close-based stops)"),
            "rules":             ("candidate pass-rules are LABELS over existing features — "
                                  "every trade stays in the log with its per-rule verdict; "
                                  "nothing is removed"),
            "respect_class":     ("did price REACT to the zone: respected (clean/stressed "
                                  "win) | partial (reversal loss or paused-positive: reacted "
                                  ">=1R then didn't fully pay) | not_respected (hard loss, "
                                  "sliced through) | neutral (unfinished-flat / ambiguous). "
                                  "respected rate excludes neutral from its denominator"),
            "htf_joint_state":   ("combined higher-TF alignment for the OB's mapped trend "
                                  "TFs: all_with | with_some_neutral | all_neutral | "
                                  "conflicting | against_some_neutral | all_against | unknown"),
            "rsi_divergence":    (f"RSI({_FL_RSI_PERIOD}) divergence at the touch bar vs the last "
                                  "CONFIRMED pivot: bullish = price lower-low + RSI higher-low; "
                                  "bearish = price higher-high + RSI lower-high. No look-ahead. "
                                  "None when no prior confirmed pivot / RSI unavailable"),
            "cvd_divergence":    ("same divergence test using Cumulative Volume Delta (2*taker_buy "
                                  "- volume, running sum). Bullish CVD higher-low into a lower "
                                  "price low = absorption. None when taker-buy volume unavailable"),
            "rsi_flags":         (f"RSI_OVERSOLD (<{_FL_RSI_OVERSOLD}) / RSI_OVERBOUGHT "
                                  f"(>{_FL_RSI_OVERBOUGHT}) at touch"),
            "open_interest":     (f"Binance OI history, last ~{_FL_OI_WINDOW_DAYS} days only "
                                  "(≤500 rows/page). OI_RISING / OI_FALLING = OI change over "
                                  f"{_FL_OI_LOOKBACK} periods before touch beyond "
                                  f"±{_FL_OI_RISE_PCT}%. Trades outside the window: "
                                  "'not available' (never guessed). See oi_coverage per class"),
            "liquidity_sweep":   ("touch bar prints beyond the last CONFIRMED pivot (bullish: "
                                  "low < prior pivot low; bearish: high > prior pivot high) — "
                                  "a stop hunt into the zone. No look-ahead"),
            "ob_kind":           ("continuation = OB formed WITH the own-TF HH/HL trend at "
                                  "formation; reversal = formed AGAINST it (CHoCH-born); "
                                  "neutral / unknown otherwise"),
            "btc_trend":         ("for altcoin OBs, BTCUSDT's HH/HL trend at the same TF at the "
                                  "touch; AGAINST_BTC_TREND = alt trade opposes BTC. N/A for "
                                  "BTC symbols"),
            "zone_penetration":  ("zone_penetration_pct = how deep price reached into the zone "
                                  "before reacting (MAE as % of zone size, exit-bounded for "
                                  f"wins); DEEP_ZONE_PENETRATION ≥ {int(_FL_DEEP_PENETRATION*100)}%. "
                                  "Informs where the entry should sit"),
            "absorption":        (f"touch-bar volume ≥ {_FL_HIGH_VOL_RATIO}x avg AND range < "
                                  f"{_FL_ABSORPTION_RANGE}x avg — high effort, small result"),
        },
        "performance": {
            "requested_cells":       len(symbols) * len(timeframes),
            "completed_cells":       completed_cells,
            "failed_cells":          len(failures),
            "network_fetch_count":   network_fetch_count,
            "htf_fetch_count":       htf_fetch_count,
            "oi_fetch_count":        oi_fetch_count,
            "btc_fetch_count":       btc_fetch_count,
            "candles_fetched_once_per_cell":
                network_fetch_count <= len(symbols) * len(timeframes),
            "total_elapsed_ms":      round((time.monotonic() - t_start) * 1000),
        },
        "constants": {
            "max_symbols":    _AP_MAX_SYMBOLS,
            "max_timeframes": _AP_MAX_TIMEFRAMES,
            "max_cells":      _AP_MAX_CELLS,
            "phase":          "20",
        },
        "notice": ("Research only. Autopsy findings are hypotheses for "
                   "walk-forward validation, not proven edges. Nothing here "
                   "affects Scanner, Live Monitor, alerts or execution."),
    }


_AP_FORBIDDEN_REQUEST_KEYS = (
    "trades", "outcomes", "metrics", "records", "reports_by_class",
    "reason_ranking", "setup_profiles", "failure_modes", "win_rate",
    "expectancy", "summaries",
)


@app.route("/api/backtest/ob-historical/autopsy", methods=["POST"])
@login_required
def api_backtest_ob_historical_autopsy():
    err = _guest_tab_check("backtest")
    if err is not None:
        return err

    payload = request.get_json(force=True, silent=True) or {}
    if not isinstance(payload, dict):
        return jsonify({"ok": False, "error": "request body must be a JSON object"}), 400

    for banned in _AP_FORBIDDEN_REQUEST_KEYS:
        if banned in payload:
            return jsonify({
                "ok": False,
                "error": "client_supplied_trade_results_not_allowed",
            }), 400

    raw_syms = payload.get("symbols",
                           ["BTCUSDT", "ETHUSDT", "BNBUSDT", "SOLUSDT", "XRPUSDT"])
    if not isinstance(raw_syms, list):
        raw_syms = [str(raw_syms)]
    seen_syms: set = set()
    symbols: List[str] = []
    for s in raw_syms:
        s = str(s or "").strip().upper()
        if not s:
            return jsonify({"ok": False, "error": "blank symbol not allowed"}), 400
        if not s.endswith("USDT"):
            s = s + "USDT"
        if s in seen_syms:
            return jsonify({"ok": False, "error": "duplicate symbols not allowed"}), 400
        seen_syms.add(s)
        symbols.append(s)
    if not symbols:
        return jsonify({"ok": False, "error": "at least one symbol required"}), 400
    if len(symbols) > _AP_MAX_SYMBOLS:
        return jsonify({"ok": False, "error": f"max {_AP_MAX_SYMBOLS} symbols"}), 400

    raw_tfs = payload.get("timeframes", ["1h", "4h"])
    if not isinstance(raw_tfs, list):
        raw_tfs = [str(raw_tfs)]
    seen_tfs: set = set()
    timeframes: List[str] = []
    for tf in raw_tfs:
        tf = str(tf).strip()
        if tf not in _BT_ALLOWED_TIMEFRAMES:
            return jsonify({"ok": False,
                            "error": f"timeframe '{tf}' not allowed. "
                                     f"Allowed: {sorted(_BT_ALLOWED_TIMEFRAMES)}"}), 400
        if tf in seen_tfs:
            return jsonify({"ok": False, "error": "duplicate timeframes not allowed"}), 400
        seen_tfs.add(tf)
        timeframes.append(tf)
    if not timeframes:
        return jsonify({"ok": False, "error": "at least one timeframe required"}), 400
    if len(timeframes) > _AP_MAX_TIMEFRAMES:
        return jsonify({"ok": False, "error": f"max {_AP_MAX_TIMEFRAMES} timeframes"}), 400
    if len(symbols) * len(timeframes) > _AP_MAX_CELLS:
        return jsonify({"ok": False,
                        "error": f"max {_AP_MAX_CELLS} symbol/timeframe cells"}), 400

    try:
        candle_count = int(payload.get("candle_count", 1000))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "candle_count must be integer"}), 400
    candle_count = max(500, min(4000, candle_count))

    rr_raw = payload.get("rr", 2)
    try:
        rr = int(rr_raw)
        if float(rr_raw) != rr:          # reject 2.9-style silent truncation
            raise ValueError
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "rr must be 1, 2 or 3"}), 400
    if rr not in (1, 2, 3):
        return jsonify({"ok": False, "error": "rr must be 1, 2 or 3"}), 400

    raw_classes = payload.get("ob_classes", ["internal", "swing"])
    if not isinstance(raw_classes, list) or not raw_classes:
        return jsonify({"ok": False, "error": "ob_classes must be a non-empty list"}), 400
    ob_classes: List[str] = []
    for c in raw_classes:
        c = str(c).strip().lower()
        if c not in ("internal", "swing"):
            return jsonify({"ok": False,
                            "error": "ob_classes entries must be 'internal' or 'swing'"}), 400
        if c not in ob_classes:
            ob_classes.append(c)

    try:
        result = _bt_run_autopsy({
            "symbols":      symbols,
            "timeframes":   timeframes,
            "candle_count": candle_count,
            "rr":           rr,
            "ob_classes":   ob_classes,
        })
        return jsonify(result), 200
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)[:500]}), 500


# ══════════════════════════════════════════════════════════════════════════════
# Backtest — Multi-Timeframe (MTF) Comparison Engine
# ══════════════════════════════════════════════════════════════════════════════

_BT_MTF_MAX_TF             = 5     # max timeframes per MTF request
_BT_MTF_MAX_EVS            = 100   # per-TF event cap when include_events=True
_BT_MTF_MAX_CANDLES_PER_TF = 1500  # hard ceiling per timeframe in MTF mode
_BT_MTF_MAX_TOTAL_CANDLES  = 5000  # hard ceiling across all timeframes combined
_BT_MTF_DEFAULT_CANDLES_BY_TF: Dict[str, int] = {
    "5m": 800, "15m": 800, "30m": 800, "1h": 1200, "4h": 1000, "1d": 600,
}


def _bt_build_mtf_leaderboard(results: dict) -> list:
    """Build sorted leaderboard from per-TF result dicts."""
    rows = []
    for tf, res in results.items():
        if not res.get("ok"):
            continue
        rs  = res.get("replay_summary",  {}) or {}
        os_ = res.get("outcome_summary", {}) or {}
        slm = os_.get("stop_loss_summary")       or {}
        rzm = os_.get("realized_summary_by_rr")  or {}

        best_rk, best_exp, best_pf = None, None, None
        for rk, rd in rzm.items():
            exp = rd.get("expectancy_r")
            pf  = rd.get("profit_factor_r")
            if exp is not None:
                if best_exp is None or exp > best_exp or (
                        exp == best_exp and (pf or 0) > (best_pf or 0)):
                    best_rk, best_exp, best_pf = rk, exp, pf
        if best_rk is None:
            for rk, rd in rzm.items():
                pf = rd.get("profit_factor_r")
                if pf is not None and (best_pf is None or pf > best_pf):
                    best_rk, best_pf = rk, pf

        best_rd = (rzm.get(best_rk) or {}) if best_rk else {}
        rows.append({
            "timeframe":            tf,
            "ob_events":            rs.get("ob_events_detected"),
            "touched_events":       rs.get("touched_events"),
            "eligible_touched":     os_.get("eligible_touched"),
            "tp_first":             os_.get("tp_first"),
            "sl_first":             os_.get("sl_first"),
            "ambiguous":            os_.get("ambiguous"),
            "avg_max_r":            os_.get("avg_max_r_reached"),
            "avg_max_adverse_r":    os_.get("avg_max_adverse_r"),
            "avg_stop_loss_r":      slm.get("avg_stop_loss_r"),
            "max_stop_loss_r":      slm.get("max_stop_loss_r"),
            "best_rr":              best_rk,
            "best_expectancy_r":    best_rd.get("expectancy_r"),
            "best_profit_factor_r": best_rd.get("profit_factor_r"),
            "net_r_at_best_rr":     best_rd.get("net_r"),
            "win_rate_at_best_rr":  best_rd.get("win_rate_pct"),
            "rr_1_expectancy":      (rzm.get("1") or {}).get("expectancy_r"),
            "rr_2_expectancy":      (rzm.get("2") or {}).get("expectancy_r"),
            "rr_3_expectancy":      (rzm.get("3") or {}).get("expectancy_r"),
            "rr_1_profit_factor":   (rzm.get("1") or {}).get("profit_factor_r"),
            "rr_2_profit_factor":   (rzm.get("2") or {}).get("profit_factor_r"),
            "rr_3_profit_factor":   (rzm.get("3") or {}).get("profit_factor_r"),
        })

    rows.sort(
        key=lambda r: (r["best_expectancy_r"] is not None,
                       r["best_expectancy_r"] or 0.0),
        reverse=True,
    )
    return rows


def _bt_run_ob_mtf_backtest(params: dict) -> dict:
    """Run single-TF engine per timeframe with candle-budget safety caps."""
    import time as _time

    symbol         = params["symbol"]
    timeframes     = params["timeframes"]
    include_events = params.get("include_events", False)
    warnings: list = []

    # ── Build per-TF candle budget ────────────────────────────────────────────
    # Caller may supply {tf: count} overrides; fall back to single candle_count
    # or the built-in safe defaults.
    base_count     = params.get("candle_count", 1000)
    override_by_tf = params.get("candle_count_by_tf") or {}

    candles_by_tf: Dict[str, int] = {}
    for tf in timeframes:
        raw = override_by_tf.get(tf, base_count)
        try:
            raw = int(raw)
        except (TypeError, ValueError):
            raw = base_count
        # per-TF hard clamp: min 300, max 1500
        candles_by_tf[tf] = max(300, min(_BT_MTF_MAX_CANDLES_PER_TF, raw))

    # ── Global total-candle cap: scale down proportionally if needed ──────────
    total_requested = sum(candles_by_tf.values())
    scaled_down     = False
    if total_requested > _BT_MTF_MAX_TOTAL_CANDLES:
        scale = _BT_MTF_MAX_TOTAL_CANDLES / total_requested
        candles_by_tf = {
            tf: max(300, int(n * scale))
            for tf, n in candles_by_tf.items()
        }
        scaled_down = True
        used_total  = sum(candles_by_tf.values())
        warnings.append(
            f"Requested {total_requested} total candles across {len(timeframes)} "
            f"timeframes; auto-scaled to {used_total} for MTF safety "
            f"(limit: {_BT_MTF_MAX_TOTAL_CANDLES})."
        )

    # ── Run per-TF ────────────────────────────────────────────────────────────
    results: Dict[str, dict] = {}
    errors:  Dict[str, str]  = {}

    for tf in timeframes:
        used_cc = candles_by_tf[tf]
        tf_params = {k: v for k, v in params.items()
                     if k not in ("timeframes", "include_events",
                                  "candle_count_by_tf", "candle_count")}
        tf_params["timeframe"]    = tf
        tf_params["candle_count"] = used_cc

        t0 = _time.time()
        try:
            res = _bt_run_ob_historical_backtest(tf_params)
        except Exception as exc:
            elapsed_ms = int((_time.time() - t0) * 1000)
            errors[tf] = str(exc)
            results[tf] = {
                "ok": False, "timeframe": tf, "error": str(exc),
                "requested_candle_count": used_cc,
                "used_candle_count":      used_cc,
                "elapsed_ms":             elapsed_ms,
            }
            continue
        elapsed_ms = int((_time.time() - t0) * 1000)

        if not res.get("ok"):
            errors[tf] = res.get("error", "unknown error")

        out: Dict = {
            "ok":                    res.get("ok", False),
            "timeframe":             tf,
            "requested_candle_count":used_cc,
            "used_candle_count":     (res.get("candle_summary") or {}).get("returned", used_cc),
            "elapsed_ms":            elapsed_ms,
            "candle_summary":        res.get("candle_summary"),
            "replay_summary":        res.get("replay_summary"),
            "outcome_summary":       res.get("outcome_summary"),
            "parity":                res.get("parity"),
            "events_total":          res.get("events_total"),
            "events_returned":       res.get("events_returned"),
            "events_sample":         res.get("events_sample"),
        }
        if not res.get("ok"):
            out["error"]   = res.get("error")
            out["details"] = res.get("details")
        if include_events:
            evs = res.get("events") or []
            out["events"] = evs[:_BT_MTF_MAX_EVS]
        results[tf] = out

    leaderboard = _bt_build_mtf_leaderboard(results)

    def _best_by(key: str, higher: bool = True):
        valid = [r for r in leaderboard if r.get(key) is not None]
        if not valid:
            return None
        return max(valid, key=lambda r: r[key]) if higher else min(valid, key=lambda r: r[key])

    def _best_3r_hit():
        best_tf, best_val = None, None
        for tf, res in results.items():
            if not res.get("ok"):
                continue
            hrr  = ((res.get("outcome_summary") or {}).get("hit_rate_by_rr") or {})
            rate = (hrr.get("3") or {}).get("rate_pct")
            if rate is not None and (best_val is None or rate > best_val):
                best_tf, best_val = tf, rate
        return best_tf

    best_exp = _best_by("best_expectancy_r",    True)
    best_pf  = _best_by("best_profit_factor_r", True)
    best_sl  = _best_by("avg_stop_loss_r",      False)
    best_3r  = _best_3r_hit()
    ok       = any(r.get("ok") for r in results.values())

    used_total_candles = sum(
        r.get("used_candle_count") or 0 for r in results.values()
    )

    return {
        "ok":           ok,
        "mode":         "multi_timeframe_ob_v1",
        "phase":        "multi_timeframe_comparison_connected",
        "symbol":       symbol,
        "timeframes":   timeframes,
        "candle_count": params.get("candle_count"),
        "rr_values":    params.get("rr_values"),
        "results":      results,
        "leaderboard":  leaderboard,
        "best": {
            "by_expectancy":          best_exp["timeframe"] if best_exp else None,
            "by_profit_factor":       best_pf["timeframe"]  if best_pf  else None,
            "by_lowest_avg_sl":       best_sl["timeframe"]  if best_sl  else None,
            "by_highest_3r_hit_rate": best_3r,
        },
        "errors":  errors,
        "mtf_limits": {
            "max_timeframes":        _BT_MTF_MAX_TF,
            "max_candles_per_tf":    _BT_MTF_MAX_CANDLES_PER_TF,
            "max_total_candles":     _BT_MTF_MAX_TOTAL_CANDLES,
            "requested_total_candles": total_requested,
            "used_total_candles":    used_total_candles,
            "scaled_down":           scaled_down,
            "warnings":              warnings,
        },
    }


@app.route("/api/backtest/ob-mtf", methods=["POST"])
@login_required
def api_backtest_ob_mtf():
    err = _guest_tab_check("backtest")
    if err is not None:
        return err

    payload = request.get_json(force=True) or {}

    raw_symbol = payload.get("symbol", "")
    if not raw_symbol or not isinstance(raw_symbol, str):
        return jsonify({"ok": False, "error": "symbol is required"}), 400
    symbol = _bt_clean_symbol(raw_symbol)

    raw_tfs = payload.get("timeframes", ["15m", "1h", "4h"])
    if not isinstance(raw_tfs, list):
        raw_tfs = [str(raw_tfs)]
    if len(raw_tfs) > _BT_MTF_MAX_TF:
        return jsonify({"ok": False,
                        "error": f"max {_BT_MTF_MAX_TF} timeframes allowed"}), 400
    timeframes = []
    for _tf in raw_tfs:
        _tf = str(_tf).strip()
        if _tf not in _BT_ALLOWED_TIMEFRAMES:
            return jsonify({"ok": False,
                            "error": f"timeframe '{_tf}' not allowed. "
                                     f"Allowed: {sorted(_BT_ALLOWED_TIMEFRAMES)}"}), 400
        timeframes.append(_tf)
    if not timeframes:
        return jsonify({"ok": False, "error": "at least one timeframe required"}), 400

    try:
        candle_count = int(payload.get("candle_count", 1000))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "candle_count must be integer"}), 400
    candle_count = max(300, min(_BT_MTF_MAX_CANDLES_PER_TF, candle_count))

    raw_cc_by_tf = payload.get("candle_count_by_tf") or {}
    candle_count_by_tf: Dict[str, int] = {}
    if isinstance(raw_cc_by_tf, dict):
        for _tf, _n in raw_cc_by_tf.items():
            try:
                candle_count_by_tf[str(_tf)] = max(300, min(_BT_MTF_MAX_CANDLES_PER_TF, int(_n)))
            except (TypeError, ValueError):
                pass

    def _bf(val, default=False):
        if isinstance(val, bool): return val
        return str(val).lower() in ("true", "1", "yes")

    params = {
        "symbol":              symbol,
        "timeframes":          timeframes,
        "candle_count":        candle_count,
        "candle_count_by_tf":  candle_count_by_tf or None,
        "exchange":            "binance",
        "market":              "perpetual",
        "rr_values":           _bt_parse_rr_values(payload.get("rr_values", [1, 2, 3])),
        "entry_rule":          "zone_high",
        "stop_rule":           "close_beyond_zone",
        "include_parity":      _bf(payload.get("include_parity", False)),
        "include_events":      _bf(payload.get("include_events", False)),
    }
    result = _bt_run_ob_mtf_backtest(params)
    return jsonify(result), 200 if result.get("ok") else 502


